INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('023446e1-5d19-45de-b1b5-9e1d9e4e8d3b', '14c0f24c-10e7-4309-a927-d9db1066897c', 19, NULL, '{\"page_id\": \"p20\", \"title\": \"结语：迈向无限可能的数字世界\", \"layout_id\": \"portfolio_industry\", \"has_image\": true, \"keywords\": [\"意境深远的全景图\", \"未来科技感\", \"深木棕与医疗白融合\", \"核心愿景\", \"无文字\"], \"depends_on\": [\"p18\"], \"must_cover\": [\"课程核心回顾\", \"未来展望\", \"结语：迈向无限可能的数字世界的核心概念与背景\", \"结语：迈向无限可能的数字世界的关键方法与执行要点\", \"结语：迈向无限可能的数字世界的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [\"pr_p11_1_3ab4dd9b\", \"pr_p01_2\"], \"points\": [\"结语：迈向无限可能的数字世界的核心概念与背景\", \"结语：迈向无限可能的数字世界的关键方法与执行要点\", \"结语：迈向无限可能的数字世界的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p11_1_3ab4dd9b\", \"pr_p01_2\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p20\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p11_1_3ab4dd9b\", \"pr_p01_2\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.774490\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'portfolio_industry', '{\"title\": \"结语：迈向无限可能的数字世界\", \"subtitle\": \"从线框构建到行业级渲染的完整蜕变。\", \"items\": [{\"image_src\": \"https://images.unsplash.com/photo-1550745165-9bc0b252726f?auto=format&fit=crop&q=80&w=1200\", \"title\": \"案例复盘：机械零件从零构建\", \"description\": \"通过严谨的拓扑优化与布线重构，成功解决复杂机械结构的变形难题，实现影视级细节与实时性能的完美平衡。\", \"tags\": [\"案例复盘\", \"结果启示\", \"技术突破\"]}, {\"image_src\": \"https://images.unsplash.com/photo-1558655146-d09347e92766?auto=format&fit=crop&q=80&w=1200\", \"title\": \"工作流全景对比：线框至渲染\", \"description\": \"展示从基础线框搭建、拓扑优化到最终光影渲染的全流程步骤，直观呈现前后效果对比与质量跃升。\", \"tags\": [\"流程步骤\", \"前后对比\", \"完整工作流\"]}], \"layout\": \"grid\", \"background_image\": \"https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&q=80&w=1920\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('0250b8da-3db4-4300-bf6c-941614837e16', '2786117f-f122-459a-8310-c05a2077848b', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"风险警示：常见违规操作后果\", \"layout_id\": \"edu_data_board\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"未泄压导致的夹伤事故数据\", \"工具脱落造成的设备损坏统计\", \"违规操作的零容忍态度\", \"风险警示：常见违规操作后果的核心概念与背景\", \"风险警示：常见违规操作后果的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"风险警示：常见违规操作后果的核心概念与背景\", \"风险警示：常见违规操作后果的关键方法与执行要点\", \"风险警示：常见违规操作后果的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_dashboard\", \"layout_variant\": \"b\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:02:17.155439\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:01:23', '2026-03-19 06:02:17', 'edu_data_board', '{\"title\": \"风险警示：常见违规操作后果\", \"subtitle\": \"基于行业事故复盘的量化分析。\", \"metrics\": [{\"value\": \"+45%\", \"label\": \"未泄压夹伤事故率\", \"note\": \"对比严格执行泄压标准组。\"}, {\"value\": \"12h\", \"label\": \"单次设备损坏修复时长\", \"note\": \"因工具脱落导致的产线停机。\"}], \"bars\": [{\"label\": \"违规操作发生率\", \"baseline\": 60, \"current\": 85}, {\"label\": \"安全事故直接损失\", \"baseline\": 40, \"current\": 92}], \"bullets\": [{\"text\": \"带压操作的致命风险。\", \"description\": \"未完全释放残余气压即拆卸连接件，极易引发高速喷射夹伤或部件飞脱伤人。\"}, {\"text\": \"非标准安装的连锁反应。\", \"description\": \"省略锁定步骤或扭矩不达标，导致高速运行中工具脱落，造成昂贵传感器与机械臂本体损毁。\"}], \"insight\": \"数据表明，严格遵循断电、泄压、锁定三步法是杜绝此类可预防性事故的唯一途径，任何侥幸心理都将付出高昂代价。\", \"background_image\": \"https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?q=80&w=2070&auto=format&fit=crop\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"data_dashboard\"}');
