INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('02d278b9-8ce0-4c76-9d7e-883a5689326a', '8a37f529-e51f-428c-8466-cdc137b73187', 21, NULL, '{\"page_id\": \"p22\", \"title\": \"推荐学习资源与进阶路径\", \"layout_id\": \"key_concepts\", \"has_image\": true, \"keywords\": [\"推荐学习资源与进阶路径\", \"场景示意\", \"视觉辅助\"], \"depends_on\": [\"p18\"], \"must_cover\": [\"专业书籍列表\", \"开源模型库推荐\", \"社区论坛指引\", \"下一步技能树\", \"推荐学习资源与进阶路径的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"推荐学习资源与进阶路径的核心概念与背景\", \"推荐学习资源与进阶路径的关键方法与执行要点\", \"推荐学习资源与进阶路径的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p22\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.108284\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 12:53:12', 'key_concepts', '{\"title\": \"推荐学习资源与进阶路径\", \"subtitle\": \"构建从理论到工程落地的完整知识体系。\", \"bullets\": [{\"icon\": \"fa-book\", \"text\": \"专业书籍精读清单。\", \"description\": \"涵盖实时渲染底层原理与程序化纹理生成，重点研读《Real-Time Rendering》第4版及《Procedural Texturing for Games》，建立扎实的数学与算\"}, {\"icon\": \"fa-code\", \"text\": \"开源模型库实战指南。\", \"description\": \"推荐接入Blender Geometry Nodes与Houdini Engine，利用其节点树架构复现PBR参数生成的像素级转化逻辑，强化工具链互补能力。\"}, {\"icon\": \"fa-users\", \"text\": \"社区论坛与技术交流。\", \"description\": \"加入Polycount与Unreal Engine官方论坛，关注GPU顶点处理能力饱和等性能陷阱的讨论案例，获取一线工程落地经验。\"}, {\"icon\": \"fa-sitemap\", \"text\": \"下一步技能树规划。\", \"description\": \"从静态资产转化为动态场景表达入手，掌握LOD技术后，进阶学习动态光照烘焙与体积云渲染，提升视觉保真度。\"}], \"keyTakeaway\": \"通过系统化的书籍研读、开源工具实战及社区交流，构建从节点树架构理解到高性能引擎优化的闭环技能体系，有效规避工程中的性能陷阱。\", \"image\": {\"src\": \"https://images.unsplash.com/photo-1517694712202-14dd9538aa97?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80\", \"alt\": \"展示程序化纹理节点树与代码编辑界面的学术风格插图，背景为冷灰色网格，无文字标识\", \"position\": \"right\", \"width\": \"35%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('035c8222-031d-4c89-abf2-52ff197cfa64', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef', 3, '第一部分：核心概念', '{\"title\": \"什么是3D建模：定义与核心价值：案例复盘\", \"points\": [\"问题与场景：传统2D设计难以直观展示产品内部结构与装配关系，导致沟通成本高。\", \"方案与执行：构建高精度虚拟原型进行碰撞检测与动态演示，替代早期物理样机制作。\", \"结果与启示：缩短研发周期40%，验证了3D模型作为跨部门协作核心载体的关键价值。\", \"风险提示：需警惕过度追求几何精度而忽视拓扑优化，影响后续动画与渲染效率。\"], \"part\": \"第一部分：核心概念\"}', '{\"text\": \"页面标题：什么是3D建模：定义与核心价值：案例复盘\\n\\n页面文字：\\n- 传统2D设计难以直观展示产品内部结构，导致跨部门沟通成本高昂。\\n- 通过构建高精度虚拟原型进行碰撞检测，有效替代了早期物理样机制作。\\n- 该方案缩短研发周期达40%，验证了3D模型作为协作核心载体的关键价值。\\n- 需警惕过度追求几何精度而忽视拓扑优化，以免拖累后续动画渲染效率。\", \"generated_at\": \"2026-03-10T05:38:52.178841\"}', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef/pages/035c8222-031d-4c89-abf2-52ff197cfa64_v1.png', 'COMPLETED', '2026-03-10 05:38:25', '2026-03-10 06:04:05', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('03632b20-aa48-41fc-9645-b835ebbc7a29', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef', 6, '第二部分：核心流程', '{\"page_id\": \"p05\", \"title\": \"标准工作流：从草图到渲染\", \"part\": \"第二部分：核心流程\", \"points\": [\"前期规划阶段需确立参考图比例与视角，规避后期建模偏差\", \"高模塑造细节与低模优化性能之间需建立动态平衡策略\", \"UV展开应遵循最小拉伸原则，确保贴图分辨率均匀分布\", \"材质映射逻辑需匹配物理属性，实现光影下的真实质感还原\"]}', '{\"text\": \"页面标题：标准工作流：从草图到渲染\\n\\n页面文字：\\n- 前期规划阶段需严格确立参考图比例与视角，有效规避后期建模过程中的几何偏差。\\n- 在高模细节塑造与低模性能优化之间建立动态平衡策略，确保视觉质量与运行效率兼顾。\\n- UV展开操作应遵循最小拉伸原则，保障贴图分辨率在模型表面实现均匀且无变形的分布。\\n- 材质映射逻辑必须精准匹配物体物理属性，从而在复杂光影环境下还原真实的质感表现。\", \"generated_at\": \"2026-03-10T05:38:52.997106\"}', NULL, 'FAILED', '2026-03-10 05:38:30', '2026-03-10 05:38:58', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('0366d7c6-5b0f-440a-a1fa-d3bcbd49d6f5', 'b494fc12-8d48-4b4c-8717-9faa745d5f79', 17, NULL, '{\"page_id\": \"p18\", \"title\": \"知识脑图：全流程技术总结\", \"layout_id\": \"mind_map_structure\", \"has_image\": true, \"keywords\": [], \"depends_on\": [\"p15\"], \"must_cover\": [\"拓扑\", \"UV\", \"材质\", \"烘焙\", \"引擎\"], \"promises_open\": [], \"promises_close\": [\"pr_p10_1_f56da1a4\", \"pr_p19_1_f82c9855\", \"pr_p01_1\", \"pr_p01_2\", \"pr_p03_1\"], \"points\": [\"知识脑图：全流程技术总结的核心概念与背景\", \"知识脑图：全流程技术总结的关键方法与执行要点\", \"知识脑图：全流程技术总结的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p10_1_f56da1a4\", \"pr_p19_1_f82c9855\", \"pr_p01_1\", \"pr_p01_2\", \"pr_p03_1\"], \"layout_archetype\": \"case_visual\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-08 02:23:20', '2026-03-08 02:23:20', 'mind_map_structure', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('039f4365-9e9a-4bc8-aebf-4aa79fb34dda', '8f10b0ec-ba8a-41c7-9730-10360d6d560d', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"分阶段实施路径推进表\", \"layout_id\": \"edu_timeline_steps\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p05\"], \"must_cover\": [\"第一阶段基础操作\", \"第二阶段项目实战\", \"第三阶段作品集优化\", \"分阶段实施路径推进表的核心概念与背景\", \"分阶段实施路径推进表的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p06_1\", \"text\": \"通过阶段性训练，最终产出可量化的能力增长指标，后续页面展示数据看板\", \"must_cover\": [\"技能提升百分比\", \"完成作品数量\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"promises_close\": [\"pr_p05_1\"], \"points\": [\"分阶段实施路径推进表的核心概念与背景\", \"分阶段实施路径推进表的关键方法与执行要点\", \"分阶段实施路径推进表的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p05_1\"], \"layout_archetype\": \"timeline\", \"layout_variant\": \"a\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p05_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T07:30:15.651444\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 07:23:27', '2026-03-08 01:15:32', 'edu_timeline_steps', '{\"title\": \"分阶段实施路径推进表\", \"subtitle\": \"从入门到精通的三阶成长规划。\", \"steps\": [{\"number\": 1, \"label\": \"步骤1\", \"description\": \"基础操作与原理验证。\", \"icon\": \"fa-check\"}, {\"number\": 2, \"label\": \"步骤2\", \"description\": \"项目实战与复杂结构。\", \"icon\": \"fa-check\"}, {\"number\": 3, \"label\": \"步骤3\", \"description\": \"作品集优化与交付。\", \"icon\": \"fa-check\"}], \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"timeline\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('03b75665-593e-479d-9499-95c9f2039c25', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 19, '第三部分：工具链选择与软件生态', '{\"title\": \"主流3D软件横向对比与场景匹配指南\", \"points\": [\"Blender（开源免费）vs Maya（影视工业）vs C4D（广告动画）\", \"各软件的学习曲线分析与上手难度评估\", \"硬件配置门槛与性能优化方案\", \"决策依据：如何根据职业方向选择最佳工具\"], \"layout_id\": \"edu_qa_case\", \"part\": \"第三部分：工具链选择与软件生态\", \"logical_page_id\": \"p20\", \"has_image\": false, \"keywords\": [\"Blender（开源免费）vs Maya（影视工业）vs C4D（广告动画）\", \"各软件的学习曲线分析与上手难度评估\", \"硬件配置门槛与性能优化方案\"], \"depends_on\": [\"p19\"], \"must_cover\": [\"Blender（开源免费）vs Maya（影视工业）vs C4D（广告动画）\", \"各软件的学习曲线分析与上手难度评估\", \"硬件配置门槛与性能优化方案\", \"决策依据：如何根据职业方向选择最佳工具\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"c\", \"layout_archetype\": \"qa_session\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.419303\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_qa_case', '{\"title\": \"主流3D软件横向选型指南\", \"subtitle\": \"基于职业场景的工具决策矩阵。\", \"question\": \"面对Blender、Maya与C4D，如何根据职业方向选择最佳工具并平衡学习成本？\", \"answer\": \"依据行业赛道精准匹配：影视工业选Maya，广告动画选C4D，独立创作或预算受限选Blender；需同步评估硬件门槛以优化性能。\", \"analysis\": [{\"title\": \"生态定位对比\", \"content\": \"Blender全功能开源免费，Maya是影视管线标准，C4D在动态设计与广告领域统治力强。\"}, {\"title\": \"学习曲线与难度\", \"content\": \"C4D上手最快适合新手，Maya逻辑复杂但深度深，Blender功能全面但操作逻辑独特需适应期。\"}, {\"title\": \"硬件与性能方案\", \"content\": \"高面数渲染需高端显卡，通过代理模型与分布式渲染降低单机配置门槛，实现性能最优解。\"}], \"conclusion\": \"工具无绝对优劣，只有是否适配当前项目需求与团队技术栈。\", \"background_image\": \"\", \"variant\": \"c\", \"layout_variant\": \"c\", \"layout_archetype\": \"qa_session\"}');
