INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('04a64d7e-f555-4647-9fa7-247a976b26e8', '5017ef94-ccdd-4b4d-b44d-bd7d5c389ec3', 0, NULL, '{\"title\": \"封面\", \"points\": [\"主题引入\"]}', '{\"text\": \"页面标题：封面\\n页面文字：\\n- 新封面描述\", \"generated_at\": \"2026-03-09T14:18:55.414295\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 06:18:55', '2026-03-09 14:18:55', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('04f1a2ec-79c2-4faf-bcc5-70d28c59ac00', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d', 6, '应用场景', '{\"page_id\": \"p06\", \"title\": \"核心任务二：命名实体识别（NER）\", \"part\": \"应用场景\", \"points\": [\"精准提取文本中的人名、地名、机构名及时间日期等关键实体\", \"基于BiLSTM-CRF的序列标注模型原理与标签解码策略解析\", \"为知识图谱构建提供结构化数据基础，实现非结构化文本向关系型数据的转化\", \"在智能客服、司法文书分析及金融风控中的核心落地场景\"]}', '{\"text\": \"页面标题：核心任务二：命名实体识别（NER）\\n\\n页面文字：\\n- 精准提取文本中的人名、地名、机构名及时间日期等关键信息，实现非结构化数据的初步结构化。\\n- 深入解析基于BiLSTM-CRF的序列标注模型原理，阐述其标签解码策略如何优化实体边界判定。\\n- 该能力为知识图谱构建提供坚实的数据基础，有效推动从自由文本到关系型数据的转化进程。\\n- 此技术在智能客服问答、司法文书自动分析及金融风控反欺诈场景中发挥着不可替代的核心作用。\", \"generated_at\": \"2026-03-16T05:37:23.049261\"}', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d/pages/04f1a2ec-79c2-4faf-bcc5-70d28c59ac00_v2.png', 'COMPLETED', '2026-03-16 05:37:03', '2026-03-16 06:31:25', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('0509584e-4e9f-4883-86b5-2ae43af04c91', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 6, '技能实操', '{\"page_id\": \"p05\", \"title\": \"硬表面建模流程演示\", \"part\": \"技能实操\", \"points\": [\"利用基础几何体组合搭建复杂机械骨架与结构逻辑\", \"通过倒角处理与细分曲面技术消除棱角提升真实感\", \"掌握布尔运算与编辑模式的高效配合以优化布线\", \"遵循硬表面建模规范确保模型在变形时保持拓扑整洁\"]}', '{\"text\": \"页面标题：硬表面建模流程演示\\n\\n页面文字：\\n- 利用基础几何体组合搭建复杂机械骨架，构建严谨的结构逻辑。\\n- 通过倒角处理与细分曲面技术消除生硬棱角，显著提升模型真实感。\\n- 掌握布尔运算与编辑模式的高效配合，在操作中持续优化布线质量。\\n- 严格遵循硬表面建模规范，确保模型在后续变形时始终保持拓扑整洁。\", \"generated_at\": \"2026-03-09T03:39:37.135408\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/0509584e-4e9f-4883-86b5-2ae43af04c91_v1.png', 'COMPLETED', '2026-03-09 03:39:16', '2026-03-09 03:45:24', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('05232f2b-8a2f-4428-a147-db5875d3da8c', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 0, '第一部分：课程导览与愿景', '{\"title\": \"3D建模专业实战体系：从理论认知到商业交付\", \"points\": [\"课程核心目标：构建系统化3D工作流思维，培养工匠精神与职业素养\", \"适用人群定位：零基础设计师至进阶创作者，强调严谨治学态度\", \"最终成果预览：商业级硬表面模型全流程解析，展现精益求精的匠心\", \"视觉风格：深邃科技蓝背景搭配青色高亮线条，体现现代工业美学\", \"承诺交付：完整工作流拆解与真实项目效率对比，树立行业标杆\"], \"layout_id\": \"edu_cover\", \"part\": \"第一部分：课程导览与愿景\", \"logical_page_id\": \"p01\", \"has_image\": false, \"keywords\": [\"课程核心目标：构建系统化3D工作流思维，培养工匠精神与职业素养\", \"适用人群定位：零基础设计师至进阶创作者，强调严谨治学态度\", \"最终成果预览：商业级硬表面模型全流程解析，展现精益求精的匠心\"], \"depends_on\": [], \"must_cover\": [\"课程核心目标：构建系统化3D工作流思维，培养工匠精神与职业素养\", \"适用人群定位：零基础设计师至进阶创作者，强调严谨治学态度\", \"最终成果预览：商业级硬表面模型全流程解析，展现精益求精的匠心\", \"视觉风格：深邃科技蓝背景搭配青色高亮线条，体现现代工业美学\", \"承诺交付：完整工作流拆解与真实项目效率对比，树立行业标杆\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"b\", \"layout_archetype\": \"cover\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.418451\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_cover', '{\"title\": \"3D建模专业实战体系：从理论认知到商业交付\", \"subtitle\": \"构建系统化工作流思维 · 践行工匠精神与职业素养。\", \"author\": \"资深3D导师团队\", \"department\": \"数字创意设计中心\", \"date\": \"2024年课程发布\", \"hero_image\": \"\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"cover\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('052cb212-14bd-4904-b941-7f4b2fd47672', 'f8ce8774-c982-4cd5-a379-23d4cf53bef2', 8, NULL, '{\"page_id\": \"p09\", \"title\": \"实操步骤一：设备调试与校准\", \"layout_id\": \"vocational_step_by_step\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p07\"], \"must_cover\": [\"气垫导轨水平调节标准\", \"细线与滑轮对齐检查\", \"光电门零位校准流程\", \"实操步骤一：设备调试与校准的核心概念与背景\", \"实操步骤一：设备调试与校准的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p08_1\"], \"points\": [\"实操步骤一：设备调试与校准的核心概念与背景\", \"实操步骤一：设备调试与校准的关键方法与执行要点\", \"实操步骤一：设备调试与校准的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p08_1\"], \"layout_archetype\": \"process_steps\", \"layout_variant\": \"a\", \"logical_page_id\": \"p09\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p08_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T06:43:32.018080\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 06:42:47', '2026-03-17 14:44:01', 'vocational_step_by_step', '{\"title\": \"实操步骤一：设备调试与校准\", \"subtitle\": \"从气垫导轨到光电门的精准设置。\", \"steps\": [{\"number\": 1, \"label\": \"导轨调平\", \"description\": \"调节底脚螺丝，使滑块静止或匀速运动，消除摩擦误差。注意轻拿轻放，防止滑块跌落损坏。\", \"icon\": \"fa-cog\"}, {\"number\": 2, \"label\": \"细线对齐\", \"description\": \"检查牵引细线与滑轮槽及导轨严格平行，避免侧向分力。确保细线未缠绕或打结。\", \"icon\": \"fa-arrows-alt-h\"}, {\"number\": 3, \"label\": \"零位校准\", \"description\": \"设定光电门初始位置为计时零点，确保位移测量基准准确。检查光电门感应是否灵敏。\", \"icon\": \"fa-ruler-combined\"}, {\"number\": 4, \"label\": \"系统自检\", \"description\": \"开启气源检查漏气情况，确认数据采集器响应灵敏无误。注意气源压力适中，防止喷溅伤人。\", \"icon\": \"fa-check-circle\"}, {\"number\": 5, \"label\": \"重复验证\", \"description\": \"进行空载预实验，验证多次测量结果的一致性以排除偶然误差。观察滑块运动是否平稳。\", \"icon\": \"fa-sync-alt\"}, {\"number\": 6, \"label\": \"记录状态\", \"description\": \"在实验记录表中登记设备初始状态参数，作为后续分析依据。发现异常立即上报。\", \"icon\": \"fa-clipboard-list\"}], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"process_steps\"}');
