INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('05c56d3f-1020-4361-8601-806d02d883c6', '1f37a671-a607-4c8a-8f40-01a92198cd70', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"第一章：3D建模基础概念解析\", \"layout_id\": \"learning_objectives\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p03\"], \"must_cover\": [\"章节引入\", \"第一章：3D建模基础概念解析的核心概念与背景\", \"第一章：3D建模基础概念解析的关键方法与执行要点\", \"第一章：3D建模基础概念解析的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第一章：3D建模基础概念解析的核心概念与背景\", \"第一章：3D建模基础概念解析的关键方法与执行要点\", \"第一章：3D建模基础概念解析的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:30:52', '2026-03-10 05:30:52', 'learning_objectives', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('0674b907-9ce0-4e26-9d7a-8ab327bfc244', '8a37f529-e51f-428c-8466-cdc137b73187', 14, NULL, '{\"title\": \"案例研究：金属与陶瓷的材质还原：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"academic_narrative\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p15\", \"depends_on\": [\"p14\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [{\"promise_id\": \"pr_p15_1_746aa857\", \"text\": \"案例研究：金属与陶瓷的材质还原：案例复盘的复盘与结果启示\", \"must_cover\": [\"案例复盘\", \"结果启示\"], \"target_page_ids\": [\"p20\"], \"is_hard\": true}], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p15\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.107976\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'academic_narrative', '{\"title\": \"知识讲解标题\", \"narrative\": [\"本案例的核心矛盾在于如何平衡物理准确性与视觉表现力。金属的高反射特性极易受环境光影响导致细节丢失，而陶瓷的漫反射主导特性则对粗糙度变化极为敏感，任何微小的参数偏差都会破坏材质的可信度。\", \"方案执行阶段，首先通过UV布局分析确定高光区域的拓扑结构，随后采用分段式参数调整策略。对于金属部分，重点修正菲涅尔方程中的折射率（IOR）以匹配实际金属光学常数；对于陶瓷部分，利用法线映射机制模拟釉面微观起伏，避免过度平滑导致的塑料感。\", \"最终结果验证表明，经过物理参数校准后的渲染图在动态光照测试中保持了能量守恒，且在不同视角下均能呈现自然的渐变效果。此过程提示我们，PBR流程的成功依赖于对基础物理定律的深刻理解与严格执行。\"], \"margin_notes\": [{\"title\": \"核心概念\", \"content\": \"IOR（折射率）：决定光线进入介质时的弯曲程度，直接影响反射强度与颜色饱和度。\"}, {\"title\": \"风险提示\", \"content\": \"切勿仅凭经验调整参数，必须结合物理测量数据或参考真实世界样本进行校准。\"}], \"pull_quote\": \"材质还原的本质不是模仿外观，而是重建其背后的物理交互逻辑。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('06ae3796-9e77-4277-a357-53fdfe9dcc22', '6c250523-422a-46f3-a1f1-42e82424897c', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"工具详解：Blender与Maya的工作流对比\", \"layout_id\": \"academic_narrative\", \"has_image\": true, \"keywords\": [\"软件界面\", \"操作面板\", \"节点编辑器\", \"时间轴\", \"专业工作台\"], \"depends_on\": [\"p08\"], \"must_cover\": [\"快捷键体系\", \"插件生态\", \"渲染引擎集成\", \"协作模式\", \"工具详解：Blender与Maya的工作流对比的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"工具详解：Blender与Maya的工作流对比的核心概念与背景\", \"工具详解：Blender与Maya的工作流对比的关键方法与执行要点\", \"工具详解：Blender与Maya的工作流对比的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.286908\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'academic_narrative', '{\"title\": \"工具详解：Blender与Maya的工作流对比\", \"narrative\": [\"Blender与Maya代表了开源独立创作与工业级管线两种截然不同的工作哲学。Blender以高度集成的节点编辑器与时间轴为核心，通过快捷键体系实现零延迟操作，其插件生态强调快速原型构建与社区驱动的创新，渲染引擎Cycles原生集成且支持实时预览，协作模式多基于版本控制文件共享，适合独立开发者与中小团队。\", \"Maya则构建了以分层属性编辑器与复杂脚本接口为基石的硬表面建模环境，其操作面板深度适配影视动画长周期制作，插件生态聚焦于高端定制化工具链，渲染引擎Arnold与Redshift提供企业级稳定性，协作模式依托ShotGrid等云端管线系统，严格遵循数据流转规范，是大型影视与游戏项目的标准配置。\"], \"margin_notes\": [{\"title\": \"核心概念：节点编辑器\", \"content\": \"Blender中通过可视化节点连接定义材质与几何逻辑，替代传统参数输入，提升复杂效果的可控性与复用性。\"}, {\"title\": \"核心概念：协作模式\", \"content\": \"Maya依赖中心化管理平台进行资产版本控制，而Blender常采用分布式文件同步，需配合Git等工具管理冲突。\"}], \"pull_quote\": \"软件选择不应仅看功能列表，而应匹配项目管线的生命周期与团队协作的深度需求。\", \"background_image\": \"https://images.unsplash.com/photo-1633356122544-f134324a6cee?auto=format&fit=crop&q=80&w=2070\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
