INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('07ca4d82-f428-438f-91b0-950a1ea3049f', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"流程解析：高模到低模的烘焙全流程\", \"layout_id\": \"group_collab\", \"has_image\": true, \"keywords\": [\"烘焙流程图\", \"UV展开示意\", \"法线贴图生成过程\", \"步骤图标\", \"职教绿进度条\"], \"depends_on\": [\"p09\"], \"must_cover\": [\"高模细节保留\", \"低模拓扑匹配\", \"烘焙参数设置\", \"流程解析：高模到低模的烘焙全流程的核心概念与背景\", \"流程解析：高模到低模的烘焙全流程的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_intro_02\"], \"points\": [\"流程解析：高模到低模的烘焙全流程的核心概念与背景\", \"流程解析：高模到低模的烘焙全流程的关键方法与执行要点\", \"流程解析：高模到低模的烘焙全流程的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_intro_02\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_intro_02\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928545\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'group_collab', '{\"title\": \"流程解析：高模到低模的烘焙全流程\", \"subtitle\": \"从ZBrush高模到Blender低模的细节传递。\", \"bullets\": [{\"icon\": \"fa-cube\", \"text\": \"高模细节保留策略。\", \"description\": \"在ZBrush中通过细分曲面增加微细节，确保法线信息完整捕获，避免高频噪点丢失。\"}, {\"icon\": \"fa-expand-arrows-alt\", \"text\": \"低模拓扑匹配。\", \"description\": \"依据关节与形变区域优化低模布线，确保UV展开无拉伸，为烘焙提供完美基础。\"}, {\"icon\": \"fa-sliders-h\", \"text\": \"烘焙参数精准设置。\", \"description\": \"配置法线贴图生成参数（如半径、采样率），解决自遮挡问题，实现细节无损转移。\"}, {\"icon\": \"fa-link\", \"text\": \"PBR材质节点连接。\", \"description\": \"将生成的法线、AO、粗糙度贴图正确连接至渲染器节点，完成视觉效果的最终呈现。\"}], \"keyTakeaway\": \"烘焙是连接高模细节与低模性能的桥梁，精准的参数设置能减少70%的后期修复时间。\", \"image\": {\"src\": \"\", \"alt\": \"流程图示：左侧ZBrush高模，中间UV展开示意，右侧Blender低模带法线贴图，职教绿进度条贯穿全程\", \"position\": \"right\", \"width\": \"35%\"}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('07ce12db-23e1-4883-9ef7-e39e97cf7346', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 14, NULL, '{\"page_id\": \"p15\", \"title\": \"常见误区与调试技巧\", \"layout_id\": \"case_before_after\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p13\"], \"must_cover\": [\"边界条件错误\", \"死循环风险\", \"调试断点设置\", \"常见误区与调试技巧的核心概念与背景\", \"常见误区与调试技巧的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"常见误区与调试技巧的核心概念与背景\", \"常见误区与调试技巧的关键方法与执行要点\", \"常见误区与调试技巧的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p15\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832374\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'case_before_after', '{\"title\": \"常见误区与调试技巧：避坑指南\", \"left\": {\"header\": \"核心误区：边界与逻辑陷阱\", \"content\": [\"常见误区与调试技巧在核心误区：边界与逻辑陷阱下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-bug\", \"text\": \"忽略空数组或单元素数组的边界处理，导致索引越界崩溃。\", \"description\": \"解释忽略空数组或单元素数组的边界处理，导致索引越界崩溃。在核心误区：边界与逻辑陷阱维度下的意义。\"}, {\"icon\": \"fa-sync\", \"text\": \"标志位重置时机错误，导致后续轮次误判为已排序而提前退出。\", \"description\": \"解释标志位重置时机错误，导致后续轮次误判为已排序而提前退出。在核心误区：边界与逻辑陷阱维度下的意义。\"}, {\"icon\": \"fa-stop-circle\", \"text\": \"死循环风险：当交换逻辑未正确更新指针时，程序陷入无限等待。\", \"description\": \"解释死循环风险：当交换逻辑未正确更新指针时，程序陷入无限等待。在核心误区：边界与逻辑陷阱维度下的意义。\"}, {\"icon\": \"fa-search-minus\", \"text\": \"过度依赖随机测试，忽略了极端有序或完全逆序的特殊用例。\", \"description\": \"解释过度依赖随机测试，忽略了极端有序或完全逆序的特殊用例。在核心误区：边界与逻辑陷阱维度下的意义。\"}]}, \"right\": {\"header\": \"调试技巧：精准定位与修复\", \"content\": [\"常见误区与调试技巧在调试技巧：精准定位与修复下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-play-circle\", \"text\": \"设置断点于循环内部，逐行观察变量变化与标志位翻转过程。\", \"description\": \"解释设置断点于循环内部，逐行观察变量变化与标志位翻转过程。在调试技巧：精准定位与修复维度下的意义。\"}, {\"icon\": \"fa-file-code\", \"text\": \"打印中间态日志：记录每一轮交换前后的数组快照以追踪逻辑。\", \"description\": \"解释打印中间态日志：记录每一轮交换前后的数组快照以追踪逻辑。在调试技巧：精准定位与修复维度下的意义。\"}, {\"icon\": \"fa-ruler-combined\", \"text\": \"构造最小复现用例：使用 3-5 个元素构建逆序、正序及混合数据。\", \"description\": \"解释构造最小复现用例：使用 3-5 个元素构建逆序、正序及混合数据。在调试技巧：精准定位与修复维度下的意义。\"}, {\"icon\": \"fa-eye\", \"text\": \"利用可视化图表监控比较次数，快速识别非预期的性能衰减点。\", \"description\": \"解释利用可视化图表监控比较次数，快速识别非预期的性能衰减点。在调试技巧：精准定位与修复维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
