INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('085acf46-e164-426b-b409-3b7273e909d7', 'f8ce8774-c982-4cd5-a379-23d4cf53bef2', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"实操步骤二：数据采集与验证\", \"layout_id\": \"vocational_step_by_step\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p08\"], \"must_cover\": [\"多次测量取平均值原则\", \"释放滑块的规范性动作\", \"异常数据的即时标记\", \"实操步骤二：数据采集与验证的核心概念与背景\", \"实操步骤二：数据采集与验证的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"实操步骤二：数据采集与验证的核心概念与背景\", \"实操步骤二：数据采集与验证的关键方法与执行要点\", \"实操步骤二：数据采集与验证的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"process_steps\", \"layout_variant\": \"a\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T06:43:32.018114\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 06:42:47', '2026-03-17 14:44:01', 'vocational_step_by_step', '{\"title\": \"实操步骤二：数据采集与验证\", \"subtitle\": \"基于多次测量与规范动作的数据获取流程。\", \"steps\": [{\"number\": 1, \"label\": \"规范释放滑块\", \"description\": \"确保细线平行导轨，轻放滑块避免初速度干扰，消除人为操作误差。严禁抛掷滑块。\", \"icon\": \"fa-hand-paper-o\"}, {\"number\": 2, \"label\": \"执行多次测量\", \"description\": \"同一条件下重复实验至少 5 次，严格遵循多次测量取平均值原则以提高精度。\", \"icon\": \"fa-refresh\"}, {\"number\": 3, \"label\": \"即时标记异常\", \"description\": \"发现数据突变立即暂停，现场标记异常点并记录原因，严禁事后随意修改。思考可能的人为失误。\", \"icon\": \"fa-exclamation-triangle\"}, {\"number\": 4, \"label\": \"数据初步校验\", \"description\": \"对比相邻组数据波动范围，若超出允许误差需重新校准设备或检查气垫状态。\", \"icon\": \"fa-check-circle\"}], \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"process_steps\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('086630e1-08ab-4f4b-8137-7b7023064da9', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef', 5, '第一部分：核心概念', '{\"title\": \"建模基石：多边形、NURBS与体素：案例复盘\", \"points\": [\"问题与场景：针对机械零件（需高精度曲面）与游戏角色（需动态变形）的差异化建模需求矛盾\", \"方案与执行：对比展示NURBS在工业曲面的参数化构建，以及多边形拓扑在角色关节处的布线策略\", \"结果与启示：明确不同几何体素在渲染效率与编辑灵活性上的权衡，确立混合工作流的最佳实践\"], \"part\": \"第一部分：核心概念\"}', '{\"text\": \"页面标题：建模基石：多边形、NURBS与体素：案例复盘\\n\\n页面文字：\\n- 针对机械零件的高精度曲面需求与游戏角色的动态变形需求存在天然矛盾。\\n- 对比展示了NURBS参数化构建工业曲面及多边形布线策略处理角色关节的方案。\\n- 明确了不同几何体素在渲染效率与编辑灵活性上的权衡，确立混合工作流最佳实践。\", \"generated_at\": \"2026-03-10T05:38:52.178850\"}', NULL, 'FAILED', '2026-03-10 05:38:29', '2026-03-10 05:38:58', NULL, NULL);
