INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('0aced277-0ad1-40ad-a8be-5ce6561a95cd', '130ea17c-c678-4285-8c4c-06b099d8fa71', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"易错点深度剖析：矢量性与瞬时性\", \"layout_id\": \"edu_qa_case\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"方向判断错误\", \"合力计算误区\", \"瞬时对应关系\", \"易错点深度剖析：矢量性与瞬时性的核心概念与背景\", \"易错点深度剖析：矢量性与瞬时性的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p01_2\"], \"points\": [\"易错点深度剖析：矢量性与瞬时性的核心概念与背景\", \"易错点深度剖析：矢量性与瞬时性的关键方法与执行要点\", \"易错点深度剖析：矢量性与瞬时性的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_2\"], \"layout_archetype\": \"qa_session\", \"layout_variant\": \"a\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:15:52.390943\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 02:14:47', '2026-03-17 02:15:52', 'edu_qa_case', '{\"title\": \"易错点深度剖析：矢量性与瞬时性\", \"question\": \"在牛顿第二定律计算中，为何常出现合力方向判断错误及瞬时加速度混淆？\", \"answer\": \"必须严格区分矢量合成路径与状态突变瞬间，建立“受力即加速”的瞬时对应逻辑。\", \"analysis\": [{\"title\": \"方向判断误区修正\", \"content\": \"避免仅凭速度方向判断受力，需依据合外力矢量和确定加速度方向，利用正交分解法消除维度干扰。\"}, {\"title\": \"瞬时对应关系解析\", \"content\": \"明确力与加速度同时产生、同时变化，绳子断裂或接触面消失的瞬间，加速度立即发生突变而非速度突变。\"}, {\"title\": \"经典解法\", \"content\": \"围绕经典解法说明审题依据、关键步骤与结果检验方式。\"}], \"conclusion\": \"解题核心在于锁定“受力瞬间”与“矢量合成”，规避惯性思维陷阱。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"qa_session\"}');
