INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('0ce15e5d-a3d9-49d3-8b7a-d588bf2848c9', 'c3f4f20a-0839-4fb0-9375-125c6af13f37', 11, NULL, '{\"page_id\": \"p12\", \"title\": \"实训工单：任务发布\", \"layout_id\": \"sk_task\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p11\"], \"must_cover\": [\"任务目标\", \"所需工具清单\", \"评分标准\", \"完成时限\", \"实训工单：任务发布的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"实训工单：任务发布的核心概念与背景\", \"实训工单：任务发布的关键方法与执行要点\", \"实训工单：任务发布的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p12\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:04:18.361040\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:03:29', '2026-03-19 06:04:18', 'sk_task', '{\"title\": \"实训工单：任务发布\", \"prompt\": \"任务：针对指定机器人末端执行器进行全流程故障模拟排查与修复，并完成SOP合规性验证。\", \"roles\": [\"操作员（负责现场执行与安全监护）\", \"技术员（负责故障诊断与参数调整）\"], \"questions\": [\"如何快速判断是气路问题还是电气信号问题？\", \"在更换密封圈时，哪些细节最容易导致二次泄漏？\"], \"notes\": [\"必须在切断主电源并悬挂警示牌后方可接触内部组件。\", \"所有维修动作需严格对照SOP核查表逐项打钩确认。\"], \"content\": [\"实训工单：任务发布在真实场景中的应用价值与落地建议。\", \"实训工单：任务发布在真实场景中的应用价值与落地建议。\"], \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
