INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('0e6a3d6d-8e4e-4806-a646-3ed669189932', '8ccaacf6-cf8f-4cd6-8ca8-7d5f28350c89', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"二、教学目标：三维能力构建\", \"layout_id\": \"vocational_objectives\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p03\"], \"must_cover\": [\"知识目标（理解定律）\", \"技能目标（参数调试）\", \"素养目标（规范操作）\", \"二、教学目标：三维能力构建的核心概念与背景\", \"二、教学目标：三维能力构建的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p03_1\", \"pr_p03_2\"], \"points\": [\"二、教学目标：三维能力构建的核心概念与背景\", \"二、教学目标：三维能力构建的关键方法与执行要点\", \"二、教学目标：三维能力构建的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p03_1\", \"pr_p03_2\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:41:09.847630\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:40:27', '2026-03-17 07:41:10', 'vocational_objectives', '{\"title\": \"二、教学目标：三维能力构建\", \"bullets\": [{\"icon\": \"fa fa-book\", \"text\": \"知识目标：定律解析与计算。\", \"description\": \"深入理解牛顿第二定律 F=ma 在机电系统中的物理意义，掌握质量、力与加速度的定量关系。\"}, {\"icon\": \"fa fa-cogs\", \"text\": \"技能目标：参数调试与优化。\", \"description\": \"能够根据 F=ma 计算结果，精准设定变频器加减速时间，消除启动冲击。\"}, {\"icon\": \"fa fa-shield\", \"text\": \"素养目标：规范操作与安全。\", \"description\": \"养成严谨的调试习惯，严格遵守设备操作规程，树立安全第一的职业意识。\"}], \"keyTakeaway\": \"教学目标紧扣职业场景，实现从理论认知到实操落地，再到安全规范的全面能力构建。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('0ec9390c-7362-4a8a-a324-e14ef03d3511', '4e889981-954e-4263-b490-230183b1a644', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"任务工单：传送带启停抖动故障排查\", \"layout_id\": \"vocational_lead_in\", \"has_image\": true, \"keywords\": [\"自动化传送带\", \"工人手持检测仪\", \"设备控制面板特写\", \"警示标识\", \"工业现场\"], \"depends_on\": [\"p02\", \"p03\"], \"must_cover\": [\"场景描述：物流分拣线\", \"故障现象：加速阶段剧烈抖动\", \"KPI目标：启停平稳度<0.5s波动\", \"任务工单：传送带启停抖动故障排查的核心概念与背景\", \"任务工单：传送带启停抖动故障排查的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p01_1\"], \"points\": [\"任务工单：传送带启停抖动故障排查的核心概念与背景\", \"任务工单：传送带启停抖动故障排查的关键方法与执行要点\", \"任务工单：传送带启停抖动故障排查的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_1\"], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p05\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:45:02.424593\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:44:26', '2026-03-19 01:37:30', 'vocational_lead_in', '{\"title\": \"任务工单：传送带启停抖动故障排查\", \"taskLabel\": \"工单编号：T-2023-Mech-Debug\", \"scenario\": \"场景描述：物流分拣线高速运转区，传送带承载重物进行频繁启停作业，环境噪音大且光照复杂。\", \"symptom\": \"故障现象：设备在加速启动阶段出现剧烈机械抖动，导致货物滑落且定位超差，严重影响生产效率。\", \"symptomLabel\": \"故障等级：高危\", \"kpi\": \"考核指标：完成参数整定后，启停平稳度波动需控制在 0.5s 以内，无过冲无震荡，货物完好率达标。\", \"kpiLabel\": \"验收标准：100% 达标\", \"layout_variant\": \"a\", \"variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('0f8ead3e-9c0c-4eb4-a7db-9ddf6839fede', '8a37f529-e51f-428c-8466-cdc137b73187', 8, NULL, '{\"page_id\": \"p09\", \"title\": \"UV展开核心算法与切缝原则\", \"layout_id\": \"theory_explanation\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p07\"], \"must_cover\": [\"理论：测地线距离最小化\", \"公式：面积畸变率计算\", \"参考文献：PolyMapper论文\", \"UV展开核心算法与切缝原则的核心概念与背景\", \"UV展开核心算法与切缝原则的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"UV展开核心算法与切缝原则的核心概念与背景\", \"UV展开核心算法与切缝原则的关键方法与执行要点\", \"UV展开核心算法与切缝原则的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p09\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.107630\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'theory_explanation', '{\"title\": \"UV展开核心算法与切缝原则\", \"theory\": [\"UV展开的本质是将三维流形映射至二维平面，其数学基础在于测地线距离的最小化。在理想状态下，我们希望所有三角形面片在展开过程中保持面积与角度不变，但受限于拓扑结构的非平面性，必然产生畸变。核心算法通过迭代优化，寻找切缝路径，使得展开后的总能量函数（包含拉伸、剪切、压缩项）达到全局最小值。\", \"切缝原则需遵循拓扑断裂的最小化逻辑。对于复杂模型，切缝应避开高曲率区域及纹理关键特征点，优先选择平坦或对称轴位置。算法通过计算各边界的测地线距离矩阵，识别出对整体畸变影响最小的割集，从而生成最优的UV岛布局。这一过程直接决定了后续PBR材质贴图的采样精度与渲染质量。\"], \"formulas\": [{\"latex\": \"\\\\text{Distortion}(f) = \\\\int_{\\\\Omega} \\\\left( \\\\| \\\\frac{\\\\partial f}{\\\\partial u} \\\\|^2 + \\\\| \\\\frac{\\\\partial f}{\\\\partial v} \\\\|^2 - 2 \\\\right)^2 du dv\", \"explanation\": \"面积畸变率计算公式：衡量UV映射 $f$ 相对于等距映射的能量偏差，积分域为UV参数域 $\\\\Omega$。\"}], \"references\": [\"Sorkine, O., et al. \\\"Least-Squares Conformal Mappings for Automatic Texture Atlas Generation.\\\" SIGGRAPH 2002.\", \"Lévy, B., et al. \\\"Spectral Geometry Processing with Harmonic Maps.\\\" Journal of Computer Graphics Techniques, 2004.\"], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('0fd8fc10-7dbf-40b4-b33b-c749a0232d64', '6c250523-422a-46f3-a1f1-42e82424897c', 14, NULL, '{\"page_id\": \"p15\", \"title\": \"案例分析：低模与高模的置换烘焙\", \"layout_id\": \"case_study\", \"has_image\": true, \"keywords\": [\"游戏资产\", \"法线贴图\", \"细节传递\", \"性能优化\", \"视觉对比\"], \"depends_on\": [\"p12\"], \"must_cover\": [\"拓扑简化\", \"法线生成\", \"UV展开技巧\", \"材质映射\", \"案例分析：低模与高模的置换烘焙的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"案例分析：低模与高模的置换烘焙的核心概念与背景\", \"案例分析：低模与高模的置换烘焙的关键方法与执行要点\", \"案例分析：低模与高模的置换烘焙的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p15\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287042\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'case_study', '{\"title\": \"案例分析：低模与高模的置换烘焙\", \"scenario\": \"在游戏引擎中部署角色或场景资产时，面临高精度细节与实时渲染性能之间的根本矛盾。开发者需在有限三角面数限制下，呈现媲美影视级的表面纹理与几何细节。\", \"challenge\": \"如何在不增加实际多边形数量的前提下，将高模的微小凹凸、划痕、接缝等细节无损传递至低模，并确保法线贴图在不同光照角度下保持视觉一致性？\", \"points\": [{\"title\": \"拓扑简化策略\", \"description\": \"高模保留全部细节用于烘焙源数据，低模则通过智能减面算法保留主体轮廓与功能分区，确保UV展开后纹理映射无拉伸变形，同时控制面数符合目标平台性能阈值。\"}, {\"title\": \"法线生成与UV技巧\", \"description\": \"采用射线投射技术将高模法线信息采样至低模对应位置，生成法线贴图；配合智能UV展开工具优化布局，最大化利用纹理空间，减少接缝可见度并避免重叠区域。\"}, {\"title\": \"材质映射与验证\", \"description\": \"将烘焙结果应用于PBR材质球，结合环境光遮蔽与粗糙度贴图增强立体感；在多种光照条件下测试效果，确保暗部细节不失真、高光过渡自然，最终输出符合引擎规范的贴图序列。\"}], \"conclusion\": \"置换烘焙技术成功解决了视觉 fidelity 与运行效率的冲突，成为现代游戏资产制作的标准范式；其核心在于理解几何数据与纹理数据的分离机制，并通过标准化流程实现跨项目复用。\", \"image\": \"\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
