INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('11ffbc6b-83f4-4976-87c1-9981d9998c42', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"课前探究：为什么你的模型在动画中会“撕裂”？\", \"layout_id\": \"warmup_inquiry\", \"has_image\": true, \"keywords\": [\"动态网格变形对比图\", \"错误拓扑导致的褶皱\", \"互动思考气泡\", \"青色背景\", \"故障艺术风格\"], \"depends_on\": [\"p02\"], \"must_cover\": [\"常见拓扑错误现象\", \"引发原因初步分析\", \"课前探究：为什么你的模型在动画中会“撕裂”？的核心概念与背景\", \"课前探究：为什么你的模型在动画中会“撕裂”？的关键方法与执行要点\", \"课前探究：为什么你的模型在动画中会“撕裂”？的应用场景与注意事项\"], \"promises_open\": [{\"promise_id\": \"pr_intro_01\", \"text\": \"后续将深入解析拓扑逻辑如何影响变形\", \"must_cover\": [\"四边面优势\", \"布线流向控制\"], \"target_page_ids\": [\"p19\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"课前探究：为什么你的模型在动画中会“撕裂”？的核心概念与背景\", \"课前探究：为什么你的模型在动画中会“撕裂”？的关键方法与执行要点\", \"课前探究：为什么你的模型在动画中会“撕裂”？的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928274\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'warmup_inquiry', '{\"question\": \"为什么你的模型在动画关键帧处会出现无法修复的“撕裂”或褶皱？\", \"thinkTime\": 30, \"hints\": [\"观察网格布线是否遵循肌肉走向与变形逻辑\", \"检查是否存在非四边形面（N-gon）导致的拓扑断裂\"], \"background_image\": \"https://example.com/images/warmup_topology_tear.jpg\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('120108cd-1e14-42da-9b06-74fc22ccc9be', '14c0f24c-10e7-4309-a927-d9db1066897c', 11, NULL, '{\"page_id\": \"p12\", \"title\": \"数字雕刻：笔刷与动态拓扑\", \"layout_id\": \"specimen_detail\", \"has_image\": true, \"keywords\": [\"雕刻笔刷工具栏\", \"动态拓扑过程\", \"泥塑质感\", \"左侧工具右侧效果\"], \"depends_on\": [\"p10\"], \"must_cover\": [\"笔刷类型选择\", \"动态拓扑原理\", \"细节层级管理\", \"数字雕刻：笔刷与动态拓扑的核心概念与背景\", \"数字雕刻：笔刷与动态拓扑的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"数字雕刻：笔刷与动态拓扑的核心概念与背景\", \"数字雕刻：笔刷与动态拓扑的关键方法与执行要点\", \"数字雕刻：笔刷与动态拓扑的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p12\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.773972\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'specimen_detail', '{\"title\": \"数字雕刻：笔刷与动态拓扑\", \"image_src\": \"https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=1200&auto=format&fit=crop\", \"annotations\": [{\"x\": 25, \"y\": 35, \"label\": \"笔刷工具栏\", \"description\": \"包含平滑、褶皱、捏取等核心笔刷，针对不同材质表现进行微调。\"}, {\"x\": 70, \"y\": 50, \"label\": \"动态拓扑过程\", \"description\": \"实时增加网格密度以支持高细节雕刻，无需手动重拓扑即可实现泥塑般的有机形态。\"}], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('121ad00c-9460-428c-bf52-af6c6d1354c1', '8a37f529-e51f-428c-8466-cdc137b73187', 15, NULL, '{\"page_id\": \"p16\", \"title\": \"第四章：程序化纹理与节点树构建\", \"layout_id\": \"key_concepts\", \"has_image\": true, \"keywords\": [\"第四章：程序化纹理与节点树构建\", \"场景示意\", \"视觉辅助\"], \"depends_on\": [\"p12\"], \"must_cover\": [\"章节引入\", \"程序化纹理优势\", \"第四章：程序化纹理与节点树构建的核心概念与背景\", \"第四章：程序化纹理与节点树构建的关键方法与执行要点\", \"第四章：程序化纹理与节点树构建的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第四章：程序化纹理与节点树构建的核心概念与背景\", \"第四章：程序化纹理与节点树构建的关键方法与执行要点\", \"第四章：程序化纹理与节点树构建的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.108022\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'key_concepts', '{\"title\": \"第四章：程序化纹理与节点树构建\", \"subtitle\": \"从物理参数到视觉生成的逻辑桥梁。\", \"bullets\": [{\"icon\": \"fa-sitemap\", \"text\": \"节点树核心架构。\", \"description\": \"通过输入节点（坐标/噪声）→ 处理节点（数学运算/混合）→ 输出节点（颜色/粗糙度）的层级结构，将抽象物理参数转化为可渲染的像素数据。\"}, {\"icon\": \"fa-bolt\", \"text\": \"程序化纹理优势。\", \"description\": \"相比位图贴图，程序化纹理具备无限分辨率、内存占用低及参数可控性强的特点，能完美适配微表面理论的动态变化需求。\"}, {\"icon\": \"fa-cogs\", \"text\": \"关键执行策略。\", \"description\": \"采用分段式调整法，先构建宏观几何形态（低频），再叠加微观表面细节（高频），最后通过遮罩控制各区域权重以平衡物理准确性。\"}, {\"icon\": \"fa-lightbulb\", \"text\": \"UV布局与拓扑分析。\", \"description\": \"在构建节点前需先行分析UV展开图，确保高光区域与漫反射区域的拓扑结构清晰，为后续的参数分段调整提供空间依据。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"物理与视觉的平衡。\", \"description\": \"在追求能量守恒等物理真实性的同时，需适当引入艺术化调整（如非物理的高光增强），以满足特定场景下的视觉表现力需求。\"}], \"keyTakeaway\": \"程序化纹理的核心在于利用节点树的逻辑组合，将微表面理论中的物理参数（粗糙度、法线）转化为具有无限细节且高度可控的视觉资产。\", \"image\": {\"src\": \"\", \"alt\": \"节点树结构示意图：展示从噪声输入到最终材质输出的层级连接关系，背景为学术网格风格\", \"position\": \"right\", \"width\": \"35%\"}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
