INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('124ed79a-b68b-4501-8ed1-d91da4a4690a', '7823309a-e50c-44f7-9823-bf26169886ac', 1, '第二部分：核心原理与规范作业', '{\"part\": \"第二部分：核心原理与规范作业\", \"pages\": [{\"title\": \"第一章：几何构建原理\", \"points\": [\"多边形建模基础：点线面关系\", \"严谨细致的态度：模型精度控制\", \"精益求精的准则：细节打磨标准\"]}, {\"title\": \"核心原理：拓扑结构与布线逻辑\", \"points\": [\"四边面优势：为何避免三角面堆积\", \"布线流向：变形支撑点的布局策略\", \"拓扑结构：优化网格流线与平滑度\"]}, {\"title\": \"规范作业：标准操作流程（SOP）\", \"points\": [\"新建单位设置：毫米/厘米单位统一\", \"原点归位：坐标轴对齐规范\", \"层级管理：场景对象分类整理\", \"命名规范：文件与组件命名规则\"]}, {\"title\": \"规范作业：标准操作流程（SOP）：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"]}], \"logical_page_id\": \"p02\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p01\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_id\": \"title_content\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:23:43.630318\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:23:03', '2026-03-08 06:23:44', 'title_content', '{\"title\": \"安全红线与禁忌规范\", \"content\": [\"严禁在未佩戴个人防护装备（PPE）的情况下进行高空或切割作业。\", \"禁止擅自修改设备参数或使用非原厂指定的辅助配件。\", \"发现任何电气线路裸露或异常震动必须立即停机上报。\"], \"highlight\": \"安全红线不可逾越，违者立即停工。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
