INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('136dbd69-d66d-4b39-842c-cd2806887eab', '1d063203-8ece-436a-ad39-9501e3c7e06b', 12, NULL, '{\"page_id\": \"p13\", \"title\": \"工单指令：完整项目实战要求\", \"layout_id\": \"task_instruction\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p12\"], \"must_cover\": [\"项目需求文档\", \"分阶段交付节点\", \"验收评分标准\", \"团队协作规范\", \"工单指令：完整项目实战要求的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"工单指令：完整项目实战要求的核心概念与背景\", \"工单指令：完整项目实战要求的关键方法与执行要点\", \"工单指令：完整项目实战要求的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p13\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-20T01:09:55.819988\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-20 01:09:18', '2026-03-20 01:09:56', 'task_instruction', '{\"title\": \"工单指令：完整项目实战要求\", \"content\": [\"本工单确立从需求文档到最终交付的全流程工程标准，严格遵循分阶段交付节点与验收评分体系。团队协作需执行统一命名规范与版本控制，确保逻辑构建的严密性。\", \"核心概念基于前序故障排除经验，将法线修复、比例校准等避坑指南转化为可执行的标准化作业指令，杜绝渲染崩溃隐患。\"], \"highlight\": \"建模不仅是构建形状，更是构建逻辑；每一个错误的法线与比例，都是未来渲染崩溃的伏笔。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
