INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('159621d6-3d2c-4925-ac47-37a707d750c5', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 13, NULL, '{\"page_id\": \"p09\", \"title\": \"初学者软件选择问答\", \"layout_id\": \"edu_qa_case\", \"has_image\": true, \"keywords\": [\"悬浮对话气泡图标\", \"界面截图虚化背景\", \"青色高亮提问框\"], \"depends_on\": [\"p08\"], \"must_cover\": [\"Blender vs Maya\", \"ZBrush 定位\", \"成本考量\", \"初学者软件选择问答的核心概念与背景\", \"初学者软件选择问答的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"初学者软件选择问答的核心概念与背景\", \"初学者软件选择问答的关键方法与执行要点\", \"初学者软件选择问答的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p14\", \"layout_variant\": \"c\", \"layout_archetype\": \"qa_session\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T13:04:03.227850\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'edu_qa_case', '{\"title\": \"初学者软件选择问答\", \"question\": \"初入行业面临多款软件，该如何精准选择？\", \"answer\": \"综合评估预算与目标：免费入门选 Blender，大厂就业选 Maya，生物细节选 ZBrush。\", \"analysis\": [{\"title\": \"Blender vs Maya\", \"content\": \"开源生态 VS 商业垄断，适应不同成本结构与社区支持力度\"}, {\"title\": \"ZBrush 定位\", \"content\": \"作为高模雕刻补充，专注于细节表现，不替代主流程建模\"}, {\"title\": \"成本考量\", \"content\": \"正版授权费差异显著，需权衡学习周期与长期项目投入产出\"}], \"conclusion\": \"选择匹配岗位需求与项目预算的工具组合，避免盲目跟风\", \"variant\": \"c\", \"layout_variant\": \"c\", \"layout_archetype\": \"qa_session\"}');
