INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('17e071cd-a0cd-4b48-bd4d-1d7c2f95abec', '8ccaacf6-cf8f-4cd6-8ca8-7d5f28350c89', 11, NULL, '{\"page_id\": \"p12\", \"title\": \"十、结果反馈：常见错误解析\", \"layout_id\": \"vocational_case_study\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p11\"], \"must_cover\": [\"典型错误案例\", \"错误成因分析\", \"正确修正方法\", \"十、结果反馈：常见错误解析的核心概念与背景\", \"十、结果反馈：常见错误解析的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p12_1_4f5b906c\", \"text\": \"十、结果反馈：常见错误解析的复盘与结果启示\", \"must_cover\": [\"案例复盘\", \"结果启示\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"十、结果反馈：常见错误解析的核心概念与背景\", \"十、结果反馈：常见错误解析的关键方法与执行要点\", \"十、结果反馈：常见错误解析的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"b\", \"logical_page_id\": \"p12\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:41:09.848188\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:40:29', '2026-03-17 07:41:10', 'vocational_case_study', '{\"title\": \"十、结果反馈：常见错误解析\", \"content\": [\"典型错误案例：重载皮带机加速时变频器报过流故障，原因系未依据负载惯量计算加速时间，仅凭经验设定导致电流冲击超限。\", \"错误成因分析：缺乏量化思维，忽略物理公式中力矩与加速度的线性关系，将调试视为纯经验操作而非科学计算过程。\", \"正确修正方法：重新采集负载参数，利用定律公式精准计算所需加速时间，并设置合理的转矩提升阈值以平滑启动曲线。\"], \"highlight\": \"从“凭感觉”转向“算得准”，实现调试过程的标准化与安全化。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"concept_explain\"}');
