INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('181cc835-7aaa-4d73-9c78-0e5b42627fec', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 22, '第四部分：硬表面建模全流程实操', '{\"title\": \"优化实践：渲染质量与性能的平衡之道\", \"points\": [\"PBR材质流程在硬表面中的应用\", \"光照环境设置与渲染引擎选择策略\", \"数据看板：优化前后帧率、纹理大小与视觉细节对比\", \"技术总结：如何在保证画质的前提下降低面数\"], \"layout_id\": \"edu_data_board\", \"part\": \"第四部分：硬表面建模全流程实操\", \"logical_page_id\": \"p23\", \"has_image\": false, \"keywords\": [\"PBR材质流程在硬表面中的应用\", \"光照环境设置与渲染引擎选择策略\", \"数据看板：优化前后帧率、纹理大小与视觉细节对比\"], \"depends_on\": [\"p22\"], \"must_cover\": [\"PBR材质流程在硬表面中的应用\", \"光照环境设置与渲染引擎选择策略\", \"数据看板：优化前后帧率、纹理大小与视觉细节对比\", \"技术总结：如何在保证画质的前提下降低面数\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"a\", \"layout_archetype\": \"data_dashboard\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.419427\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_data_board', '{\"title\": \"优化实践：渲染质量与性能平衡数据看板\", \"subtitle\": \"PBR材质与光照策略下的效能提升。\", \"metrics\": [{\"value\": \"+45%\", \"label\": \"渲染帧率提升\", \"note\": \"在保持视觉细节前提下。\"}, {\"value\": \"-60%\", \"label\": \"面数降低比例\", \"note\": \"通过拓扑优化实现。\"}], \"bars\": [{\"label\": \"纹理大小对比\", \"baseline\": 80, \"current\": 35}, {\"label\": \"视觉细节保留度\", \"baseline\": 60, \"current\": 95}], \"bullets\": [{\"text\": \"PBR材质硬表面应用。\", \"description\": \"利用金属度与粗糙度贴图替代高模细节，减少几何复杂度。\"}, {\"text\": \"光照环境策略选择。\", \"description\": \"采用HDRI环境光配合三点布光，以最少光源达成最大体积感。\"}], \"insight\": \"在保证画质不降级的前提下，通过优化布线与材质替代方案，显著降低硬件负载并提升实时渲染效率。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_dashboard\"}');
