INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('18eeeac2-1676-41f2-bf9d-236833200bc8', 'c3f4f20a-0839-4fb0-9375-125c6af13f37', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"SOP关键点核查表\", \"layout_id\": \"sk_checklist\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"漏气检测步骤\", \"螺栓扭矩确认\", \"信号反馈测试\", \"空载试运行\", \"SOP关键点核查表的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"SOP关键点核查表的核心概念与背景\", \"SOP关键点核查表的关键方法与执行要点\", \"SOP关键点核查表的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:04:18.360982\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:03:28', '2026-03-19 06:04:22', 'sk_checklist', '{\"title\": \"SOP关键点核查表\", \"rows\": [{\"label\": \"漏气检测步骤\", \"value\": \"使用肥皂水涂抹密封接口，观察是否有气泡产生以确认气路完整性。\", \"extra\": \"重点检查法兰盘与吸盘连接处\"}, {\"label\": \"螺栓扭矩确认\", \"value\": \"使用定扭扳手对固定螺栓进行二次紧固，确保扭矩值符合工艺标准。\", \"extra\": \"需记录具体数值并签字确认\"}, {\"label\": \"信号反馈测试\", \"value\": \"手动触发真空发生器，验证传感器状态灯是否由红变绿且无延迟。\", \"extra\": \"模拟断电信号干扰场景\"}, {\"label\": \"空载试运行\", \"value\": \"在无人工干预下执行单次完整抓取动作，监测运行轨迹与速度曲线。\", \"extra\": \"确认无异常震动或异响\"}], \"summary\": \"本核查表基于前序工具更换流程，通过四项核心指标确保设备在投入生产前的安全性与可靠性，任何一项未达标均需立即停机整改。\", \"bullets\": [{\"icon\": \"fa-check\", \"text\": \"SOP关键点核查表的关键概念。\", \"description\": \"说明SOP关键点核查表的关键概念在当前主题中的价值与应用方式。\"}, {\"icon\": \"fa-check\", \"text\": \"SOP关键点核查表的实践方法。\", \"description\": \"说明SOP关键点核查表的实践方法在当前主题中的价值与应用方式。\"}, {\"icon\": \"fa-check\", \"text\": \"SOP关键点核查表的风险与边界。\", \"description\": \"说明SOP关键点核查表的风险与边界在当前主题中的价值与应用方式。\"}], \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('192161fb-d16e-42d9-b2cd-9bef88fce938', '2210a36d-b61a-453a-83ee-86edc9925e6a', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"实操案例：低模椅子构建\", \"layout_id\": \"case_study\", \"has_image\": true, \"keywords\": [\"3D 线框模型图\", \"简约几何体堆叠\", \"未着色材质效果\", \"透视视图展示\"], \"depends_on\": [\"p07\"], \"must_cover\": [\"立方体基础切割\", \"卡线处理演示\", \"视角切换操作\", \"实操案例：低模椅子构建的核心概念与背景\", \"实操案例：低模椅子构建的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p08_advanced\", \"text\": \"复杂曲面修整与最终渲染\", \"must_cover\": [\"平滑组设置\", \"灯光布景分析\"], \"target_page_ids\": [\"p18\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"实操案例：低模椅子构建的核心概念与背景\", \"实操案例：低模椅子构建的关键方法与执行要点\", \"实操案例：低模椅子构建的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p08\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T06:30:50.647657\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 06:24:26', '2026-03-07 07:17:35', 'case_study', '{\"title\": \"典型案例分析\", \"scenario\": \"低模硬表面家具制作流程，平衡几何精度与面数限制\", \"challenge\": \"原始模型无支撑线导致变形，视角切换影响布线观察\", \"points\": [{\"title\": \"立方体基础切割\", \"description\": \"利用布尔运算切分椅腿，保持顶点流形完整性。\"}, {\"title\": \"卡线处理演示\", \"description\": \"关键转折处卡线，确保阴影平滑过渡。\"}, {\"title\": \"视角切换操作\", \"description\": \"快捷键快速切换视图，优化建模空间认知。\"}], \"conclusion\": \"标准化操作提升效率，避免过度依赖自动吸附\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('19ca752d-3b94-4b5b-8ec6-9f97a552a26b', '1d063203-8ece-436a-ad39-9501e3c7e06b', 8, NULL, '{\"page_id\": \"p09\", \"title\": \"章节二：高级材质与渲染流程\", \"layout_id\": \"detail_specs\", \"has_image\": true, \"keywords\": [\"章节二：高级材质与渲染流程\", \"场景示意\", \"视觉辅助\"], \"depends_on\": [\"p08\"], \"must_cover\": [\"章节导语\", \"PBR材质流程\", \"章节二：高级材质与渲染流程的核心概念与背景\", \"章节二：高级材质与渲染流程的关键方法与执行要点\", \"章节二：高级材质与渲染流程的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"章节二：高级材质与渲染流程的核心概念与背景\", \"章节二：高级材质与渲染流程的关键方法与执行要点\", \"章节二：高级材质与渲染流程的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p09\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-20T01:09:55.819833\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-20 01:09:17', '2026-03-20 01:09:56', 'detail_specs', '{\"title\": \"章节二：高级材质与渲染流程\", \"content\": [\"PBR材质流程基于物理光照原理，通过金属度、粗糙度通道实现真实感材质还原，替代传统漫反射模拟。\", \"关键执行要点包括建立分层材质库、校准环境光遮蔽（AO）及控制高光反射阈值，避免过曝或死黑。\", \"应用场景涵盖产品可视化与虚拟仿真，注意事项在于保持渲染引擎版本一致性及光照预设标准化。\", \"本章构建了从几何到材质的完整闭环，确保设备模型在复杂光照环境下依然保持高保真度与逻辑一致性。\"], \"highlight\": \"PBR流程是连接几何精度与视觉真实的唯一桥梁。\", \"image\": {\"src\": \"\", \"alt\": \"工业设备场景示意，展示金属与橡胶材质在不同光照下的物理反射效果\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1a0c2746-f4e4-4813-8d6b-8d19a9fa8e1c', '8a37f529-e51f-428c-8466-cdc137b73187', 12, NULL, '{\"page_id\": \"p13\", \"title\": \"反射率与粗糙度的物理推导\", \"layout_id\": \"theory_explanation\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p10\"], \"must_cover\": [\"理论：微表面理论\", \"公式：GGX分布函数\", \"结论：能量守恒约束\", \"反射率与粗糙度的物理推导的核心概念与背景\", \"反射率与粗糙度的物理推导的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p10_1\"], \"points\": [\"反射率与粗糙度的物理推导的核心概念与背景\", \"反射率与粗糙度的物理推导的关键方法与执行要点\", \"反射率与粗糙度的物理推导的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p10_1\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p13\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.107902\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'theory_explanation', '{\"title\": \"理论推导\", \"theory\": [\"微表面理论将宏观粗糙表面视为无数微观平面的集合，反射率取决于这些微表面的法线分布。GGX分布函数通过长尾特性准确描述了高粗糙度下的能量衰减行为，确保在掠射角下保持物理真实性。\", \"能量守恒约束要求材质的反射总能量不能超过入射能量。通过调整粗糙度参数与菲涅尔效应的耦合，推导得出在完全光滑与完全粗糙极限下的反射率边界值，验证了模型的物理自洽性。\"], \"formulas\": [{\"latex\": \"D_{GGX}(\\\\mathbf{h}) = \\\\frac{\\\\alpha^2}{\\\\pi [ (\\\\mathbf{n} \\\\cdot \\\\mathbf{h})^2 (\\\\alpha^2 - 1) + 1 ]^2}\", \"explanation\": \"GGX法线分布函数，α为粗糙度参数，决定微表面法线的离散程度。\"}, {\"latex\": \"\\\\int_{\\\\Omega} f_r(\\\\omega_i, \\\\omega_o) \\\\cos\\\\theta_i d\\\\omega_i \\\\leq 1\", \"explanation\": \"能量守恒积分约束，确保漫反射与镜面反射之和不超过单位入射能量。\"}], \"references\": [\"Heitz, E. (2014). Understanding the Masking-Shadowing Function in Microfacet-Based BRDFs.\", \"Walter, B., et al. (2007). Microfacet Models for Refraction through Rough Surfaces.\"], \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1a0ea914-7b2d-4294-a7e9-ce9d391f2ba0', '3ba66aac-bac2-4c02-b7f4-d1d534d00b1d', 17, NULL, '{\"page_id\": \"p18\", \"title\": \"高效学习法：模仿-解构-创新\", \"layout_id\": \"edu_tri_compare\", \"has_image\": true, \"keywords\": [\"三个并列的学习阶段卡片\", \"模仿作品\", \"拆解图纸\", \"原创草图\", \"阶梯上升图形\"], \"depends_on\": [\"p16\"], \"must_cover\": [\"临摹训练\", \"逆向工程\", \"风格化创作\", \"高效学习法：模仿-解构-创新的核心概念与背景\", \"高效学习法：模仿-解构-创新的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"高效学习法：模仿-解构-创新的核心概念与背景\", \"高效学习法：模仿-解构-创新的关键方法与执行要点\", \"高效学习法：模仿-解构-创新的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_compare\", \"layout_variant\": \"b\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:04:29', '2026-03-10 05:04:29', 'edu_tri_compare', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1afd9ce0-6ecd-4694-a2f2-a89ec2cbfbc0', '6c250523-422a-46f3-a1f1-42e82424897c', 12, NULL, '{\"page_id\": \"p13\", \"title\": \"第三章：核心建模技法与流程解析\", \"layout_id\": \"academic_narrative\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p10\"], \"must_cover\": [\"建模方法论\", \"迭代思维\", \"非破坏性工作流\", \"第三章：核心建模技法与流程解析的核心概念与背景\", \"第三章：核心建模技法与流程解析的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第三章：核心建模技法与流程解析的核心概念与背景\", \"第三章：核心建模技法与流程解析的关键方法与执行要点\", \"第三章：核心建模技法与流程解析的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p13\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.286992\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'academic_narrative', '{\"title\": \"核心建模技法与流程解析：方法论重构\", \"narrative\": [\"从立方体构建的复盘可知，独立操作与系统化工作流存在本质差异。核心建模技法并非孤立工具的堆砌，而是基于迭代思维的非破坏性工作流体系。该方法论强调在软件底层逻辑上建立可回溯的修改路径，将‘创建对象’升级为‘构建数据关系’，确保后续调整无需重做基础结构。\", \"非破坏性编辑是工业级管线（如Maya）与高效原型开发（如Blender）的共同基石。通过保留原始参数、历史记录及层级关联，设计师可在任何阶段回滚或分支实验，极大降低试错成本。这种思维模式要求操作者先规划拓扑流向，再执行几何变换，而非盲目依赖即时渲染结果。\", \"在复杂资产制作中，迭代思维体现为‘低模打形、高模细化、烘焙传递’的循环过程。每一次迭代都需验证法线方向、UV展开效率及拓扑密度分布，确保模型既满足视觉精度又符合性能预算。这种结构化流程将艺术创作转化为可量化、可协作的工程任务。\"], \"margin_notes\": [{\"title\": \"非破坏性工作流\", \"content\": \"指所有修改操作均不直接改变原始几何数据，而是通过修改器堆栈、历史节点或参数化记录实现。支持随时撤销、调整顺序或移除特定步骤，是专业管线区别于新手随意操作的核心特征。\"}, {\"title\": \"迭代思维\", \"content\": \"建模非一次性完成，而是通过多轮‘假设-验证-修正’循环逼近最优解。每轮迭代聚焦特定问题（如布线合理性），逐步累积细节，避免后期因结构缺陷导致全盘推翻。\"}], \"pull_quote\": \"真正的建模能力不在于掌握多少快捷键，而在于能否构建一个可无限扩展且易于维护的数据架构。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1b4f416b-b0ee-4be5-885a-6a0ca88def01', '8a37f529-e51f-428c-8466-cdc137b73187', 11, NULL, '{\"page_id\": \"p12\", \"title\": \"第三章：PBR材质物理基础\", \"layout_id\": \"diagram_illustration\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"章节引入\", \"基于物理的渲染概念\", \"第三章：PBR材质物理基础的核心概念与背景\", \"第三章：PBR材质物理基础的关键方法与执行要点\", \"第三章：PBR材质物理基础的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [\"pr_p10_1\"], \"points\": [\"第三章：PBR材质物理基础的核心概念与背景\", \"第三章：PBR材质物理基础的关键方法与执行要点\", \"第三章：PBR材质物理基础的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p10_1\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p12\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p10_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.107833\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'diagram_illustration', '{\"title\": \"基于物理的渲染（PBR）基础\", \"subtitle\": \"从光照方程到材质参数。\", \"explanations\": [{\"label\": \"能量守恒原理\", \"description\": \"反射光能量加漫反射能量不得超过入射光总能量，确保材质在不同光照下表现真实。\"}, {\"label\": \"微表面理论\", \"description\": \"将宏观粗糙表面视为无数微小镜面集合，通过法线分布函数（NDF）模拟高光形态。\"}, {\"label\": \"菲涅尔效应\", \"description\": \"观察角度越接近切线方向，表面反射率越高，金属与非金属表现差异显著。\"}], \"summary\": \"PBR流程通过标准化物理参数（如粗糙度、金属度）替代主观艺术调整，实现跨引擎一致的光照响应。\", \"diagram_url\": \"\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1b74b31f-296a-49ad-81c6-d75fb4539a54', '60390839-f925-4662-a2dc-c92d64253b33', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"第一章：3D空间与几何基础\", \"layout_id\": \"academic_practice\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p03\"], \"must_cover\": [\"坐标系定义\", \"基本几何体\", \"第一章：3D空间与几何基础的核心概念与背景\", \"第一章：3D空间与几何基础的关键方法与执行要点\", \"第一章：3D空间与几何基础的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第一章：3D空间与几何基础的核心概念与背景\", \"第一章：3D空间与几何基础的关键方法与执行要点\", \"第一章：3D空间与几何基础的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:29:50', '2026-03-10 05:29:50', 'academic_practice', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1b751779-1e6e-42ed-b73b-b1ee96eb5818', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 8, '视觉表现', '{\"page_id\": \"p07\", \"title\": \"UV展开与材质贴图基础\", \"part\": \"视觉表现\", \"points\": [\"优化UV岛布局策略，在最小化空间浪费的同时避免纹理拉伸\", \"掌握PBR工作流核心参数，精准设置粗糙度、金属度与法线强度\", \"理解法线与置换贴图的层级差异，实现从表面细节到几何形变的真实还原\", \"规范贴图命名与分辨率标准，确保资产在不同渲染引擎中的兼容性\"]}', '{\"text\": \"页面标题：UV展开与材质贴图基础\\n\\n页面文字：\\n- 优化UV岛布局策略，在最小化空间浪费的同时有效避免纹理拉伸现象。\\n- 掌握PBR工作流核心参数，精准设置粗糙度、金属度与法线强度数值。\\n- 理解法线与置换贴图的层级差异，实现从表面细节到几何形变的真实还原。\\n- 规范贴图命名与分辨率标准，确保资产在不同渲染引擎中完美兼容运行。\", \"generated_at\": \"2026-03-09T03:39:37.135424\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/1b751779-1e6e-42ed-b73b-b1ee96eb5818_v1.png', 'COMPLETED', '2026-03-09 03:39:19', '2026-03-09 03:46:20', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1b853e2d-98b5-4afd-8a07-d818807dcb11', '8a37f529-e51f-428c-8466-cdc137b73187', 19, NULL, '{\"page_id\": \"p20\", \"title\": \"关键知识点回顾与知识图谱\", \"layout_id\": \"key_takeaways\", \"has_image\": true, \"keywords\": [\"关键知识点回顾与知识图谱\", \"场景示意\", \"视觉辅助\"], \"depends_on\": [\"p16\"], \"must_cover\": [\"拓扑规范总结\", \"UV展开核心原则\", \"PBR参数逻辑\", \"程序化工作流要点\", \"关键知识点回顾与知识图谱的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p15_1_746aa857\", \"pr_p05_1\", \"pr_p10_1\"], \"points\": [\"关键知识点回顾与知识图谱的核心概念与背景\", \"关键知识点回顾与知识图谱的关键方法与执行要点\", \"关键知识点回顾与知识图谱的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p15_1_746aa857\", \"pr_p05_1\", \"pr_p10_1\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p20\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p15_1_746aa857\", \"pr_p05_1\", \"pr_p10_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.108205\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 12:53:09', 'key_takeaways', '{\"title\": \"关键知识点回顾与知识图谱\", \"subtitle\": \"从程序化构建到实时优化的全链路闭环。\", \"bullets\": [{\"icon\": \"fa-cube\", \"text\": \"节点树架构与数据流。\", \"description\": \"掌握输入（坐标/噪声）→处理（数学运算）→输出（PBR参数）的层级逻辑，实现物理参数的像素级转化。\"}, {\"icon\": \"fa-tools\", \"text\": \"工具链互补策略。\", \"description\": \"Substance Designer用于高精度资产生产，Blender Nodes用于动态整合与特效调试，两者协同工作。\"}, {\"icon\": \"fa-tachometer-alt\", \"text\": \"LOD与烘焙优化。\", \"description\": \"基于距离的动态精度切换与光照预计算，是解决实时渲染瓶颈的核心手段。\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"金属与陶瓷材质还原。\", \"description\": \"复盘案例：通过精确控制粗糙度与金属度通道，解决非平面UV下的材质失效问题。\"}, {\"icon\": \"fa-project-diagram\", \"text\": \"拓扑与布线密度。\", \"description\": \"四边面生成逻辑与布线密度控制，为后续动画变形与细分曲面提供基础。\"}], \"keyTakeaway\": \"从程序化纹理的底层构建到实时引擎的性能优化，再到具体材质的物理还原，形成了一套完整的工业化生产标准。\", \"image\": {\"src\": \"\", \"alt\": \"展示从噪声节点到LOD层级再到最终渲染效果的流程图，无文字标识\", \"position\": \"right\", \"width\": \"35%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
