INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1ba0af92-b212-4e8a-bc78-9e38d1bb88ef', '8ccaacf6-cf8f-4cd6-8ca8-7d5f28350c89', 14, NULL, '{\"page_id\": \"p15\", \"title\": \"十三、拓展资源：推荐学习路径\", \"layout_id\": \"vocational_homework\", \"has_image\": true, \"keywords\": [\"十三、拓展资源：推荐学习路径\", \"场景示意\", \"视觉辅助\"], \"depends_on\": [\"p14\"], \"must_cover\": [\"在线课程链接\", \"参考书籍列表\", \"仿真软件推荐\", \"十三、拓展资源：推荐学习路径的核心概念与背景\", \"十三、拓展资源：推荐学习路径的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"十三、拓展资源：推荐学习路径的核心概念与背景\", \"十三、拓展资源：推荐学习路径的关键方法与执行要点\", \"十三、拓展资源：推荐学习路径的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p15\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:41:09.848403\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:40:29', '2026-03-17 07:41:10', 'vocational_homework', '{\"title\": \"十三、拓展资源：推荐学习路径\", \"subtitle\": \"构建“理论 - 仿真 - 实操”三位一体进阶体系。\", \"bullets\": [{\"icon\": \"fa fa-video\", \"text\": \"在线精品课程库。\", \"description\": \"精选国家职业教育资源库中关于变频器参数整定的高清视频课程，支持倍速播放与断点续学。\"}, {\"icon\": \"fa fa-book\", \"text\": \"核心参考书籍清单。\", \"description\": \"收录《电气传动自动化技术》及行业最新标准手册，提供关键公式推导与案例解析。\"}, {\"icon\": \"fa fa-laptop-code\", \"text\": \"专业仿真软件推荐。\", \"description\": \"推荐使用MATLAB/Simulink或Proficy Machine Edition进行虚拟调试，降低实机试错成本。\"}, {\"icon\": \"fa fa-link\", \"text\": \"行业案例数据库。\", \"description\": \"接入企业真实故障案例库，涵盖重载启动过流、低频振荡等典型问题解决方案。\"}], \"keyTakeaway\": \"通过多元化资源组合，将抽象的物理公式转化为可视化的仿真操作与可执行的调试步骤，实现从知识到技能的无缝转化。\", \"image\": {\"src\": \"\", \"alt\": \"展示学习路径流程图，包含在线课程图标、书籍封面轮廓、仿真软件界面截图及案例库文件夹图标，背景为职教工作台底纹\", \"position\": \"right\", \"width\": \"35%\"}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
