INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1ca4f508-e952-44f8-b001-5638b9e9ac72', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 16, NULL, '{\"page_id\": \"p17\", \"title\": \"名言金句：光影是3D世界的灵魂\", \"layout_id\": \"feedback_poll\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p15\"], \"must_cover\": [\"大师观点引用\", \"渲染美学原则\", \"名言金句：光影是3D世界的灵魂的核心概念与背景\", \"名言金句：光影是3D世界的灵魂的关键方法与执行要点\", \"名言金句：光影是3D世界的灵魂的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"名言金句：光影是3D世界的灵魂的核心概念与背景\", \"名言金句：光影是3D世界的灵魂的关键方法与执行要点\", \"名言金句：光影是3D世界的灵魂的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p17\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928779\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'feedback_poll', '{\"title\": \"名言金句：光影是3D世界的灵魂\", \"content\": [\"光影不仅是照亮物体的工具，更是定义空间情绪、引导视觉焦点的核心语言。正如大师所言，没有光影的3D模型只是冰冷的数据堆砌。\", \"掌握光影美学原则，意味着学会用光线讲述故事，让材质在明暗交界中呼吸，赋予虚拟世界以生命力和情感深度。\"], \"highlight\": \"光影是3D世界的灵魂，决定画面的情感温度\", \"image\": {\"src\": \"\", \"alt\": \"一束温暖的晨光穿透极简几何空间，照亮漂浮的尘埃粒子，营造出静谧而充满希望的意境\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1ce0c6f0-bed6-4ab0-a3a5-7f92187d6d7a', '8ccaacf6-cf8f-4cd6-8ca8-7d5f28350c89', 2, NULL, '{\"page_id\": \"p03\", \"title\": \"一、情景导入：传送带启动冲击故障\", \"layout_id\": \"vocational_lead_in\", \"has_image\": true, \"keywords\": [\"工厂传送带\", \"电机过载报警\", \"工人排查现场\", \"工业蓝灰调\", \"真实设备场景\"], \"depends_on\": [\"p02\"], \"must_cover\": [\"故障现象描述\", \"痛点分析\", \"引入牛顿第二定律\", \"一、情景导入：传送带启动冲击故障的核心概念与背景\", \"一、情景导入：传送带启动冲击故障的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p03_1\", \"text\": \"通过F=ma公式计算电机推力与加速度关系\", \"must_cover\": [\"质量对加速度的影响\", \"力矩与惯性的换算\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}, {\"promise_id\": \"pr_p03_2\", \"text\": \"展示从理论到参数设定的完整调试步骤\", \"must_cover\": [\"变频器参数设置\", \"加减速时间优化\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"一、情景导入：传送带启动冲击故障的核心概念与背景\", \"一、情景导入：传送带启动冲击故障的关键方法与执行要点\", \"一、情景导入：传送带启动冲击故障的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p03\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:41:09.847548\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:40:27', '2026-03-17 07:41:10', 'vocational_lead_in', '{\"title\": \"一、情景导入：传送带启动冲击故障\", \"content\": [\"某自动化物流产线在重载启动瞬间，电机频繁触发过载报警，导致传送带皮带打滑甚至断裂，严重影响生产效率。\", \"经排查发现，原因为启动加速度设定过大，产生的惯性冲击力超出机械结构承受极限，需引入牛顿第二定律进行定量分析。\", \"本任务将利用 F=ma 公式，通过调整加速度参数，消除启动冲击，实现设备平稳运行。\"], \"highlight\": \"痛点：启动冲击导致设备损坏；解法：基于 F=ma 优化加速度参数。\", \"image\": {\"src\": \"\", \"alt\": \"工厂传送带电机过载报警现场实拍图，工人正在查看控制面板\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
