INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1f63df47-c662-4d51-98c1-4d69d5dd56e5', '130ea17c-c678-4285-8c4c-06b099d8fa71', 13, NULL, '{\"page_id\": \"p14\", \"title\": \"经典例题实战演练\", \"layout_id\": \"edu_qa_case\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p12\"], \"must_cover\": [\"受力分析步骤\", \"正交分解法\", \"方程组求解\", \"经典例题实战演练的核心概念与背景\", \"经典例题实战演练的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"经典例题实战演练的核心概念与背景\", \"经典例题实战演练的关键方法与执行要点\", \"经典例题实战演练的应用场景与注意事项\"], \"layout_archetype\": \"qa_session\", \"layout_variant\": \"d\", \"required_close_promise_ids\": [], \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:15:52.391053\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 02:14:48', '2026-03-17 02:15:52', 'edu_qa_case', '{\"title\": \"经典例题实战演练\", \"subtitle\": \"复杂场景下的受力分析与方程求解。\", \"question\": \"一辆载重卡车以恒定加速度行驶，车厢内货物受摩擦力作用保持相对静止。已知货物质量、摩擦系数及最大静摩擦力，求卡车允许的最大加速度是多少？\", \"answer\": \"最大加速度为 a = μg；通过正交分解法锁定水平方向合力，利用 F=ma 建立方程组求解临界状态。\", \"analysis\": [{\"title\": \"受力步骤拆解\", \"content\": \"严格区分重力、支持力与静摩擦力，明确合力方向即为加速度方向，避免矢量合成错误。\"}, {\"title\": \"方程构建逻辑\", \"content\": \"在临界状态下，静摩擦力达到最大值 f_max = μN，代入牛顿第二定律 F_net = ma 推导极限值。\"}, {\"title\": \"经典解法\", \"content\": \"围绕经典解法说明审题依据、关键步骤与结果检验方式。\"}], \"conclusion\": \"解题核心在于锁定“受力瞬间”与“矢量合成”，规避惯性思维陷阱，确保计算精准。\", \"background_image\": null, \"variant\": \"d\", \"layout_variant\": \"d\", \"layout_archetype\": \"qa_session\"}');
