INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('23e9b048-9c2d-4ac5-a924-c26e5ba09d86', 'ab2ec2c8-cb17-41e9-beb4-40c851abbea2', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"核心机制：三要素的关联模型\", \"layout_id\": \"edu_logic_flow\", \"has_image\": true, \"keywords\": [\"中心节点发散图\", \"青色连接线\", \"深蓝背景\", \"科学示意图\", \"无文字标注\"], \"depends_on\": [\"p03\"], \"must_cover\": [\"力的作用效果\", \"质量的阻碍作用\", \"加速度的响应\", \"核心机制：三要素的关联模型的核心概念与背景\", \"核心机制：三要素的关联模型的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p04_1\", \"text\": \"控制变量法实验数据的量化分析\", \"must_cover\": [\"a-F 图像特征\", \"a-m 图像特征\"], \"target_page_ids\": [\"p20\"], \"is_hard\": true}], \"promises_close\": [\"pr_p01_1\"], \"points\": [\"核心机制：三要素的关联模型的核心概念与背景\", \"核心机制：三要素的关联模型的关键方法与执行要点\", \"核心机制：三要素的关联模型的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_1\"], \"layout_archetype\": \"process_flow\", \"layout_variant\": \"b\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p01_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:06:57.190567\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 01:41:59', '2026-03-17 02:07:23', 'edu_logic_flow', '{\"title\": \"核心机制：三要素的关联模型\", \"stages\": [{\"title\": \"力的驱动效应\", \"description\": \"外力作为运动状态改变的唯一原因，直接决定加速度的产生方向与大小。\"}, {\"title\": \"质量的阻碍效应\", \"description\": \"质量表征物体惯性大小，对加速度起反向制约作用，数值越大响应越慢。\"}, {\"title\": \"加速度的响应结果\", \"description\": \"加速度是力与质量共同作用的瞬时结果，体现为运动状态变化的快慢程度。\"}], \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"process_flow\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('242798b0-e227-4519-9ab9-cc7d83f34cf0', '4e90bc0e-4b73-474f-bef6-45b157dc576e', 0, NULL, '{\"title\": \"教学目标：三维素养构建\", \"points\": [\"知识目标\", \"技能目标\"], \"layout_id\": \"vocational_objectives\"}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-03-17 06:21:45', '2026-03-17 14:21:45', 'vocational_objectives', '{\"title\": \"教学目标：三维素养构建\", \"knowledgeGoals\": [{\"title\": \"知识目标：深度解析F=ma。\", \"description\": \"掌握牛顿第二定律。\"}], \"skillGoals\": [{\"title\": \"技能目标：公式灵活应用。\", \"description\": \"准确计算合外力。\"}], \"attitudeGoals\": [{\"title\": \"素养目标：严谨科学思维。\", \"description\": \"培养数据化工程判断。\"}], \"keyPoints\": \"本章节强调理论与实操结合。\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('248a107a-b632-4594-81d9-f8f978761655', '6c250523-422a-46f3-a1f1-42e82424897c', 18, NULL, '{\"page_id\": \"p19\", \"title\": \"常见问题与边界条件探讨\", \"layout_id\": \"theory_explanation\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p15\"], \"must_cover\": [\"破面修复\", \"自相交问题\", \"法线翻转\", \"计算溢出\", \"常见问题与边界条件探讨的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"常见问题与边界条件探讨的核心概念与背景\", \"常见问题与边界条件探讨的关键方法与执行要点\", \"常见问题与边界条件探讨的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p19\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287165\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'theory_explanation', '{\"title\": \"常见问题与边界条件探讨\", \"subtitle\": \"破面修复、自相交与数值稳定性分析。\", \"theory\": [\"在几何处理流程中，破面修复是确保模型水密性的关键步骤。当网格存在非流形边或孔洞时，需通过拓扑重建算法自动闭合表面，防止渲染引擎出现穿透或光照异常。此过程要求保持原始曲率特征的同时消除几何缺陷。\", \"自相交问题常发生于高细分网格或变形动画过程中，导致法线方向混乱与渲染伪影。解决策略包括空间分割树（BVH）加速检测与局部翻转修正。同时，法线翻转需结合平滑组设置，确保光影过渡自然，避免硬边突兀。\", \"计算溢出是浮点运算中的潜在风险，尤其在坐标值过大或缩放比例极端时。建议采用归一化坐标系处理中间数据，并限制最大迭代次数以防止算法发散。边界条件的严格定义能有效提升求解器的鲁棒性。\"], \"formulas\": [{\"latex\": \"\\\\mathbf{n}_{new} = \\\\frac{\\\\sum (\\\\mathbf{v}_i - \\\\mathbf{c})}{\\\\|\\\\sum (\\\\mathbf{v}_i - \\\\mathbf{c})\\\\|}\", \"explanation\": \"新法向量计算：基于顶点位置与质心差值的归一化求和，用于修正自相交导致的法线错误。\"}, {\"latex\": \"\\\\text{Error} = \\\\max(|x_i|, |y_i|, |z_i|) > \\\\epsilon_{threshold}\", \"explanation\": \"溢出检测阈值：当坐标分量绝对值超过设定阈值时触发警告或重缩放机制。\"}], \"references\": [\"Wang, Y., & Zhang, L. (2023). Robust Mesh Repairing Techniques in Real-time Rendering. ACM Transactions on Graphics.\", \"Botsch, M., et al. (2022). Geometric Modeling and Processing: Theory and Practice. Springer.\"], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
