INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('26177cf5-cb32-428e-9b02-4bc2c9e65ec4', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 15, '第二部分：思维重塑与底层逻辑', '{\"title\": \"核心机制解析：3D建模的底层逻辑框架\", \"points\": [\"多边形拓扑结构对模型质量的决定性作用\", \"UV展开原理与贴图映射的数学逻辑\", \"材质节点系统与灯光渲染流程的协同机制\", \"应用场景深度解析：不同行业对拓扑的差异化要求\"], \"layout_id\": \"edu_timeline_steps\", \"part\": \"第二部分：思维重塑与底层逻辑\", \"logical_page_id\": \"p16\", \"has_image\": false, \"keywords\": [\"多边形拓扑结构对模型质量的决定性作用\", \"UV展开原理与贴图映射的数学逻辑\", \"材质节点系统与灯光渲染流程的协同机制\"], \"depends_on\": [\"p15\"], \"must_cover\": [\"多边形拓扑结构对模型质量的决定性作用\", \"UV展开原理与贴图映射的数学逻辑\", \"材质节点系统与灯光渲染流程的协同机制\", \"应用场景深度解析：不同行业对拓扑的差异化要求\"], \"promises_open\": [{\"promise_id\": \"pr_p16_1_d2c4b35e\", \"text\": \"UV展开原理与贴图映射的数学逻辑\", \"must_cover\": [], \"target_page_ids\": [\"p28\"], \"is_hard\": true}], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"b\", \"layout_archetype\": \"timeline\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.419132\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_timeline_steps', '{\"title\": \"核心机制解析：3D建模的底层逻辑框架\", \"subtitle\": \"从拓扑结构到渲染协同的全链路闭环。\", \"steps\": [{\"title\": \"阶段一：多边形拓扑构建质量基石\", \"description\": \"通过规范布线控制模型形变与细分精度，决定最终渲染的物理真实性。\", \"highlights\": [\"四边面优先布线策略\", \"动态变形区域加密处理\"]}, {\"title\": \"阶段二：UV展开与贴图映射数学逻辑\", \"description\": \"基于球面投影与极坐标算法将三维表面精准映射至二维平面，消除纹理拉伸。\", \"highlights\": [\"无缝接缝最小化布局\", \"像素密度均匀性校准\"]}, {\"title\": \"阶段三：材质节点与灯光渲染协同\", \"description\": \"利用PBR物理渲染流程，使材质属性与光照环境在数学层面实现能量守恒。\", \"highlights\": [\"法线贴图与粗糙度联动\", \"全局光照路径追踪优化\"]}], \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"timeline\"}');
