INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('28998dae-5520-4c60-b20f-fc4b5dba1dd4', '8fe0913d-702f-417c-94c8-da894fd3fa3d', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"坐标系统与空间变换原理\", \"layout_id\": \"theory_explanation\", \"has_image\": true, \"keywords\": [\"三维直角坐标系\", \"旋转矩阵示意\", \"平移向量\", \"冷灰背景\", \"数学公式块\"], \"depends_on\": [\"p06\"], \"must_cover\": [\"局部坐标系与全局坐标系\", \"旋转变换矩阵 T\", \"缩放变换逻辑\", \"坐标系统与空间变换原理的核心概念与背景\", \"坐标系统与空间变换原理的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"坐标系统与空间变换原理的核心概念与背景\", \"坐标系统与空间变换原理的关键方法与执行要点\", \"坐标系统与空间变换原理的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:25:15', '2026-03-10 05:25:15', 'theory_explanation', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('28a7e61e-5e73-4b9e-9e44-0ed3f841cf3e', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d', 10, NULL, '{\"title\": \"实战演示：Python NLP工具链：案例复盘\", \"points\": [\"核心矛盾：传统规则方法难以应对电商评论中的多义词与口语化表达，导致情感识别准确率低下\", \"方案执行：采用 spaCy 进行分词与依存句法分析，结合 Hugging Face 预训练模型实现端到端微调\", \"决策依据：对比统计模型与深度学习模型在长文本语境下的表现，最终选定 Transformer 架构作为基座\", \"结果启示：模型准确率提升至 92%，验证了预训练模型在特定领域迁移学习的显著优势\", \"风险提示：需警惕小样本数据导致的过拟合问题，并建立人工审核机制以处理边界模糊的极端案例\"]}', '{\"text\": \"页面标题：实战演示：Python NLP工具链：案例复盘\\n\\n页面文字：\\n- 问题背景：传统规则方法难以应对电商评论多义词，导致情感识别准确率低下。\\n- 方法动作：采用spaCy进行句法分析，结合Hugging Face预训练模型实现端到端微调。\\n- 结果启示：模型准确率提升至92%，验证了预训练模型在特定领域迁移学习的优势。\\n- 风险提示：需警惕小样本过拟合风险，并建立人工审核机制处理边界模糊案例。\\n- 决策依据：对比统计与深度学习模型表现，最终选定Transformer架构作为基座方案。\", \"generated_at\": \"2026-03-16T05:37:22.733009\"}', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d/pages/28a7e61e-5e73-4b9e-9e44-0ed3f841cf3e_v2.png', 'COMPLETED', '2026-03-16 05:37:10', '2026-03-16 06:32:38', NULL, NULL);
