INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('28c0e62a-4ec8-47ae-bf28-e5a8e7d2d59e', '8a37f529-e51f-428c-8466-cdc137b73187', 2, NULL, '{\"page_id\": \"p03\", \"title\": \"进阶课程学习目标 (SMART)\", \"layout_id\": \"learning_objectives\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p02\"], \"must_cover\": [\"掌握高级拓扑技巧\", \"理解PBR渲染流程\", \"能独立完成资产制作\", \"进阶课程学习目标 (SMART)的核心概念与背景\", \"进阶课程学习目标 (SMART)的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"进阶课程学习目标 (SMART)的核心概念与背景\", \"进阶课程学习目标 (SMART)的关键方法与执行要点\", \"进阶课程学习目标 (SMART)的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p03\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.107425\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'learning_objectives', '{\"title\": \"进阶课程学习目标 (SMART)\", \"objectives\": [{\"text\": \"掌握高级拓扑技巧，能够针对硬表面模型进行最优布线重构，确保边缘流畅且面数可控。\", \"level\": \"应用\", \"hours\": 4, \"checked\": false}, {\"text\": \"理解PBR（基于物理的渲染）核心流程，包括漫反射、法线、粗糙度及金属度贴图的生成逻辑与交互关系。\", \"level\": \"分析\", \"hours\": 3, \"checked\": false}, {\"text\": \"能独立完成从高精度雕刻到低模烘焙再到引擎导入的全流程资产制作，输出符合行业标准的项目文件。\", \"level\": \"综合\", \"hours\": 6, \"checked\": false}, {\"text\": \"深入解析SMART目标在3D工作流中的核心概念，明确具体性、可衡量性及时限性对资产质量的影响。\", \"level\": \"评价\", \"hours\": 1, \"checked\": false}, {\"text\": \"执行关键方法要点，通过迭代测试验证拓扑结构与光照表现，优化渲染管线性能并解决常见 artifacts 问题。\", \"level\": \"应用\", \"hours\": 2, \"checked\": false}], \"course_code\": \"CG-ADV-2024\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
