t_archetype\": \"data_metrics\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2a1f5fe7-75ee-45a3-b689-c292a0a29a06', '7823309a-e50c-44f7-9823-bf26169886ac', 2, '第三部分：故障排除与进阶技巧', '{\"part\": \"第三部分：故障排除与进阶技巧\", \"pages\": [{\"title\": \"第二章：常见故障排除与纠错思维\", \"points\": [\"常见建模错误：破面、重叠顶点识别\", \"批判性思维：主动发现潜在问题\", \"自我修正能力：快速定位并修复错误\"]}, {\"title\": \"错漏对照：法线与破面的修复\", \"points\": [\"法线反转原因：内外表面判断失误\", \"非流形几何：封闭性与连通性检查\", \"一键修复技巧：自动与手动结合方案\"]}, {\"title\": \"进阶技巧：布尔运算后的优化策略\", \"points\": [\"布尔后乱码处理：清理冗余顶点\", \"手动重拓扑：恢复均匀布线\", \"保持比例：缩放后的几何完整性\", \"平滑组设置：渲染效果优化\"]}], \"logical_page_id\": \"p03\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p02\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_id\": \"title_content\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:23:43.630424\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:23:03', '2026-03-08 06:23:44', 'title_content', '{\"title\": \"构造认知与标准定位\", \"content\": [\"解析铝合金龙骨节点连接原理，明确受力传递路径与关键支撑点。\", \"依据设计图纸精准放线，利用激光水平仪建立三维空间基准坐标系。\", \"严格执行公差控制标准，确保构件安装偏差控制在毫米级范围内。\"], \"highlight\": \"精准定位是后续质量交付的核心前提。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2a1f9208-dd89-4e00-9a38-3206ce12ee27', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef', 8, '第三部分：案例实战', '{\"page_id\": \"p09\", \"title\": \"进阶挑战：参数化设计与实时引擎\", \"part\": \"第三部分：案例实战\", \"points\": [\"利用 Grasshopper 算法生成复杂几何形态与批量实例化\", \"PBR 材质流程在 Unity 与 Unreal 引擎中的无缝集成配置\", \"基于视距动态切换的 LOD 层级优化策略以提升渲染帧率\", \"程序化纹理贴图与实时光照烘焙的协同工作模式\"]}', '{\"text\": \"页面标题：进阶挑战：参数化设计与实时引擎\\n\\n页面文字：\\n- 针对游戏开发中复杂形态生成难题，利用 Grasshopper 算法实现批量实例化与几何形态创新构建。\\n- 解决跨平台资产流转痛点，通过 PBR 材质流程在 Unity 与 Unreal 引擎中的无缝集成配置方案。\\n- 应对移动端帧率瓶颈问题，基于视距动态切换的 LOD 层级优化策略有效提升渲染性能表现。\\n- 程序化纹理贴图与实时光照烘焙的协同工作模式，为实时交互场景提供了高效且逼真的视觉解决方案。\", \"generated_at\": \"2026-03-10T05:38:52.997111\"}', NULL, 'FAILED', '2026-03-10 05:38:34', '2026-03-10 05:38:58', NULL, NULL);
