INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2b5a7359-4532-42ba-b773-f8206f9b0f20', '9da12907-ffda-40fb-9be6-d245c93b1363', 9, '案例分析', '{\"page_id\": \"p08\", \"title\": \"案例拆解：角色生物建模实战\", \"part\": \"案例分析\", \"points\": [\"基于解剖学骨骼肌肉结构分析，精准构建符合人体工学的比例与动态姿态\", \"执行高模细节雕刻流程，并通过法线贴图烘焙技术将细节映射至低模表面\", \"运用四边面重拓扑技术优化布线，确保角色关节在动画弯曲时变形自然流畅\", \"结合UV展开策略合理分配纹理空间，解决复杂曲面贴图拉伸问题\"]}', '{\"text\": \"页面标题：案例拆解：角色生物建模实战\\n\\n页面文字：\\n- 基于解剖学骨骼肌肉结构分析，精准构建符合人体工学的比例与动态姿态。\\n- 执行高模细节雕刻流程，并通过法线贴图烘焙技术将细节映射至低模表面。\\n- 运用四边面重拓扑技术优化布线，确保角色关节在动画弯曲时变形自然流畅。\\n- 结合UV展开策略合理分配纹理空间，有效解决复杂曲面贴图拉伸问题。\", \"generated_at\": \"2026-03-10T06:06:00.404468\"}', NULL, 'FAILED', '2026-03-10 06:04:57', '2026-03-10 06:08:31', NULL, NULL);
