INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2c08320b-e9aa-458f-96ed-ab90e1dd338f', '6c250523-422a-46f3-a1f1-42e82424897c', 6, NULL, '{\"page_id\": \"p07\", \"title\": \"理论讲解：多边形建模的数学原理\", \"layout_id\": \"theory_explanation\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p05\"], \"must_cover\": [\"贝塞尔曲线原理\", \"NURBS曲面方程\", \"细分算法简述\", \"理论讲解：多边形建模的数学原理的核心概念与背景\", \"理论讲解：多边形建模的数学原理的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"理论讲解：多边形建模的数学原理的核心概念与背景\", \"理论讲解：多边形建模的数学原理的关键方法与执行要点\", \"理论讲解：多边形建模的数学原理的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p07\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.286825\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'theory_explanation', '{\"title\": \"理论推导\", \"theory\": [\"多边形建模的数学基础源于离散几何与微分几何的近似。贝塞尔曲线通过控制点定义的参数方程生成平滑轨迹，其凸包性质保证了曲线的可控性。NURBS（非均匀有理B样条）则引入权重因子，能够精确描述圆锥曲线及自由曲面，是工业级高精度建模的核心算法。\", \"细分算法（Subdivision Surface）通过递归分割面片并计算新顶点位置来逼近光滑曲面。Catmull-Clark算法针对四边形网格，而Loop算法针对三角形网格，两者均基于局部加权平均原理，确保在无限细分极限下达到C1或C2连续的光滑度。\"], \"formulas\": [{\"latex\": \"\\\\vec{P}(t) = \\\\sum_{i=0}^{n} B_{i,n}(t) \\\\cdot \\\\vec{P}_i\", \"explanation\": \"贝塞尔曲线定义：\\\\vec{P}(t)为曲线上点，\\\\vec{P}_i为控制点，B_{i,n}(t)为伯恩斯坦基函数。\"}, {\"latex\": \"S = \\\\frac{1}{4} \\\\sum_{k=0}^{3} V_k + \\\\frac{1}{2} \\\\sum_{k=0}^{3} (V_k - M_k)\", \"explanation\": \"Catmull-Clark细分规则简述：新顶点位置由周围顶点的加权平均与中点修正项共同决定。\"}], \"references\": [\"Piegl, L., & Tiller, W. (1997). The NURBS Book.\", \"Zorin, D., Schröder, P., & Sweldens, W. (1996). Interpolating Subdivision Surfaces.\"], \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2c11836d-205b-4bf4-a928-efa3893e6e98', '4e889981-954e-4263-b490-230183b1a644', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"原理拆解：力、质量与加速度的物理映射\", \"layout_id\": \"vocational_theory\", \"has_image\": true, \"keywords\": [\"矢量示意图\", \"电机扭矩曲线\", \"负载质量块\", \"加速度波形图\", \"深色科技背景\"], \"depends_on\": [\"p04\"], \"must_cover\": [\"F（合力）对应电机电磁推力\", \"m（质量）对应机械负载惯量\", \"a（加速度）对应速度变化率\", \"原理拆解：力、质量与加速度的物理映射的核心概念与背景\", \"原理拆解：力、质量与加速度的物理映射的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"原理拆解：力、质量与加速度的物理映射的核心概念与背景\", \"原理拆解：力、质量与加速度的物理映射的关键方法与执行要点\", \"原理拆解：力、质量与加速度的物理映射的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:45:02.424638\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:44:26', '2026-03-19 01:37:30', 'vocational_theory', '{\"title\": \"原理拆解：力、质量与加速度的物理映射\", \"description\": \"理论说明：将抽象的牛顿第二定律（F=ma）映射至机电系统，明确各物理量对应的工程实体。合力 F 直接决定驱动电机的输出需求，质量 m 代表系统的总惯量，而加速度 a 则是控制策略中速度变化率的直接体现。三者相互制约，任何一项参数的改变都会直接影响设备的动态响应特性。\", \"bullets\": [\"F（合力）对应电机电磁推力与负载阻力之差，决定驱动能力，需综合考虑摩擦力和惯性力。\", \"m（质量）对应机械负载惯量，包含电机转子与传送带物料总重，是系统稳定性的基础变量。\", \"a（加速度）对应速度变化率，直接关联加减速时间设定与电流冲击，过高会导致设备损坏。\"], \"practiceLabel\": \"实践区：参数计算与波形分析\", \"layout_variant\": \"a\", \"variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2c2031fc-5e15-4b31-a882-101911714107', 'faba4721-d6bc-47a9-847e-395b2a603584', 8, NULL, '{\"page_id\": \"p09\", \"title\": \"性能实测：多维指标仪表盘\", \"layout_id\": \"title_content\", \"has_image\": true, \"keywords\": [\"数字化仪表盘\", \"实时数据曲线\", \"荧光绿数值\", \"深色网格背景\", \"科技感图表\"], \"depends_on\": [\"p08\"], \"must_cover\": [\"QPS 峰值数据\", \"端到端延迟统计\", \"GPU/CPU利用率\", \"性能实测：多维指标仪表盘的核心概念与背景\", \"性能实测：多维指标仪表盘的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p08_1\"], \"points\": [\"性能实测：多维指标仪表盘的核心概念与背景\", \"性能实测：多维指标仪表盘的关键方法与执行要点\", \"性能实测：多维指标仪表盘的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p08_1\"], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p09\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p08_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:24:32.582319\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:23:01', '2026-03-10 06:24:33', 'title_content', '{\"title\": \"性能实测：多维指标仪表盘\", \"content\": [\"数字化仪表盘实时汇聚QPS峰值、端到端延迟及GPU/CPU利用率等关键指标，以荧光绿数值在深色网格背景中直观呈现系统运行的极致状态。\", \"实测数据显示，系统在百万级请求冲击下吞吐量提升300%，平均延迟降低至5ms以内，能耗比优化显著，验证了架构设计的鲁棒性。\", \"多维度数据曲线清晰展示了高负载场景下的资源动态平衡能力，确保业务连续性不受波动影响，为规模化推广提供坚实的数据支撑。\"], \"highlight\": \"真实数据看板见证：吞吐量、延迟与能耗比的全面跃升。\", \"image\": {\"src\": \"\", \"alt\": \"科技感HUD风格仪表盘界面，深色网格背景，荧光绿数字曲线跳动，展示QPS与延迟数据，无具体文字数字\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2cd7c508-a9e2-4726-8fb4-910af19559cf', '8fb9adbb-55b5-496b-9569-be1757626e7c', 2, NULL, '{\"page_id\": \"p03\", \"title\": \"教学目标：三维素养构建\", \"layout_id\": \"vocational_objectives\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p02\"], \"must_cover\": [\"知识目标：理解F=ma\", \"技能目标：公式灵活计算\", \"素养目标：科学思维与严谨态度\", \"教学目标：三维素养构建的核心概念与背景\", \"教学目标：三维素养构建的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"教学目标：三维素养构建的核心概念与背景\", \"教学目标：三维素养构建的关键方法与执行要点\", \"教学目标：三维素养构建的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p03\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T04:44:29.430204\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 04:43:50', '2026-03-17 04:44:29', 'vocational_objectives', '{\"title\": \"教学目标：三维素养构建\", \"bullets\": [{\"icon\": \"fa-book\", \"text\": \"知识目标：深度解析F=ma。\", \"description\": \"掌握牛顿第二定律的数学表达及其物理内涵，理解力是改变物体运动状态的原因。\"}, {\"icon\": \"fa-cogs\", \"text\": \"技能目标：公式灵活应用。\", \"description\": \"能够根据已知条件（质量、加速度）准确计算合外力，或反之求解运动参数。\"}, {\"icon\": \"fa-lightbulb-o\", \"text\": \"素养目标：严谨科学思维。\", \"description\": \"培养基于数据的工程决策习惯，树立安全第一的职业规范意识。\"}, {\"icon\": \"fa-globe\", \"text\": \"思政融入：工匠精神培育。\", \"description\": \"通过精密仪器操作体验，感悟精益求精的工匠精神与国家制造实力。\"}, {\"icon\": \"fa-check-circle\", \"text\": \"执行要点：任务驱动教学。\", \"description\": \"以真实职业场景问题为切入点，引导学生在解决实际问题中内化理论知识。\"}], \"keyTakeaway\": \"本章节旨在通过理论与实操结合，培养学生解决实际工程问题的综合能力与职业素养。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2ceaf63a-3309-4f2c-a922-01e9f83aaa13', '60390839-f925-4662-a2dc-c92d64253b33', 2, NULL, '{\"page_id\": \"p03\", \"title\": \"学习目标与课程概览\", \"layout_id\": \"toc_academic\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p01\"], \"must_cover\": [], \"promises_open\": [{\"promise_id\": \"pr_p02_1\", \"text\": \"深入解析多边形建模的核心拓扑规则\", \"must_cover\": [\"布线逻辑\", \"四边面优先\", \"极点处理\"], \"target_page_ids\": [\"p18\"], \"is_hard\": true}, {\"promise_id\": \"pr_p02_2\", \"text\": \"演示从草图到成品的完整工作流\", \"must_cover\": [\"建模步骤\", \"修改器应用\", \"优化技巧\"], \"target_page_ids\": [\"p18\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"toc\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:29:50', '2026-03-10 05:29:50', 'toc_academic', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2e597d5e-f8cd-4140-9132-8f32ee994002', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef', 1, '课程导入', '{\"page_id\": \"p02\", \"title\": \"目录：课程结构与逻辑脉络\", \"part\": \"课程导入\", \"points\": [\"构建从三维空间理论认知到主流软件实操的递进式学习路径\", \"深度解析从草图规划、拓扑布线到UV展开与渲染的标准工业工作流\", \"通过硬表面产品与有机生物角色两大经典案例拆解实战技巧\", \"引入参数化设计与实时引擎应用等进阶内容，拓展行业视野\"]}', '{\"text\": \"页面标题：目录：课程结构与逻辑脉络\\n\\n页面文字：\\n- 构建从三维空间理论认知到主流软件实操的递进式学习路径，确保知识体系完整严密。\\n- 深度解析涵盖草图规划、拓扑布线、UV展开与渲染的标准工业工作流关键环节。\\n- 通过硬表面产品与有机生物角色两大经典案例拆解实战技巧，并引入参数化设计等新内容拓展视野。\", \"generated_at\": \"2026-03-10T05:38:52.044268\"}', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef/pages/2e597d5e-f8cd-4140-9132-8f32ee994002_v1.png', 'COMPLETED', '2026-03-10 05:38:21', '2026-03-10 06:03:48', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2e79ff7d-6709-46e2-9267-834223c6520d', '6eea18f8-c641-48a1-ba84-4c49ed3830d6', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"第二章：核心架构重塑与模型跃迁\", \"layout_id\": \"edu_logic_flow\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p04\"], \"must_cover\": [\"架构重构目标\", \"新模型定义\", \"第二章：核心架构重塑与模型跃迁的核心概念与背景\", \"第二章：核心架构重塑与模型跃迁的关键方法与执行要点\", \"第二章：核心架构重塑与模型跃迁的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第二章：核心架构重塑与模型跃迁的核心概念与背景\", \"第二章：核心架构重塑与模型跃迁的关键方法与执行要点\", \"第二章：核心架构重塑与模型跃迁的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"process_flow\", \"layout_variant\": \"a\", \"logical_page_id\": \"p05\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:27:09.079480\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:25:44', '2026-03-10 06:27:09', 'edu_logic_flow', '{\"title\": \"第二章：核心架构重塑与模型跃迁\", \"stages\": [{\"title\": \"从单体到分布式重构\", \"description\": \"摒弃传统烟囱式架构，转向微服务化与容器化部署，实现计算资源的弹性伸缩与动态分配。\"}, {\"title\": \"构建统一算力调度层\", \"description\": \"建立全局资源视图，通过智能算法自动匹配任务与节点，彻底消除算力孤岛与资源浪费。\"}, {\"title\": \"定义标准化交互协议\", \"description\": \"制定通用数据接口与通信规范，打通上下游生态壁垒，支持异构设备即插即用与无缝协同。\"}], \"background_image\": \"https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=1920&auto=format&fit=crop\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"process_flow\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2ed261d8-8ade-4ad9-965a-02b4acd238b2', '3cb9762c-0eb3-483e-bfb0-227b9e866667', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"AI 转型五步实施路径\", \"layout_id\": \"edu_timeline_steps\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p10\"], \"must_cover\": [\"需求洞察\", \"数据治理\", \"模型训练\", \"试点部署\", \"全面推广\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"AI 转型五步实施路径的核心概念与背景\", \"AI 转型五步实施路径的关键方法与执行要点\", \"AI 转型五步实施路径的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"timeline\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:06:16', '2026-03-10 05:06:16', 'edu_timeline_steps', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2f90c3fb-edc9-47a8-9ef1-eb5812576663', 'c3f4f20a-0839-4fb0-9375-125c6af13f37', 12, NULL, '{\"page_id\": \"p13\", \"title\": \"课堂互动：零件选配决策\", \"layout_id\": \"sk_sop\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p12\"], \"must_cover\": [\"案例零件A（易碎曲面）\", \"案例零件B（不规则金属块）\", \"案例零件C（高温焊件）\", \"选型理由阐述\", \"课堂互动：零件选配决策的核心概念与背景\"], \"promises_open\": [{\"promise_id\": \"pr_p13_1_cbdf457b\", \"text\": \"课堂互动：零件选配决策的复盘与结果启示\", \"must_cover\": [\"案例复盘\", \"结果启示\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"promises_close\": [\"pr_p07_1\"], \"points\": [\"课堂互动：零件选配决策的核心概念与背景\", \"课堂互动：零件选配决策的关键方法与执行要点\", \"课堂互动：零件选配决策的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p07_1\"], \"layout_archetype\": \"process_steps\", \"layout_variant\": \"a\", \"logical_page_id\": \"p13\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:04:18.361070\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:03:29', '2026-03-19 06:04:18', 'sk_sop', '{\"title\": \"课堂互动：零件选配决策\", \"steps\": [{\"number\": 1, \"label\": \"步骤1\", \"description\": \"识别零件A（易碎曲面）、B（不规则金属块）、C（高温焊件）的关键物理属性与风险点。\", \"icon\": \"fa-check\"}, {\"number\": 2, \"label\": \"步骤2\", \"description\": \"基于零件特征，匹配夹具类型、材质要求及温控策略，阐述选型背后的工程逻辑。\", \"icon\": \"fa-check\"}, {\"number\": 3, \"label\": \"步骤3\", \"description\": \"对比不同选配方案在安全性、效率与成本上的差异，预判潜在故障场景。\", \"icon\": \"fa-check\"}, {\"number\": 4, \"label\": \"步骤4\", \"description\": \"各组确定最终零件选配方案，并准备汇报理由，完成从理论到实战的转化。\", \"icon\": \"fa-check\"}], \"summary\": \"核心概念：零件特征决定选型逻辑；背景：承接实训工单任务发布，为后续实战演练奠定决策基础。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"process_steps\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2f918c61-37d3-4918-b0e2-cab13c404828', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 7, '第四阶段', '{\"page_id\": \"p07\", \"title\": \"大模型时代：Transformer架构与生成式AI\", \"part\": \"第四阶段\", \"points\": [\"Transformer引入自注意力机制，突破RNN序列限制，实现高效并行计算\", \"GPT系列与大语言模型（LLM）通过海量预训练展现卓越泛化与推理能力\", \"AIGC技术推动AI从被动分析向主动内容创作跨越，重塑内容生产范式\", \"多模态融合成为趋势，文本、图像与音频在统一架构下协同处理\"]}', '{\"text\": \"页面标题：大模型时代：Transformer架构与生成式AI\\n\\n页面文字：\\n- Transformer引入自注意力机制，突破RNN序列限制，实现了高效的并行计算能力。\\n- GPT系列与大语言模型通过海量预训练，展现出卓越的泛化能力与复杂推理水平。\\n- AIGC技术推动AI从被动分析向主动内容创作跨越，彻底重塑了全球内容生产范式。\\n- 多模态融合成为核心趋势，文本、图像与音频在统一架构下实现高效协同处理。\"}', 'a4eba850-5434-409c-bcf0-b43c6ff24364/pages/2f918c61-37d3-4918-b0e2-cab13c404828_v1.png', 'COMPLETED', '2026-03-09 08:54:29', '2026-03-09 08:55:36', NULL, NULL);
