INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('3216e6b0-bc7f-4d6c-adca-e93cd9ed6e95', '8ccaacf6-cf8f-4cd6-8ca8-7d5f28350c89', 0, NULL, '{\"page_id\": \"p01\", \"title\": \"封面：牛顿第二定律在机电设备调试中的应用\", \"layout_id\": \"vocational_cover\", \"has_image\": true, \"keywords\": [\"工业机械臂\", \"蓝色科技背景\", \"橙色工具元素\", \"机电一体化实训\", \"无文字背景\"], \"depends_on\": [], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"cover\", \"layout_variant\": \"a\", \"logical_page_id\": \"p01\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:41:09.847369\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:40:26', '2026-03-17 07:41:10', 'vocational_cover', '{\"title\": \"牛顿第二定律在机电设备调试中的应用\", \"subtitle\": \"工业机械臂与传送带系统实训项目。\", \"author\": \"机电一体化教研室\", \"department\": \"智能制造实训中心\", \"date\": \"2023-10\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"cover\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('32409087-ce10-4087-ac37-96e33a19ebf0', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 8, '现状', '{\"page_id\": \"p08\", \"title\": \"关键应用：AI如何重塑行业生态\", \"part\": \"现状\", \"points\": [\"医疗领域利用AI加速新药筛选与病理影像分析，显著提升诊断效率与准确率\", \"金融行业通过智能风控模型实时拦截欺诈交易，并实现量化策略的自动化执行\", \"制造业借助预测性维护降低设备停机风险，推动柔性生产线向自适应制造转型\", \"跨行业数据融合打破信息孤岛，促使企业从单一业务优化转向全链路智能决策\"]}', '{\"text\": \"页面标题：关键应用：AI如何重塑行业生态\\n\\n页面文字：\\n- 医疗领域利用AI加速新药筛选与病理影像分析，显著提升诊断效率与临床准确率。\\n- 金融行业通过智能风控模型实时拦截欺诈交易，并实现量化策略的自动化精准执行。\\n- 制造业借助预测性维护降低设备停机风险，推动柔性生产线向自适应制造转型。\\n- 跨行业数据融合打破信息孤岛，促使企业从单一业务优化转向全链路智能决策。\", \"generated_at\": \"2026-03-09T08:54:48.599777\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:31', '2026-03-09 08:54:49', NULL, NULL);
