INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('348d2b98-4510-43fc-9c19-b110d5c906a7', 'f8ce8774-c982-4cd5-a379-23d4cf53bef2', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"核心原理回顾\", \"layout_id\": \"vocational_theory\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p04\"], \"must_cover\": [\"牛顿第二定律数学表达式\", \"加速度与合外力的正比关系\", \"质量对加速度的反比影响\", \"核心原理回顾的核心概念与背景\", \"核心原理回顾的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p06_1\"], \"points\": [\"核心原理回顾的核心概念与背景\", \"核心原理回顾的关键方法与执行要点\", \"核心原理回顾的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p06_1\"], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"b\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p06_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T06:43:32.017979\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 06:42:46', '2026-03-17 14:44:01', 'vocational_theory', '{\"title\": \"核心原理回顾\", \"left\": {\"header\": \"数学表达\", \"content\": [\"核心原理回顾在数学表达下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-square-root-alt\", \"text\": \"公式：F = ma（合外力等于质量乘加速度）。\", \"description\": \"解释公式：F = ma（合外力等于质量乘加速度）在数学表达维度下的意义。\"}, {\"icon\": \"fa-arrows-h\", \"text\": \"方向性：加速度方向始终与合外力一致。\", \"description\": \"解释方向性：加速度方向始终与合外力一致在数学表达维度下的意义。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"瞬时性：力变则加速度即刻改变。\", \"description\": \"解释瞬时性：力变则加速度即刻改变在数学表达维度下的意义。\"}]}, \"right\": {\"header\": \"变量逻辑\", \"content\": [\"核心原理回顾在变量逻辑下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-line-chart\", \"text\": \"正比关系：合外力增大，加速度线性增加。\", \"description\": \"解释正比关系：合外力增大，加速度线性增加在变量逻辑维度下的意义。\"}, {\"icon\": \"fa-minus-circle\", \"text\": \"反比关系：质量增大，加速度成反比减小。\", \"description\": \"解释反比关系：质量增大，加速度成反比减小在变量逻辑维度下的意义。\"}, {\"icon\": \"fa-sliders\", \"text\": \"控制逻辑：固定质量分析力变，固定力分析质变。\", \"description\": \"解释