INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('359a6d0c-9e9a-46b0-bc61-1c606a3fed53', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d', 9, '实践', '{\"page_id\": \"p09\", \"title\": \"实战演示：Python NLP工具链\", \"part\": \"实践\", \"points\": [\"掌握NLTK与spaCy在分词、词性标注及实体识别中的核心API调用\", \"利用Hugging Face Transformers库一键加载预训练模型进行推理\", \"通过代码构建基于规则与简单分类的简易聊天机器人原型\", \"解析从文本输入到生成回复的完整数据处理流水线\", \"对比不同工具链在开发效率与运行性能上的差异\"]}', '{\"text\": \"页面标题：实战演示：Python NLP工具链\\n\\n页面文字：\\n- 掌握NLTK与spaCy在分词、词性标注及实体识别中的核心API调用方法。\\n- 利用Hugging Face Transformers库一键加载预训练模型进行高效推理。\\n- 通过代码构建基于规则与简单分类的简易聊天机器人原型系统。\\n- 解析从文本输入到生成回复的完整数据处理流水线运作机制。\\n- 对比不同工具链在开发效率与运行性能上的显著差异与适用场景。\", \"generated_at\": \"2026-03-16T05:37:22.733001\"}', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d/pages/359a6d0c-9e9a-46b0-bc61-1c606a3fed53_v2.png', 'COMPLETED', '2026-03-16 05:37:08', '2026-03-16 06:32:22', NULL, NULL);
