INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('3aac4501-166b-42ea-8f69-37e252b84d4b', '4e889981-954e-4263-b490-230183b1a644', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"实操演练：关键参数计算与校验\", \"layout_id\": \"vocational_step_by_step\", \"has_image\": true, \"keywords\": [\"工程师手写计算草稿\", \"计算器特写\", \"PLC参数输入界面\", \"数据表格\", \"专注神情\"], \"depends_on\": [\"p06\"], \"must_cover\": [\"步骤1：测量皮带与物料总质量\", \"步骤2：设定目标加速度\", \"步骤3：反推所需最大推力\", \"步骤4：校验电机额定扭矩\", \"实操演练：关键参数计算与校验的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"实操演练：关键参数计算与校验的核心概念与背景\", \"实操演练：关键参数计算与校验的关键方法与执行要点\", \"实操演练：关键参数计算与校验的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"process_steps\", \"layout_variant\": \"a\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:45:02.424756\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:44:26', '2026-03-19 01:37:30', 'vocational_step_by_step', '{\"title\": \"实操演练：关键参数计算与校验\", \"steps\": [{\"title\": \"测量皮带与物料总质量\", \"label\": \"STEP 01\", \"desc\": \"使用高精度称重设备精确获取传送带及满载货物总重，作为 F=ma 中 m 值输入，确保数据源头准确无误。\"}, {\"title\": \"设定目标加速度\", \"label\": \"STEP 02\", \"desc\": \"依据物流分拣线工艺要求，确定最大允许加速度 a，避免货物滑落，同时兼顾节拍效率与设备承受能力。\"}, {\"title\": \"反推所需最大推力\", \"label\": \"STEP 03\", \"desc\": \"代入公式 F=ma 计算理论驱动力，并叠加摩擦阻力得出电机需输出合力，预留适当的安全余量以防意外过载。\"}, {\"title\": \"校验电机额定扭矩\", \"label\": \"STEP 04\", \"desc\": \"对比计算推力与电机额定扭矩，确认选型余量，防止过载跳闸风险，确保电机在长期运行中处于高效区间。\"}], \"layout_variant\": \"a\", \"variant\": \"a\", \"layout_archetype\": \"process_steps\"}');
