INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('3bf1626d-aecc-45e8-aad0-8e0b6dbe3c91', '1d063203-8ece-436a-ad39-9501e3c7e06b', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"硬表面建模：布尔运算与倒角\", \"layout_id\": \"sop_vertical_steps\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p05\"], \"must_cover\": [\"布尔运算顺序\", \"倒角厚度控制\", \"法线翻转处理\", \"网格清理步骤\", \"硬表面建模：布尔运算与倒角的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p04_1\"], \"points\": [\"硬表面建模：布尔运算与倒角的核心概念与背景\", \"硬表面建模：布尔运算与倒角的关键方法与执行要点\", \"硬表面建模：布尔运算与倒角的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p04_1\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p04_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-20T01:09:55.819734\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-20 01:09:16', '2026-03-20 01:09:56', 'sop_vertical_steps', '{\"title\": \"硬表面建模：布尔运算与倒角\", \"events\": [{\"title\": \"布尔运算顺序控制\", \"description\": \"严格执行先并集后差集的运算逻辑，防止因法线方向错误导致的网格自相交与渲染黑斑。\", \"is_highlighted\": false}, {\"title\": \"倒角厚度精密控制\", \"description\": \"根据工业零件公差要求设定倒角半径，平衡视觉圆滑度与机械结构强度的物理限制。\", \"is_highlighted\": true}, {\"title\": \"网格清理与修复\", \"description\": \"自动检测并移除重叠顶点与非流形边，重建平滑的法线朝向，完成从布尔结果到可编辑网格的转化。\", \"is_highlighted\": false}], \"accent_color\": \"#27ae60\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
