INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('3c98d898-9adb-4dc5-8461-da23dc6d21c1', 'faba4721-d6bc-47a9-847e-395b2a603584', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"开发工作流：从代码到部署\", \"layout_id\": \"title_content\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p10\"], \"must_cover\": [\"编译阶段\", \"调试阶段\", \"部署上线流程\", \"开发工作流：从代码到部署的核心概念与背景\", \"开发工作流：从代码到部署的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"开发工作流：从代码到部署的核心概念与背景\", \"开发工作流：从代码到部署的关键方法与执行要点\", \"开发工作流：从代码到部署的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:24:32.582363\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:23:02', '2026-03-10 06:24:33', 'title_content', '{\"title\": \"开发工作流：从代码到部署\", \"content\": [\"基于前序性能实测与竞品优势分析，本阶段构建标准化开发流水线，将编译、调试与部署全流程自动化串联，彻底消除人工干预带来的版本不一致风险。\", \"在编译阶段引入智能增量构建引擎，结合动态调度策略，使万卡集群下的代码重构时间缩短至分钟级；调试环节集成实时断点追踪与资源画像技术，快速定位分布式环境下的隐性故障。\", \"部署上线流程采用蓝绿发布与金丝雀灰度机制，配合零信任安全网关，确保新架构在金融风控等核心场景的平滑迁移与毫秒级故障自愈能力。\"], \"highlight\": \"编译即交付，调试即监控，部署即验证。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
