INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('3dbc5c18-3749-440f-82b4-c343cec18e0d', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d', 5, '应用场景', '{\"page_id\": \"p05\", \"title\": \"核心任务一：情感分析与分类\", \"part\": \"应用场景\", \"points\": [\"基于上下文语义精准判断文本情感倾向（正/负/中）及强度\", \"支持多标签分类与细粒度情绪拆解（如愤怒、失望、期待）\", \"在电商评论挖掘中量化产品口碑并辅助运营决策\", \"应用于社交媒体舆情监控，实时预警负面舆论爆发风险\"]}', '{\"text\": \"页面标题：核心任务一：情感分析与分类\\n\\n页面文字：\\n- 基于上下文语义精准判断文本情感倾向及强度，支持正负中多维度的细致拆解。\\n- 算法可识别愤怒失望等多标签情绪，有效应用于电商评论挖掘以量化产品口碑。\\n- 该技术助力社交媒体舆情监控，实时预警负面舆论爆发风险并辅助运营决策制定。\", \"generated_at\": \"2026-03-16T05:37:22.407821\"}', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d/pages/3dbc5c18-3749-440f-82b4-c343cec18e0d_v1.png', 'FAILED', '2026-03-16 05:37:02', '2026-03-16 06:30:51', NULL, NULL);
