INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('3e556156-8c94-48d2-8547-777c7996a273', '4e889981-954e-4263-b490-230183b1a644', 13, NULL, '{\"page_id\": \"p14\", \"title\": \"进阶应用：变负载系统的自适应控制\", \"layout_id\": \"vocational_theory\", \"has_image\": true, \"keywords\": [\"传感器阵列\", \"自适应算法流程图\", \"动态负载模拟\", \"数据流可视化\", \"未来科技感\"], \"depends_on\": [\"p12\"], \"must_cover\": [\"实时质量检测技术\", \"PID参数的在线自整定\", \"F=ma在智能控制中的演变\", \"进阶应用：变负载系统的自适应控制的核心概念与背景\", \"进阶应用：变负载系统的自适应控制的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"进阶应用：变负载系统的自适应控制的核心概念与背景\", \"进阶应用：变负载系统的自适应控制的关键方法与执行要点\", \"进阶应用：变负载系统的自适应控制的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"b\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:45:02.424983\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:44:28', '2026-03-19 01:37:30', 'vocational_theory', '{\"title\": \"进阶应用：变负载系统的自适应控制\", \"description\": \"引入传感器阵列与智能算法，实现F=ma公式在复杂环境下的动态演化。通过实时质量检测技术捕捉负载变化，利用在线自整定PID参数匹配当前工况，构建数据流可视化监控体系，确保系统响应始终处于最优区间，适应多变的工业生产需求。\", \"bullets\": [\"多源传感器融合技术实时采集负载质量与摩擦系数，为算法提供精准的输入数据。\", \"自适应算法根据F=ma实时重构加速度曲线参数，自动补偿负载变化带来的影响。\", \"数据流可视化界面监控系统响应滞后与超调量，辅助工程师快速诊断系统异常。\"], \"practiceLabel\": \"实践区：智能控制演示\", \"layout_variant\": \"b\", \"variant\": \"b\", \"layout_archetype\": \"data_metrics\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('3e783962-e17c-4831-ab4c-4626a83b5654', '6c250523-422a-46f3-a1f1-42e82424897c', 16, NULL, '{\"page_id\": \"p17\", \"title\": \"关键知识点：UV展开与纹理映射\", \"layout_id\": \"key_concepts\", \"has_image\": true, \"keywords\": [\"UV网格\", \"展开图\", \"接缝处理\", \"纹理坐标\", \"像素密度\"], \"depends_on\": [\"p13\"], \"must_cover\": [\"UV岛布局\", \"接缝切割原则\", \"拉伸与重叠检测\", \"图集打包\", \"关键知识点：UV展开与纹理映射的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"关键知识点：UV展开与纹理映射的核心概念与背景\", \"关键知识点：UV展开与纹理映射的关键方法与执行要点\", \"关键知识点：UV展开与纹理映射的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p17\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287108\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'key_concepts', '{\"title\": \"关键知识点：UV展开与纹理映射\", \"subtitle\": \"从三维空间到二维平面的精准映射。\", \"bullets\": [{\"icon\": \"fa-cube\", \"text\": \"UV岛布局策略。\", \"description\": \"将模型表面切割为独立UV岛，最大化利用UV空间，减少空白浪费，提升纹理利用率。\"}, {\"icon\": \"fa-cut\", \"text\": \"接缝切割原则。\", \"description\": \"沿模型自然边缘或隐蔽区域（如腋下、背部中线）切割，确保展开后形状规则，减少拉伸。\"}, {\"icon\": \"fa-expand-arrows-alt\", \"text\": \"拉伸与重叠检测。\", \"description\": \"检查UV网格比例是否均匀，消除非均匀拉伸导致的纹理扭曲，确保像素密度一致。\"}, {\"icon\": \"fa-th-large\", \"text\": \"图集打包优化。\", \"description\": \"将多个UV岛紧凑排列至单一纹理图集（Atlas）中，减少Draw Call，提升渲染性能。\"}, {\"icon\": \"fa-ruler-combined\", \"text\": \"像素密度控制。\", \"description\": \"根据模型在屏幕中的占比设定UV缩放比例，确保近景物体拥有更高密度的纹理细节。\"}], \"keyTakeaway\": \"UV展开是连接几何模型与纹理材质的桥梁，科学的布局与切割直接决定最终画面的清晰度与渲染效率。\", \"image\": {\"src\": \"\", \"alt\": \"展示UV展开过程对比图：左侧为未优化的混乱UV，右侧为整齐排列的UV岛及对应的纹理预览\", \"position\": \"right\", \"width\": \"35%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
