INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('3f93ff2e-9942-4fc5-b695-aa7fbee62fdf', '14c0f24c-10e7-4309-a927-d9db1066897c', 7, NULL, '{\"title\": \"标本特写：布线错误与修复案例：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"case_before_after\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p08\", \"depends_on\": [\"p07\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.773869\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'case_before_after', '{\"title\": \"标本特写：布线错误与修复案例：案例复盘\", \"left\": {\"header\": \"问题与场景：核心矛盾\", \"content\": [\"原始模型在关节弯曲处出现不可逆的三角面撕裂，导致动态渲染时网格塌陷。\"], \"bullets\": [{\"icon\": \"fa-exclamation-triangle\", \"text\": \"N-gon（多边面）破坏流体动力学计算路径。\", \"description\": \"解释N-gon（多边面）破坏流体动力学计算路径。在问题与场景：核心矛盾维度下的意义。\"}, {\"icon\": \"fa-bolt\", \"text\": \"极点过度聚集引发局部法线翻转与光照噪点。\", \"description\": \"解释极点过度聚集引发局部法线翻转与光照噪点。在问题与场景：核心矛盾维度下的意义。\"}, {\"icon\": \"fa-link-slash\", \"text\": \"布线断裂导致蒙皮权重分配失效，角色动作僵硬。\", \"description\": \"解释布线断裂导致蒙皮权重分配失效，角色动作僵硬。在问题与场景：核心矛盾维度下的意义。\"}, {\"icon\": \"fa-search-minus\", \"text\": \"微观层面观察发现网格密度分布极度不均。\", \"description\": \"解释微观层面观察发现网格密度分布极度不均。在问题与场景：核心矛盾维度下的意义。\"}]}, \"right\": {\"header\": \"方案与执行：关键决策\", \"content\": [\"采用拓扑重构策略，移除无效极点，建立符合肌肉走向的支撑环结构。\", \"结论：标本特写：布线错误与修复案例：案例复盘需要结合目标场景做取舍。\"], \"bullets\": [{\"icon\": \"fa-cog\", \"text\": \"执行切割与融合操作，将五边/六边面强制拆解为四边面流形。\", \"description\": \"解释执行切割与融合操作，将五边/六边面强制拆解为四边面流形。在方案与执行：关键决策维度下的意义。\"}, {\"icon\": \"fa-magic\", \"text\": \"重新布设循环边，确保曲率变化处的布线密度梯度平滑过渡。\", \"description\": \"解释重新布设循环边，确保曲率变化处的布线密度梯度平滑过渡。在方案与执行：关键决策维度下的意义。\"}, {\"icon\": \"fa-check-circle\", \"text\": \"验证修复后模型在极限姿态下的体积保持能力与表面连续性。\", \"description\": \"解释验证修复后模型在极限姿态下的体积保持能力与表面连续性。在方案与执行：关键决策维度下的意义。\"}, {\"icon\": \"fa-lightbulb\", \"text\": \"经验启示：硬表面布线需预留变形余量，避免死结式极点。\", \"description\": \"解释经验启示：硬表面布线需预留变形余量，避免死结式极点。在方案与执行：关键决策维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('3f975d47-93ae-473b-bcb8-0e612545f105', '3ba66aac-bac2-4c02-b7f4-d1d534d00b1d', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"第二章：核心工具与技法详解\", \"layout_id\": \"edu_data_board\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p06\"], \"must_cover\": [\"建模工具分类\", \"编辑模式\", \"修改器堆栈\", \"第二章：核心工具与技法详解的核心概念与背景\", \"第二章：核心工具与技法详解的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第二章：核心工具与技法详解的核心概念与背景\", \"第二章：核心工具与技法详解的关键方法与执行要点\", \"第二章：核心工具与技法详解的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_dashboard\", \"layout_variant\": \"b\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:04:29', '2026-03-10 05:04:29', 'edu_data_board', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('3fc9451d-a69a-4101-a860-4af482375484', '6df20e77-c8f8-4a94-8aed-6817a95a893a', 1, '第二部分：核心内容演示', '{\"part\": \"第二部分：核心内容演示\", \"pages\": [{\"title\": \"格式选择策略\", \"points\": [\"简短内容采用简单格式（单页列表）\", \"长篇内容采用分部分格式（章节结构）\", \"本演示选用分部分格式以体现结构清晰度\"]}, {\"title\": \"案例背景：AI 医疗应用\", \"points\": [\"当前挑战：医疗资源分布不均与诊断效率瓶颈\", \"解决方案：引入 AI 辅助诊断系统\", \"预期价值：提升准确率并降低误诊率\"]}, {\"title\": \"方法详解：AI 诊断系统实施路径\", \"points\": [\"数据层：整合多源电子病历与影像数据\", \"算法层：部署深度学习模型进行病灶识别\", \"交互层：医生端可视化反馈与决策支持\"]}, {\"title\": \"结果分析：试点项目成效\", \"points\": [\"准确率提升：从 82% 提高至 94%\", \"效率优化：单次诊断时间缩短 40%\", \"用户反馈：医生满意度达 90% 以上\"]}, {\"title\": \"经验总结与启示\", \"points\": [\"成功关键：高质量数据清洗与跨部门协作\", \"潜在风险：数据隐私保护与算法偏见问题\", \"未来方向：向基层医疗机构推广普及\"]}]}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-08 01:11:50', '2026-03-08 01:11:50', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('3fe3e6b3-acb3-42e6-a95a-25d631a5c4e6', '2210a36d-b61a-453a-83ee-86edc9925e6a', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"第一阶段知识图谱总结\", \"layout_id\": \"key_takeaways\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"建模核心步骤回顾\", \"常见问题解决方案\", \"第一阶段知识图谱总结的核心概念与背景\", \"第一阶段知识图谱总结的关键方法与执行要点\", \"第一阶段知识图谱总结的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第一阶段知识图谱总结的核心概念与背景\", \"第一阶段知识图谱总结的关键方法与执行要点\", \"第一阶段知识图谱总结的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p11\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T06:30:50.647711\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 06:24:26', '2026-03-07 15:18:14', 'key_takeaways', '{\"title\": \"第一阶段知识图谱总结\", \"subtitle\": \"建模流程与核心复盘。\", \"bullets\": [{\"icon\": \"fa-project-diagram\", \"text\": \"步骤回顾。\", \"description\": \"确立低模布线与拓扑连接关系。\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"问题解决。\", \"description\": \"针对拓扑断裂与冗余进行修正。\"}, {\"icon\": \"fa-tasks\", \"text\": \"效率工具。\", \"description\": \"避免过度依赖自动吸附功能。\"}], \"keyTakeaway\": \"规范操作积累可复用的项目经验体系\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('402d8372-5ae2-4bdc-acd0-fc313c82efdf', '9b5d83ef-2600-4c3b-b852-00607680277d', 16, NULL, '{\"title\": \"新页面\", \"points\": []}', '{\"text\": \"页面标题：目录：技术演进全景图\\n\\n页面文字：\\n为了更全面地展现当前 AI 行业的竞争态势与技术深度，我将你提供的四个核心维度扩展为 20 个具体的技术与行业观察点。\\n-涌现能力的首次具象化：回顾 GPT-3.5 如何通过 RLHF（人类反馈强化学习）让模型具备了惊人的对话逻辑，打破了大众对“聊天机器人”的刻板印象。\\n-Prompt Engineering 的兴起：分析“提示词工程”如何成为连接人类意图与机器算力的桥梁，定义了最初的人机协作模式。\\n-插件与 GPTs 生态：探讨 OpenAI 如何通过 GPTs 尝试构建应用商店，将大模型从单一工具转化为可定制的智能助手平台。\\n-推理模型的范式转移：以 o1 系列模型 为例，解析“思维链”如何让 AI 从单纯的概率预测进化到具备深层逻辑推理能力。\\n-劳动力市场的深层重构：反思 ChatGPT 在翻译、文案、基础代码等领域引发的生产力革命，以及对未来技能需求的结构性改变。\\n-宪法 AI（Constitutional AI）：深入解析 Anthropic 如何通过自监督对齐技术，在减少模型偏见与有害输出方面树立行业标杆。\\n-长上下文的先发优势：回顾 Claude 率先突破 100k/200k context window，如何彻底改变了长文档分析与法务、金融等行业的处理流程。\\n-Computer Use 交互创新：分析 Claude 3.5 Sonnet 如何通过“直接操作电脑”的能力，将 AI 从“对话框”释放到真实的桌面操作系统中。\\n-学术与代码的严谨性：探讨 Claude 在复杂逻辑代码编写与科学论文总结中表现出的低幻觉率，及其在开发者群体中的口碑积累。\\n-Artifacts 的实时协作：解析 Claude 界面如何通过侧边栏实时渲染代码与图表，提升了人机异步协作的效率。\\n-Native Multimodal 的底层逻辑：解释 Gemini 如何从底层开始训练即支持视频、音频和图像，而非通过多个单一模型拼凑。\\n-百万级上下文（1M-2M Token）：分析 Gemini 1.5 Pro 在处理超长视频序列和整库代码重构时的独特技术优势。\\n-Google Workspace 深度整合：探讨 Gemini 如何无缝嵌入 Gmail、Docs 和 Sheets，将 AI 转化为数亿用户的原生生产力套件。\\n-端侧模型（Gemini Nano）的普及：解析 Google 如何利用 Android 生态，在 Pixel 等设备上实现离线、隐私安全的端侧 AI 体验。\\n-Deep Research 的情报能力：评估 Google 利用其搜索搜索底座，如何让 Gemini 在处理长达数百页的复杂课题研究时保持数据实时性。\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/402d8372-5ae2-4bdc-acd0-fc313c82efdf_v1.png', 'COMPLETED', '2026-03-09 09:20:49', '2026-03-09 09:21:54', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('410a54d6-9f64-451d-b3d0-cd40ebc879fa', '2786117f-f122-459a-8310-c05a2077848b', 2, NULL, '{\"page_id\": \"p03\", \"title\": \"情境导入：汽车焊装线的双重挑战\", \"layout_id\": \"edu_timeline_steps\", \"has_image\": true, \"keywords\": [\"汽车白车身生产线\", \"机器人焊接作业\", \"机械手抓取零件\", \"工业流水线特写\", \"动态模糊效果\"], \"depends_on\": [\"p02\"], \"must_cover\": [\"焊接任务中的稳定性需求\", \"抓取任务中的多样性需求\", \"传统单一夹具的局限性\", \"情境导入：汽车焊装线的双重挑战的核心概念与背景\", \"情境导入：汽车焊装线的双重挑战的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_intro_1\"], \"points\": [\"情境导入：汽车焊装线的双重挑战的核心概念与背景\", \"情境导入：汽车焊装线的双重挑战的关键方法与执行要点\", \"情境导入：汽车焊装线的双重挑战的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_intro_1\"], \"layout_archetype\": \"timeline\", \"layout_variant\": \"a\", \"logical_page_id\": \"p03\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_intro_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:02:17.155163\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:01:22', '2026-03-19 06:02:17', 'edu_timeline_steps', '{\"title\": \"情境导入：汽车焊装线的双重挑战\", \"subtitle\": \"传统单一夹具在复杂产线中的局限性分析。\", \"steps\": [{\"title\": \"阶段一：焊接任务的高精度稳定性需求\", \"description\": \"在汽车白车身焊装过程中，机器人需连续进行数千次点焊，要求末端执行器具备极高的刚性以保持焊枪姿态稳定，任何微小抖动都会导致焊缝质量缺陷。\", \"highlights\": [\"微米级路径跟踪\", \"抗振动干扰设计\"]}, {\"title\": \"阶段二：抓取任务的多样化适应性瓶颈\", \"description\": \"同一条产线需处理不同型号的车身部件，传统固定夹具无法快速切换，导致换型时间过长，严重制约了柔性制造的生产效率与响应速度。\", \"highlights\": [\"多规格零件兼容\", \"快速换模机制缺失\"]}, {\"title\": \"阶段三：技术痛点总结与破局方向\", \"description\": \"面对‘稳’与‘变’的双重矛盾，单一功能夹具已无法满足现代工业需求，亟需引入模块化、自适应及智能感知的新型末端执行系统以解决效率与质量的双重瓶颈。\", \"highlights\": [\"突破单一功能局限\", \"构建柔性化解决方案\"]}], \"background_image\": \"https://images.unsplash.com/photo-1565514020176-db79237e6e1c?auto=format&fit=crop&q=80&w=1920\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"timeline\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('41359dd5-762c-4bda-9f51-883b60aef825', '3ba66aac-bac2-4c02-b7f4-d1d534d00b1d', 18, NULL, '{\"page_id\": \"p19\", \"title\": \"关键知识点回顾\", \"layout_id\": \"edu_core_hub\", \"has_image\": true, \"keywords\": [\"悬浮的文字气泡\", \"思维导图碎片\", \"聚光灯效果\", \"深邃星空背景\", \"金色文字强调\"], \"depends_on\": [\"p17\"], \"must_cover\": [\"核心思维总结\", \"技术难点重申\", \"行动号召\", \"关键知识点回顾的核心概念与背景\", \"关键知识点回顾的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"关键知识点回顾的核心概念与背景\", \"关键知识点回顾的关键方法与执行要点\", \"关键知识点回顾的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"core_model\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:04:29', '2026-03-10 05:04:29', 'edu_core_hub', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('41bab88b-85dc-41f0-9463-211215add3d1', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 14, '第二部分：思维重塑与底层逻辑', '{\"title\": \"认知重塑：传统2D设计与3D空间思维的差异\", \"points\": [\"2D平面思维向3D立体思维的转换难点分析\", \"空间坐标轴概念在建模中的核心地位\", \"视口旋转操作误区与正确习惯养成\", \"案例复盘：初学者常见的“平面陷阱”及其破局策略\"], \"layout_id\": \"edu_logic_flow\", \"part\": \"第二部分：思维重塑与底层逻辑\", \"logical_page_id\": \"p15\", \"has_image\": false, \"keywords\": [\"2D平面思维向3D立体思维的转换难点分析\", \"空间坐标轴概念在建模中的核心地位\", \"视口旋转操作误区与正确习惯养成\"], \"depends_on\": [\"p14\"], \"must_cover\": [\"2D平面思维向3D立体思维的转换难点分析\", \"空间坐标轴概念在建模中的核心地位\", \"视口旋转操作误区与正确习惯养成\", \"案例复盘：初学者常见的“平面陷阱”及其破局策略\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"b\", \"layout_archetype\": \"process_flow\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.419089\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_logic_flow', '{\"title\": \"思维重塑：2D平面向3D立体的认知突围\", \"stages\": [{\"title\": \"阶段一：思维转换难点\", \"description\": \"突破二维视图惯性，解决深度感知缺失导致的比例失调与透视错误。\"}, {\"title\": \"阶段二：坐标轴核心构建\", \"description\": \"确立XYZ空间坐标系为操作基石，强化空间定位与轴向操作的肌肉记忆。\"}, {\"title\": \"阶段三：视口习惯养成\", \"description\": \"纠正单一视角依赖，建立多角度的动态旋转观察与全局空间把控能力。\"}, {\"title\": \"阶段四：陷阱破局策略\", \"description\": \"通过“先框后细”建模法规避平面陷阱，利用辅助线系统验证空间逻辑。\"}], \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"process_flow\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('41d96248-c1e0-4f8b-b2d2-4e38b579c2b9', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 13, NULL, '{\"page_id\": \"p14\", \"title\": \"交互测验：识别错误的材质反射\", \"layout_id\": \"quiz_interaction\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p12\"], \"must_cover\": [\"物理材质原理\", \"常见视觉错误识别\", \"环境光影响\", \"交互测验：识别错误的材质反射的核心概念与背景\", \"交互测验：识别错误的材质反射的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"交互测验：识别错误的材质反射的核心概念与背景\", \"交互测验：识别错误的材质反射的关键方法与执行要点\", \"交互测验：识别错误的材质反射的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928661\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'quiz_interaction', '{\"title\": \"交互测验：识别错误的材质反射\", \"subtitle\": \"基于物理渲染原理的视觉错误排查。\", \"bullets\": [{\"icon\": \"fa-exclamation-triangle\", \"text\": \"金属度与粗糙度混淆。\", \"description\": \"高反光表面误设为粗糙，导致金属质感缺失；或非金属表面过度光滑，产生不真实的镜面效果。\"}, {\"icon\": \"fa-sun\", \"text\": \"环境光遮蔽（AO）异常。\", \"description\": \"接触阴影过深或消失，导致物体漂浮感或细节丢失，破坏场景真实感。\"}, {\"icon\": \"fa-eye\", \"text\": \"反射率超出物理范围。\", \"description\": \"非金属材质反射值超过0.04，违反物理规律，导致画面出现“发光”错觉。\"}, {\"icon\": \"fa-link\", \"text\": \"节点连接逻辑断裂。\", \"description\": \"关键输入端口未连接或连接顺序错误，导致材质计算结果全黑或全白。\"}, {\"icon\": \"fa-check-circle\", \"text\": \"正确反射特征识别。\", \"description\": \"掌握真实世界中光线在不同材质表面的衰减规律，快速定位并修正错误。\"}], \"keyTakeaway\": \"精准识别材质反射错误是提升资产质量的关键，需严格遵循物理参数边界与节点逻辑规范。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('420cba1b-4d29-437c-afeb-7bbb9187337b', '7823309a-e50c-44f7-9823-bf26169886ac', 0, '第一部分：入门基础与规范', '{\"part\": \"第一部分：入门基础与规范\", \"pages\": [{\"title\": \"3D建模入门：从原理到实战\", \"points\": [\"课程目标：掌握核心建模流程与规范\", \"行业前景：工业设计与数字制造趋势\", \"学习路径：从零基础到项目实战\"]}, {\"title\": \"实训目录与任务清单\", \"points\": [\"基础认知：软件界面与工具定义\", \"实操步骤：几何构建与布线逻辑\", \"故障排除：常见错误与纠错思维\", \"案例复盘：精密零件全流程演示\", \"成果评估：自评标准与互评维度\"]}, {\"title\": \"安全禁令：数字工坊的红线\", \"points\": [\"数据备份规范：防止工程丢失\", \"版权法律红线：尊重原创与知识产权\", \"设备操作禁忌：硬件维护与安全操作\"]}, {\"title\": \"设备认知：软件界面与工具定义\", \"points\": [\"视图导航：多视角切换技巧\", \"建模工具箱：常用命令解析\", \"属性面板：参数化设置逻辑\", \"快捷键逻辑：提升操作效率\"]}, {\"title\": \"基础认知：重点展开\", \"points\": [\"基础认知的核心概念与边界\", \"基础认知的典型案例与结果\", \"基础认知在本主题中的落地建议\"]}, {\"title\": \"实操步骤：重点展开\", \"points\": [\"实操步骤的核心概念与边界\", \"实操步骤的典型案例与结果\", \"实操步骤在本主题中的落地建议\"]}, {\"title\": \"视图导航：重点展开\", \"points\": [\"视图导航的核心概念与边界\", \"视图导航的典型案例与结果\", \"视图导航在本主题中的落地建议\"]}, {\"title\": \"建模工具箱：重点展开\", \"points\": [\"建模工具箱的核心概念与边界\", \"建模工具箱的典型案例与结果\", \"建模工具箱在本主题中的落地建议\"]}], \"logical_page_id\": \"p01\", \"has_image\": false, \"keywords\": [], \"depends_on\": [], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_id\": \"title_content\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:23:43.630159\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:23:03', '2026-03-08 06:23:44', 'title_content', '{\"title\": \"实训准备与基础点检\", \"content\": [\"确认作业区域环境安全，清除周边障碍物并设置警示隔离带。\", \"全面检查铝合金型材表面无划伤、无变形，确保材料符合施工标准。\", \"核对工具清单，确保电动工具电量充足且防护装置完好无损。\"], \"highlight\": \"未通过点检严禁进入下一工序。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
