INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('42c01503-d6a9-4b0a-8394-a3be28c7aefa', '7a4f3408-ca73-4a61-998e-174a92497610', 13, NULL, '{\"page_id\": \"p14\", \"title\": \"情境模拟：复杂曲面角色绑定前奏\", \"layout_id\": \"role_play_scenario\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p12\"], \"must_cover\": [\"角色岗位设定\", \"拓扑检查清单\", \"权重绘制难点预判\", \"情境模拟：复杂曲面角色绑定前奏的核心概念与背景\", \"情境模拟：复杂曲面角色绑定前奏的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"情境模拟：复杂曲面角色绑定前奏的核心概念与背景\", \"情境模拟：复杂曲面角色绑定前奏的关键方法与执行要点\", \"情境模拟：复杂曲面角色绑定前奏的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.267200\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:01', 'role_play_scenario', '{\"title\": \"情境模拟：复杂曲面角色绑定前奏\", \"content\": [\"作为初级绑定师，你接手了一个拥有复杂有机曲面的科幻角色模型，该模型刚完成高精度拓扑检查，但关节活动区域存在潜在的拉伸风险。你需要立即制定权重绘制策略，预判可能出现的形变瑕疵。\", \"面对手臂弯曲时三角面撕裂、胸部肌肉挤压变形等典型问题，请结合之前的UV岛布局经验，规划合理的骨骼权重分配方案，确保动画流畅性与模型完整性。\"], \"highlight\": \"预警：未优化的拓扑结构将导致权重绘制效率降低60%，且极易引发不可逆的模型形变。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('42d9cccd-16a6-40d1-b81b-804d3049f3fa', '6eea18f8-c641-48a1-ba84-4c49ed3830d6', 8, NULL, '{\"page_id\": \"p09\", \"title\": \"数据看板：性能与成本的双重突破\", \"layout_id\": \"edu_data_board\", \"has_image\": true, \"keywords\": [\"数据仪表盘\", \"上升曲线图表\", \"绿色增长柱状图\", \"深色背景面板\", \"发光数字显示\"], \"depends_on\": [\"p08\"], \"must_cover\": [\"吞吐量提升数据\", \"能耗降低比例\", \"延迟优化指标\", \"数据看板：性能与成本的双重突破的核心概念与背景\", \"数据看板：性能与成本的双重突破的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p06_1\"], \"points\": [\"数据看板：性能与成本的双重突破的核心概念与背景\", \"数据看板：性能与成本的双重突破的关键方法与执行要点\", \"数据看板：性能与成本的双重突破的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p06_1\"], \"layout_archetype\": \"data_dashboard\", \"layout_variant\": \"a\", \"logical_page_id\": \"p09\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p06_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:27:09.079628\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:25:45', '2026-03-10 06:27:09', 'edu_data_board', '{\"title\": \"数据看板：性能与成本的双重突破\", \"subtitle\": \"实测环境下的极限表现。\", \"metrics\": [{\"value\": \"+45%\", \"label\": \"吞吐量提升数据\", \"note\": \"峰值并发处理能力增强。\"}, {\"value\": \"-30%\", \"label\": \"能耗降低比例\", \"note\": \"单位算力碳排放显著下降。\"}, {\"value\": \"-25ms\", \"label\": \"延迟优化指标\", \"note\": \"端到端响应速度大幅缩短。\"}], \"bars\": [{\"label\": \"综合效能指数\", \"baseline\": 60, \"current\": 95}], \"bullets\": [{\"text\": \"吞吐量与能耗双优。\", \"description\": \"在提升处理能力的同时，有效抑制了能源消耗增长曲线。\"}, {\"text\": \"延迟控制极致化。\", \"description\": \"通过调度策略微调，将关键业务延迟压缩至行业领先水平。\"}], \"insight\": \"数据证明技术行动成功打破了算力孤岛，实现了效率与绿色的双赢。\", \"background_image\": \"https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=1920&auto=format&fit=crop\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_dashboard\"}');
