INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('4674d5e0-6ced-4383-91d2-23915a8e007d', 'ab2ec2c8-cb17-41e9-beb4-40c851abbea2', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"公式推导与单位定义\", \"layout_id\": \"edu_logic_flow\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p05\"], \"must_cover\": [\"F=kma 到 F=ma 的简化\", \"牛顿单位的定义\", \"矢量性强调\", \"公式推导与单位定义的核心概念与背景\", \"公式推导与单位定义的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p06_1\", \"text\": \"解题规范与常见陷阱解析\", \"must_cover\": [\"正方向设定\", \"合力计算误区\"], \"target_page_ids\": [\"p20\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"公式推导与单位定义的核心概念与背景\", \"公式推导与单位定义的关键方法与执行要点\", \"公式推导与单位定义的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"process_flow\", \"layout_variant\": \"a\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:06:57.190651\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 01:41:59', '2026-03-17 02:07:23', 'edu_logic_flow', '{\"title\": \"公式推导与单位定义\", \"stages\": [{\"title\": \"从一般式到标准式\", \"description\": \"基于实验确定的比例关系引入系数 k，通过单位制定义使 k=1，得出 F=ma。\"}, {\"title\": \"牛顿单位的物理定义\", \"description\": \"规定使 1kg 物体产生 1m/s²加速度的力为 1N，实现量纲自洽与数值统一。\"}, {\"title\": \"矢量性的严格强调\", \"description\": \"明确公式中力与加速度均为矢量，方向始终一致，计算需遵循矢量合成法则。\"}], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"process_flow\"}');
