INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('4c5d9f8a-b7ee-4d52-a52e-1227a583700c', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 7, NULL, '{\"title\": \"第一章：基础概念框架：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"logical_page_id\": \"p08\", \"has_image\": false, \"keywords\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"depends_on\": [\"p07\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [{\"promise_id\": \"pr_p08_1_89539810\", \"text\": \"问题与场景：案例要解决的核心矛盾\", \"must_cover\": [], \"target_page_ids\": [\"p13\"], \"is_hard\": true}, {\"promise_id\": \"pr_p08_2_bf6003be\", \"text\": \"方案与执行：关键动作与决策依据\", \"must_cover\": [], \"target_page_ids\": [\"p13\"], \"is_hard\": true}, {\"promise_id\": \"pr_p08_3_187de709\", \"text\": \"结果与启示：可复用经验与风险提示\", \"must_cover\": [], \"target_page_ids\": [\"p13\"], \"is_hard\": true}], \"promises_close\": [\"pr_p04_1_47b1d58c\"], \"required_close_promise_ids\": [\"pr_p04_1_47b1d58c\"], \"layout_id\": \"title_content\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p04_1_47b1d58c\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T13:04:03.227713\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'title_content', '{\"title\": \"第一章：基础概念框架：案例复盘\", \"content\": [\"初期混淆商业与军工标准导致交付失效，通过统一教学目标与案例规范，实现理论认知到实操能力的闭环转化。\", \"确认标准化流程是核心驱动力，注意防止脱离工程场景，复用经验需结合具体项目风险灵活调整。\"], \"highlight\": \"实现从理论认知到实操能力的精准闭环。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
