INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('4cfc93a3-45a1-4875-a814-565f3574bcb2', '14c0f24c-10e7-4309-a927-d9db1066897c', 16, NULL, '{\"page_id\": \"p17\", \"title\": \"实时引擎中的模型优化策略\", \"layout_id\": \"case_before_after\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p15\"], \"must_cover\": [\"LOD层级设置\", \"UV展开规范\", \"面数限制\", \"实时引擎中的模型优化策略的核心概念与背景\", \"实时引擎中的模型优化策略的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p05_1\"], \"points\": [\"实时引擎中的模型优化策略的核心概念与背景\", \"实时引擎中的模型优化策略的关键方法与执行要点\", \"实时引擎中的模型优化策略的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p05_1\"], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p17\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p05_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.774193\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'case_before_after', '{\"title\": \"实时引擎中的模型优化策略\", \"left\": {\"header\": \"拓扑优化与布线技巧\", \"content\": [\"针对复杂模型进行拓扑重构，消除冗余面片，确保变形区域的流畅性与逻辑性。\"], \"bullets\": [{\"icon\": \"fa-sitemap\", \"text\": \"采用四边面主导的布线结构，为动画蒙皮提供稳定的几何支撑基础。\", \"description\": \"解释采用四边面主导的布线结构，为动画蒙皮提供稳定的几何支撑基础。在拓扑优化与布线技巧维度下的意义。\"}, {\"icon\": \"fa-cut\", \"text\": \"利用对称编辑与重拓扑工具，在保持细节特征的同时大幅降低面数密度。\", \"description\": \"解释利用对称编辑与重拓扑工具，在保持细节特征的同时大幅降低面数密度。在拓扑优化与布线技巧维度下的意义。\"}]}, \"right\": {\"header\": \"性能限制与UV规范\", \"content\": [\"严格执行LOD层级设置与UV展开规范，最大化利用显存并减少绘制调用次数。\", \"结论：实时引擎中的模型优化策略需要结合目标场景做取舍。\"], \"bullets\": [{\"icon\": \"fa-layer-group\", \"text\": \"构建多级LOD系统，根据摄像机距离动态切换模型精度以维持帧率稳定。\", \"description\": \"解释构建多级LOD系统，根据摄像机距离动态切换模型精度以维持帧率稳定。在性能限制与UV规范维度下的意义。\"}, {\"icon\": \"fa-expand-arrows-alt\", \"text\": \"遵循无重叠、无拉伸原则进行UV展开，提升纹理利用率并优化采样效果。\", \"description\": \"解释遵循无重叠、无拉伸原则进行UV展开，提升纹理利用率并优化采样效果。在性能限制与UV规范维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
