INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('4ef3012e-2694-4d32-8545-7965e5aec6e1', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"直观演示：气泡如何“冒泡”\", \"layout_id\": \"infographic_flow\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p04\"], \"must_cover\": [\"遍历过程\", \"最大值上浮机制\", \"直观演示：气泡如何“冒泡”的核心概念与背景\", \"直观演示：气泡如何“冒泡”的关键方法与执行要点\", \"直观演示：气泡如何“冒泡”的应用场景与注意事项\"], \"promises_open\": [{\"promise_id\": \"pr_p05_1\", \"text\": \"稍后将通过代码实现展示具体逻辑\", \"must_cover\": [\"伪代码\", \"循环结构\"], \"target_page_ids\": [\"p20\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"直观演示：气泡如何“冒泡”的核心概念与背景\", \"直观演示：气泡如何“冒泡”的关键方法与执行要点\", \"直观演示：气泡如何“冒泡”的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p05\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.831986\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'infographic_flow', '{\"title\": \"直观演示：气泡如何“冒泡”\", \"subtitle\": \"遍历机制与最大值上浮原理。\", \"bullets\": [{\"icon\": \"fa-arrows-alt-h\", \"text\": \"相邻元素两两比较。\", \"description\": \"从序列头部开始，依次比较相邻两个数据的大小，若顺序错误则立即交换位置。\"}, {\"icon\": \"fa-arrow-up\", \"text\": \"大值逐次上浮。\", \"description\": \"经过一轮完整遍历后，当前未排序部分中的最大值必然移动至该轮次的末尾位置。\"}, {\"icon\": \"fa-repeat\", \"text\": \"多轮迭代收敛。\", \"description\": \"重复上述过程，每轮减少一个待排序元素，直至所有数据完成有序排列。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"稳定性保障。\", \"description\": \"仅在严格大于时交换，确保相等元素的相对顺序保持不变。\"}, {\"icon\": \"fa-chart-line\", \"text\": \"渐进式有序化。\", \"description\": \"数据从无序到有序是一个平滑过渡的物理过程，而非突变。\"}], \"keyTakeaway\": \"冒泡排序通过反复的相邻交换，利用“大数下沉、小数上浮”的物理直觉，将无序集合逐步转化为有序序列。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('4f102670-a7fa-405b-8f4b-504c004d18f7', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 15, '收尾', '{\"page_id\": \"p13\", \"title\": \"答疑互动与下一步行动\", \"part\": \"收尾\", \"points\": [\"现场开放提问，针对性解决建模拓扑与渲染报错等具体困惑\", \"发布课后进阶任务清单，涵盖低模硬表面与角色雕刻实战练习\", \"引导加入专属学习社群，获取最新插件资源与行业接单渠道\", \"推荐后续高阶课程路径，规划从入门到职业级建模师的成长路线\"]}', '{\"text\": \"答疑互动与下一步行动\\n\\n页面文字：\\n- 现场开放提问环节，针对性解决建模拓扑错误与渲染报错等具体困惑与技术难题。\\n- 发布课后进阶任务清单，涵盖低模硬表面设计与角色雕刻实战练习以巩固所学。\\n- 引导加入专属学习社群获取最新插件资源与行业接单渠道，拓展职业发展机会。\\n- 推荐后续高阶课程路径，科学规划从入门新手到职业级建模师的完整成长路线。\", \"generated_at\": \"2026-03-09T03:39:42.429944\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/4f102670-a7fa-405b-8f4b-504c004d18f7_v1.png', 'COMPLETED', '2026-03-09 03:39:30', '2026-03-09 03:49:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('4f61e4f8-90c6-4c0e-8214-d515fa7b0a79', '4e889981-954e-4263-b490-230183b1a644', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"三维教学目标：知识·技能·素质\", \"layout_id\": \"vocational_objectives\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p01\", \"p02\"], \"must_cover\": [\"知识目标：理解F=ma公式及变量关系\", \"技能目标：能计算负载并调整PID参数\", \"素质目标：树立严谨的调试安全意识\", \"三维教学目标：知识·技能·素质的核心概念与背景\", \"三维教学目标：知识·技能·素质的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p01_2\"], \"points\": [\"三维教学目标：知识·技能·素质的核心概念与背景\", \"三维教学目标：知识·技能·素质的关键方法与执行要点\", \"三维教学目标：知识·技能·素质的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_2\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:45:02.424547\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:44:25', '2026-03-19 01:37:30', 'vocational_objectives', '{\"title\": \"三维教学目标：知识·技能·素质\", \"knowledgeGoals\": [{\"title\": \"深刻理解 F=ma 公式中力、质量与加速度的变量关系，掌握物理量之间的线性比例特性。\"}, {\"title\": \"掌握牛顿第二定律在机电负载动态分析中的核心概念，能够识别不同工况下的受力模型。\"}], \"skillGoals\": [{\"title\": \"能精准计算设备运行负载并推导理论加速度值，独立完成从物理模型到工程参数的转换。\"}, {\"title\": \"具备基于 F=ma 参数调整伺服 PID 及加减速时间能力，通过数据量化解决启停抖动问题。\"}], \"attitudeGoals\": [{\"title\": \"树立机电调试中严守操作红线的严谨安全意识，养成按章操作、杜绝违章作业的职业习惯。\"}, {\"title\": \"培养精益求精、数据驱动的工匠精神与质量验收标准，以实测数据作为调试合格的唯一依据。\"}], \"keyPoints\": \"重难点说明：从物理公式到工程参数的转化逻辑；调试过程中的安全红线与规范动作。\", \"layout_variant\": \"a\", \"variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('4f924c00-d1bb-41bd-ad0b-9053eb25979e', '2f844b20-de75-4ac5-98d1-2f44296e9e2b', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"避坑指南：三大高频易错点\", \"layout_id\": \"edu_logic_flow\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p10\"], \"must_cover\": [\"重力与压力混淆\", \"合力方向判断\", \"单位未统一\", \"避坑指南：三大高频易错点的核心概念与背景\", \"避坑指南：三大高频易错点的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p10_1\"], \"points\": [\"避坑指南：三大高频易错点的核心概念与背景\", \"避坑指南：三大高频易错点的关键方法与执行要点\", \"避坑指南：三大高频易错点的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p10_1\"], \"layout_archetype\": \"process_flow\", \"layout_variant\": \"b\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p10_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:09:35.126076\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 02:08:45', '2026-03-17 02:09:35', 'edu_logic_flow', '{\"title\": \"避坑指南：三大高频易错点\", \"stages\": [{\"title\": \"误区一：重力与压力混淆\", \"description\": \"在水平面上，物体对地面的压力大小等于重力，但二者性质不同；受力分析时严禁将重力直接代入水平方向方程。\"}, {\"title\": \"误区二：合力方向误判\", \"description\": \"加速度方向始终与合外力方向一致，需先进行正交分解求合力，切勿仅凭拉力方向判断加速度方向。\"}, {\"title\": \"误区三：单位未统一\", \"description\": \"计算前必须将所有物理量转换为国际单位制（SI），如质量用 kg、力用 N，避免因单位混乱导致数量级错误。\"}], \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"process_flow\"}');
