INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5174e2e4-a861-47e6-9a66-ae024435f581', 'c3f4f20a-0839-4fb0-9375-125c6af13f37', 0, NULL, '{\"page_id\": \"p01\", \"title\": \"工业机器人末端执行器（夹持器）分类与应用\", \"layout_id\": \"sk_cover\", \"has_image\": true, \"keywords\": [\"工业机器臂\", \"机械手夹具\", \"自动化生产线\", \"科技感背景\", \"工程绿配色\"], \"depends_on\": [], \"must_cover\": [], \"promises_open\": [{\"promise_id\": \"pr_p01_1\", \"text\": \"汽车产线焊接与抓取的真实情境分析\", \"must_cover\": [\"情境痛点\", \"任务需求\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}, {\"promise_id\": \"pr_p01_2\", \"text\": \"吸附式与夹持式执行器的深度结构对比\", \"must_cover\": [\"真空原理\", \"机械结构\", \"适用场景\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}, {\"promise_id\": \"pr_p01_3\", \"text\": \"末端工具更换的标准化安全操作流程\", \"must_cover\": [\"断电锁定\", \"气路检查\", \"紧固确认\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"cover\", \"layout_variant\": \"a\", \"logical_page_id\": \"p01\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:04:18.360609\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:03:26', '2026-03-19 06:04:18', 'sk_cover', '{\"title\": \"工业机器人末端执行器（夹持器）分类与应用\", \"subtitle\": \"面向自动化产线的精密抓取与作业方案。\", \"meta\": \"高职实训课程 | 工业机器人应用专业\", \"details\": [\"掌握机械手夹具的分类标准与选型逻辑\", \"理解不同工况下末端执行器的功能需求\", \"分析汽车、电子等行业典型应用场景\"], \"teacher\": \"智能制造教研室\", \"background_image\": \"https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?auto=format&fit=crop&w=1200&q=80\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"cover\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('51f8e2e4-ec01-4df6-a664-90e3277ac04c', '130ea17c-c678-4285-8c4c-06b099d8fa71', 6, NULL, '{\"page_id\": \"p07\", \"title\": \"实验探究：控制变量法的应用\", \"layout_id\": \"edu_data_board\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p05\"], \"must_cover\": [\"保持质量不变看力与a的关系\", \"保持力不变看质量与a的关系\", \"实验探究：控制变量法的应用的核心概念与背景\", \"实验探究：控制变量法的应用的关键方法与执行要点\", \"实验探究：控制变量法的应用的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [\"pr_p05_1\"], \"points\": [\"实验探究：控制变量法的应用的核心概念与背景\", \"实验探究：控制变量法的应用的关键方法与执行要点\", \"实验探究：控制变量法的应用的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p05_1\"], \"layout_archetype\": \"data_dashboard\", \"layout_variant\": \"b\", \"logical_page_id\": \"p07\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p05_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:15:52.390783\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 02:14:47', '2026-03-17 02:18:22', 'edu_data_board', '{\"title\": \"实验探究：控制变量法的应用\", \"subtitle\": \"基线：定性观察 | 当前：定量验证。\", \"metrics\": [{\"value\": \"+100%\", \"label\": \"精度提升\", \"note\": \"从模糊趋势到精确数值。\"}, {\"value\": \"2:1\", \"label\": \"变量控制比\", \"note\": \"双路径独立验证。\"}], \"bars\": [{\"label\": \"力与加速度关系 (m 恒定)\", \"baseline\": 50, \"current\": 92}, {\"label\": \"质量与加速度关系 (F 恒定)\", \"baseline\": 45, \"current\": 88}], \"bullets\": [{\"text\": \"保持质量不变，探究力与a的关系。\", \"description\": \"通过改变拉力大小，观测加速度线性增长，确立正比关系。\"}, {\"text\": \"保持力不变，探究质量与a的关系。\", \"description\": \"通过增减负载质量，观测加速度随质量增加而减小，确立反比关系。\"}, {\"text\": \"核心执行要点。\", \"description\": \"严格控制单一变量，消除摩擦力干扰，确保数据采集的纯净度。\"}], \"insight\": \"控制变量法成功将复杂的三角关系拆解为两个独立的线性过程，为公式推导奠定实证基础。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"data_dashboard\"}');
