INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5363f44b-3a3b-40ff-9e55-ebbdd908eb09', 'e7189705-04c2-4928-8d6c-da2bacf02e42', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"典型例题：斜面滑块模型\", \"layout_id\": \"vocational_step_by_step\", \"has_image\": true, \"keywords\": [\"斜面受力分析图\", \"重力分解矢量\", \"摩擦力标注\", \"解题步骤流程图\", \"黑板板书风格\"], \"depends_on\": [\"p09\"], \"must_cover\": [\"受力分析画全\", \"建立坐标系\", \"列出牛顿第二定律方程\", \"典型例题：斜面滑块模型的核心概念与背景\", \"典型例题：斜面滑块模型的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p09_1\"], \"points\": [\"典型例题：斜面滑块模型的核心概念与背景\", \"典型例题：斜面滑块模型的关键方法与执行要点\", \"典型例题：斜面滑块模型的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p09_1\"], \"layout_archetype\": \"process_steps\", \"layout_variant\": \"b\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p09_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T01:36:50.689340\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 01:36:10', '2026-03-19 01:36:51', 'vocational_step_by_step', '{\"title\": \"典型例题：斜面滑块模型\", \"steps\": [{\"title\": \"步骤一：全面受力分析\", \"label\": \"STEP 01\", \"desc\": \"以滑块为研究对象，画出重力G、支持力N及摩擦力f（若有），确保不漏力、不多画力。\"}, {\"title\": \"步骤二：建立正交坐标系\", \"label\": \"STEP 02\", \"desc\": \"以加速度方向（沿斜面向下）为x轴，垂直斜面为y轴，将重力G正交分解为Gx=mgsinθ和Gy=mgcosθ。\"}, {\"title\": \"步骤三：列方程求解\", \"label\": \"STEP 03\", \"desc\": \"根据牛顿第二定律列式：x轴方向 mgsinθ-f=ma，y轴方向 N-mgcosθ=0，联立解出加速度a或摩擦力f。\"}], \"layout_variant\": \"b\", \"variant\": \"b\", \"layout_archetype\": \"process_steps\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5474aa6c-3d42-49b9-829b-0a846ee55a68', 'ab2ec2c8-cb17-41e9-beb4-40c851abbea2', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"数据看板：实验结论可视化\", \"layout_id\": \"edu_data_board\", \"has_image\": true, \"keywords\": [\"折线图与散点图\", \"数据面板\", \"青色高亮趋势线\", \"深色底纹\", \"无数字水印\"], \"depends_on\": [\"p04\"], \"must_cover\": [\"加速度与力成正比\", \"加速度与质量成反比\", \"比例系数 k=1\", \"数据看板：实验结论可视化的核心概念与背景\", \"数据看板：实验结论可视化的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p04_1\"], \"points\": [\"数据看板：实验结论可视化的核心概念与背景\", \"数据看板：实验结论可视化的关键方法与执行要点\", \"数据看板：实验结论可视化的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p04_1\"], \"layout_archetype\": \"data_dashboard\", \"layout_variant\": \"b\", \"logical_page_id\": \"p05\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p04_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:06:57.190615\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 01:41:59', '2026-03-17 02:07:23', 'edu_data_board', '{\"title\": \"数据看板：实验结论可视化\", \"subtitle\": \"控制变量法量化分析。\", \"metrics\": [{\"value\": \"线性正比\", \"label\": \"a-F 关系\", \"note\": \"斜率恒定验证比例性。\"}, {\"value\": \"反比曲线\", \"label\": \"a-m 关系\", \"note\": \"双曲线特征确认反比。\"}], \"bars\": [{\"label\": \"恒力下 a 随 m 变化\", \"baseline\": 60, \"current\": 20}, {\"label\": \"恒质下 a 随 F 变化\", \"baseline\": 40, \"current\": 95}], \"bullets\": [{\"text\": \"加速度与力成正比。\", \"description\": \"在质量不变条件下，合力增大几倍，加速度同步增大相同倍数。\"}, {\"text\": \"加速度与质量成反比。\", \"description\": \"在合力不变条件下，质量增大几倍，加速度减小为原来的几分之一。\"}, {\"text\": \"比例系数 k=1。\", \"description\": \"通过国际单位制定义，使得比例系数自然归一化，简化公式表达。\"}], \"insight\": \"实验数据完美契合理论预测，确立 F、m、a 三者严格的定量逻辑链条。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"data_dashboard\"}');
