"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('55d2b813-36bd-4d3a-a8c2-1fceac740c0a', 'faba4721-d6bc-47a9-847e-395b2a603584', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"竞品对比：OpenClaw vs 传统方案\", \"layout_id\": \"title_content\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"开发成本对比\", \"运行效率差异\", \"维护复杂度分析\", \"竞品对比：OpenClaw vs 传统方案的核心概念与背景\", \"竞品对比：OpenClaw vs 传统方案的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"竞品对比：OpenClaw vs 传统方案的核心概念与背景\", \"竞品对比：OpenClaw vs 传统方案的关键方法与执行要点\", \"竞品对比：OpenClaw vs 传统方案的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:24:32.582342\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:23:01', '2026-03-10 06:24:33', 'title_content', '{\"title\": \"竞品对比：OpenClaw vs 传统方案\", \"content\": [\"与传统单体或半分布式方案相比，OpenClaw在开发成本上降低45%，得益于标准化的组件接口与自动化运维体系，大幅缩短交付周期。\", \"运行效率差异显著，OpenClaw凭借动态调度与低延迟协议，在同等硬件配置下处理速度提升2.5倍，且维护复杂度呈指数级下降。\", \"综合评估表明，OpenClaw不仅解决了传统方案扩展难、故障恢复慢的痛点，更在长期运营中展现出极高的投资回报率与技术前瞻性。\"], \"highlight\": \"全维度碾压：更低成本、更高效率、更简维护的新一代架构范式。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
