INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('56021844-4fbf-4d04-aa1e-65fbd3483048', '3ba66aac-bac2-4c02-b7f4-d1d534d00b1d', 12, NULL, '{\"page_id\": \"p13\", \"title\": \"材质与光照：赋予模型生命\", \"layout_id\": \"edu_data_board\", \"has_image\": true, \"keywords\": [\"PBR材质球展示\", \"HDRI环境光\", \"反射率数值面板\", \"色彩直方图\", \"金属质感特写\"], \"depends_on\": [\"p11\"], \"must_cover\": [\"PBR工作流\", \"粗糙度与金属度\", \"全局光照设置\", \"材质与光照：赋予模型生命的核心概念与背景\", \"材质与光照：赋予模型生命的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"材质与光照：赋予模型生命的核心概念与背景\", \"材质与光照：赋予模型生命的关键方法与执行要点\", \"材质与光照：赋予模型生命的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_dashboard\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:04:29', '2026-03-10 05:04:29', 'edu_data_board', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('561d8dab-4e58-4a97-b899-d50c9cc23ac1', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 6, NULL, '{\"page_id\": \"p07\", \"title\": \"案例研讨：角色关节处的布线策略\", \"layout_id\": \"case_discussion\", \"has_image\": true, \"keywords\": [\"角色手臂关节解剖图\", \"环形布线示意图\", \"小组讨论引导卡片\", \"工业实操感\", \"橙色重点标记\"], \"depends_on\": [\"p05\"], \"must_cover\": [\"肘部/膝盖环形结构\", \"肌肉走向模拟\", \"折叠与拉伸测试\", \"案例研讨：角色关节处的布线策略的核心概念与背景\", \"案例研讨：角色关节处的布线策略的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_case_01\", \"text\": \"稍后展示该案例的最终动画测试效果\", \"must_cover\": [\"动画测试结果\", \"常见问题复盘\"], \"target_page_ids\": [\"p19\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"案例研讨：角色关节处的布线策略的核心概念与背景\", \"案例研讨：角色关节处的布线策略的关键方法与执行要点\", \"案例研讨：角色关节处的布线策略的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p07\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928384\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'case_discussion', '{\"title\": \"案例研讨：角色关节处的布线策略\", \"content\": [\"在工业级角色动画中，肘部与膝盖的变形是检验拓扑质量的关键试金石。若布线未遵循肌肉走向形成环形结构，模型在弯曲时极易出现非预期的褶皱或拉伸撕裂。\", \"本案例聚焦于构建完美的“支撑环”系统，通过模拟真实解剖结构，确保网格在极限折叠与拉伸测试中保持平滑过渡，避免三角面导致的硬边缺陷。\"], \"highlight\": \"环形布线是关节变形的生命线，必须严格匹配肌肉收缩方向。\", \"image\": {\"src\": \"\", \"alt\": \"角色手臂关节解剖图与环形布线示意图，橙色重点标记关键支撑环位置，展示折叠与拉伸测试效果\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5660f5b8-fe95-4cb1-8580-574f5b3b1c43', '6eea18f8-c641-48a1-ba84-4c49ed3830d6', 13, NULL, '{\"page_id\": \"p14\", \"title\": \"开发者指南：快速上手的三个步骤\", \"layout_id\": \"edu_timeline_steps\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p13\"], \"must_cover\": [\"环境配置\", \"核心 API 调用\", \"调试工具使用\", \"开发者指南：快速上手的三个步骤的核心概念与背景\", \"开发者指南：快速上手的三个步骤的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"开发者指南：快速上手的三个步骤的核心概念与背景\", \"开发者指南：快速上手的三个步骤的关键方法与执行要点\", \"开发者指南：快速上手的三个步骤的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"timeline\", \"layout_variant\": \"b\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:27:09.079757\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:25:46', '2026-03-10 06:27:09', 'edu_timeline_steps', '{\"title\": \"开发者指南：快速上手的三个步骤\", \"subtitle\": \"从环境配置到生产部署的极简路径。\", \"steps\": [{\"title\": \"第一步：环境极速配置\", \"description\": \"基于容器化技术实现零依赖初始化，一键拉取最新镜像并自动适配异构硬件。\", \"highlights\": [\"Docker Compose 一键部署\", \"智能识别本地算力资源\"]}, {\"title\": \"第二步：核心 API 调用\", \"description\": \"通过标准化 SDK 封装复杂逻辑，支持多语言接入，5 分钟内完成首个推理任务调用。\", \"highlights\": [\"Python/Go 原生 SDK 支持\", \"流式响应与异步处理机制\"]}, {\"title\": \"第三步：调试工具实战\", \"description\": \"集成可视化监控面板与日志追踪系统，实时定位性能瓶颈，支持断点调试与热更新。\", \"highlights\": [\"全链路 Trace 追踪\", \"动态参数热调整\"]}], \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"timeline\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('568e336d-71ae-4a33-b115-3dd652696afb', '8a37f529-e51f-428c-8466-cdc137b73187', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"实战任务：复杂模型UV布局规划\", \"layout_id\": \"academic_practice\", \"has_image\": true, \"keywords\": [\"软件界面截图\", \"UV编辑器视图\", \"网格切割线示意\", \"无文字标注\"], \"depends_on\": [\"p08\"], \"must_cover\": [\"操作步骤：自动展开与手动调整\", \"评价标准：像素密度均匀性\", \"常见错误规避\", \"实战任务：复杂模型UV布局规划的核心概念与背景\", \"实战任务：复杂模型UV布局规划的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"实战任务：复杂模型UV布局规划的核心概念与背景\", \"实战任务：复杂模型UV布局规划的关键方法与执行要点\", \"实战任务：复杂模型UV布局规划的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.107672\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'academic_practice', '{\"title\": \"随堂实训：复杂模型UV布局规划\", \"task_type\": \"task\", \"description\": \"针对高面数硬表面或有机混合模型，完成从自动展开到手动优化的全流程布局，确保像素密度均匀且空间利用率达标。\", \"requirements\": [\"切缝路径需遵循测地线最短原则，避免关键特征区域拉伸超过5%\", \"UV岛排列需紧凑，整体空间利用率不低于85%，无重叠且边界对齐网格\", \"保留主要纹理方向一致性，便于后续PBR材质绘制\"], \"options\": [], \"hint\": \"核心难点在于平衡拉伸与空间占用；硬表面侧重边缘锐利度，有机体侧重形变自然性，需动态调整策略。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('56adcc1c-f032-4537-ac05-d6d07681454a', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 10, '实战演练', '{\"page_id\": \"p09\", \"title\": \"综合案例：现代家居场景搭建\", \"part\": \"实战演练\", \"points\": [\"利用参数化组件库实现沙发、灯具等家具的快速模块化组装与复用\", \"基于人体工学设定空间尺度，运用三分法与引导线优化视觉构图\", \"从基础白模布线到材质赋予、灯光布置及最终渲染输出的全流程复盘\", \"针对室内环境的光影反射特性进行细节调试，提升场景真实感\"]}', '{\"text\": \"页面标题：综合案例：现代家居场景搭建\\n\\n页面文字：\\n- 面对复杂家具组装难题，利用参数化组件库实现沙发灯具的快速模块化复用与搭建。\\n- 基于人体工学设定空间尺度，运用三分法构图引导视线，优化整体视觉平衡关系。\\n- 从白模布线到材质赋予及灯光调试的全流程复盘，成功解决室内光影反射细节问题。\\n- 最终通过精细调试大幅提升场景真实感，为后续硬表面建模实战打下坚实基础。\", \"generated_at\": \"2026-03-09T03:39:38.191762\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/56adcc1c-f032-4537-ac05-d6d07681454a_v1.png', 'COMPLETED', '2026-03-09 03:39:22', '2026-03-09 03:47:53', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('57800964-1b16-4c9e-9d40-e686791d0386', 'c3f4f20a-0839-4fb0-9375-125c6af13f37', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"执行器分类二：吸附式（真空吸盘）\", \"layout_id\": \"sk_sop\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p05\"], \"must_cover\": [\"负压产生原理\", \"软性接触保护优势\", \"平面/曲面适应性\", \"执行器分类二：吸附式（真空吸盘）的核心概念与背景\", \"执行器分类二：吸附式（真空吸盘）的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p01_2\"], \"points\": [\"执行器分类二：吸附式（真空吸盘）的核心概念与背景\", \"执行器分类二：吸附式（真空吸盘）的关键方法与执行要点\", \"执行器分类二：吸附式（真空吸盘）的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_2\"], \"layout_archetype\": \"process_steps\", \"layout_variant\": \"b\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p01_2\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:04:18.360847\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:03:27', '2026-03-19 06:04:18', 'sk_sop', '{\"title\": \"执行器分类二：吸附式（真空吸盘）\", \"steps\": [{\"number\": 1, \"label\": \"步骤1\", \"description\": \"利用文丘里效应或真空泵在吸盘内部形成负压区，利用大气压差吸附工件。\", \"icon\": \"fa-check\"}, {\"number\": 2, \"label\": \"步骤2\", \"description\": \"采用聚氨酯或橡胶材质吸盘，通过形变贴合工件表面，实现无损伤抓取。\", \"icon\": \"fa-check\"}, {\"number\": 3, \"label\": \"步骤3\", \"description\": \"单吸盘适应平面，多吸盘阵列可自动补偿曲面角度，适应复杂几何形状。\", \"icon\": \"fa-check\"}, {\"number\": 4, \"label\": \"步骤4\", \"description\": \"集成真空传感器实时监测负压数值，一旦泄漏立即报警并停止动作。\", \"icon\": \"fa-check\"}, {\"number\": 5, \"label\": \"步骤5\", \"description\": \"多个吸盘并联组成阵列，分散受力点，提升大尺寸薄板工件的稳定性。\", \"icon\": \"fa-check\"}, {\"number\": 6, \"label\": \"步骤6\", \"description\": \"广泛用于电子屏幕、汽车挡风玻璃、包装纸箱等轻质或易损物品的搬运。\", \"icon\": \"fa-check\"}], \"summary\": \"吸附式执行器利用真空原理实现非接触式或软接触抓取，完美解决易损件与曲面工件的自动化难题。其核心优势在于对工件表面的无损保护与对不规则形状的强适应性。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"process_steps\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('580c9105-55a4-4263-92bf-db99f3ddece1', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"双重循环的逻辑拆解\", \"layout_id\": \"site_survey\", \"has_image\": true, \"keywords\": [\"左侧代码高亮\", \"右侧流程图对应\", \"对比色块\", \"技术文档风格\", \"清晰排版\"], \"depends_on\": [\"p07\"], \"must_cover\": [\"外层控制轮次\", \"内层控制比较\", \"双重循环的逻辑拆解的核心概念与背景\", \"双重循环的逻辑拆解的关键方法与执行要点\", \"双重循环的逻辑拆解的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [\"pr_p05_1\", \"pr_p07_1\"], \"points\": [\"双重循环的逻辑拆解的核心概念与背景\", \"双重循环的逻辑拆解的关键方法与执行要点\", \"双重循环的逻辑拆解的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p05_1\", \"pr_p07_1\"], \"layout_archetype\": \"case_visual\", \"layout_variant\": \"a\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p05_1\", \"pr_p07_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832103\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'site_survey', '{\"title\": \"双重循环的逻辑拆解：内外协同\", \"image_src\": \"https://example.com/images/code-flow-diagram.jpg\", \"image_alt\": \"左侧为高亮显示的嵌套循环代码片段，右侧为对应的黑白流程图，通过对比色块清晰展示外层控制变量 i 与内层控制变量 j 的层级关系及数据流向。\", \"caption\": \"图 2.2 双重循环逻辑全景：左侧代码精准对应右侧流程，红色高亮区分控制轮次（外层）与比较动作（内层），直观呈现算法运行的微观秩序。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"case_visual\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('582513ef-904a-41c0-981e-a905e73658cc', '1d063203-8ece-436a-ad39-9501e3c7e06b', 15, NULL, '{\"page_id\": \"p16\", \"title\": \"成果交付与自我评价\", \"layout_id\": \"ending_practical\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p14\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"summary_reflection\", \"layout_variant\": \"a\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-20T01:09:55.820104\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-20 01:09:18', '2026-03-20 09:10:21', 'ending_practical', '{\"title\": \"成果交付与自我评价\", \"subtitle\": \"工程标准闭环验收。\", \"contact\": \"项目交付组 | 工程质检部\", \"reflection_blocks\": [{\"title\": \"核心矛盾复盘\", \"items\": [\"非流形几何导致渲染崩溃的根源已定位\", \"法线修复与比例校准转化为标准化作业指令\"]}, {\"title\": \"交付执行评估\", \"items\": [\"严格遵循分阶段交付节点与验收评分体系\", \"统一命名规范与版本控制确保逻辑严密性\"]}], \"closing\": \"杜绝隐患，以标准化作业铸就零缺陷交付。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"summary_reflection\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('586d24b4-f440-4146-b540-4c8bf13b32bc', '6c250523-422a-46f3-a1f1-42e82424897c', 17, NULL, '{\"page_id\": \"p18\", \"title\": \"进阶技巧：雕刻与细节塑造\", \"layout_id\": \"academic_narrative\", \"has_image\": true, \"keywords\": [\"数字雕刻\", \"笔刷效果\", \"肌肉纹理\", \"岩石质感\", \"高精度模型\"], \"depends_on\": [\"p14\"], \"must_cover\": [\"动态拓扑\", \"细节层次\", \"平滑组设置\", \"法线叠加\", \"进阶技巧：雕刻与细节塑造的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"进阶技巧：雕刻与细节塑造的核心概念与背景\", \"进阶技巧：雕刻与细节塑造的关键方法与执行要点\", \"进阶技巧：雕刻与细节塑造的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p18\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287133\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'academic_narrative', '{\"title\": \"进阶技巧：雕刻与细节塑造\", \"narrative\": [\"数字雕刻打破了传统多边形建模的拓扑限制，允许艺术家直接在虚拟粘土上创作，通过笔刷模拟真实物理质感。该技术核心在于动态拓扑（Dynamic Topology），系统根据笔触压力自动细分网格，实现从宏观形体到微观毛孔的多层次细节塑造，广泛应用于角色肌肉纹理、岩石风化痕迹等高精度资产制作。\", \"在细节深化阶段，平滑组（Smoothing Groups）的设置决定了光影过渡的自然度，而法线叠加（Normal Blending）则用于融合不同笔触产生的细微起伏。通过分层雕刻策略，先确立大体积结构，再逐步添加次级细节，最后进行微调，确保模型在高分辨率下依然保持结构清晰，避免细节杂乱无章。\", \"应用实践中，需注意雕刻深度与游戏引擎性能的平衡。虽然高精度模型能呈现极致细节，但需通过置换烘焙将其转化为低模可用的贴图数据。风险提示包括过度细分导致的内存溢出，以及缺乏整体构图意识造成的局部过度修饰，建议在雕刻前制定明确的细节层级规划。\"], \"margin_notes\": [{\"title\": \"核心概念：动态拓扑\", \"content\": \"一种实时细分算法，仅在笔触作用区域增加多边形数量，无需预先规划布线，极大提升了自由创作的灵活性。\"}, {\"title\": \"细节层级（LOD）\", \"content\": \"雕刻时需考虑不同观察距离下的细节表现，远观看大形，近观看细节，避免无效的高频噪声。\"}], \"pull_quote\": \"雕刻不仅是形状的塑造，更是对光影关系的预判；每一笔落下，都是在定义光线如何在曲面上流动。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('588ef5d1-3cf2-44d6-97cc-a54f7c8c58ad', '9b5d83ef-2600-4c3b-b852-00607680277d', 12, '总结', '{\"page_id\": \"p11\", \"title\": \"核心回顾：发展脉络与关键节点\", \"part\": \"总结\", \"points\": [\"ChatGPT引爆大众认知，Claude确立安全与长文本标杆，Gemini实现多模态原生融合\", \"技术演进从单一对话交互跨越至复杂逻辑推理与全感官理解的新阶段\", \"未来竞争焦点将聚焦于模型对齐的可靠性与推理成本的极致优化\"]}', '{\"text\": \"核心回顾：发展脉络与关键节点\\n\\n页面文字：\\n- ChatGPT引爆大众认知，Claude确立安全与长文本标杆，Gemini实现多模态原生融合。\\n- 技术演进从单一对话交互跨越至复杂逻辑推理与全感官理解的新阶段。\\n- 未来竞争焦点将聚焦于模型对齐的可靠性与推理成本的极致优化。\", \"generated_at\": \"2026-03-09T08:14:14.372588\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/588ef5d1-3cf2-44d6-97cc-a54f7c8c58ad_v1.png', 'FAILED', '2026-03-09 08:13:57', '2026-03-09 09:20:26', NULL, NULL);
