INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5a14a89d-468c-42f5-9e77-ce40e118776f', '4e889981-954e-4263-b490-230183b1a644', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"案例复盘：某包装机组的调试实录\", \"layout_id\": \"vocational_case_study\", \"has_image\": true, \"keywords\": [\"包装机整体外观\", \"调试前后波形对比图\", \"工厂车间环境\", \"团队讨论场景\", \"成功指示灯\"], \"depends_on\": [\"p08\"], \"must_cover\": [\"企业背景：食品包装线升级\", \"改造方案：基于F=ma的参数优化\", \"改造成效：故障率下降90%\", \"案例复盘：某包装机组的调试实录的核心概念与背景\", \"案例复盘：某包装机组的调试实录的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p10_1_dedd06ac\", \"text\": \"案例复盘：某包装机组的调试实录的复盘与结果启示\", \"must_cover\": [\"案例复盘\", \"结果启示\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"案例复盘：某包装机组的调试实录的核心概念与背景\", \"案例复盘：某包装机组的调试实录的关键方法与执行要点\", \"案例复盘：某包装机组的调试实录的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:45:02.424835\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:44:27', '2026-03-19 01:37:30', 'vocational_case_study', '{\"title\": \"案例复盘：某包装机组的调试实录\", \"background\": \"某食品企业包装线因加减速控制不当，导致频繁卡顿与废品率飙升，传统经验调试失效，急需引入科学计算方法。\", \"solutions\": [\"基于F=ma公式重构加速度曲线参数，精确匹配负载惯量，消除机械冲击根源。\", \"实施变频器PID与机械惯量匹配整定，优化控制回路响应，提升系统动态性能。\"], \"layout_variant\": \"a\", \"variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5a3ed3f7-b6a4-4ca3-a9c6-c23cc1dbbf30', '8fb9adbb-55b5-496b-9569-be1757626e7c', 12, NULL, '{\"page_id\": \"p13\", \"title\": \"易错点警示：常见误区辨析\", \"layout_id\": \"vocational_case_study\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p11\"], \"must_cover\": [\"力是维持运动的原因 vs 改变运动状态\", \"速度与加速度的混淆\", \"合力为零时的状态\", \"易错点警示：常见误区辨析的核心概念与背景\", \"易错点警示：常见误区辨析的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"易错点警示：常见误区辨析的核心概念与背景\", \"易错点警示：常见误区辨析的关键方法与执行要点\", \"易错点警示：常见误区辨析的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"b\", \"logical_page_id\": \"p13\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T04:44:29.430704\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 04:43:52', '2026-03-17 04:44:29', 'vocational_case_study', '{\"title\": \"易错点警示：常见误区辨析\", \"content\": [\"误区一：认为力是维持物体运动的原因。实际上，力是改变物体运动状态（产生加速度）的原因，惯性才是维持运动的原因。\", \"误区二：混淆速度与加速度的概念。速度大不代表加速度大，匀速直线运动中速度虽大但加速度为零。\", \"误区三：误判合力为零的状态。合力为零时物体处于静止或匀速直线运动状态，并非一定静止。\"], \"highlight\": \"牛顿第一定律核心：力不是维持速度的原因，而是改变速度的原因。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5a4b92b7-99e2-41e7-aad2-f3d9f0afb0b9', '8a37f529-e51f-428c-8466-cdc137b73187', 17, NULL, '{\"page_id\": \"p18\", \"title\": \"工具链对比：Substance Designer vs Blender Nodes\", \"layout_id\": \"comparison_table\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p14\"], \"must_cover\": [\"功能维度对比\", \"性能指标对比\", \"学习曲线评估\", \"适用场景建议\", \"工具链对比：Substance Designer vs Blender Nodes的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"工具链对比：Substance Designer vs Blender Nodes的核心概念与背景\", \"工具链对比：Substance Designer vs Blender Nodes的关键方法与执行要点\", \"工具链对比：Substance Designer vs Blender Nodes的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p18\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.108114\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'comparison_table', '{\"title\": \"工具链对比：Substance Designer vs Blender Nodes\", \"subtitle\": \"专业流程选择与效能评估。\", \"items\": [{\"name\": \"功能维度\", \"description\": \"Substance Designer专注于2D纹理的模块化生产，拥有庞大的预设库与强大的UV编辑能力；Blender Nodes则深度集成于3D建模软件，支持实时视口反馈与3D投影纹理的直接操作。\", \"features\": [\"模块化资产库丰富\", \"UV编辑器原生集成\", \"实时3D预览\", \"无缝切换建模与材质阶段\"]}, {\"name\": \"性能指标\", \"description\": \"SD生成的纹理通常经过优化压缩，适合大规模资产部署；Blender节点树依赖GPU实时计算，在大场景下可能面临显存压力，但灵活性极高。\", \"features\": [\"离线渲染效率极高\", \"文件体积小\", \"实时计算依赖硬件\", \"动态参数调整快\"]}, {\"name\": \"学习曲线\", \"description\": \"SD需要掌握专业的纹理制作逻辑与节点连接规范，初期门槛较高但产出标准化程度高；Blender Nodes对初学者更友好，易于上手快速迭代，但复杂项目易形成难以维护的节点网络。\", \"features\": [\"标准化工作流程\", \"社区资源丰富\", \"直观拖拽式操作\", \"易产生节点冗余\"]}], \"conclusion\": \"两者并非替代关系而是互补关系。建议在资产生产阶段利用Substance Designer构建高精度基础纹理，在后期整合与特效调试阶段导入Blender进行节点式的二次加工与动态调整，以实现效率与质量的最优解。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5add2e6f-127b-47e7-b4de-ad347abecc19', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 1, '导览', '{\"page_id\": \"p02\", \"title\": \"目录：AI发展的四个核心阶段\", \"part\": \"导览\", \"points\": [\"萌芽期：图灵测试与达特茅斯会议奠定理论基石（1950s前）\", \"第一次浪潮：专家系统主导逻辑推理，遭遇知识工程瓶颈（1956-1980）\", \"第二次浪潮：统计学习兴起，大数据驱动算法从规则转向概率（1990-2010）\", \"爆发期：深度学习与大模型重构产业，开启生成式智能新纪元（2012至今）\"]}', '{\"text\": \"页面标题：目录：AI发展的四个核心阶段\\n\\n页面文字：\\n- 萌芽期由图灵测试与达特茅斯会议奠定理论基石，确立了机器思维的哲学基础。\\n- 第一次浪潮以专家系统主导逻辑推理，却因知识工程瓶颈遭遇发展停滞困境。\\n- 第二次浪潮统计学习兴起，大数据驱动算法从规则转向概率解决不确定性问题。\\n- 爆发期深度学习重构产业，开启生成式智能新纪元并推动应用全面落地生根。\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:20', '2026-03-09 16:55:02', NULL, NULL);
