INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5bc6e4a0-57eb-4cdf-ab1c-052c22e09696', '2786117f-f122-459a-8310-c05a2077848b', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"SOP 实操：更换流程五步法\", \"layout_id\": \"edu_tri_compare\", \"has_image\": true, \"keywords\": [\"维修人员操作演示\", \"安全锁具特写\", \"气路断开操作\", \"工业现场环境\", \"严谨的操作姿态\"], \"depends_on\": [\"p08\"], \"must_cover\": [\"Step1: 停机与能量隔离\", \"Step2: 残余压力释放\", \"Step3: 螺栓拆卸顺序\", \"Step4: 新工具安装校准\", \"Step5: 空载测试\"], \"promises_open\": [], \"promises_close\": [\"pr_safety_1\", \"pr_safety_2\"], \"points\": [\"SOP 实操：更换流程五步法的核心概念与背景\", \"SOP 实操：更换流程五步法的关键方法与执行要点\", \"SOP 实操：更换流程五步法的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_safety_1\", \"pr_safety_2\"], \"layout_archetype\": \"feature_compare\", \"layout_variant\": \"b\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_safety_1\", \"pr_safety_2\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:02:17.155407\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:01:23', '2026-03-19 06:02:17', 'edu_tri_compare', '{\"title\": \"SOP 实操：更换流程五步法\", \"badge\": \"安全零事故目标\", \"columns\": [{\"title\": \"能量隔离与释放\", \"points\": [\"执行停机程序并切断主电源，悬挂“禁止合闸”警示牌\", \"手动操作泄压阀彻底释放气路残余压力至零值\", \"确认机械臂处于静止状态，防止意外复位动作\"]}, {\"title\": \"拆卸与安装规范\", \"points\": [\"遵循对角线顺序分次松开螺栓，避免受力不均变形\", \"使用专用工具进行新工具安装，确保定位销精准对齐\", \"人工辅助校准工具姿态，消除微米级装配误差\"]}, {\"title\": \"测试与验证闭环\", \"points\": [\"执行空载运行测试，监测气压波动与电流异常数据\", \"模拟抓取动作验证夹持力与吸附稳定性是否达标\", \"记录关键参数并归档，完成标准化操作流程闭环\"]}], \"background_image\": \"https://images.unsplash.com/photo-1581093450021-4a7360e9a6b5?q=80&w=2070&auto=format&fit=crop\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_compare\"}');
