INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5d8f482e-d52c-469e-8d8e-82420b35466d', '9d298a55-d8b5-48bc-9737-d3dadbe48813', 17, NULL, '{\"page_id\": \"p18\", \"title\": \"行业趋势：AI辅助建模与实时渲染\", \"layout_id\": \"edu_core_hub\", \"has_image\": true, \"keywords\": [\"AI生成3D模型概念\", \"实时光线追踪效果\", \"科技蓝绿配色\", \"未来工作流图示\", \"无文字趋势分析\"], \"depends_on\": [\"p16\"], \"must_cover\": [\"NeRF技术应用\", \"UE5 Nanite特性\", \"自动化拓扑工具\", \"行业趋势：AI辅助建模与实时渲染的核心概念与背景\", \"行业趋势：AI辅助建模与实时渲染的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"行业趋势：AI辅助建模与实时渲染的核心概念与背景\", \"行业趋势：AI辅助建模与实时渲染的关键方法与执行要点\", \"行业趋势：AI辅助建模与实时渲染的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"core_model\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:31:45', '2026-03-10 05:31:45', 'edu_core_hub', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5d95298b-a4ec-4c1a-a74e-e16eb1df4e4e', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d', 13, '总结', '{\"title\": \"课程总结：知识体系回顾：案例复盘\", \"points\": [\"问题与场景：聚焦电商评论情感分析中数据噪声大与标注成本高的核心矛盾\", \"方案与执行：对比传统规则匹配与BERT微调模型，确立基于预训练迁移的学习策略\", \"结果与启示：准确率提升15%验证了深度学习优势，同时提示需警惕小样本下的过拟合风险\"], \"part\": \"总结\"}', '{\"text\": \"页面标题：课程总结：知识体系回顾：案例复盘\\n\\n页面文字：\\n- 问题背景聚焦电商评论情感分析中数据噪声大与标注成本高的核心矛盾。\\n- 方法动作对比传统规则匹配与BERT微调模型，确立基于预训练迁移的学习策略。\\n- 结果启示准确率提升百分之十五验证了深度学习优势，同时提示需警惕小样本下的过拟合风险。\\n- 本案例深刻揭示了技术选型对业务效果的决定性作用，引出对未来趋势的思考。\", \"generated_at\": \"2026-03-16T05:37:22.715809\"}', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d/pages/5d95298b-a4ec-4c1a-a74e-e16eb1df4e4e_v2.png', 'COMPLETED', '2026-03-16 05:37:15', '2026-03-16 06:33:36', NULL, NULL);
