INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5ee37fd0-e03c-45c8-8ce0-cb05f517d25a', '8ccaacf6-cf8f-4cd6-8ca8-7d5f28350c89', 15, NULL, '{\"page_id\": \"p16\", \"title\": \"十四、互动答疑：常见问题解答\", \"layout_id\": \"vocational_case_study\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p15\"], \"must_cover\": [\"学生疑问汇总\", \"教师深度解析\", \"延伸思考题\", \"十四、互动答疑：常见问题解答的核心概念与背景\", \"十四、互动答疑：常见问题解答的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p12_1_4f5b906c\", \"pr_p03_1\", \"pr_p03_2\"], \"points\": [\"十四、互动答疑：常见问题解答的核心概念与背景\", \"十四、互动答疑：常见问题解答的关键方法与执行要点\", \"十四、互动答疑：常见问题解答的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p12_1_4f5b906c\", \"pr_p03_1\", \"pr_p03_2\"], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p12_1_4f5b906c\", \"pr_p03_1\", \"pr_p03_2\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:41:09.848468\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:40:30', '2026-03-17 07:41:10', 'vocational_case_study', '{\"title\": \"十四、互动答疑：常见问题解答\", \"content\": [\"针对前序环节提到的‘重载皮带机加速过流’问题，核心在于未依据T=J×Δω/M公式精准计算加速时间。学生常误以为经验设定即可，实则忽略了力矩与加速度的线性关系。正确做法是重新采集负载参数，利用定律公式反推所需时间，并设置合理的转矩提升阈值以平\", \"关于F=ma在电机控制中的应用，质量（等效转动惯量）越大，达到相同加速度所需的推力（扭矩）呈线性增长。在参数设定时，必须完成从理论公式到变频器具体参数（如加速时间、转矩限制）的完整换算与映射，否则系统将无法稳定运行。\", \"延伸思考：若现场负载惯量随物料装载量动态变化，静态计算的加速时间是否仍适用？请结合变频器的自适应功能或模糊控制策略进行探讨。\"], \"highlight\": \"调试不是纯经验操作，而是基于物理定律的科学计算过程。缺乏量化思维是导致故障频发的根源。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
