INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('60e1eb2c-6418-4544-80ed-71677ced46e2', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d', 4, '核心技术', '{\"page_id\": \"p04\", \"title\": \"基础基石：文本预处理与表示\", \"part\": \"核心技术\", \"points\": [\"分词、去停用词与词形还原：清洗噪声数据，统一词汇形态以构建标准语料库\", \"词袋模型与TF-IDF权重计算：将文本转化为稀疏向量，量化关键词在文档中的重要性\", \"Word2Vec与上下文向量表示：利用分布式假设将词语映射为稠密向量，捕捉语义相似度\", \"数据标准化对后续模型训练的影响：高质量的特征工程是提升分类与预测精度的前提\"]}', '{\"text\": \"页面标题：基础基石：文本预处理与表示\\n\\n页面文字：\\n- 分词、去停用词与词形还原清洗噪声数据，统一词汇形态以构建标准语料库。\\n- 词袋模型与TF-IDF权重计算将文本转化为稀疏向量，量化关键词在文档中的重要性。\\n- Word2Vec与上下文向量表示利用分布式假设将词语映射为稠密向量，捕捉语义相似度。\\n- 数据标准化对后续模型训练影响深远，高质量的特征工程是提升分类与预测精度的前提。\", \"generated_at\": \"2026-03-16T05:37:22.407817\"}', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d/pages/60e1eb2c-6418-4544-80ed-71677ced46e2_v1.png', 'COMPLETED', '2026-03-16 05:37:00', '2026-03-16 06:30:35', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6129c49c-471e-4d89-8679-f16b6e98aa78', '2f844b20-de75-4ac5-98d1-2f44296e9e2b', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"公式推导：从比例到等式\", \"layout_id\": \"edu_timeline_steps\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p05\"], \"must_cover\": [\"单位制选择\", \"k值归一化\", \"F=ma的诞生\", \"公式推导：从比例到等式的核心概念与背景\", \"公式推导：从比例到等式的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p06_1\", \"text\": \"深入理解公式中各物理量的矢量性与瞬时性\", \"must_cover\": [\"方向一致性\", \"同时性\"], \"target_page_ids\": [\"p19\"], \"is_hard\": true}], \"promises_close\": [\"pr_p05_1\"], \"points\": [\"公式推导：从比例到等式的核心概念与背景\", \"公式推导：从比例到等式的关键方法与执行要点\", \"公式推导：从比例到等式的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p05_1\"], \"layout_archetype\": \"timeline\", \"layout_variant\": \"b\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p05_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:09:35.125929\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 02:08:44', '2026-03-17 02:09:35', 'edu_timeline_steps', '{\"title\": \"公式推导：从比例到等式\", \"subtitle\": \"单位制定义与k值归一化过程。\", \"steps\": [{\"title\": \"步骤一：引入比例系数\", \"description\": \"基于上一页结论，建立通用表达式 a = k·(F/m)，其中 k 为待定的比例常数。\", \"highlights\": [\"确立数学模型\", \"引入待定系数 k\"]}, {\"title\": \"步骤二：巧选单位制\", \"description\": \"定义力的单位（牛顿），使得当质量为 1kg、加速度为 1m/s²时，力恰好为 1N，强制设定 k=1。\", \"highlights\": [\"定义标准单位\", \"实现数值归一化\"]}, {\"title\": \"步骤三：定律最终形态\", \"description\": \"代入 k=1，消除比例系数，直接导出简洁有力的牛顿第二定律标准公式：F = ma。\", \"highlights\": [\"消去常数项\", \"完成公式诞生\"]}], \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"timeline\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('614a7604-6051-4fe7-9335-f8005187e436', '14c0f24c-10e7-4309-a927-d9db1066897c', 12, NULL, '{\"page_id\": \"p13\", \"title\": \"第三章：材质表现与光照叙事\", \"layout_id\": \"field_observation\", \"has_image\": true, \"keywords\": [], \"depends_on\": [\"p11\"], \"must_cover\": [\"材质物理属性\", \"光影氛围营造\", \"第三章：材质表现与光照叙事的核心概念与背景\", \"第三章：材质表现与光照叙事的关键方法与执行要点\", \"第三章：材质表现与光照叙事的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第三章：材质表现与光照叙事的核心概念与背景\", \"第三章：材质表现与光照叙事的关键方法与执行要点\", \"第三章：材质表现与光照叙事的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"case_visual\", \"layout_variant\": \"a\", \"logical_page_id\": \"p13\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.773995\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'field_observation', '{\"title\": \"材质物理属性与光影叙事\", \"image_src\": \"https://images.unsplash.com/photo-1600607686527-6fb886090705?q=80&w=1200&auto=format&fit=crop\", \"image_alt\": \"展示金属表面粗糙度与光线反射的微观特写，配合冷暖光对比营造氛围\", \"caption\": \"材质不仅是视觉还原，更是情绪载体。通过精确控制物理属性（粗糙度、金属度）与环境光交互，构建具有叙事张力的光影空间。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"case_visual\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('618e9d9c-bcb7-4d68-80a2-273e307470c6', '4e889981-954e-4263-b490-230183b1a644', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"风险警示：过载与共振的物理边界\", \"layout_id\": \"vocational_ideology\", \"has_image\": true, \"keywords\": [\"红色警示灯\", \"断裂的齿轮模型\", \"安全护目镜\", \"禁止触摸标志\", \"严肃工业氛围\"], \"depends_on\": [\"p09\"], \"must_cover\": [\"超限加速导致的机械损伤\", \"共振频率对精度的影响\", \"职业素养：严守安全红线\", \"风险警示：过载与共振的物理边界的核心概念与背景\", \"风险警示：过载与共振的物理边界的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"风险警示：过载与共振的物理边界的核心概念与背景\", \"风险警示：过载与共振的物理边界的关键方法与执行要点\", \"风险警示：过载与共振的物理边界的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"quote\", \"layout_variant\": \"a\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:45:02.424875\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:44:27', '2026-03-19 01:37:30', 'vocational_ideology', '{\"title\": \"风险警示：过载与共振的物理边界\", \"quote\": \"物理定律不可逾越，超限加速即埋下设备损毁隐患，必须严格遵守安全操作规程。\", \"standard\": \"GB/T 5226.1-2019 机械安全标准 - 极限参数控制\", \"layout_variant\": \"a\", \"variant\": \"a\", \"layout_archetype\": \"quote\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('61f9493d-9653-45ae-b80a-677181b968f5', 'c3f4f20a-0839-4fb0-9375-125c6af13f37', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"职业标准与安全红线\", \"layout_id\": \"sk_keypoints\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p03\"], \"must_cover\": [\"未断电禁止拆卸\", \"气压不足禁止操作\", \"工具坠落风险预防\", \"职业标准与安全红线的核心概念与背景\", \"职业标准与安全红线的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p04_1\", \"text\": \"具体更换步骤将拆解为SOP流程\", \"must_cover\": [\"操作步骤\", \"检查清单\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"promises_close\": [\"pr_p01_3\"], \"points\": [\"职业标准与安全红线的核心概念与背景\", \"职业标准与安全红线的关键方法与执行要点\", \"职业标准与安全红线的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_3\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p01_3\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:04:18.360764\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:03:27', '2026-03-19 06:04:18', 'sk_keypoints', '{\"title\": \"职业标准与安全红线\", \"cards\": [{\"title\": \"断电锁定原则\", \"value\": \"未断电禁止拆卸\", \"description\": \"执行任何末端工具更换或维护前，必须切断电源并上锁挂牌，防止意外启动。\"}, {\"title\": \"气路压力监测\", \"value\": \"气压不足禁止操作\", \"description\": \"系统气压低于额定值（通常<0.4MPa）时严禁作业，避免夹持力失效导致工件坠落。\"}, {\"title\": \"防坠落管理\", \"value\": \"工具坠落风险预防\", \"description\": \"所有悬挂工具必须配备防坠绳，拆卸部件需置于专用托盘，严禁悬空放置。\"}, {\"title\": \"标准化流程\", \"value\": \"三步安全确认法\", \"description\": \"遵循“断电锁定 - 气路检查 - 紧固确认”的标准化闭环操作流程，确保作业零事故。\"}, {\"title\": \"职业红线意识\", \"value\": \"违规即停工\", \"description\": \"触碰安全红线（如带压拆卸、未断电作业）将立即终止实训资格，强化底线思维。\"}], \"summary\": \"安全是实训的生命线。本环节确立了以断电锁定、气压监测及防坠落为核心的三大红线，严格执行“断-查-固”标准化流程，确保汽车产线环境下的高风险作业安全可控。\", \"bullets\": [{\"icon\": \"fa-check\", \"text\": \"职业标准与安全红线的关键概念。\", \"description\": \"说明职业标准与安全红线的关键概念在当前主题中的价值与应用方式。\"}, {\"icon\": \"fa-check\", \"text\": \"职业标准与安全红线的实践方法。\", \"description\": \"说明职业标准与安全红线的实践方法在当前主题中的价值与应用方式。\"}, {\"icon\": \"fa-check\", \"text\": \"职业标准与安全红线的风险与边界。\", \"description\": \"说明职业标准与安全红线的风险与边界在当前主题中的价值与应用方式。\"}], \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
