INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6495a0f6-5f93-44ee-96e9-d08213a1a651', 'ab2ec2c8-cb17-41e9-beb4-40c851abbea2', 13, NULL, '{\"page_id\": \"p14\", \"title\": \"易错点专项：摩擦力与合力\", \"layout_id\": \"edu_qa_case\", \"has_image\": false, \"keywords\": [\"问答气泡\", \"错误警示标\", \"高亮修正区\", \"无文字符号\", \"教育风格\"], \"depends_on\": [\"p11\"], \"must_cover\": [\"滑动摩擦力方向判断\", \"合力不等于某个分力\", \"静摩擦力突变\", \"易错点专项：摩擦力与合力的核心概念与背景\", \"易错点专项：摩擦力与合力的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p01_2\"], \"points\": [\"易错点专项：摩擦力与合力的核心概念与背景\", \"易错点专项：摩擦力与合力的关键方法与执行要点\", \"易错点专项：摩擦力与合力的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_2\"], \"layout_archetype\": \"qa_session\", \"layout_variant\": \"b\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p01_2\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:06:57.190927\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 01:42:01', '2026-03-17 02:06:57', 'edu_qa_case', '{\"title\": \"易错点专项：摩擦力与合力辨析\", \"subtitle\": \"破除直觉误区，重构力学逻辑。\", \"question\": \"滑动摩擦力方向是否总与运动方向相反？合力大小是否等于分力之和？\", \"answer\": \"摩擦力方向取决于相对运动趋势；合力遵循矢量平行四边形定则，不等于代数和。\", \"analysis\": [{\"title\": \"方向判断陷阱\", \"content\": \"滑动摩擦力阻碍的是相对运动而非绝对运动，需严格区分参考系与相对速度方向。\"}, {\"title\": \"合力概念修正\", \"content\": \"静摩擦力具有突变性，合力是矢量和，当分力夹角变化时，合力大小可能小于任一分力。\"}], \"conclusion\": \"牢记矢量法则，拒绝标量直觉，精准判断相对运动状态。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"qa_session\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('64ebb468-3d77-4506-b16e-ef183d52baf1', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 0, '封面', '{\"page_id\": \"p01\", \"title\": \"封面：AI发展史——从图灵测试到智能时代\", \"part\": \"封面\", \"points\": [\"主题：人工智能的演进历程与关键转折\", \"副标题：探索技术爆发的百年轨迹\", \"演讲人：[您的姓名/团队名称]\", \"日期：2023年X月X日\"]}', '{\"text\": \"页面标题：封面：AI发展史——从图灵测试到智能时代\\n\\n页面文字：\\n- 本页面聚焦人工智能的演进历程，梳理其从理论萌芽到关键转折的核心脉络。\\n- 副标题旨在探索技术爆发的百年轨迹，见证机器如何从逻辑模拟迈向自主智能。\\n- 演讲人将带领观众回顾历史节点，展望智能时代带来的产业变革与未来机遇。\", \"generated_at\": \"2026-03-09T08:54:47.422422\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:19', '2026-03-09 08:54:49', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('651fd4d0-99f0-4cbd-ae11-b792d8017f84', 'c3f4f20a-0839-4fb0-9375-125c6af13f37', 15, NULL, '{\"title\": \"总结与答疑\", \"points\": [\"核心结论：情境导入：汽车产线的挑战的关键认知与边界\", \"行动建议：下一步如何落地与评估效果\", \"开放答疑：常见问题与延伸讨论方向\"], \"layout_id\": \"sk_safety\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p16\", \"depends_on\": [\"p15\"], \"must_cover\": [\"核心结论：情境导入：汽车产线的挑战的关键认知与边界\", \"行动建议：下一步如何落地与评估效果\", \"开放答疑：常见问题与延伸讨论方向\"], \"promises_open\": [], \"required_close_promise_ids\": [\"pr_p08_1_3b3af7f7\", \"pr_p13_1_cbdf457b\", \"pr_p01_1\", \"pr_p01_2\", \"pr_p01_3\", \"pr_p04_1\", \"pr_p07_1\"], \"promises_close\": [\"pr_p08_1_3b3af7f7\", \"pr_p13_1_cbdf457b\", \"pr_p01_1\", \"pr_p01_2\", \"pr_p01_3\", \"pr_p04_1\", \"pr_p07_1\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p08_1_3b3af7f7\", \"pr_p13_1_cbdf457b\", \"pr_p01_1\", \"pr_p01_2\", \"pr_p01_3\", \"pr_p04_1\", \"pr_p07_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:04:18.361171\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:03:30', '2026-03-19 06:04:18', 'sk_safety', '{\"title\": \"安全规范与复盘总结\", \"alerts\": [{\"level\": \"danger\", \"title\": \"禁止操作\", \"content\": \"严禁在气路未泄压、电源未锁定状态下更换末端工具，违者将导致设备损坏或人员重伤。\"}, {\"level\": \"warning\", \"title\": \"警告事项\", \"content\": \"焊接搬运与零件选配中，忽略高温焊件温控策略及易碎曲面受力点，将引发抓取失效或工件破损事故。\"}, {\"level\": \"caution\", \"title\": \"注意事项\", \"content\": \"执行SOP时需严格核对断电锁定状态、气路检查清单及紧固确认步骤，确保吸附与夹持原理应用无误。\"}], \"summary\": \"基于汽车产线真实情境，重申真空/机械结构选型逻辑，强调案例复盘中的风险预判与标准化操作流程是保障实训安全的核心。\", \"bullets\": [{\"icon\": \"fa-check\", \"text\": \"总结与答疑的关键概念。\", \"description\": \"说明总结与答疑的关键概念在当前主题中的价值与应用方式。\"}, {\"icon\": \"fa-check\", \"text\": \"总结与答疑的实践方法。\", \"description\": \"说明总结与答疑的实践方法在当前主题中的价值与应用方式。\"}, {\"icon\": \"fa-check\", \"text\": \"总结与答疑的风险与边界。\", \"description\": \"说明总结与答疑的风险与边界在当前主题中的价值与应用方式。\"}], \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
