INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6786e6c8-3160-4fcc-ade1-f49462ba59b3', 'c3f4f20a-0839-4fb0-9375-125c6af13f37', 8, NULL, '{\"page_id\": \"p09\", \"title\": \"标准操作流程（SOP）：末端工具更换\", \"layout_id\": \"sk_sop\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p08\"], \"must_cover\": [\"停机挂牌\", \"气源切断\", \"快速换接板对接\", \"电气接口锁紧\", \"标准操作流程（SOP）：末端工具更换的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p04_1\"], \"points\": [\"标准操作流程（SOP）：末端工具更换的核心概念与背景\", \"标准操作流程（SOP）：末端工具更换的关键方法与执行要点\", \"标准操作流程（SOP）：末端工具更换的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p04_1\"], \"layout_archetype\": \"process_steps\", \"layout_variant\": \"b\", \"logical_page_id\": \"p09\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p04_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:04:18.360950\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:03:28', '2026-03-19 06:04:22', 'sk_sop', '{\"title\": \"标准操作流程（SOP）：末端工具更换\", \"steps\": [{\"number\": 1, \"label\": \"步骤1\", \"description\": \"按下急停按钮，切断主电源，悬挂‘禁止合闸’警示牌，确认机器人处于静止状态。\", \"icon\": \"fa-check\"}, {\"number\": 2, \"label\": \"步骤2\", \"description\": \"关闭供气阀门排空余压，拔除电气插头并检查接口无异物，防止带电信号误触发。\", \"icon\": \"fa-check\"}, {\"number\": 3, \"label\": \"步骤3\", \"description\": \"松开法兰盘螺栓，平稳取下旧执行器，检查机器人本体接口是否完好无损。\", \"icon\": \"fa-check\"}, {\"number\": 4, \"label\": \"步骤4\", \"description\": \"将新工具对准快速换接板，推入到位后锁紧机械卡扣，手动确认无松动间隙。\", \"icon\": \"fa-check\"}, {\"number\": 5, \"label\": \"步骤5\", \"description\": \"插回气管与电缆，确保接头完全啮合，检查密封圈完好，无漏气漏液风险。\", \"icon\": \"fa-check\"}, {\"number\": 6, \"label\": \"步骤6\", \"description\": \"解除锁定，缓慢送气送电，运行自检程序，模拟抓取动作确认参数正常后恢复生产。\", \"icon\": \"fa-check\"}], \"summary\": \"流程提示：严格执行‘断电断气’原则，每一步操作后必须进行二次确认，确保人员与设备双重安全。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"process_steps\"}');
