INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('68a65832-f474-4254-b3b4-007649629c38', '6c250523-422a-46f3-a1f1-42e82424897c', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"实战演练：从零开始构建一个立方体\", \"layout_id\": \"academic_practice\", \"has_image\": true, \"keywords\": [\"鼠标操作\", \"软件界面截图\", \"高亮选区\", \"指令输入\", \"教学演示\"], \"depends_on\": [\"p09\"], \"must_cover\": [\"创建基本体\", \"视图导航\", \"变换工具使用\", \"保存工程文件\", \"实战演练：从零开始构建一个立方体的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p02_2\"], \"points\": [\"实战演练：从零开始构建一个立方体的核心概念与背景\", \"实战演练：从零开始构建一个立方体的关键方法与执行要点\", \"实战演练：从零开始构建一个立方体的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p02_2\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p02_2\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.286933\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'academic_practice', '{\"title\": \"实战演练：从零开始构建一个立方体\", \"task_type\": \"task\", \"description\": \"请在选定的3D软件（Blender或Maya）中，从零开始创建一个标准立方体模型，并完成基础视图导航、变换调整及工程保存。\", \"requirements\": [\"准确使用创建基本体指令（如Shift+A>Mesh>Cube或Create>Polygonal Primitives>Cube）\", \"熟练运用视图导航工具（旋转、平移、缩放）从多角度观察模型\", \"正确应用变换工具对立方体进行非均匀缩放或位移操作\", \"将工程文件保存至指定路径，并命名包含个人标识与日期\"], \"options\": [], \"hint\": \"注意检查法线方向是否正确；在Blender中按N键呼出侧边栏查看属性，在Maya中按Ctrl+A打开属性编辑器。\", \"background_image\": \"https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?auto=format&fit=crop&q=80&w=2064\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
