INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6a92b75c-7f58-49a3-a067-b675cd09c155', '2f844b20-de75-4ac5-98d1-2f44296e9e2b', 17, NULL, '{\"page_id\": \"p18\", \"title\": \"答疑环节：Q&A\", \"layout_id\": \"edu_qa_case\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p17\"], \"must_cover\": [\"常见问题预设\", \"互动解答逻辑\", \"答疑环节：Q&A的核心概念与背景\", \"答疑环节：Q&A的关键方法与执行要点\", \"答疑环节：Q&A的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"答疑环节：Q&A的核心概念与背景\", \"答疑环节：Q&A的关键方法与执行要点\", \"答疑环节：Q&A的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"qa_session\", \"layout_variant\": \"a\", \"logical_page_id\": \"p18\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:09:35.126319\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 02:08:46', '2026-03-17 02:09:35', 'edu_qa_case', '{\"title\": \"答疑环节：Q&A\", \"subtitle\": \"深度解析常见疑惑。\", \"question\": \"为什么增加载重会显著降低小车的加速能力？\", \"answer\": \"根据F=ma，在推力（F）不变的情况下，质量（m）增大必然导致加速度（a）减小。\", \"analysis\": [{\"title\": \"物理机制分析\", \"content\": \"质量是惯性的量度，质量越大，改变运动状态所需的力就越大，同等推力下加速度越低。\"}, {\"title\": \"工程优化建议\", \"content\": \"若需维持高加速性能，必须同步增加动力系统功率或减轻车身结构重量以优化质量比。\"}], \"conclusion\": \"理解质量与加速度的反比关系，是优化车辆性能的关键。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"qa_session\"}');
