INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6b721ce7-69c3-4b40-b93f-e2bfc29d1afe', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"时间复杂度：O(n^2)的由来\", \"layout_id\": \"site_survey\", \"has_image\": true, \"keywords\": [\"全景数据分布图\", \"局部放大分析\", \"经纬度式坐标轴\", \"工程测绘风\", \"中性色大色块\"], \"depends_on\": [\"p10\"], \"must_cover\": [\"比较次数计算\", \"交换次数上限\", \"时间复杂度：O(n^2)的由来的核心概念与背景\", \"时间复杂度：O(n^2)的由来的关键方法与执行要点\", \"时间复杂度：O(n^2)的由来的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [\"pr_p01_2\", \"pr_p10_1\"], \"points\": [\"时间复杂度：O(n^2)的由来的核心概念与背景\", \"时间复杂度：O(n^2)的由来的关键方法与执行要点\", \"时间复杂度：O(n^2)的由来的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_2\", \"pr_p10_1\"], \"layout_archetype\": \"case_visual\", \"layout_variant\": \"a\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p01_2\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832209\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'site_survey', '{\"title\": \"时间复杂度剖析：O(n²)的几何溯源\", \"image_src\": \"https://example.com/images/complexity-geometric-map.jpg\", \"image_alt\": \"工程测绘风格的全景数据分布图，展示经纬度式坐标轴下的比较次数热力分布\", \"caption\": \"图 3.1 数据规模与操作次数的非线性关系：左侧为全局数据分布，右侧局部放大揭示嵌套循环导致的平方级增长趋势；中性色大色块清晰界定最坏情况下的比较上限与交换频率，直观呈现 O(n²) 的数学本质。\", \"background_image\": \"https://example.com/images/mapping-bg-subtle.jpg\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"case_visual\"}');
