ant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6c82e9f2-eab3-4bb3-b19d-9d985495c291', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 13, '总结', '{\"page_id\": \"p12\", \"title\": \"课程核心知识点回顾\", \"part\": \"总结\", \"points\": [\"串联建模、UV、材质到渲染的全链路技术闭环\", \"重申规范拓扑布线对模型变形与优化的决定性作用\", \"强调标准化工作流在提升效率与协作中的核心价值\", \"指出通过高频实战练习与案例拆解实现技能内化的必要性\"]}', '{\"text\": \"页面标题：课程核心知识点回顾\\n\\n页面文字：\\n- 串联建模、UV展开、材质贴图到最终渲染的全链路技术闭环逻辑。\\n- 重申规范拓扑布线对模型变形控制与后期优化的决定性作用。\\n- 强调标准化工作流在提升个人效率与团队协作中的核心价值。\\n- 指出通过高频实战练习与深度案例拆解实现技能内化的必要性。\", \"generated_at\": \"2026-03-09T03:39:36.946449\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/6c82e9f2-eab3-4bb3-b19d-9d985495c291_v1.png', 'COMPLETED', '2026-03-09 03:39:27', '2026-03-09 03:50:19', NULL, NULL);
