INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6d5bd4c8-70dd-40a1-8d19-b95baa593f50', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 24, '第五部分：动态呈现与资产交付', '{\"title\": \"资产交付规范：工程协作与格式标准\", \"points\": [\"通用文件格式（FBX/OBJ/GLTF）的适用场景\", \"命名规范标准与版本管理策略\", \"参数化设计与程序化生成的高级应用\", \"社区平台资源推荐与持续学习路径指引\"], \"has_image\": false, \"keywords\": [], \"layout_id\": \"edu_timeline_steps\", \"part\": \"第五部分：动态呈现与资产交付\", \"logical_page_id\": \"p25\", \"depends_on\": [\"p24\"], \"must_cover\": [\"通用文件格式（FBX/OBJ/GLTF）的适用场景\", \"命名规范标准与版本管理策略\", \"参数化设计与程序化生成的高级应用\", \"社区平台资源推荐与持续学习路径指引\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"b\", \"layout_archetype\": \"timeline\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.419506\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_timeline_steps', '{\"title\": \"资产交付规范：工程协作与格式标准\", \"subtitle\": \"构建高效流转的工业化管线体系。\", \"steps\": [{\"title\": \"通用格式适配策略\", \"description\": \"根据目标平台选择最优导出方案，平衡画质与兼容性。\", \"highlights\": [\"FBX：全功能数据封装，适用于游戏引擎与动画交换\", \"GLTF/GLB：Web端实时渲染首选，体积压缩率最高\", \"OBJ：基础几何体兼容，适用于静态展示与3D打印\"]}, {\"title\": \"命名与版本管控\", \"description\": \"建立标准化文件索引，杜绝协作中的资源错乱风险。\", \"highlights\": [\"层级命名法：项目_类型_名称_版本_状态.fbx\", \"语义化标签：v01（草稿）, v02（评审）, v03（发布）\", \"增量备份机制：每日自动归档历史迭代节点\"]}, {\"title\": \"参数化与程序化进阶\", \"description\": \"利用节点逻辑替代手动操作，实现资产的可变性与复用性。\", \"highlights\": [\"几何节点驱动形态变化，一键生成变体模型\", \"程序化材质库：基于参数调整PBR属性而非贴图\", \"社区资源集成：Blender Market与Sketchfab生态对接\"]}], \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"timeline\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6d7a7d85-e5a9-4202-bb74-3e1b08cf5f47', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 20, NULL, '{\"page_id\": \"p21\", \"title\": \"评价结语：开启你的工业化建模之旅\", \"layout_id\": \"ending_interactive\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p19\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"summary_reflection\", \"layout_variant\": \"a\", \"logical_page_id\": \"p21\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928924\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'ending_interactive', '{\"title\": \"开启你的工业化建模之旅\", \"subtitle\": \"评价结语与行动指南。\", \"contact\": \"扫码加入社群 | 获取更多实战素材包\", \"reflection_blocks\": [{\"title\": \"核心思维复盘\", \"items\": [\"拓扑不仅是布线，更是为动画变形预留的“血管”系统。\", \"光影不仅是照明，更是定义虚拟世界情绪与故事的语言。\", \"材质不仅是贴图，更是基于物理属性（PBR）的科学模拟。\"]}, {\"title\": \"下一步行动\", \"items\": [\"立即检查手头项目的布线流向是否支持平滑变形。\", \"尝试在场景中应用IES光源复现真实灯具配光曲线。\", \"整理一份个人常用的材质节点组合库以备复用。\"]}], \"closing\": \"没有完美的模型，只有不断迭代的工作流；让每一次渲染都成为对现实世界的深情致敬。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"summary_reflection\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6d821e93-681c-4a9c-9c7b-c727d212d766', '6c250523-422a-46f3-a1f1-42e82424897c', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"核心概念：顶点、边与面的拓扑关系\", \"layout_id\": \"case_study\", \"has_image\": true, \"keywords\": [\"三维坐标轴\", \"线框模型\", \"几何拓扑\", \"学术图解\", \"冷色调\"], \"depends_on\": [\"p04\"], \"must_cover\": [\"顶点(Vertex)\", \"边(Edge)\", \"面(Face)\", \"欧拉公式应用\", \"核心概念：顶点、边与面的拓扑关系的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p02_1\"], \"points\": [\"核心概念：顶点、边与面的拓扑关系的核心概念与背景\", \"核心概念：顶点、边与面的拓扑关系的关键方法与执行要点\", \"核心概念：顶点、边与面的拓扑关系的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p02_1\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p02_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.286797\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'case_study', '{\"title\": \"典型案例分析\", \"scenario\": \"在低多边形角色建模中，初学者常因忽视拓扑流向导致模型在动画变形时出现非预期的撕裂或褶皱。\", \"challenge\": \"如何设计一个既符合人体肌肉走向又能保证UV展开效率的头部拓扑结构？\", \"points\": [{\"title\": \"顶点(Vertex)定位策略\", \"description\": \"关键特征点（如眼角、嘴角）需精确放置，利用循环边（Loop Edge）控制轮廓，避免在变形关节处产生三角面聚集。\"}, {\"title\": \"边(Edge)布线规则\", \"description\": \"遵循“四边面为主”原则，在肌肉运动区域采用平行于运动方向的环形布线，确保细分曲面后的平滑度。\"}, {\"title\": \"面(Face)与欧拉公式验证\", \"description\": \"通过 V-E+F=2 公式实时校验网格闭合性，确保无孤立项、无自相交，形成合法的流形（Manifold）结构。\"}], \"conclusion\": \"案例启示：优秀的拓扑不仅是几何连接，更是功能性的布线规划，直接决定后续动画变形的质量与渲染效率。\", \"image\": \"https://example.com/case-topology-analysis.jpg\", \"background_image\": \"https://example.com/academic-bg-stone-blue-grid.jpg\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
