INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('72e2addd-ca70-4ec0-8dee-760923d6e561', '6c250523-422a-46f3-a1f1-42e82424897c', 8, NULL, '{\"page_id\": \"p09\", \"title\": \"第二章：主流软件生态与工具选择\", \"layout_id\": \"comparison_table\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p07\"], \"must_cover\": [\"行业软件概览\", \"选型标准\", \"平台特性\", \"第二章：主流软件生态与工具选择的核心概念与背景\", \"第二章：主流软件生态与工具选择的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第二章：主流软件生态与工具选择的核心概念与背景\", \"第二章：主流软件生态与工具选择的关键方法与执行要点\", \"第二章：主流软件生态与工具选择的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p09\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.286881\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'comparison_table', '{\"title\": \"对比分析\", \"subtitle\": \"主流3D软件生态选型指南。\", \"items\": [{\"name\": \"行业定位与核心优势\", \"description\": \"不同软件在影视、游戏与工程领域的侧重。\", \"features\": [\"Maya：影视动画行业标准，节点式架构强大\", \"Blender：开源全能，社区活跃，性价比极高\", \"3ds Max：建筑可视化与游戏资产制作首选\"]}, {\"name\": \"建模功能与工作流\", \"description\": \"多边形、NURBS与雕刻工具的深度对比。\", \"features\": [\"ZBrush：数字雕刻霸主，处理亿级多边形细节\", \"Houdini：程序化建模先驱，适合复杂特效与自动化\", \"Cinema 4D：运动图形友好，学习曲线平缓\"]}, {\"name\": \"插件生态与输出规范\", \"description\": \"第三方资源支持与跨平台协作能力。\", \"features\": [\"Maya/Max：拥有最成熟的商业插件库（如Arnold, V-Ray）\", \"Blender：内置渲染引擎Cycles，支持GLTF实时导出\", \"通用标准：FBX/OBJ格式兼容性，UV展开效率\"]}], \"conclusion\": \"选型应基于项目管线需求：影视动画首选Maya/Houdini，独立创作与快速原型推荐Blender，建筑与游戏资产可考虑3ds Max或C4D。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
