INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7394336e-4bcb-4624-aded-4341327eb6a2', 'e7189705-04c2-4928-8d6c-da2bacf02e42', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"实验数据分析与结论推导\", \"layout_id\": \"vocational_theory\", \"has_image\": true, \"keywords\": [\"a-F线性图表\", \"a-1/m双曲线拟合\", \"坐标轴刻度清晰\", \"工业蓝数据可视化\", \"无文字科学图表\"], \"depends_on\": [\"p06\"], \"must_cover\": [\"a与F成正比\", \"a与m成反比\", \"综合得出F=ma\", \"实验数据分析与结论推导的核心概念与背景\", \"实验数据分析与结论推导的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"实验数据分析与结论推导的核心概念与背景\", \"实验数据分析与结论推导的关键方法与执行要点\", \"实验数据分析与结论推导的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"b\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T01:36:50.689245\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 01:36:09', '2026-03-19 01:36:51', 'vocational_theory', '{\"title\": \"实验数据分析与结论推导：牛顿第二定律实证\", \"description\": \"基于气垫导轨实验采集的精确数据，通过线性拟合与曲线分析，从定量角度揭示力、质量与加速度的内在联系，为传送带故障排查提供理论支撑。\", \"bullets\": [\"a-F图像呈过原点直线，证实加速度与合外力成正比\", \"a-1/m图像呈过原点直线，证实加速度与质量成反比\", \"综合推导得出 F=ma，完成从定性经验到定量公式的跨越\"], \"practiceLabel\": \"工业数据可视化分析区\", \"layout_variant\": \"b\", \"variant\": \"b\", \"layout_archetype\": \"data_metrics\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('73f59bd6-6457-441e-ad3f-c0f962d3e093', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d', 0, '开篇', '{\"page_id\": \"p01\", \"title\": \"封面：自然语言处理（NLP）课程导论\", \"part\": \"开篇\", \"points\": [\"主讲人：[您的姓名/职称] | 所属机构：[学校或公司名称]\", \"核心定义：通过计算模型赋予机器理解、生成及交互人类语言的能力\", \"学习目标：掌握从传统统计方法到Transformer大模型的完整技术栈\", \"应用前景：覆盖智能客服、机器翻译、情感分析及内容生成等关键领域\"]}', '{\"text\": \"页面标题：封面：自然语言处理（NLP）课程导论\\n\\n页面文字：\\n- 主讲人信息待填，所属机构请根据实际填写。\\n- 本课程核心定义是通过计算模型赋予机器理解、生成及交互人类语言的能力。\\n- 学习目标涵盖掌握从传统统计方法到Transformer大模型的完整技术栈体系。\\n- 应用前景广泛覆盖智能客服、机器翻译、情感分析及内容生成等关键领域。\", \"generated_at\": \"2026-03-16T05:37:22.205120\"}', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d/pages/73f59bd6-6457-441e-ad3f-c0f962d3e093_v2.png', 'COMPLETED', '2026-03-16 05:36:54', '2026-03-16 06:29:15', NULL, NULL);
