INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('75f8e991-845d-49f5-b751-21be7e500fd6', '8a37f529-e51f-428c-8466-cdc137b73187', 13, NULL, '{\"page_id\": \"p14\", \"title\": \"案例研究：金属与陶瓷的材质还原\", \"layout_id\": \"case_study\", \"has_image\": true, \"keywords\": [\"高反光金属球\", \"磨砂陶瓷杯\", \"真实光照环境\", \"学术摄影风格\"], \"depends_on\": [\"p11\"], \"must_cover\": [\"场景描述\", \"问题诊断：高光过曝\", \"分析过程：IOR值调整\", \"结论：正确参数组合\", \"案例研究：金属与陶瓷的材质还原的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"案例研究：金属与陶瓷的材质还原的核心概念与背景\", \"案例研究：金属与陶瓷的材质还原的关键方法与执行要点\", \"案例研究：金属与陶瓷的材质还原的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.107951\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'case_study', '{\"title\": \"典型案例分析\", \"scenario\": \"场景描述：构建包含高反光金属球体与磨砂陶瓷杯的静物组合，置于标准学术摄影光照环境下，旨在复现真实世界的光影交互效果。\", \"challenge\": \"问题诊断：初始渲染中金属球高光区域出现严重过曝，缺乏层次；陶瓷杯表面反射过于均匀，丢失了微表面粗糙带来的柔和过渡感。\", \"points\": [{\"title\": \"金属材质优化\", \"description\": \"针对高光过曝问题，降低粗糙度至0.05并引入次表面散射模拟内部光路，同时调整IOR值至2.4以增强边缘反射强度。\"}, {\"title\": \"陶瓷材质还原\", \"description\": \"通过提升粗糙度至0.6并启用各向异性参数，模拟陶瓷釉面微观不平，使高光从锐利点状扩散为柔和片状，符合物理观测。\"}, {\"title\": \"案例研究：金属与陶瓷的材质还原的应用场景与注意事项\", \"description\": \"围绕案例研究：金属与陶瓷的材质还原的应用场景与注意事项给出问题、方法与启示。\"}], \"conclusion\": \"案例启示：正确组合IOR、粗糙度与法线贴图是还原材质质感的关键，需依据物理属性而非主观审美进行参数微调。\", \"image\": \"\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7650adbe-a571-49cf-ae97-0ca257ce53bf', 'f8ce8774-c982-4cd5-a379-23d4cf53bef2', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"典型故障案例：摩擦力过大\", \"layout_id\": \"vocational_case_study\", \"has_image\": true, \"keywords\": [\"磨损的导轨表面\", \"倾斜的气垫管\", \"错误的数据曲线\", \"维修工具\", \"故障对比图\"], \"depends_on\": [\"p09\"], \"must_cover\": [\"现象描述：a-F图线不过原点\", \"原因分析：导轨未调平或气孔堵塞\", \"解决方案：重新调平与清洁\", \"典型故障案例：摩擦力过大的核心概念与背景\", \"典型故障案例：摩擦力过大的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"典型故障案例：摩擦力过大的核心概念与背景\", \"典型故障案例：摩擦力过大的关键方法与执行要点\", \"典型故障案例：摩擦力过大的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"b\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T06:43:32.018145\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 06:42:47', '2026-03-17 14:44:01', 'vocational_case_study', '{\"title\": \"典型故障案例：摩擦力过大\", \"content\": [\"在 a-F 图像分析中，若图线不经过原点且存在明显截距，通常表明系统摩擦力未被完全平衡。\", \"主要原因为导轨底脚螺丝调节不当导致未水平，或气孔堵塞致使气垫层失效，产生额外阻力。\"], \"highlight\": \"现象：a-F 图线不过原点；对策：重调平、清气孔。\", \"image\": {\"src\": \"\", \"alt\": \"磨损的导轨表面与错误 a-F 数据曲线的对比展示图\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('766e5475-bd4a-40f9-91fe-d89edcd87464', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 1, NULL, '{\"title\": \"3D建模进阶：从拓扑逻辑到工业级渲染：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"agenda_path\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p02\", \"depends_on\": [\"p01\"], \"must_cover\": [], \"promises_open\": [], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"toc\", \"layout_variant\": \"a\", \"logical_page_id\": \"p02\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928199\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'agenda_path', '{\"title\": \"课程目录：核心模块概览\", \"items\": [{\"index\": 1, \"text\": \"第一章：拓扑逻辑基础与规范构建。\"}, {\"index\": 2, \"text\": \"第二章：复杂曲面建模技巧解析。\"}, {\"index\": 3, \"text\": \"第三章：工业级材质与光照设置。\"}, {\"index\": 4, \"text\": \"第四章：渲染引擎参数调优实战。\"}, {\"index\": 5, \"text\": \"第五章：典型产品案例全流程复盘。\"}], \"background_image\": \"https://example.com/images/minimal_grid_layout.jpg\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"toc\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('768faa8c-0582-4ca8-bd09-f64d532ba8b1', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 15, NULL, '{\"page_id\": \"p16\", \"title\": \"总结与回顾\", \"layout_id\": \"case_before_after\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p14\"], \"must_cover\": [\"核心知识点串联\", \"学习心得提炼\", \"总结与回顾的核心概念与背景\", \"总结与回顾的关键方法与执行要点\", \"总结与回顾的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"总结与回顾的核心概念与背景\", \"总结与回顾的关键方法与执行要点\", \"总结与回顾的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832414\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'case_before_after', '{\"title\": \"总结与回顾\", \"left\": {\"header\": \"核心脉络与心得提炼\", \"content\": [\"从无序数据流的混乱场景出发，我们经历了从问题识别到工业级算法落地的完整闭环。\"], \"bullets\": [{\"icon\": \"fa fa-link\", \"text\": \"串联知识点：场景选择→边界处理→稳定性优化。\", \"description\": \"解释串联知识点：场景选择→边界处理→稳定性优化在核心脉络与心得提炼维度下的意义。\"}, {\"icon\": \"fa fa-lightbulb\", \"text\": \"心得：稳定排序是应对复杂数据流的关键基石。\", \"description\": \"解释心得：稳定排序是应对复杂数据流的关键基石在核心脉络与心得提炼维度下的意义。\"}, {\"icon\": \"fa fa-check-circle\", \"text\": \"执行要点：必须前置处理空数组与单元素边界。\", \"description\": \"解释执行要点：必须前置处理空数组与单元素边界在核心脉络与心得提炼维度下的意义。\"}, {\"icon\": \"fa fa-bookmark\", \"text\": \"背景：工业级应用对响应延迟的零容忍要求。\", \"description\": \"解释背景：工业级应用对响应延迟的零容忍要求在核心脉络与心得提炼维度下的意义。\"}]}, \"right\": {\"header\": \"方法执行与应用场景\", \"content\": [\"通过对比不同场景下的排序策略，明确了在数据量级与稳定性需求之间的平衡点。\", \"结论：总结与回顾需要结合目标场景做取舍。\"], \"bullets\": [{\"icon\": \"fa fa-cogs\", \"text\": \"关键方法：分层筛选法结合归并排序思想。\", \"description\": \"解释关键方法：分层筛选法结合归并排序思想在方法执行与应用场景维度下的意义。\"}, {\"icon\": \"fa fa-bug\", \"text\": \"避坑指南：警惕索引越界与逻辑死循环陷阱。\", \"description\": \"解释避坑指南：警惕索引越界与逻辑死循环陷阱在方法执行与应用场景维度下的意义。\"}, {\"icon\": \"fa fa-rocket\", \"text\": \"应用场景：高并发日志清洗与实时推荐系统。\", \"description\": \"解释应用场景：高并发日志清洗与实时推荐系统在方法执行与应用场景维度下的意义。\"}, {\"icon\": \"fa fa-exclamation-triangle\", \"text\": \"注意事项：动态数据流需预留缓冲机制。\", \"description\": \"解释注意事项：动态数据流需预留缓冲机制在方法执行与应用场景维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
