INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('77a14413-a5c1-4bf5-9031-e8bc61f41a29', '9b5d83ef-2600-4c3b-b852-00607680277d', 13, '总结', '{\"page_id\": \"p12\", \"title\": \"未来展望：迈向AGI的下一步\", \"part\": \"总结\", \"points\": [\"智能体（Agent）将从被动问答进化为具备自主规划与执行能力的主动交互形态\", \"通用大模型将作为底座，与垂直领域专用小模型形成互补共存的生态格局\", \"全球监管框架将加速完善，在伦理安全与创新速度间寻找动态平衡\", \"多模态感知与具身智能结合，推动AI从数字世界向物理世界深度延伸\"]}', '{\"text\": \"未来展望：迈向AGI的下一步\\n\\n页面文字：\\n- 智能体将从被动问答进化为具备自主规划与执行能力的主动交互形态。\\n- 通用大模型将作为底座，与垂直领域专用小模型形成互补共存的生态格局。\\n- 全球监管框架将加速完善，在伦理安全与创新速度间寻找动态平衡。\\n- 多模态感知与具身智能结合，推动AI从数字世界向物理世界深度延伸。\", \"generated_at\": \"2026-03-09T08:14:14.372594\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/77a14413-a5c1-4bf5-9031-e8bc61f41a29_v1.png', 'FAILED', '2026-03-09 08:13:59', '2026-03-09 09:20:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('77f4e3ad-a506-49d5-8732-e2ae1f6de131', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d', 8, '实践', '{\"page_id\": \"p09\", \"title\": \"实战演示：Python NLP工具链\", \"part\": \"实践\", \"points\": [\"掌握NLTK与spaCy库的分词、词性标注及实体识别基础用法\", \"利用Hugging Face Transformers库一键调用预训练模型\", \"通过代码示例快速搭建具备上下文理解能力的简易聊天机器人\", \"对比不同工具链在文本预处理效率上的性能差异\"]}', '{\"text\": \"页面标题：实战演示：Python NLP工具链\\n\\n页面文字：\\n- 熟练掌握NLTK与spaCy库的分词、词性标注及实体识别功能，夯实NLP开发的基础操作技能。\\n- 利用Hugging Face Transformers库可一键调用海量预训练模型，大幅降低复杂算法的落地门槛。\\n- 通过代码示例快速搭建具备上下文理解能力的简易聊天机器人，直观展示技术应用的可行性。\\n- 对比不同工具链在文本预处理阶段的性能差异，帮助开发者根据实际需求选择最优技术路径。\", \"generated_at\": \"2026-03-16T05:37:23.049270\"}', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d/pages/77f4e3ad-a506-49d5-8732-e2ae1f6de131_v1.png', 'FAILED', '2026-03-16 05:37:06', '2026-03-16 06:31:58', NULL, NULL);
