INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('786bc953-5176-4007-a2d7-ac6bcf1281fa', '1d063203-8ece-436a-ad39-9501e3c7e06b', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"故障排除：破面与法线修复\", \"layout_id\": \"common_faults\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"非流形几何修复\", \"双面渲染设置\", \"法线方向统一\", \"重叠顶点合并\", \"故障排除：破面与法线修复的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p08_1\"], \"points\": [\"故障排除：破面与法线修复的核心概念与背景\", \"故障排除：破面与法线修复的关键方法与执行要点\", \"故障排除：破面与法线修复的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p08_1\"], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-20T01:09:55.819886\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-20 01:09:17', '2026-03-20 01:09:56', 'common_faults', '{\"title\": \"故障排除：破面与法线修复\", \"left\": {\"header\": \"核心故障诊断\", \"content\": [\"非流形几何是渲染崩溃的根源，必须通过布尔运算后的网格清理消除悬空边与重叠顶点。\"], \"bullets\": [{\"icon\": \"fa-exclamation-triangle\", \"text\": \"破面问题：多边形重叠或自相交导致光照计算错误。\", \"description\": \"解释破面问题：多边形重叠或自相交导致光照计算错误在核心故障诊断维度下的意义。\"}, {\"icon\": \"fa-eye-slash\", \"text\": \"法线错误：双面渲染未开启或法线方向不一致造成黑面。\", \"description\": \"解释法线错误：双面渲染未开启或法线方向不一致造成黑面在核心故障诊断维度下的意义。\"}, {\"icon\": \"fa-cube\", \"text\": \"重叠顶点：未合并导致模型内部出现隐形裂缝。\", \"description\": \"解释重叠顶点：未合并导致模型内部出现隐形裂缝在核心故障诊断维度下的意义。\"}]}, \"right\": {\"header\": \"标准化修复流程\", \"content\": [\"统一法线方向并应用“重算法线”命令，确保所有表面朝向一致以支撑正确的光照反馈。\", \"结论：故障排除：破面与法线修复需要结合目标场景做取舍。\"], \"bullets\": [{\"icon\": \"fa-wrench\", \"text\": \"执行网格清理：移除重复顶点与零面积面片。\", \"description\": \"解释执行网格清理：移除重复顶点与零面积面片在标准化修复流程维度下的意义。\"}, {\"icon\": \"fa-sync\", \"text\": \"强制反转法线：针对单面渲染错误的快速修正。\", \"description\": \"解释强制反转法线：针对单面渲染错误的快速修正在标准化修复流程维度下的意义。\"}, {\"icon\": \"fa-check-circle\", \"text\": \"验证非流形几何：使用检测工具扫描异常拓扑结构。\", \"description\": \"解释验证非流形几何：使用检测工具扫描异常拓扑结构在标准化修复流程维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
