INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('790d477f-7c4b-47e8-b3d4-b6aa1e2bdab1', '9da12907-ffda-40fb-9be6-d245c93b1363', 12, '总结回顾', '{\"page_id\": \"p11\", \"title\": \"课程核心知识点回顾\", \"part\": \"总结回顾\", \"points\": [\"巩固点线面拓扑逻辑，确立三维空间坐标系的建模基石地位\", \"复盘从创意草图、白模构建到材质渲染的全流程闭环链路\", \"辨析多边形与NURBS等技法，明确不同场景下的选型策略\", \"强调工程规范与艺术表现的平衡，提升模型复用性与优化能力\"]}', '{\"text\": \"页面标题：课程核心知识点回顾\\n\\n页面文字：\\n- 巩固点线面拓扑逻辑，确立三维空间坐标系的建模基石地位。\\n- 复盘从创意草图、白模构建到材质渲染的全流程闭环链路。\\n- 辨析多边形与NURBS等技法，明确不同场景下的选型策略。\\n- 强调工程规范与艺术表现的平衡，提升模型复用性与优化能力。\", \"generated_at\": \"2026-03-10T06:06:00.887600\"}', NULL, 'FAILED', '2026-03-10 06:05:01', '2026-03-10 06:08:43', NULL, NULL);
