INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('79b5bf26-34e7-4665-927a-aa212f255d0f', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"核心概念：四边面与三角面的博弈\", \"layout_id\": \"quiz_interaction\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p04\"], \"must_cover\": [\"N-gon的局限性\", \"三角面在特定场景的应用\", \"主流引擎兼容性\", \"核心概念：四边面与三角面的博弈的核心概念与背景\", \"核心概念：四边面与三角面的博弈的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"核心概念：四边面与三角面的博弈的核心概念与背景\", \"核心概念：四边面与三角面的博弈的关键方法与执行要点\", \"核心概念：四边面与三角面的博弈的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928349\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'quiz_interaction', '{\"title\": \"核心概念：四边面与三角面的博弈\", \"subtitle\": \"解析不同拓扑形态在引擎中的表现差异。\", \"bullets\": [{\"icon\": \"fa-cube\", \"text\": \"四边面优势。\", \"description\": \"提供平滑的细分曲面效果，支持双向流动，是角色建模与动态变形的首选方案。\"}, {\"icon\": \"fa-triangle\", \"text\": \"三角面局限。\", \"description\": \"虽能封闭空间，但会导致细分后产生不可控的折痕，严重破坏表面平滑度。\"}, {\"icon\": \"fa-ban\", \"text\": \"N-gon风险。\", \"description\": \"多边形数量大于四的面片在重拓扑或动画时极易发生扭曲和拉伸错误。\"}, {\"icon\": \"fa-gamepad\", \"text\": \"引擎兼容性。\", \"description\": \"主流游戏引擎（如UE5/Unity）自动将三角面化，若源文件拓扑混乱将导致法线错误。\"}], \"keyTakeaway\": \"坚持四边面主导原则，仅在封闭角落谨慎使用三角面，彻底杜绝 N-gon，是保证模型动态表现稳定的基石。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7a148deb-5d21-4af6-b7ee-a31f600d3ac0', 'c3f4f20a-0839-4fb0-9375-125c6af13f37', 1, NULL, '{\"page_id\": \"p02\", \"title\": \"实训课程导览\", \"layout_id\": \"sk_toc\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p01\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"toc\", \"layout_variant\": \"b\", \"logical_page_id\": \"p02\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:04:18.360676\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:03:27', '2026-03-19 06:04:18', 'sk_toc', '{\"title\": \"实训课程导览\", \"items\": [{\"index\": 1, \"text\": \"情境导入：汽车产线挑战。\", \"note\": \"分析焊接与抓取的真实痛点。\"}, {\"index\": 2, \"text\": \"核心概念：末端执行器分类。\", \"note\": \"气动、电动与专用夹具详解。\"}, {\"index\": 3, \"text\": \"安全规范：作业风险防控。\", \"note\": \"高压、高温与机械伤害防护。\"}, {\"index\": 4, \"text\": \"设备认知：结构与原理。\", \"note\": \"关键部件拆解与功能解析。\"}, {\"index\": 5, \"text\": \"SOP 流程：选型与调试。\", \"note\": \"标准化操作五步法。\"}, {\"index\": 6, \"text\": \"工单执行：实战任务演练。\", \"note\": \"模拟产线故障排除与优化。\"}, {\"index\": 7, \"text\": \"核查要点：质量与安全。\", \"note\": \"关键指标检查清单。\"}, {\"index\": 8, \"text\": \"考核评价：技能达标测试。\", \"note\": \"基于评分标准的实操考核。\"}], \"background_image\": null, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"toc\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7a7021cb-f189-46ed-9a02-9d3f4eb31309', 'ab2ec2c8-cb17-41e9-beb4-40c851abbea2', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"矢量性与独立性详解\", \"layout_id\": \"edu_qa_case\", \"has_image\": false, \"keywords\": [\"左右分栏布局\", \"对比箭头\", \"学术图标\", \"无文字图形\", \"深色背景\"], \"depends_on\": [\"p07\"], \"must_cover\": [\"力的方向决定加速度方向\", \"分方向列方程的方法\", \"矢量性与独立性详解的核心概念与背景\", \"矢量性与独立性详解的关键方法与执行要点\", \"矢量性与独立性详解的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [\"pr_p06_1\"], \"points\": [\"矢量性与独立性详解的核心概念与背景\", \"矢量性与独立性详解的关键方法与执行要点\", \"矢量性与独立性详解的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p06_1\"], \"layout_archetype\": \"qa_session\", \"layout_variant\": \"a\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p06_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:06:57.190718\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 01:42:00', '2026-03-17 02:07:23', 'edu_qa_case', '{\"title\": \"矢量性与独立性详解\", \"subtitle\": \"力的方向决定加速度方向的分步解析。\", \"question\": \"当物体受多个共点力作用时，如何准确计算合加速度并避免方向判断错误？\", \"answer\": \"严格遵循矢量分解原则：选定正方向后，将各力沿坐标轴投影，分别列写 x、y 方向的牛顿第二定律方程，最后合成加速度矢量。\", \"analysis\": [{\"title\": \"正方向设定的规范性\", \"content\": \"以加速度方向或主要运动趋势为正方向，确保所有矢量符号（正负）在代数运算中逻辑自洽，杜绝随意设定导致的符号混乱。\"}, {\"title\": \"合力计算的误区规避\", \"content\": \"严禁直接对力的大小进行代数加减，必须基于矢量三角形法则或正交分解法求解合力，特别注意垂直方向力的平衡条件。\"}], \"conclusion\": \"矢量性是动力学的灵魂：方向即本质，分解即解法。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"qa_session\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7b2b6e7e-ffff-4444-a9b8-e7ddc5b48ee4', 'd7c36534-7285-4cae-8238-824e62b67e0f', 1, NULL, '{\"page_id\": \"p02\", \"title\": \"课程导航：从现象到本质的探索\", \"layout_id\": \"edu_toc\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p01\"], \"must_cover\": [\"五大模块概览\", \"课程导航：从现象到本质的探索的核心概念与背景\", \"课程导航：从现象到本质的探索的关键方法与执行要点\", \"课程导航：从现象到本质的探索的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"课程导航：从现象到本质的探索的核心概念与背景\", \"课程导航：从现象到本质的探索的关键方法与执行要点\", \"课程导航：从现象到本质的探索的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"toc\", \"layout_variant\": \"b\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-19 01:41:34', '2026-03-19 01:41:34', 'edu_toc', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7b6c7249-b5b5-48bf-8eef-7ebfadf3d44c', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef', 2, '第一部分：核心概念', '{\"page_id\": \"p03\", \"title\": \"什么是3D建模：定义与核心价值\", \"part\": \"第一部分：核心概念\", \"points\": [\"基于XYZ轴构建三维空间坐标系，确立物体在虚拟环境中的位置、旋转与缩放基准\", \"通过数字化几何体连接虚拟创意与现实需求，实现从抽象构思到可视化的精准转化\", \"在游戏开发中构建沉浸式场景，在影视制作中生成特效资产，在工业制造中完成原型验证\"]}', '{\"text\": \"页面标题：什么是3D建模：定义与核心价值\\n\\n页面文字：\\n- 基于XYZ轴构建三维空间坐标系，确立物体在虚拟环境中的位置、旋转与缩放基准。\\n- 通过数字化几何体连接虚拟创意与现实需求，实现从抽象构思到可视化成果的精准转化。\\n- 在游戏开发中构建沉浸式场景，在影视制作中生成特效资产，在工业制造中完成原型验证，最终推动行业创新。\", \"generated_at\": \"2026-03-10T05:38:52.044269\"}', NULL, 'GENERATING', '2026-03-10 05:38:23', '2026-03-10 05:38:57', NULL, NULL);
