INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7c8e51f8-3836-4816-b84a-1ca51f14bcb9', '4e889981-954e-4263-b490-230183b1a644', 14, NULL, '{\"page_id\": \"p15\", \"title\": \"综合实训：多机协同调试挑战\", \"layout_id\": \"vocational_step_by_step\", \"has_image\": true, \"keywords\": [\"多台机器人协同\", \"复杂流水线\", \"团队协作手势\", \"监控大屏\", \"紧张而有序的现场\"], \"depends_on\": [\"p13\"], \"must_cover\": [\"步骤：多轴同步性计算\", \"步骤：联合负载惯性匹配\", \"检查：系统响应一致性\", \"综合实训：多机协同调试挑战的核心概念与背景\", \"综合实训：多机协同调试挑战的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"综合实训：多机协同调试挑战的核心概念与背景\", \"综合实训：多机协同调试挑战的关键方法与执行要点\", \"综合实训：多机协同调试挑战的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"process_steps\", \"layout_variant\": \"a\", \"logical_page_id\": \"p15\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:45:02.425035\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:44:28', '2026-03-19 01:37:30', 'vocational_step_by_step', '{\"title\": \"综合实训：多机协同调试挑战\", \"steps\": [{\"title\": \"步骤一：多轴同步性计算\", \"label\": \"STEP 01\", \"desc\": \"依据各轴负载质量与目标速度，利用F=ma公式分别计算所需推力，校核总功率裕量，确保主从轴力矩分配无冲突。\"}, {\"title\": \"步骤二：联合负载惯性匹配\", \"label\": \"STEP 02\", \"desc\": \"模拟流水线突发加减速工况，调整各变频器惯量比参数，消除因机械连接导致的相位差与震荡风险，提升整体协调性。\"}, {\"title\": \"步骤三：系统响应一致性检查\", \"label\": \"STEP 03\", \"desc\": \"执行标准节拍测试，观察电机波形与位置误差，确认所有节点在变负载下均满足±0.5mm定位精度要求，保证产品质量。\"}], \"layout_variant\": \"a\", \"variant\": \"a\", \"layout_archetype\": \"process_steps\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7c92561d-4fe8-40ca-b82d-b534d4ee2ae0', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 4, NULL, '{\"page_id\": \"p04\", \"title\": \"现状痛点与学习目标对比\", \"layout_id\": \"edu_tri_compare\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p03\"], \"must_cover\": [\"新手常见误区\", \"行业需求差异\", \"现状痛点与学习目标对比的核心概念与背景\", \"现状痛点与学习目标对比的关键方法与执行要点\", \"现状痛点与学习目标对比的应用场景与注意事项\"], \"promises_open\": [{\"promise_id\": \"pr_practice_1\", \"text\": \"具体的操作流程拆解\", \"must_cover\": [\"建模步骤\", \"软件工作流\"], \"target_page_ids\": [\"p26\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"现状痛点与学习目标对比的核心概念与背景\", \"现状痛点与学习目标对比的关键方法与执行要点\", \"现状痛点与学习目标对比的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p05\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_compare\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T13:04:03.227647\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'edu_tri_compare', '{\"title\": \"现状痛点与学习目标对比\", \"left\": {\"header\": \"现状痛点\", \"content\": [\"当前学习普遍存在碎片化问题，脱离实际应用。\"], \"bullets\": [{\"icon\": \"fa-exclamation-triangle\", \"text\": \"新手误区：仅重工具操作，忽略底层原理。\", \"description\": \"解释新手误区：仅重工具操作，忽略底层原理在现状痛点维度下的意义。\"}, {\"icon\": \"fa-eye-slash\", \"text\": \"认知偏差：忽视国家战略背景的重要性。\", \"description\": \"解释认知偏差：忽视国家战略背景的重要性在现状痛点维度下的意义。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"需求错位：未对标工业级高精度标准。\", \"description\": \"解释需求错位：未对标工业级高精度标准在现状痛点维度下的意义。\"}, {\"icon\": \"fa-cogs\", \"text\": \"落地困难：缺乏工程化全流程思维。\", \"description\": \"解释落地困难：缺乏工程化全流程思维在现状痛点维度下的意义。\"}]}, \"right\": {\"header\": \"学习目标\", \"content\": [\"目标需指向实战能力转化与国产软件适配。\", \"结论：现状痛点与学习目标对比需要结合目标场景做取舍。\"], \"bullets\": [{\"icon\": \"fa-brain\", \"text\": \"掌握核心算法逻辑基础与三维构建。\", \"description\": \"解释掌握核心算法逻辑基础与三维构建在学习目标维度下的意义。\"}, {\"icon\": \"fa-flag-checkered\", \"text\": \"理解国产软件替代路径与发展趋势。\", \"description\": \"解释理解国产软件替代路径与发展趋势在学习目标维度下的意义。\"}, {\"icon\": \"fa-tasks\", \"text\": \"达成国防级建模精度与交付要求。\", \"description\": \"解释达成国防级建模精度与交付要求在学习目标维度下的意义。\"}, {\"icon\": \"fa-lightbulb\", \"text\": \"构建自主创新解决问题能力体系。\", \"description\": \"解释构建自主创新解决问题能力体系在学习目标维度下的意义。\"}]}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_compare\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7cf18fb2-06da-44f0-bc24-b84ba869f6d7', '1d063203-8ece-436a-ad39-9501e3c7e06b', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"故障排除：比例失调与重缩放\", \"layout_id\": \"common_faults\", \"has_image\": true, \"keywords\": [\"巨大模型对比\", \"微小模型对比\", \"单位换算图示\", \"重置变换操作\", \"坐标轴校准\"], \"depends_on\": [\"p10\"], \"must_cover\": [\"世界坐标重置\", \"局部缩放陷阱\", \"实例化对象影响\", \"导入导出单位转换\", \"故障排除：比例失调与重缩放的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p08_1\"], \"points\": [\"故障排除：比例失调与重缩放的核心概念与背景\", \"故障排除：比例失调与重缩放的关键方法与执行要点\", \"故障排除：比例失调与重缩放的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p08_1\"], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p08_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-20T01:09:55.819923\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-20 01:09:17', '2026-03-20 01:09:56', 'common_faults', '{\"title\": \"故障排除：比例失调与重缩放\", \"left\": {\"header\": \"比例陷阱视觉对比\", \"content\": [\"故障排除：比例失调与重缩放在比例陷阱视觉对比下的核心结论与适用条件。\"], \"bullets\": []}, \"right\": {\"header\": \"坐标重置与单位校准\", \"content\": [\"局部缩放会破坏物理引擎计算，必须执行“应用变换”将世界坐标重置为标准单位系统。\", \"结论：故障排除：比例失调与重缩放需要结合目标场景做取舍。\"], \"bullets\": [{\"icon\": \"fa-ruler-combined\", \"text\": \"导入导出陷阱：不同软件单位制转换导致的尺寸偏差。\", \"description\": \"解释导入导出陷阱：不同软件单位制转换导致的尺寸偏差在坐标重置与单位校准维度下的意义。\"}, {\"icon\": \"fa-expand-arrows-alt\", \"text\": \"实例化对象影响：缩放实例会导致材质偏移与光照失真。\", \"description\": \"解释实例化对象影响：缩放实例会导致材质偏移与光照失真在坐标重置与单位校准维度下的意义。\"}, {\"icon\": \"fa-undo\", \"text\": \"世界坐标重置：清除非均匀缩放数据以恢复原始比例。\", \"description\": \"解释世界坐标重置：清除非均匀缩放数据以恢复原始比例在坐标重置与单位校准维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7d084297-fe74-4953-9a36-3bd38b8b9965', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 24, NULL, '{\"page_id\": \"p19\", \"title\": \"思政第二课：工匠精神与数字行业伦理\", \"layout_id\": \"edu_qa_case\", \"has_image\": true, \"keywords\": [\"天平图标\", \"版权保护符号\", \"团队协作剪影\"], \"depends_on\": [\"p18\"], \"must_cover\": [\"知识产权尊重\", \"原创精神培养\", \"数据安全与合规\", \"思政第二课的核心概念与背景\", \"思政第二课的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"思政第二课的核心概念与背景\", \"思政第二课的关键方法与执行要点\", \"思政第二课的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p25\", \"layout_variant\": \"a\", \"layout_archetype\": \"qa_session\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T12:17:13.187735\"}', NULL, 'FAILED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'edu_qa_case', '{\"title\": \"数字创作伦理准则\", \"question\": \"项目使用素材如何规避侵权风险？\", \"answer\": \"核对授权许可，商用购正版，练习注出处。\", \"analysis\": [{\"title\": \"版权与原创\", \"content\": \"尊重知识产权，坚持原创精神，禁止抄袭挪用。\"}, {\"title\": \"安全与执行\", \"content\": \"落实数据安全合规，严格执行行业伦理执行要点。\"}], \"conclusion\": \"守正创新，做有温度的数字工匠。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"qa_session\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7d49dc77-18e7-4152-9fa3-5bb5cf0a33e6', 'faba4721-d6bc-47a9-847e-395b2a603584', 11, NULL, '{\"page_id\": \"p12\", \"title\": \"安全机制：零信任架构集成\", \"layout_id\": \"title_bullets\", \"has_image\": true, \"keywords\": [\"安全机制：零信任架构集成\", \"场景示意\", \"视觉辅助\"], \"depends_on\": [\"p11\"], \"must_cover\": [\"身份认证要求\", \"数据传输加密\", \"访问控制列表\", \"安全机制：零信任架构集成的核心概念与背景\", \"安全机制：零信任架构集成的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"安全机制：零信任架构集成的核心概念与背景\", \"安全机制：零信任架构集成的关键方法与执行要点\", \"安全机制：零信任架构集成的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p12\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:24:32.582389\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:23:02', '2026-03-10 06:59:06', 'title_bullets', '{\"title\": \"安全机制：零信任架构集成\", \"subtitle\": \"构建全域可信的计算边界。\", \"bullets\": [{\"icon\": \"fa-shield-alt\", \"text\": \"动态身份认证。\", \"description\": \"摒弃传统静态边界，实施基于设备指纹、行为分析与上下文感知的多因子动态认证，确保每一次访问请求均经过实时校验。\"}, {\"icon\": \"fa-lock\", \"text\": \"端到端加密传输。\", \"description\": \"全链路采用国密算法与TLS 1.3混合加密体系，对数据传输进行量子抗性封装，防止中间人攻击与数据窃听。\"}, {\"icon\": \"fa-user-clock\", \"text\": \"最小权限访问控制。\", \"description\": \"基于RBAC与ABAC模型的动态访问控制列表，仅授予任务执行所需的瞬时最小权限，杜绝横向移动风险。\"}, {\"icon\": \"fa-network-wired\", \"text\": \"微隔离网络架构。\", \"description\": \"将系统划分为数千个逻辑微域，通过软件定义网络（SDN）实现服务间流量的精细化管控与可视化管理。\"}, {\"icon\": \"fa-bug\", \"text\": \"持续威胁监测。\", \"description\": \"集成AI驱动的行为分析引擎，实时扫描流量异常与潜在漏洞，实现从被动防御向主动预测性安全的转变。\"}], \"keyTakeaway\": \"零信任架构通过‘永不信任，始终验证’原则，将安全内嵌于每一行代码与每一次交互中。\", \"image\": {\"src\": \"\", \"alt\": \"科技感十足的盾牌图标环绕着发光的网络连接节点，背景为深色网格与流动的数据线，无文字数字\", \"position\": \"right\", \"width\": \"35%\"}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7d9706b1-337b-46ac-9a1c-da9e483c8b89', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 18, '第二部分：思维重塑与底层逻辑', '{\"title\": \"总结与答疑\", \"points\": [\"核心结论：3D建模专业实战体系：从理论认知到商业交付的关键认知与边界\", \"行动建议：下一步如何落地与评估效果\", \"开放答疑：常见问题与延伸讨论方向\"], \"layout_id\": \"edu_core_hub\", \"part\": \"第二部分：思维重塑与底层逻辑\", \"logical_page_id\": \"p19\", \"has_image\": false, \"keywords\": [\"核心结论：3D建模专业实战体系：从理论认知到商业交付的关键认知与边界\", \"行动建议：下一步如何落地与评估效果\", \"开放答疑：常见问题与延伸讨论方向\"], \"depends_on\": [\"p18\"], \"must_cover\": [\"核心结论：3D建模专业实战体系：从理论认知到商业交付的关键认知与边界\", \"行动建议：下一步如何落地与评估效果\", \"开放答疑：常见问题与延伸讨论方向\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"a\", \"layout_archetype\": \"core_model\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.419252\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:53', 'edu_core_hub', '{\"title\": \"3D建模实战体系：从理论到交付的闭环\", \"subtitle\": \"核心认知边界与落地评估路径。\", \"center_label\": \"商业交付能力\", \"nodes\": [{\"title\": \"理论认知重构\"}, {\"title\": \"空间坐标基准\"}, {\"title\": \"工作流标准化\"}, {\"title\": \"效果量化评估\"}], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"core_model\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7dbbf52b-3b6e-4752-8e6c-e2c44c0702af', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 3, '基础准备', '{\"page_id\": \"p03\", \"title\": \"主流建模软件对比分析\", \"part\": \"基础准备\", \"points\": [\"Blender：全功能开源免费，社区插件丰富，适合独立创作者与初学者入门\", \"Maya/3ds Max：行业标准软件，在影视特效与大型游戏开发中占据主导地位\", \"C4D：以操作流畅著称，是广告设计与动态图形（Motion Graphics）的首选工具\", \"决策建议：根据职业目标选择软件，初学者可从 Blender 切入降低学习成本\"]}', '{\"text\": \"页面标题：主流建模软件对比分析\\n\\n页面文字：\\n- Blender作为全功能开源软件，凭借丰富社区插件成为独立创作者与初学者的首选入门工具。\\n- Maya与3ds Max占据影视特效及大型游戏开发主导地位，是行业标准的专业级解决方案。\\n- C4D以操作流畅著称，在广告设计与动态图形领域拥有不可替代的广泛应用场景。\\n- 建议根据职业目标选择软件，初学者可从Blender切入以有效降低学习成本与试错风险。\", \"generated_at\": \"2026-03-09T03:39:37.774078\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/7dbbf52b-3b6e-4752-8e6c-e2c44c0702af_v1.png', 'COMPLETED', '2026-03-09 03:39:12', '2026-03-09 03:40:39', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7e236251-b0c2-4da9-915f-17d30e392507', '2786117f-f122-459a-8310-c05a2077848b', 6, NULL, '{\"page_id\": \"p07\", \"title\": \"理实结合：不同场景下的选型策略\", \"layout_id\": \"edu_tri_compare\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p05\", \"p06\"], \"must_cover\": [\"痛点分析：夹持 vs 吸附\", \"行动指南：如何根据材质/形状选择\", \"目标达成：效率与成本的平衡\", \"理实结合：不同场景下的选型策略的核心概念与背景\", \"理实结合：不同场景下的选型策略的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"理实结合：不同场景下的选型策略的核心概念与背景\", \"理实结合：不同场景下的选型策略的关键方法与执行要点\", \"理实结合：不同场景下的选型策略的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_compare\", \"layout_variant\": \"a\", \"logical_page_id\": \"p07\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:02:17.155301\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:01:22', '2026-03-19 06:02:17', 'edu_tri_compare', '{\"title\": \"理实结合：不同场景下的选型策略\", \"badge\": \"效率与成本平衡\", \"columns\": [{\"title\": \"夹持式执行器\", \"points\": [\"机械接触结构，依赖摩擦力或形状定位\", \"适用于不规则、多孔或高硬度材质\", \"需考虑夹持力控制以防损伤工件表面\"]}, {\"title\": \"吸附式执行器\", \"points\": [\"真空负压原理，非接触式柔性搬运\", \"专攻光滑、平整且气密性良好的板材\", \"换型便捷，适合多品种小批量混线生产\"]}, {\"title\": \"混合选型策略\", \"points\": [\"复杂曲面优先夹持，薄板平面首选吸附\", \"高节拍场景采用复合工具实现双重稳定\", \"依据材质透气性与表面粗糙度动态决策\"]}], \"background_image\": \"https://images.unsplash.com/photo-1581092160562-40aa08e78837\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_compare\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7e8c5fbe-7188-4f10-8701-dd26a89d04fc', 'b494fc12-8d48-4b4c-8717-9faa745d5f79', 16, NULL, '{\"page_id\": \"p17\", \"title\": \"即时反馈：你选择哪种烘焙方案？\", \"layout_id\": \"feedback_poll\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p14\"], \"must_cover\": [\"方案A优缺点\", \"方案B优缺点\", \"决策依据\", \"即时反馈：你选择哪种烘焙方案？的核心概念与背景\", \"即时反馈：你选择哪种烘焙方案？的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"即时反馈：你选择哪种烘焙方案？的核心概念与背景\", \"即时反馈：你选择哪种烘焙方案？的关键方法与执行要点\", \"即时反馈：你选择哪种烘焙方案？的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-08 02:23:20', '2026-03-08 02:23:20', 'feedback_poll', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7e9559d8-bb34-41ad-8543-007aeb781760', '8a37f529-e51f-428c-8466-cdc137b73187', 10, NULL, '{\"title\": \"实战任务：复杂模型UV布局规划：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"academic_narrative\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p11\", \"depends_on\": [\"p10\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.107726\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'academic_narrative', '{\"title\": \"案例复盘：装甲角色UV布局优化\", \"narrative\": [\"问题与场景：某机械战士模型因装甲板数量多、曲率变化大，导致自动展开后出现严重拉伸，且UV空间浪费率达40%，无法支撑高精度纹理贴图。\", \"方案与执行：采用分段式切缝策略，沿装甲接缝处切断非关键区域；对曲面部分应用角度加权算法进行局部重映射，并手动微调岛屿间距以消除缝隙。\", \"结果与启示：最终拉伸误差控制在3%以内，空间利用率提升至92%；经验表明，混合拓扑模型需分区域制定UV策略，不可一概而论。\"], \"margin_notes\": [{\"title\": \"核心概念：测地线切缝\", \"content\": \"沿三维表面最短路径切割，可最大限度减少展开后的几何畸变。\"}, {\"title\": \"风险提示\", \"content\": \"过度追求紧凑可能导致接缝错位，需在渲染测试中验证。\"}], \"pull_quote\": \"UV布局的本质是三维信息向二维平面的无损（或可控损耗）投影，而非简单的图形拼贴。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7ec30dcb-ca44-4666-a8d6-77d7ea989bb8', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 19, NULL, '{\"page_id\": \"p20\", \"title\": \"学习资源推荐与进阶路径\", \"layout_id\": \"group_collab\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p18\"], \"must_cover\": [\"官方文档链接\", \"优质教程网站\", \"插件工具包\", \"社区交流渠道\", \"学习资源推荐与进阶路径的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"学习资源推荐与进阶路径的核心概念与背景\", \"学习资源推荐与进阶路径的关键方法与执行要点\", \"学习资源推荐与进阶路径的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p20\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928891\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'group_collab', '{\"title\": \"学习资源推荐与进阶路径\", \"subtitle\": \"构建你的工业化建模知识体系。\", \"bullets\": [{\"icon\": \"fa-book\", \"text\": \"官方文档与规范。\", \"description\": \"深入阅读Autodesk及Blender官方文档，掌握PBR标准与拓扑规范，确保资产符合工业交付要求。\"}, {\"icon\": \"fa-video\", \"text\": \"优质教程网站。\", \"description\": \"推荐CGSociety与ArtStation精选课程，重点学习角色变形控制与复杂场景的光影叙事技巧。\"}, {\"icon\": \"fa-plug\", \"text\": \"插件工具包。\", \"description\": \"集成TopoGun与SpeedTree等高效插件，提升布线效率与植被生成速度，缩短项目周期。\"}, {\"icon\": \"fa-users\", \"text\": \"社区交流渠道。\", \"description\": \"加入专业3D论坛与Discord群组，参与技术研讨，获取最新渲染器优化方案与避坑指南。\"}, {\"icon\": \"fa-chart-line\", \"text\": \"进阶路径建议。\", \"description\": \"从基础拓扑入手，逐步掌握材质节点逻辑，最终实现从模型构建到光影渲染的全流程掌控。\"}], \"keyTakeaway\": \"系统化整合官方规范、工具链与社区资源，是突破个人瓶颈、迈向工业化生产的关键。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7ecabf3c-1609-4649-a712-1b09da0c0cb9', '130ea17c-c678-4285-8c4c-06b099d8fa71', 15, NULL, '{\"page_id\": \"p16\", \"title\": \"课程复盘与思维升华\", \"layout_id\": \"edu_summary\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p14\"], \"must_cover\": [\"三点式复盘\", \"结语收束\", \"未来展望\", \"课程复盘与思维升华的核心概念与背景\", \"课程复盘与思维升华的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p11_1\"], \"points\": [\"课程复盘与思维升华的核心概念与背景\", \"课程复盘与思维升华的关键方法与执行要点\", \"课程复盘与思维升华的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p11_1\"], \"layout_archetype\": \"summary_reflection\", \"layout_variant\": \"b\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p11_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:15:52.391123\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 02:14:48', '2026-03-17 10:27:43', 'edu_summary', '{\"title\": \"课程复盘与思维升华\", \"columns\": [{\"title\": \"知识闭环复盘\", \"points\": [\"从惯性保护到推力加速的工程实践，完成牛顿定律的现实映射。\", \"通过卡车货物受力分析，掌握复杂场景下的方程求解核心方法。\"]}, {\"title\": \"思维模型跃迁\", \"points\": [\"将物理公式推导转化为通用工程语言，构建从理论到实践的闭环。\", \"确立以摩擦力为约束条件的动态平衡思维，提升系统分析能力。\"]}, {\"title\": \"未来行动展望\", \"points\": [\"运用三点式复盘法，持续优化个人在复杂系统中的决策逻辑。\", \"将课堂习得的力学思维迁移至生活场景，实现知行合一的进阶。\"]}], \"closing\": \"结语：物理不仅是公式的推演，更是理解世界运行规律的思维钥匙。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"summary_reflection\"}');
