INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7f070f44-13ff-4448-9d03-692e14ca9c89', '9b5d83ef-2600-4c3b-b852-00607680277d', 10, '应用价值', '{\"page_id\": \"p09\", \"title\": \"行业影响：重塑内容生产与工作流\", \"part\": \"应用价值\", \"points\": [\"生成式AI实现文案、代码与视觉素材的自动化批量生产，显著提升创意产出效率\", \"个性化教育辅导与智能客服系统成为行业标准配置，推动服务体验从通用化向定制化转型\", \"企业级应用加速从概念验证走向规模化落地，深度重构研发、营销与运营核心工作流\"]}', '{\"text\": \"页面标题：行业影响：重塑内容生产与工作流\\n\\n页面文字：\\n- 生成式AI实现文案、代码与视觉素材自动化批量生产，显著提升创意产出效率。\\n- 个性化教育辅导与智能客服系统成为行业标准配置，推动服务体验从通用化向定制化转型。\\n- 企业级应用加速从概念验证走向规模化落地，深度重构研发、营销与运营核心工作流。\", \"generated_at\": \"2026-03-09T08:14:14.326505\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/7f070f44-13ff-4448-9d03-692e14ca9c89_v1.png', 'FAILED', '2026-03-09 08:13:54', '2026-03-09 09:20:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7f7fced4-d1a1-45c9-badb-c59ef54e09ba', '4e889981-954e-4263-b490-230183b1a644', 15, NULL, '{\"page_id\": \"p16\", \"title\": \"课堂总结与课后实训工单\", \"layout_id\": \"vocational_summary_homework\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p14\"], \"must_cover\": [\"核心结论：F=ma是调试的基石\", \"课后任务：撰写《传送带参数计算书》\", \"下节预告：摩擦力对净力的影响\", \"课堂总结与课后实训工单的核心概念与背景\", \"课堂总结与课后实训工单的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p01_1\", \"pr_p01_2\", \"pr_p10_1_dedd06ac\"], \"points\": [\"课堂总结与课后实训工单的核心概念与背景\", \"课堂总结与课后实训工单的关键方法与执行要点\", \"课堂总结与课后实训工单的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_1\", \"pr_p01_2\", \"pr_p10_1_dedd06ac\"], \"layout_archetype\": \"summary_reflection\", \"layout_variant\": \"a\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p01_1\", \"pr_p01_2\", \"pr_p10_1_dedd06ac\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:45:02.425076\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:44:28', '2026-03-19 01:37:30', 'vocational_summary_homework', '{\"title\": \"课堂总结与课后实训工单\", \"summary\": [\"核心结论：F=ma是解决设备加减速异常与变负载调试的基石，需将静态公式转化为实时响应策略，指导现场参数整定。\", \"案例启示：通过传感器融合与自适应算法重构参数，成功解决包装机组在波动工况下的定位精准度问题，提升生产效率。\"], \"homework\": \"撰写《传送带参数计算书》：基于今日实训数据，完成不同负载工况下的质量、摩擦力及加速度计算，并制定PID自整定方案，形成完整的技术文档。\", \"deadline\": \"下节课课前提交（24:00前）\", \"layout_variant\": \"a\", \"variant\": \"a\", \"layout_archetype\": \"summary_reflection\"}');
