INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('80b9de44-9e64-44e3-99bf-3cb8fc9e4ddb', '7a4f3408-ca73-4a61-998e-174a92497610', 16, NULL, '{\"page_id\": \"p17\", \"title\": \"金句回顾：工匠精神的数字化表达\", \"layout_id\": \"feedback_poll\", \"has_image\": true, \"keywords\": [\"暖色调光影\", \"专注的手部特写\", \"数字建模界面虚化\", \"极简排版留白\", \"激励性氛围\"], \"depends_on\": [\"p15\"], \"must_cover\": [\"质量意识\", \"迭代思维\", \"职业信念\", \"金句回顾：工匠精神的数字化表达的核心概念与背景\", \"金句回顾：工匠精神的数字化表达的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p09_1_6aa9e5d0\", \"pr_p01_1\", \"pr_p01_2\", \"pr_p04_1\", \"pr_p07_1\"], \"points\": [\"金句回顾：工匠精神的数字化表达的核心概念与背景\", \"金句回顾：工匠精神的数字化表达的关键方法与执行要点\", \"金句回顾：工匠精神的数字化表达的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p09_1_6aa9e5d0\", \"pr_p01_1\", \"pr_p01_2\", \"pr_p04_1\", \"pr_p07_1\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p17\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p09_1_6aa9e5d0\", \"pr_p01_1\", \"pr_p01_2\", \"pr_p04_1\", \"pr_p07_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.267444\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:01', 'feedback_poll', '{\"title\": \"金句回顾：工匠精神的数字化表达\", \"content\": [\"从精密仪器外壳的复盘到多边形建模的拓扑逻辑，每一次迭代都是对质量意识的坚守。\", \"在参数化与非参数化的选择中，以职业信念驱动细节刻画，实现从分块思路到最终渲染的完美闭环。\"], \"highlight\": \"工匠精神不是重复劳动，而是对每一个顶点、每一条边线的极致负责。\", \"image\": {\"src\": \"\", \"alt\": \"暖色调光影下的专注手部特写，背景虚化为数字建模界面，极简排版留白\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
