INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('85e91374-dc8e-45b4-a252-d1655e313ef7', '8a37f529-e51f-428c-8466-cdc137b73187', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"第一章：多边形建模的底层逻辑\", \"layout_id\": \"diagram_illustration\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p03\"], \"must_cover\": [\"章节引入\", \"核心概念界定\", \"第一章：多边形建模的底层逻辑的核心概念与背景\", \"第一章：多边形建模的底层逻辑的关键方法与执行要点\", \"第一章：多边形建模的底层逻辑的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第一章：多边形建模的底层逻辑的核心概念与背景\", \"第一章：多边形建模的底层逻辑的关键方法与执行要点\", \"第一章：多边形建模的底层逻辑的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.107452\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'diagram_illustration', '{\"title\": \"原理图解：多边形建模底层逻辑\", \"subtitle\": \"从几何定义到拓扑流形。\", \"explanations\": [{\"label\": \"顶点与法线 (Vertex & Normal)\", \"description\": \"构建空间坐标基础，法线方向决定光照计算与表面平滑度，是渲染计算的原始数据源。\"}, {\"label\": \"边与面连接 (Edge & Face Connectivity)\", \"description\": \"定义网格的拓扑结构，边的数量直接约束面的形状，形成封闭或开放的流形几何体。\"}, {\"label\": \"UV映射基底 (UV Mapping Base)\", \"description\": \"将三维曲面展开为二维参数空间，确保纹理坐标与几何拓扑一一对应，避免拉伸变形。\"}], \"summary\": \"多边形建模并非简单的堆砌，而是基于图论的流形构建过程；核心在于维持拓扑连续性以支持后续变形与材质投射。\", \"diagram_url\": \"https://example.com/3d_topology_diagram.png\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
