INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('8720ef38-1560-461c-879b-7a50dc641c71', '6eea18f8-c641-48a1-ba84-4c49ed3830d6', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"案例复盘：极端场景下的稳定性测试\", \"layout_id\": \"edu_qa_case\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"测试场景描述\", \"异常处理逻辑\", \"最终结论启示\", \"案例复盘：极端场景下的稳定性测试的核心概念与背景\", \"案例复盘：极端场景下的稳定性测试的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p12_1\", \"text\": \"未来扩展方向与潜在风险预判\", \"must_cover\": [\"AI 融合趋势\", \"安全边界挑战\"], \"target_page_ids\": [\"p19\"], \"is_hard\": true}, {\"promise_id\": \"pr_p10_2_40ae35dc\", \"text\": \"案例复盘：极端场景下的稳定性测试的复盘与结果启示\", \"must_cover\": [\"案例复盘\", \"结果启示\"], \"target_page_ids\": [\"p19\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"案例复盘：极端场景下的稳定性测试的核心概念与背景\", \"案例复盘：极端场景下的稳定性测试的关键方法与执行要点\", \"案例复盘：极端场景下的稳定性测试的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"qa_session\", \"layout_variant\": \"a\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:27:09.079659\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:25:46', '2026-03-10 06:27:09', 'edu_qa_case', '{\"title\": \"案例复盘：极端场景下的稳定性测试\", \"subtitle\": \"从算力孤岛到系统韧性的极限验证。\", \"question\": \"在突发流量洪峰与异构硬件故障并发的极端场景下，如何保障核心服务零中断？\", \"answer\": \"构建“感知 - 隔离 - 自愈”三级防御体系，通过动态资源熔断与跨节点智能调度，实现毫秒级异常响应与自动恢复。\", \"analysis\": [{\"title\": \"极端场景描述\", \"content\": \"模拟双路供电失效叠加300%瞬时流量冲击，触发传统架构的级联雪崩效应，暴露算力孤岛导致的资源僵化问题。\"}, {\"title\": \"异常处理逻辑\", \"content\": \"部署自适应熔断机制切断非核心链路，利用分布式共识算法将负载实时迁移至健康节点，确保关键业务连续性。\"}], \"conclusion\": \"唯有打破算力壁垒，建立弹性架构，方能在极端不确定性中铸就确定性稳定。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"qa_session\"}');
