INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('87448715-77af-446e-a9b4-8b992edf1558', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d', 2, '导览', '{\"title\": \"目录：课程核心架构：案例复盘\", \"points\": [\"深度剖析典型案例的业务痛点与数据特征\", \"拆解从数据清洗到模型部署的全链路执行策略\", \"量化评估项目成果并总结关键成功要素\", \"识别技术落地中的常见陷阱与风险防控机制\"], \"part\": \"导览\"}', '{\"text\": \"页面标题：目录：课程核心架构：案例复盘\\n\\n页面文字：\\n- 深度剖析典型案例的业务痛点并明确其数据特征以定位问题背景。\\n- 拆解从数据清洗到模型部署的全链路执行策略以指导具体方法动作。\\n- 量化评估项目成果并总结关键成功要素以形成明确的结论启示。\\n- 识别技术落地中的常见陷阱并建立风险防控机制以确保稳健运行。\", \"generated_at\": \"2026-03-16T05:37:22.205140\"}', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d/pages/87448715-77af-446e-a9b4-8b992edf1558_v2.png', 'COMPLETED', '2026-03-16 05:36:57', '2026-03-16 06:36:03', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('87b6864b-dd0e-4a34-a656-b2e314654013', '7a4f3408-ca73-4a61-998e-174a92497610', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"核心原理：拓扑结构与布线逻辑\", \"layout_id\": \"quiz_interaction\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p04\"], \"must_cover\": [\"四边形与三角形区别\", \"循环边与支撑边的作用\", \"布线对变形动画的影响\", \"核心原理：拓扑结构与布线逻辑的核心概念与背景\", \"核心原理：拓扑结构与布线逻辑的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p04_1\"], \"points\": [\"核心原理：拓扑结构与布线逻辑的核心概念与背景\", \"核心原理：拓扑结构与布线逻辑的关键方法与执行要点\", \"核心原理：拓扑结构与布线逻辑的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p04_1\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p04_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.266630\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:25', 'quiz_interaction', '{\"title\": \"核心原理：拓扑结构与布线逻辑\", \"subtitle\": \"决定模型变形质量与动画表现的关键因素。\", \"bullets\": [{\"icon\": \"fa-shapes\", \"text\": \"四边形与三角形区别。\", \"description\": \"四边形便于均匀细分与平滑变形，三角形易导致表面撕裂或凹陷。\"}, {\"icon\": \"fa-link\", \"text\": \"循环边与支撑边的作用。\", \"description\": \"循环边定义轮廓走向，支撑边控制局部曲率与硬度。\"}, {\"icon\": \"fa-video\", \"text\": \"布线对变形动画的影响。\", \"description\": \"错误的布线会导致肌肉挤压、骨骼扭曲等穿模现象。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"拓扑优化原则。\", \"description\": \"保持面数分布均匀，减少不必要的几何冗余。\"}], \"keyTakeaway\": \"合理的拓扑结构是高质量建模与流畅动画的基石，需严格遵循布线逻辑。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('87cacfee-7716-4cbe-a4c6-0b8c8a326763', '8a37f529-e51f-428c-8466-cdc137b73187', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"拓扑结构定义与规范\", \"layout_id\": \"academic_practice\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p04\"], \"must_cover\": [\"定义：什么是有效拓扑\", \"原理：流线与变形关系\", \"应用：角色动画适配\", \"拓扑结构定义与规范的核心概念与背景\", \"拓扑结构定义与规范的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p05_1\"], \"points\": [\"拓扑结构定义与规范的核心概念与背景\", \"拓扑结构定义与规范的关键方法与执行要点\", \"拓扑结构定义与规范的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p05_1\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p05\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p05_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.107476\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'academic_practice', '{\"title\": \"随堂实训：有效拓扑判定\", \"task_type\": \"task\", \"description\": \"请根据提供的模型截图，识别无效布线区域并规划优化路径。\", \"requirements\": [\"准确圈出非四边形（N-gon）及极点过多区域\", \"绘制流线走向草图，确保符合肌肉或机械运动趋势\", \"标注布线密度变化过渡区，避免突变导致动画撕裂\"], \"options\": [], \"hint\": \"评分关键点：是否识别出关节处的环状支撑结构，以及布线密度是否随曲率变化而调整。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
