INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('88448ff0-9890-41e7-ae36-1986f3ac6c7d', 'faba4721-d6bc-47a9-847e-395b2a603584', 17, NULL, '{\"page_id\": \"p18\", \"title\": \"关键技术指标预测\", \"layout_id\": \"two_column\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p15\"], \"must_cover\": [\"能效比提升预期\", \"并发规模上限\", \"延迟降低目标\", \"关键技术指标预测的核心概念与背景\", \"关键技术指标预测的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p15_1\"], \"points\": [\"关键技术指标预测的核心概念与背景\", \"关键技术指标预测的关键方法与执行要点\", \"关键技术指标预测的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p15_1\"], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p18\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p15_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:24:32.582559\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:23:03', '2026-03-10 06:24:33', 'two_column', '{\"title\": \"关键技术指标预测\", \"left\": {\"header\": \"能效与规模突破预期\", \"content\": [\"基于存算一体架构的深度优化，预计能效比提升 300%，并发处理规模将突破百万级节点限制。\"], \"bullets\": [{\"icon\": \"fa-chart-line\", \"text\": \"能效比提升：3.5x @ 2nm 工艺节点。\", \"description\": \"解释能效比提升：3.5x @ 2nm 工艺节点在能效与规模突破预期维度下的意义。\"}, {\"icon\": \"fa-server\", \"text\": \"并发上限：单集群 1,000,000+ 任务。\", \"description\": \"解释并发上限：单集群 1,000,000+ 任务在能效与规模突破预期维度下的意义。\"}, {\"icon\": \"fa-expand-arrows-alt\", \"text\": \"资源利用率：98% 峰值吞吐达成。\", \"description\": \"解释资源利用率：98% 峰值吞吐达成在能效与规模突破预期维度下的意义。\"}]}, \"right\": {\"header\": \"延迟与响应性能目标\", \"content\": [\"针对自动驾驶与工业质检场景，通过零拷贝通信与上下文切换优化，实现微秒级确定性低延迟。\", \"结论：关键技术指标预测需要结合目标场景做取舍。\"], \"bullets\": [{\"icon\": \"fa-stopwatch\", \"text\": \"端到端延迟：< 1ms (P99)。\", \"description\": \"解释端到端延迟：< 1ms (P99)在延迟与响应性能目标维度下的意义。\"}, {\"icon\": \"fa-tachometer-alt\", \"text\": \"上下文切换开销：降低 60%。\", \"description\": \"解释上下文切换开销：降低 60%在延迟与响应性能目标维度下的意义。\"}, {\"icon\": \"fa-shield-alt\", \"text\": \"故障恢复时间：< 50ms。\", \"description\": \"解释故障恢复时间：< 50ms在延迟与响应性能目标维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
