INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('897b11ab-8dba-4e21-9d17-6dad39a00f7f', 'ab2ec2c8-cb17-41e9-beb4-40c851abbea2', 6, NULL, '{\"page_id\": \"p07\", \"title\": \"章节一：原理深度解析\", \"layout_id\": \"edu_timeline_steps\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p06\"], \"must_cover\": [\"章节过渡\", \"原理深化引导\", \"章节一：原理深度解析的核心概念与背景\", \"章节一：原理深度解析的关键方法与执行要点\", \"章节一：原理深度解析的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"章节一：原理深度解析的核心概念与背景\", \"章节一：原理深度解析的关键方法与执行要点\", \"章节一：原理深度解析的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"timeline\", \"layout_variant\": \"a\", \"logical_page_id\": \"p07\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:06:57.190686\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 01:41:59', '2026-03-17 02:06:57', 'edu_timeline_steps', '{\"title\": \"推进步骤：原理深度解析\", \"subtitle\": \"从公式推导走向矢量与因果的深层逻辑。\", \"steps\": [{\"title\": \"概念重构与背景锚定\", \"description\": \"承接前序实验结论，将 F、m、a 的定量关系上升为矢量动力学模型，明确牛顿第二定律的适用边界。\", \"highlights\": [\"确立矢量分析框架\", \"界定瞬时作用范围\"]}, {\"title\": \"核心方法执行要点\", \"description\": \"针对复杂受力场景，建立分方向列方程的标准化解题路径，规避正方向设定与合力计算的常见误区。\", \"highlights\": [\"正方向规范设定\", \"合力矢量合成\"]}, {\"title\": \"应用场景与注意事项\", \"description\": \"解析变力作用下的动态过程，强调加速度随力变化的瞬时性，区分速度惯性与加速度突变的关系。\", \"highlights\": [\"变力动态分析\", \"惯性误区澄清\"]}], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"timeline\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('89f48922-0e30-4cc4-a27f-6f38b5285527', '6c250523-422a-46f3-a1f1-42e82424897c', 15, NULL, '{\"title\": \"案例分析：低模与高模的置换烘焙：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"academic_narrative\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p16\", \"depends_on\": [\"p15\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [{\"promise_id\": \"pr_p16_1_630fbd9d\", \"text\": \"案例分析：低模与高模的置换烘焙：案例复盘的复盘与结果启示\", \"must_cover\": [\"案例复盘\", \"结果启示\"], \"target_page_ids\": [\"p21\"], \"is_hard\": true}], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287073\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'academic_narrative', '{\"title\": \"案例分析：低模与高模的置换烘焙：案例复盘\", \"narrative\": [\"在游戏引擎部署中，核心矛盾在于实时渲染性能限制与影视级细节需求之间的冲突。本案例针对角色资产，通过构建高精度雕刻模型（高模）与优化拓扑的低多边形模型（低模），利用置换贴图技术将高模表面的微小凹凸、划痕等几何细节无损传递至低模表面，解决了面数受限下的视觉保真问题。\", \"执行过程中，关键决策在于建立精确的UV映射关系并设置合理的烘焙距离。通过法线贴图捕捉光影信息，配合置换贴图在着色器阶段动态生成微细几何形变，确保在不同光照角度下纹理一致且无拉伸。此流程实现了在不增加实际三角面数的情况下，显著提升资产细节表现力。\", \"经验表明，该工作流可复用至场景资产制作，但需警惕过度依赖导致显存占用过高。风险提示包括UV接缝处理不当引发的纹理断裂，以及烘焙精度不足造成的细节丢失，建议建立标准化的测试渲染环节以验证最终效果。\"], \"margin_notes\": [{\"title\": \"核心概念：置换烘焙\", \"content\": \"一种利用高度图（Height Map）驱动顶点位移的技术，使低模在渲染时呈现高模细节，兼顾性能与画质。\"}, {\"title\": \"技术边界\", \"content\": \"适用于静态或低动态变形物体；对于剧烈形变的角色动画，需结合蒙皮权重与骨骼绑定进行优化。\"}], \"pull_quote\": \"真正的效率提升不在于减少操作步数，而在于构建可回溯的数据关系，让每一次调整都基于底层逻辑而非重复劳动。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
