INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('8c1374ec-e063-4cd1-ad00-88b032fefd33', 'c3f4f20a-0839-4fb0-9375-125c6af13f37', 16, NULL, '{\"page_id\": \"p17\", \"title\": \"课程总结与回顾\", \"layout_id\": \"sk_ending\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p15\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"summary_reflection\", \"layout_variant\": \"b\", \"logical_page_id\": \"p17\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:04:18.361201\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:03:30', '2026-03-19 06:04:18', 'sk_ending', '{\"title\": \"课程总结与回顾\", \"summary_points\": [\"核心结论：掌握汽车产线焊接与搬运的情境痛点，明确真空吸附与机械夹持的适用边界及工程选型逻辑。\", \"行动建议：将标准化更换流程（断电、检气、紧固）转化为个人操作习惯，依据考核标准自我评估实训效果。\", \"结果启示：通过案例复盘与互动决策，理解安全规范是效率的前提，建立“风险预判-方案匹配-验证执行”的思维闭环。\"], \"actions\": [\"完成《末端工具更换SOP自查表》并签字归档\", \"撰写一份关于不同材质零件夹具选型的简短分析报告\"], \"next_step\": \"下节预告：自动化产线故障诊断与快速响应机制实战演练\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"summary_reflection\"}');
