INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('8f033926-8f47-4419-884d-c7de3113282b', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 2, '第一阶段', '{\"page_id\": \"p03\", \"title\": \"萌芽期：图灵、达特茅斯会议与早期构想\", \"part\": \"第一阶段\", \"points\": [\"1950年图灵发表《计算机器与智能》，提出“图灵测试”奠定机器思维哲学基石\", \"1956年达特茅斯会议汇聚学界精英，正式确立“人工智能”学科名称并开启探索纪元\", \"早期突破：逻辑理论家（Logic Theorist）等程序诞生，验证了机器模拟人类推理的可行性\", \"技术瓶颈：受限于当时硬件算力与存储能力，复杂模型无法训练，为后续寒冬埋下伏笔\"]}', '{\"text\": \"页面标题：萌芽期：图灵、达特茅斯会议与早期构想\\n\\n页面文字：\\n- 1950年图灵发表著作提出“图灵测试”，为机器思维奠定了坚实的哲学理论基础。\\n- 1956年达特茅斯会议汇聚学界精英，正式确立学科名称并开启长达数十年的探索纪元。\\n- 早期逻辑理论家程序诞生验证了机器模拟人类推理的可行性，但受限于算力无法训练复杂模型。\\n- 这一时期的硬件瓶颈为后续寒冬埋下伏笔，也促使研究者不断反思技术路径与突破方向。\", \"generated_at\": \"2026-03-09T08:54:47.422430\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:22', '2026-03-09 08:54:49', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('8f52f332-42b9-49c3-ac69-5f7d0b0f8185', '8ccaacf6-cf8f-4cd6-8ca8-7d5f28350c89', 1, NULL, '{\"page_id\": \"p02\", \"title\": \"目录：任务全流程导航\", \"layout_id\": \"vocational_toc\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p01\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"toc\", \"layout_variant\": \"a\", \"logical_page_id\": \"p02\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:41:09.847473\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:40:27', '2026-03-17 07:41:10', 'vocational_toc', '{\"title\": \"目录\", \"items\": [{\"index\": 1, \"text\": \"情景导入：传送带启动冲击故障。\"}, {\"index\": 2, \"text\": \"教学目标：知识、技能与素养。\"}, {\"index\": 3, \"text\": \"核心概念：F=ma在机电系统中的解析。\"}, {\"index\": 4, \"text\": \"实操步骤：加速度参数整定与调试。\"}, {\"index\": 5, \"text\": \"随堂测验：故障诊断与计算。\"}, {\"index\": 6, \"text\": \"总结回顾：从理论到实践的闭环。\"}, {\"index\": 7, \"text\": \"课后作业：撰写调试分析报告。\"}], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"toc\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('902045e2-eda5-485b-b1d1-f8d139fb49a6', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef', 10, '第三部分：案例实战', '{\"page_id\": \"p09\", \"title\": \"进阶挑战：参数化设计与实时引擎\", \"part\": \"第三部分：案例实战\", \"points\": [\"利用 Grasshopper 构建参数化逻辑，实现复杂形态的快速迭代与生成\", \"打通 PBR 材质流程，将高精度模型无缝集成至 Unity/Unreal 实时渲染环境\", \"实施 LOD 多细节层次策略，根据视距动态调整模型精度以优化性能\", \"探索程序化纹理与实例化技术，解决大规模场景的资源加载瓶颈\"]}', '{\"text\": \"页面标题：进阶挑战：参数化设计与实时引擎\\n\\n页面文字：\\n- 面对复杂形态迭代效率低的难题，利用Grasshopper构建参数化逻辑实现快速生成与多方案验证。\\n- 打通PBR材质全流程将高精度模型无缝集成至Unity或Unreal引擎，并实施LOD策略优化视距精度以提升性能。\\n- 探索程序化纹理与实例化技术有效解决大规模场景资源加载瓶颈，为实时渲染应用提供高效解决方案。\", \"generated_at\": \"2026-03-10T05:38:52.925728\"}', NULL, 'FAILED', '2026-03-10 05:38:39', '2026-03-10 05:38:58', NULL, NULL);
