INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('92e0cd36-f585-4120-bfb6-ecf3847c5280', 'e7189705-04c2-4928-8d6c-da2bacf02e42', 15, NULL, '{\"page_id\": \"p16\", \"title\": \"课堂总结与课后实训工单\", \"layout_id\": \"vocational_summary_homework\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p14\"], \"must_cover\": [\"F=ma核心结论回顾\", \"矢量性与瞬时性强调\", \"课后任务：设计简易测力装置\", \"课堂总结与课后实训工单的核心概念与背景\", \"课堂总结与课后实训工单的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p14_1_e95c4d3e\", \"pr_p15_1_a1695507\", \"pr_p04_1\"], \"points\": [\"课堂总结与课后实训工单的核心概念与背景\", \"课堂总结与课后实训工单的关键方法与执行要点\", \"课堂总结与课后实训工单的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p14_1_e95c4d3e\", \"pr_p15_1_a1695507\", \"pr_p04_1\"], \"layout_archetype\": \"summary_reflection\", \"layout_variant\": \"a\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p14_1_e95c4d3e\", \"pr_p15_1_a1695507\", \"pr_p04_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T01:36:50.689486\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 01:36:11', '2026-03-19 01:36:51', 'vocational_summary_homework', '{\"title\": \"课堂总结与课后实训工单\", \"summary\": [\"核心结论：F=ma是定量分析制动距离的基石，力与加速度呈正比，与质量呈反比。\", \"关键强调：牛顿第二定律具有矢量性（方向一致）与瞬时性（力变即变），需结合ABS系统平滑减速曲线。\"], \"homework\": \"设计简易测力装置：利用弹簧、刻度尺及已知质量块，构建可测量0-50N范围力的原型，并绘制校准曲线。\", \"deadline\": \"下周一实训课前提交实物模型及校准数据报告\", \"layout_variant\": \"a\", \"variant\": \"a\", \"layout_archetype\": \"summary_reflection\"}');
