INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('945c9947-f3cf-4dd3-8fa5-5a1ae2831e72', '9da12907-ffda-40fb-9be6-d245c93b1363', 13, '总结回顾', '{\"page_id\": \"p12\", \"title\": \"课后思考与实践作业布置\", \"part\": \"总结回顾\", \"points\": [\"选定工业或生物主题，独立完成从拓扑构建到渲染输出的全流程原创模型\", \"提交包含线框图、细分过程及最终效果图的对比报告，重点阐述优化思路\", \"研读指定行业案例文献，梳理不同建模流派在特定场景下的优劣对比\", \"整理课堂疑问与个人心得，作为下节课小组讨论的核心议题素材\"]}', '{\"text\": \"页面标题：课后思考与实践作业布置\\n\\n页面文字：\\n- 选定工业或生物主题，独立完成从拓扑构建到渲染输出的全流程原创模型。\\n- 提交包含线框图、细分过程及最终效果图的对比报告，重点阐述优化思路。\\n- 研读指定行业案例文献，梳理不同建模流派在特定场景下的优劣对比。\\n- 整理课堂疑问与个人心得，作为下节课小组讨论的核心议题素材。\", \"generated_at\": \"2026-03-10T06:06:00.887634\"}', NULL, 'FAILED', '2026-03-10 06:05:02', '2026-03-10 06:08:46', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('94b42633-6027-4bd1-ba63-39a0126424d4', '3ba66aac-bac2-4c02-b7f4-d1d534d00b1d', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"坐标系与空间定位基础\", \"layout_id\": \"edu_timeline_steps\", \"has_image\": true, \"keywords\": [\"XYZ轴示意图\", \"网格地面\", \"旋转操作图标\", \"蓝色与绿色辅助线\", \"科技感UI元素\"], \"depends_on\": [\"p04\"], \"must_cover\": [\"世界坐标系\", \"局部坐标系\", \"视图切换技巧\", \"坐标系与空间定位基础的核心概念与背景\", \"坐标系与空间定位基础的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"坐标系与空间定位基础的核心概念与背景\", \"坐标系与空间定位基础的关键方法与执行要点\", \"坐标系与空间定位基础的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"timeline\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:04:29', '2026-03-10 05:04:29', 'edu_timeline_steps', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('94b43a37-00f1-410c-bd7a-b1ffe69ae58a', '9da12907-ffda-40fb-9be6-d245c93b1363', 3, NULL, '{\"title\": \"课程导览与学习目标：案例复盘\", \"points\": [\"回顾上节课机械零件建模中因拓扑错误导致的变形失败场景，明确核心矛盾为布线逻辑与功能需求的冲突\", \"解析通过重新规划四边面流向及局部细分策略成功修复模型的执行过程与决策依据\", \"总结从错误诊断到方案落地的关键步骤，形成可复用的拓扑检查清单与风险规避经验\", \"引出本节课将重点梳理软件界面布局逻辑，确保学生能高效复用上述排查流程\"]}', '{\"text\": \"页面标题：课程导览与学习目标：案例复盘\\n\\n页面文字：\\n- 回顾上节课机械零件建模因拓扑错误导致的变形失败，明确核心矛盾在于布线逻辑与功能需求的冲突。\\n- 解析通过重新规划四边面流向及实施局部细分策略，成功修复模型并确立执行决策依据。\\n- 总结从错误诊断到方案落地的关键步骤，形成可复用的拓扑检查清单以规避未来风险。\\n- 引出本节课将重点梳理软件界面布局逻辑，确保学生能高效复用上述排查流程。\", \"generated_at\": \"2026-03-10T06:06:00.508775\"}', '9da12907-ffda-40fb-9be6-d245c93b1363/pages/94b43a37-00f1-410c-bd7a-b1ffe69ae58a_v1.png', 'COMPLETED', '2026-03-10 06:04:48', '2026-03-10 06:08:25', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('94b5f8be-1a8d-41bd-976a-56b73746382f', '6eea18f8-c641-48a1-ba84-4c49ed3830d6', 2, NULL, '{\"page_id\": \"p03\", \"title\": \"第一章：原点的困境与挑战\", \"layout_id\": \"edu_timeline_steps\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p02\"], \"must_cover\": [\"早期版本痛点\", \"行业瓶颈分析\", \"第一章：原点的困境与挑战的核心概念与背景\", \"第一章：原点的困境与挑战的关键方法与执行要点\", \"第一章：原点的困境与挑战的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第一章：原点的困境与挑战的核心概念与背景\", \"第一章：原点的困境与挑战的关键方法与执行要点\", \"第一章：原点的困境与挑战的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"timeline\", \"layout_variant\": \"b\", \"logical_page_id\": \"p03\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:27:09.079370\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:25:44', '2026-03-10 14:47:56', 'edu_timeline_steps', '{\"title\": \"第一章：原点的困境与挑战\", \"subtitle\": \"早期版本痛点与行业瓶颈深度剖析。\", \"steps\": [{\"title\": \"阶段一：早期原型局限\", \"description\": \"初代机械爪在极端深海高压环境下，存在结构强度不足、关节卡死及控制延迟严重等致命缺陷，导致作业成功率低于15%。\", \"highlights\": [\"材料疲劳断裂频发\", \"液压系统响应滞后\"]}, {\"title\": \"阶段二：行业共性瓶颈\", \"description\": \"传统工业标准无法适配深海复杂工况，缺乏模块化设计导致维护成本高昂，且无法兼容多类型传感器集成，形成技术孤岛。\", \"highlights\": [\"非标准化接口壁垒\", \"运维周期长达数月\"]}, {\"title\": \"阶段三：破局需求确立\", \"description\": \"面对能源开采与科研探测的双重压力，亟需一套具备高鲁棒性、可快速迭代且支持生态扩展的全新机械爪解决方案。\", \"highlights\": [\"建立自适应控制算法\", \"构建开放硬件生态\"]}], \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"timeline\"}');
