INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('95de3017-7944-41f1-9bdb-4f76604adc75', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 16, NULL, '{\"page_id\": \"p17\", \"title\": \"延伸思考：与其他排序算法的对话\", \"layout_id\": \"case_before_after\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p15\"], \"must_cover\": [\"快速排序对比\", \"归并排序启示\", \"延伸思考：与其他排序算法的对话的核心概念与背景\", \"延伸思考：与其他排序算法的对话的关键方法与执行要点\", \"延伸思考：与其他排序算法的对话的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"延伸思考：与其他排序算法的对话的核心概念与背景\", \"延伸思考：与其他排序算法的对话的关键方法与执行要点\", \"延伸思考：与其他排序算法的对话的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p17\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832534\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'case_before_after', '{\"title\": \"延伸思考：与其他排序算法的对话\", \"left\": {\"header\": \"快速排序的深度对比\", \"content\": [\"快速排序以空间换时间的激进策略，在特定场景下展现出极致性能，但也带来了不稳定性风险。\"], \"bullets\": [{\"icon\": \"fa fa-tachometer\", \"text\": \"核心差异：原地排序 vs 额外空间开销。\", \"description\": \"解释核心差异：原地排序 vs 额外空间开销在快速排序的深度对比维度下的意义。\"}, {\"icon\": \"fa fa-balance-scale\", \"text\": \"适用边界：数据分布均匀且无需保持顺序。\", \"description\": \"解释适用边界：数据分布均匀且无需保持顺序在快速排序的深度对比维度下的意义。\"}, {\"icon\": \"fa fa-shield\", \"text\": \"潜在风险：最坏时间复杂度退化至 O(n²)。\", \"description\": \"解释潜在风险：最坏时间复杂度退化至 O(n²)在快速排序的深度对比维度下的意义。\"}, {\"icon\": \"fa fa-code\", \"text\": \"启示：混合排序策略可兼顾速度与稳定。\", \"description\": \"解释启示：混合排序策略可兼顾速度与稳定在快速排序的深度对比维度下的意义。\"}]}, \"right\": {\"header\": \"归并排序的哲学启示\", \"content\": [\"归并排序的分治思想揭示了‘化繁为简’的本质，为处理大规模数据提供了稳健的架构思路。\", \"结论：延伸思考：与其他排序算法的对话需要结合目标场景做取舍。\"], \"bullets\": [{\"icon\": \"fa fa-puzzle-piece\", \"text\": \"核心启示：分而治之是解决复杂问题的通用解。\", \"description\": \"解释核心启示：分而治之是解决复杂问题的通用解在归并排序的哲学启示维度下的意义。\"}, {\"icon\": \"fa fa-layer-group\", \"text\": \"执行要点：递归拆分与有序合并的精准衔接。\", \"description\": \"解释执行要点：递归拆分与有序合并的精准衔接在归并排序的哲学启示维度下的意义。\"}, {\"icon\": \"fa fa-infinity\", \"text\": \"场景优势：链表排序与外部大文件处理。\", \"description\": \"解释场景优势：链表排序与外部大文件处理在归并排序的哲学启示维度下的意义。\"}, {\"icon\": \"fa fa-sync\", \"text\": \"注意事项：内存占用需严格评估与限制。\", \"description\": \"解释注意事项：内存占用需严格评估与限制在归并排序的哲学启示维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
