INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('96e84fd5-72c0-4ba5-97d2-65c30667cd1b', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 20, '第三部分：工具链选择与软件生态', '{\"title\": \"实战案例复盘：软件选型对项目产出的影响\", \"points\": [\"问题与场景：跨团队协作中的格式兼容矛盾\", \"方案与执行：基于工作流的软件组合策略\", \"结果与启示：资源复用率提升与制作周期缩短数据\"], \"layout_id\": \"edu_tri_compare\", \"part\": \"第三部分：工具链选择与软件生态\", \"logical_page_id\": \"p21\", \"has_image\": false, \"keywords\": [\"问题与场景：跨团队协作中的格式兼容矛盾\", \"方案与执行：基于工作流的软件组合策略\", \"结果与启示：资源复用率提升与制作周期缩短数据\"], \"depends_on\": [\"p20\"], \"must_cover\": [\"问题与场景：跨团队协作中的格式兼容矛盾\", \"方案与执行：基于工作流的软件组合策略\", \"结果与启示：资源复用率提升与制作周期缩短数据\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"a\", \"layout_archetype\": \"feature_compare\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.419350\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_tri_compare', '{\"title\": \"实战复盘：软件选型对项目产出的影响\", \"badge\": \"效率提升35%\", \"columns\": [{\"title\": \"问题与场景\", \"points\": [\"跨团队协作中多软件格式转换导致资产丢失\", \"不同版本软件兼容性差造成返工率高\", \"资源复用率低导致重复制作浪费工时\"]}, {\"title\": \"方案与执行\", \"points\": [\"建立统一中间格式交换标准（如FBX/USD）\", \"采用混合工作流：C4D建模+Octane渲染+MayA合成\", \"制定自动化脚本批量处理通用资产导入导出\"]}, {\"title\": \"结果与启示\", \"points\": [\"资产复用率提升40%，大幅降低边际成本\", \"制作周期缩短35%，按时交付率显著提高\", \"团队沟通成本降低，错误率下降至可控范围\"]}], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_compare\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('9727a391-a2d2-4c43-8ed1-7628216bcbf1', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 12, '第二阶段', '{\"title\": \"第二次浪潮：重点展开\", \"points\": [\"核心概念：从规则驱动转向统计学习，利用海量数据训练概率模型以解决不确定性问题\", \"技术边界：主要聚焦于判别式任务（如分类、回归），尚未具备生成式内容的创造能力\", \"典型案例：AlphaGo通过蒙特卡洛树搜索与深度强化学习击败人类冠军，标志AI在复杂博弈中超越人类\", \"落地建议：企业应优先布局结构化数据分析场景，建立数据治理体系以支撑机器学习模型的持续迭代\"], \"part\": \"第二阶段\"}', '{\"text\": \"页面标题：第二次浪潮：重点展开\\n\\n页面文字：\\n- 核心概念从规则驱动转向统计学习，利用海量数据训练概率模型以解决不确定性问题。\\n- 技术边界主要聚焦于判别式任务，如分类与回归，尚未具备生成式内容的创造能力。\\n- AlphaGo通过蒙特卡洛树搜索与深度强化学习击败人类冠军，标志AI在复杂博弈中超越人类。\\n- 企业应优先布局结构化数据分析场景，建立数据治理体系以支撑机器学习模型的持续迭代。\", \"generated_at\": \"2026-03-09T08:54:47.550865\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:36', '2026-03-09 08:54:49', NULL, NULL);
