INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('997ba213-adae-4557-b024-ac636dbc32c5', '8fb9adbb-55b5-496b-9569-be1757626e7c', 6, NULL, '{\"page_id\": \"p07\", \"title\": \"规律总结：正比与反比关系\", \"layout_id\": \"vocational_step_by_step\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p06\"], \"must_cover\": [\"a与F成正比\", \"a与m成反比\", \"综合得出a=kF/m\", \"规律总结：正比与反比关系的核心概念与背景\", \"规律总结：正比与反比关系的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p07_1\", \"text\": \"国际单位制下k=1的推导及最终公式确立\", \"must_cover\": [\"单位定义\", \"公式标准化\"], \"target_page_ids\": [\"p17\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"规律总结：正比与反比关系的核心概念与背景\", \"规律总结：正比与反比关系的关键方法与执行要点\", \"规律总结：正比与反比关系的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"process_steps\", \"layout_variant\": \"a\", \"logical_page_id\": \"p07\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T04:44:29.430414\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 04:43:51', '2026-03-17 04:44:42', 'vocational_step_by_step', '{\"title\": \"规律总结：正比与反比关系\", \"subtitle\": \"牛顿第二定律的数学表达。\", \"steps\": [{\"number\": 1, \"label\": \"分步验证\", \"description\": \"固定质量m，发现a随F线性增加；固定力F，发现a随m增大而减小。\", \"icon\": \"fa-microscope\"}, {\"number\": 2, \"label\": \"比例推导\", \"description\": \"综合实验数据得出：a与F成正比，与m成反比。\", \"icon\": \"fa-calculator\"}, {\"number\": 3, \"label\": \"公式构建\", \"description\": \"引入比例系数k，得到通用表达式 a = k * (F/m)。\", \"icon\": \"fa-square-root-alt\"}, {\"number\": 4, \"label\": \"单位定义\", \"description\": \"定义1N使1kg物体产生1m/s²加速度，令k=1。\", \"icon\": \"fa-ruler-combined\"}, {\"number\": 5, \"label\": \"最终结论\", \"description\": \"确立牛顿第二定律核心公式：F = ma。\", \"icon\": \"fa-check-circle\"}, {\"number\": 6, \"label\": \"工程应用\", \"description\": \"指导车辆制动距离计算及机械臂加减速控制策略。\", \"icon\": \"fa-industry\"}], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"process_steps\"}');
