INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('9abf54c4-55ee-44b7-ab36-7e874122cb9e', '9b5d83ef-2600-4c3b-b852-00607680277d', 11, '风险探讨', '{\"page_id\": \"p10\", \"title\": \"挑战与隐忧：伦理、偏见与版权\", \"part\": \"风险探讨\", \"points\": [\"模型幻觉导致事实性错误频发，严重制约其在医疗、法律等高风险场景的落地应用\", \"训练数据版权归属模糊引发全球诉讼潮，迫使企业重构数据合规与授权机制\", \"生成式内容易被用于制造深度伪造（Deepfake），对新闻真实性与社会信任体系构成严峻挑战\", \"算法隐含的性别、种族等社会偏见若未被有效修正，将加剧现实世界的不平等现象\"]}', '{\"text\": \"页面标题：挑战与隐忧：伦理、偏见与版权\\n\\n页面文字：\\n- 模型幻觉导致事实性错误频发，严重制约其在医疗、法律等高风险场景的落地应用。\\n- 训练数据版权归属模糊引发全球诉讼潮，迫使企业重构数据合规与授权机制。\\n- 生成式内容易被用于制造深度伪造，对新闻真实性与社会信任体系构成严峻挑战。\\n- 算法隐含的社会偏见若未被有效修正，将加剧现实世界的不平等现象。\", \"generated_at\": \"2026-03-09T08:14:14.326507\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/9abf54c4-55ee-44b7-ab36-7e874122cb9e_v1.png', 'FAILED', '2026-03-09 08:13:55', '2026-03-09 09:20:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('9aca30f4-e1fd-4464-84be-92d76d1a036f', '2210a36d-b61a-453a-83ee-86edc9925e6a', 14, NULL, '{\"page_id\": \"p15\", \"title\": \"硬件配置与运行环境对比\", \"layout_id\": \"comparison_table\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p12\"], \"must_cover\": [\"CPU 单核性能需求\", \"显卡显存容量建议\", \"内存扩展方案\", \"硬件配置与运行环境对比的核心概念与背景\", \"硬件配置与运行环境对比的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"硬件配置与运行环境对比的核心概念与背景\", \"硬件配置与运行环境对比的关键方法与执行要点\", \"硬件配置与运行环境对比的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p15\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T06:30:50.647770\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 06:24:26', '2026-03-07 07:17:35', 'comparison_table', '{\"title\": \"对比分析\", \"subtitle\": \"工作流硬件性能需求评估。\", \"items\": [{\"name\": \"CPU 单核性能\", \"description\": \"建模操作主要依赖单线程计算速度，影响交互流畅度。\", \"features\": [\"高频主频优先\", \"低延迟响应机制\", \"复杂视图实时计算\"]}, {\"name\": \"GPU 显存容量\", \"description\": \"渲染预览与光照计算需要大量显存支持纹理加载。\", \"features\": [\"大纹理无缝加载\", \"光线追踪硬件加速\", \"视口平滑渲染\"]}, {\"name\": \"内存扩展方案\", \"description\": \"存储场景数据以防程序崩溃，确保多任务并行稳定。\", \"features\": [\"高容量随机存取\", \"分层缓存管理机制\", \"数据交换安全性\"]}], \"conclusion\": \"高单核 CPU 提升操作流畅度，大显存 GPU 保障纹理分辨率，大容量内存避免场景崩溃。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('9af70f9e-bd05-4917-a270-e43205df4d00', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 4, '理论基石', '{\"page_id\": \"p04\", \"title\": \"核心概念：多边形与拓扑结构\", \"part\": \"理论基石\", \"points\": [\"掌握顶点、边、面三大基础元素的连接逻辑与层级关系\", \"理解循环布线如何决定模型变形流畅度与渲染光影效果\", \"区分低模（游戏）与高模（影视）在拓扑密度上的核心差异\", \"识别三角面、四边面与N-gon在不同软件中的处理规范\"]}', '{\"text\": \"页面标题：核心概念：多边形与拓扑结构\\n\\n页面文字：\\n- 需深入掌握顶点、边、面三大基础元素的连接逻辑及其层级关系以构建正确模型骨架。\\n- 循环布线直接决定模型变形的流畅度以及渲染光影的最终呈现效果，是拓扑的核心价值。\\n- 必须区分低模与高模在拓扑密度上的差异，前者服务于游戏实时渲染，后者用于影视细节。\\n- 应严格识别三角面、四边面与N-gon在不同软件中的处理规范，避免后续流程出现技术故障。\", \"generated_at\": \"2026-03-09T03:39:37.774093\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/9af70f9e-bd05-4917-a270-e43205df4d00_v1.png', 'COMPLETED', '2026-03-09 03:39:13', '2026-03-09 03:42:54', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('9b250f8e-f772-444f-aabf-6f5df821f434', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"什么是冒泡排序？\", \"layout_id\": \"field_observation\", \"has_image\": true, \"keywords\": [\"带比例尺的数据网格\", \"微观粒子运动\", \"专业标注红圈\", \"古籍黄背景\", \"高精度测绘图\"], \"depends_on\": [\"p03\"], \"must_cover\": [\"基本定义\", \"核心操作单元（相邻交换）\", \"什么是冒泡排序？的核心概念与背景\", \"什么是冒泡排序？的关键方法与执行要点\", \"什么是冒泡排序？的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [\"pr_p03_1\"], \"points\": [\"什么是冒泡排序？的核心概念与背景\", \"什么是冒泡排序？的关键方法与执行要点\", \"什么是冒泡排序？的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p03_1\"], \"layout_archetype\": \"case_visual\", \"layout_variant\": \"a\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.831944\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'field_observation', '{\"title\": \"算法现场：数据流动的微观观测\", \"image_src\": \"https://example.com/images/bubble-sort-field-observation.jpg\", \"image_alt\": \"一张带有精密比例尺和经纬度网格的古籍黄背景图，展示微观粒子（数据元素）在无序状态下的运动轨迹，红圈标注出正在进行交换的两个相邻粒子，整体呈现高精度测绘图的质感。\", \"caption\": \"图 2.1 冒泡排序的现场观测视角：数据元素如同深海气泡，通过两两比较与交换，在物理类比中逐步上浮至有序位置。\", \"background_image\": \"https://example.com/images/darkwood-overlay-bg.jpg\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"case_visual\"}');
