INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a12ca233-2635-4244-8bce-46ee48a37e78', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 3, '第一阶段', '{\"page_id\": \"p04\", \"title\": \"第一次浪潮：专家系统的崛起与瓶颈\", \"part\": \"第一阶段\", \"points\": [\"MYCIN等系统成功应用于医疗诊断，确立了知识工程的核心地位\", \"基于规则的系统在地质勘探、化学分析等领域实现早期商业化落地\", \"缺乏通用推理能力导致系统难以迁移，维护成本随规则膨胀而激增\", \"僵化的逻辑架构无法应对复杂场景，直接引发了第二次AI寒冬\"]}', '{\"text\": \"页面标题：第一次浪潮：专家系统的崛起与瓶颈\\n\\n页面文字：\\n- MYCIN等系统成功应用于医疗诊断，确立了知识工程在专业领域的核心地位。\\n- 基于规则的系统在地质勘探、化学分析等领域实现早期商业化落地应用。\\n- 缺乏通用推理能力导致系统难以迁移，维护成本随规则膨胀而激增。\\n- 僵化的逻辑架构无法应对复杂场景，直接引发了第二次AI寒冬的到来。\", \"generated_at\": \"2026-03-09T08:54:47.141682\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:23', '2026-03-09 08:54:49', NULL, NULL);
