INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a1490d00-0f69-42e3-9d75-a149112a3efe', '1d063203-8ece-436a-ad39-9501e3c7e06b', 14, NULL, '{\"page_id\": \"p15\", \"title\": \"步骤指导：资产导出与交付\", \"layout_id\": \"sop_vertical_steps\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p13\"], \"must_cover\": [\"FBX/OBJ格式规范\", \"贴图路径打包\", \"层级命名规则\", \"压缩与加密设置\", \"步骤指导：资产导出与交付的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p14_1_c917342a\"], \"points\": [\"步骤指导：资产导出与交付的核心概念与背景\", \"步骤指导：资产导出与交付的关键方法与执行要点\", \"步骤指导：资产导出与交付的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p14_1_c917342a\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p15\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p14_1_c917342a\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-20T01:09:55.820070\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-20 01:09:18', '2026-03-20 01:09:56', 'sop_vertical_steps', '{\"title\": \"步骤指导：资产导出与交付\", \"events\": [{\"title\": \"格式规范校验\", \"description\": \"严格执行FBX/OBJ格式标准，剔除冗余数据，确保拓扑结构符合游戏引擎或渲染器导入要求。\", \"is_highlighted\": false}, {\"title\": \"贴图路径打包\", \"description\": \"将所有材质贴图资源相对路径化，打包为独立文件夹，禁止使用绝对路径，防止跨设备丢失。\", \"is_highlighted\": true}, {\"title\": \"层级命名标准化\", \"description\": \"依据工程规范重命名所有对象与骨骼，采用“类别_功能_序号”格式，确保场景树清晰可读。\", \"is_highlighted\": false}, {\"title\": \"压缩与加密交付\", \"description\": \"对最终资产包进行无损压缩，并设置访问权限加密，完成从开发环境到生产环境的最终移交。\", \"is_highlighted\": false}], \"accent_color\": \"#27ae60\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a179865d-996d-45e0-850e-2bcde1ffac19', '2786117f-f122-459a-8310-c05a2077848b', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"技术解析二：吸附式执行器（Vacuum Grippers）\", \"layout_id\": \"edu_timeline_steps\", \"has_image\": true, \"keywords\": [\"真空吸盘阵列\", \"玻璃板材吸附\", \"负压气流示意\", \"平滑表面接触\", \"高科技蓝绿色调\"], \"depends_on\": [\"p04\"], \"must_cover\": [\"结构特点：吸盘/管路/发生器\", \"动力源：真空泵/文丘里管\", \"典型应用：平面/易碎件搬运\", \"技术解析二：吸附式执行器（Vacuum Grippers）的核心概念与背景\", \"技术解析二：吸附式执行器（Vacuum Grippers）的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_detail_1\"], \"points\": [\"技术解析二：吸附式执行器（Vacuum Grippers）的核心概念与背景\", \"技术解析二：吸附式执行器（Vacuum Grippers）的关键方法与执行要点\", \"技术解析二：吸附式执行器（Vacuum Grippers）的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_detail_1\"], \"layout_archetype\": \"timeline\", \"layout_variant\": \"b\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_detail_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:02:17.155271\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:01:22', '2026-03-19 06:02:17', 'edu_timeline_steps', '{\"title\": \"技术解析二：吸附式执行器（Vacuum Grippers）\", \"subtitle\": \"非接触式搬运的高效解决方案。\", \"steps\": [{\"title\": \"负压发生阶段\", \"description\": \"利用真空泵或文丘里管产生稳定负压气流，建立吸盘与工件间的压力差。\", \"highlights\": [\"真空发生装置启动\", \"管路气密性检测\"]}, {\"title\": \"平面吸附阶段\", \"description\": \"吸盘阵列紧密贴合光滑表面，通过多点分布均匀分散负载，防止工件变形。\", \"highlights\": [\"吸盘阵列自动校准\", \"接触面密封形成\"]}, {\"title\": \"平稳搬运阶段\", \"description\": \"在移动过程中实时监测真空度，对玻璃、薄膜等易碎或薄壁件实现无损搬运。\", \"highlights\": [\"泄漏报警联动\", \"动态轨迹平滑控制\"]}], \"background_image\": \"https://images.unsplash.com/photo-1518770660439-4636190af475?auto=format&fit=crop&q=80&w=1200\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"timeline\"}');
