INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a192ee70-954f-449c-b522-4610d4aa0136', '2786117f-f122-459a-8310-c05a2077848b', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"末端执行器：机器人的“手”与“脑”\", \"layout_id\": \"edu_data_board\", \"has_image\": true, \"keywords\": [\"机器人末端法兰盘\", \"中心辐射结构图\", \"科技感节点连接\", \"深蓝色调\", \"抽象机械结构\"], \"depends_on\": [\"p03\"], \"must_cover\": [\"定义：末端执行器（EOAT）\", \"功能：力传递与动作执行\", \"分类：接触式与非接触式\", \"末端执行器：机器人的“手”与“脑”的核心概念与背景\", \"末端执行器：机器人的“手”与“脑”的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_detail_1\", \"text\": \"详细拆解夹持式与吸附式的内部结构\", \"must_cover\": [\"连杆机构\", \"真空发生装置\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"末端执行器：机器人的“手”与“脑”的核心概念与背景\", \"末端执行器：机器人的“手”与“脑”的关键方法与执行要点\", \"末端执行器：机器人的“手”与“脑”的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_dashboard\", \"layout_variant\": \"a\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:02:17.155204\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:01:22', '2026-03-19 06:02:17', 'edu_data_board', '{\"title\": \"末端执行器：机器人的“手”与“脑”\", \"subtitle\": \"定义：EOAT | 功能：力传递与动作执行。\", \"metrics\": [{\"value\": \"100%\", \"label\": \"核心覆盖\", \"note\": \"接触式与非接触式全分类。\"}, {\"value\": \"3D\", \"label\": \"结构维度\", \"note\": \"法兰盘至指尖的完整链路。\"}], \"bars\": [{\"label\": \"传统夹具局限\", \"baseline\": 60, \"current\": 20}, {\"label\": \"智能 EOAT 效率\", \"baseline\": 20, \"current\": 85}], \"bullets\": [{\"text\": \"核心定义与背景。\", \"description\": \"末端执行器（EOAT）是连接机器人本体与作业对象的接口，承担力传递与精准动作执行的双重使命。\"}, {\"text\": \"两大技术分类。\", \"description\": \"分为接触式（机械夹持、磁吸）与非接触式（真空吸附、气流吹扫），适配不同工件特性与工艺需求。\"}, {\"text\": \"关键执行要点。\", \"description\": \"选型需综合考量负载、抓取精度、表面材质及环境适应性，确保产线柔性化与安全性。\"}], \"insight\": \"从单一刚性夹具向模块化、智能化 EOAT 演进，是解决复杂产线柔性制造挑战的核心路径。\", \"background_image\": \"https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?auto=format&fit=crop&q=80&w=1200\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_dashboard\"}');
