INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a263ab82-3194-4f90-893c-926a69670007', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d', 12, '总结', '{\"page_id\": \"p11\", \"title\": \"课程总结：知识体系回顾\", \"part\": \"总结\", \"points\": [\"全景复盘：从文本清洗、特征工程到深度学习模型构建的完整技术链路\", \"核心聚焦：深度回顾情感分析、NER、机器翻译等五大任务的关键算法与落地场景\", \"范式升级：理解从传统统计方法向预训练大模型（Transformer）的技术演进逻辑\", \"知行合一：强调理论公式推导与Python实战代码在解决实际问题中的互补价值\", \"能力沉淀：建立系统化的NLP思维框架，为后续探索多模态与垂直行业应用奠基\"]}', '{\"text\": \"页面标题：课程总结：知识体系回顾\\n\\n页面文字：\\n- 全景复盘从文本清洗、特征工程到深度学习模型构建的完整技术链路。\\n- 核心聚焦深度回顾情感分析、NER、机器翻译等五大任务的关键算法与落地场景。\\n- 范式升级理解从传统统计方法向预训练大模型Transformer的技术演进逻辑。\\n- 知行合一强调理论公式推导与Python实战代码在解决实际问题中的互补价值。\\n- 能力沉淀建立系统化的NLP思维框架，为后续探索多模态与垂直行业应用奠基。\", \"generated_at\": \"2026-03-16T05:37:22.715804\"}', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d/pages/a263ab82-3194-4f90-893c-926a69670007_v1.png', 'COMPLETED', '2026-03-16 05:37:13', '2026-03-16 06:33:18', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a2b2ec84-3e89-48e2-a8bb-3c0c3f9f74c8', '8fb9adbb-55b5-496b-9569-be1757626e7c', 14, NULL, '{\"page_id\": \"p15\", \"title\": \"生活应用：安全带与安全气囊\", \"layout_id\": \"vocational_case_study\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p13\"], \"must_cover\": [\"惯性危害\", \"作用时间与力的关系\", \"牛顿第二定律在安全设计中的应用\", \"生活应用：安全带与安全气囊的核心概念与背景\", \"生活应用：安全带与安全气囊的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"生活应用：安全带与安全气囊的核心概念与背景\", \"生活应用：安全带与安全气囊的关键方法与执行要点\", \"生活应用：安全带与安全气囊的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p15\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T04:44:29.430781\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 04:43:52', '2026-03-17 04:44:29', 'vocational_case_study', '{\"title\": \"生活应用：安全带与安全气囊\", \"content\": [\"当车辆急停时，乘客因惯性继续向前运动。若仅靠摩擦力或撞击，作用时间极短，根据动量定理（Ft=Δmv），瞬间冲击力极大，易造成严重伤害。\", \"安全带通过限制位移延长作用时间，安全气囊则进一步增大缓冲面积并延长减速过程。两者协同将巨大的瞬时冲击力转化为可承受的平均力，保护乘员安全。\"], \"highlight\": \"核心原理：延长作用时间以减小平均冲击力。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a2def1be-83a8-4a53-b3a7-9f17c6dd007f', '569b1b8b-6b9c-4a1a-91e4-ba81a726a470', 0, '引言', '{\"title\": \"封面\", \"points\": [\"项目背景\"], \"part\": \"引言\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-09 06:18:55', '2026-03-09 06:18:55', NULL, NULL);
