INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a568d2a0-f6ba-4f7e-8363-70c0c40b2741', '6c250523-422a-46f3-a1f1-42e82424897c', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"对比分析：硬表面 vs 有机生物建模\", \"layout_id\": \"comparison_table\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p05\"], \"must_cover\": [\"布线密度差异\", \"工具链区别\", \"变形需求对比\", \"优化策略\", \"对比分析：硬表面 vs 有机生物建模的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"对比分析：硬表面 vs 有机生物建模的核心概念与背景\", \"对比分析：硬表面 vs 有机生物建模的关键方法与执行要点\", \"对比分析：硬表面 vs 有机生物建模的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.286854\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'comparison_table', '{\"title\": \"对比分析\", \"subtitle\": \"硬表面 vs 有机生物建模策略差异。\", \"items\": [{\"name\": \"布线密度与拓扑流向\", \"description\": \"硬表面追求结构清晰，有机模型强调肌肉走向。\", \"features\": [\"硬表面：低密度、四边化为主、注重倒角与支撑线\", \"有机生物：高密度、遵循解剖结构、注重环状循环\"]}, {\"name\": \"工具链与变形需求\", \"description\": \"硬表面侧重布尔与偏移，有机侧重雕刻与蒙皮。\", \"features\": [\"硬表面：布尔运算、阵列、参数化修改器\", \"有机生物：动态拓扑、雕刻笔刷、骨骼绑定系统\"]}, {\"name\": \"优化策略与渲染表现\", \"description\": \"硬表面依赖法线贴图模拟细节，有机依赖高模烘焙。\", \"features\": [\"硬表面：保持低面数、利用高光反射掩盖瑕疵\", \"有机生物：保留关键形变区、烘焙法线与置换贴图\"]}], \"conclusion\": \"硬表面建模以几何精度和逻辑结构为核心，有机生物建模则以形态自然度和动画适应性为导向，二者需根据最终应用场景选择差异化工作流。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a56da531-7e7c-466f-afea-0a6336a67732', '9da12907-ffda-40fb-9be6-d245c93b1363', 2, '课程导入', '{\"page_id\": \"p02\", \"title\": \"课程导览与学习目标\", \"part\": \"课程导入\", \"points\": [\"系统梳理主流建模软件界面布局，掌握视图导航、工具栏及快捷键的基础操作逻辑\", \"深度解析多边形硬表面建模与NURBS曲面建模的核心流派差异及适用场景\", \"明确课程考核维度，包括理论测试、模型拓扑规范及最终渲染效果评分标准\", \"布置课后阶梯式实践任务，要求从基础几何体组合到简单场景搭建的完整产出\"]}', '{\"text\": \"页面标题：课程导览与学习目标\\n\\n页面文字：\\n- 系统梳理主流软件界面布局，掌握视图导航、工具栏及快捷键操作逻辑。\\n- 深度解析多边形硬表面与NURBS曲面建模流派差异及其适用场景边界。\\n- 明确理论测试、拓扑规范及渲染评分标准，布置阶梯式实践任务目标。\", \"generated_at\": \"2026-03-10T06:06:00.213491\"}', '9da12907-ffda-40fb-9be6-d245c93b1363/pages/a56da531-7e7c-466f-afea-0a6336a67732_v1.png', 'COMPLETED', '2026-03-10 06:04:47', '2026-03-10 06:08:15', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a5967fdb-9e06-448d-a2b0-e88e770744ec', '9b5d83ef-2600-4c3b-b852-00607680277d', 7, NULL, '{\"title\": \"生态优势：Google Gemini：案例复盘\", \"points\": [\"场景痛点：传统多模态模型在跨模态理解（如视频分析结合文本）上存在割裂，导致复杂任务响应延迟。\", \"执行方案：利用Gemini原生多模态架构，直接处理混合输入数据，并依托Google Cloud实现端云协同推理。\", \"实施成效：将内容审核与搜索优化效率提升40%，显著降低API调用成本并缩短端到端响应时间。\", \"经验启示：构建统一的数据底座是发挥大模型效能的关键，需警惕过度依赖单一生态带来的迁移风险。\"]}', '{\"text\": \"页面标题：生态优势：Google Gemini：案例复盘\\n\\n页面文字：\\n- 传统多模态模型在跨模态理解上存在割裂，导致复杂任务响应延迟成为主要痛点。\\n- 利用Gemini原生架构直接处理混合输入数据，并依托Google Cloud实现端云协同推理。\\n- 内容审核与搜索优化效率提升40%，显著降低API调用成本并缩短端到端响应时间。\\n- 构建统一数据底座是发挥大模型效能的关键，需警惕过度依赖单一生态带来的迁移风险。\", \"generated_at\": \"2026-03-09T08:14:14.916915\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/a5967fdb-9e06-448d-a2b0-e88e770744ec_v1.png', 'FAILED', '2026-03-09 08:13:49', '2026-03-09 09:20:26', NULL, NULL);
