INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a6872b3f-4b86-4519-880b-86961a313312', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 1, '第一部分：课程导览与愿景', '{\"title\": \"课程全景导航与学习路径规划\", \"points\": [\"六大核心模块逻辑架构概览\", \"从思维重塑到资产交付的进阶阶梯\", \"预期能力达成标准与技能迁移建议\", \"关键学习方法论与执行要点提示\"], \"layout_id\": \"edu_toc\", \"part\": \"第一部分：课程导览与愿景\", \"logical_page_id\": \"p02\", \"has_image\": false, \"keywords\": [\"六大核心模块逻辑架构概览\", \"从思维重塑到资产交付的进阶阶梯\", \"预期能力达成标准与技能迁移建议\"], \"depends_on\": [\"p01\"], \"must_cover\": [\"六大核心模块逻辑架构概览\", \"从思维重塑到资产交付的进阶阶梯\", \"预期能力达成标准与技能迁移建议\", \"关键学习方法论与执行要点提示\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"b\", \"layout_archetype\": \"toc\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.418525\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_toc', '{\"title\": \"课程全景导航与学习路径规划\", \"subtitle\": \"六大核心模块逻辑架构概览。\", \"items\": [{\"index\": 1, \"text\": \"思维重塑：从二维认知到三维空间逻辑构建。\"}, {\"index\": 2, \"text\": \"硬表面技法：高精度模型拓扑与布线规范。\"}, {\"index\": 3, \"text\": \"材质光影：PBR工作流与物理渲染真实感。\"}, {\"index\": 4, \"text\": \"资产优化：多边形减面与引擎实时适配。\"}, {\"index\": 5, \"text\": \"项目实战：商业级案例全流程拆解与协作。\"}, {\"index\": 6, \"text\": \"交付标准：行业规范验收与效率提升策略。\"}], \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"toc\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a6ae437d-8a96-4ed7-ae3e-5d98d66e1277', '9da12907-ffda-40fb-9be6-d245c93b1363', 5, '流程解析', '{\"page_id\": \"p04\", \"title\": \"通用工作流：从草图到渲染\", \"part\": \"流程解析\", \"points\": [\"需求分析与白模构建的标准化步骤：确立比例基准与结构框架，确保设计意图准确落地\", \"高精度细节雕刻与低模优化的平衡策略：通过拓扑重绘与法线烘焙实现视觉细节与性能效率的统一\", \"材质赋予、灯光布置及最终渲染输出：构建物理正确的光照环境与表面质感，完成从模型到图像的转化\"]}', '{\"text\": \"页面标题：通用工作流：从草图到渲染\\n\\n页面文字：\\n- 执行需求分析与白模构建标准化步骤，确立比例基准与结构框架以确保设计意图准确落地。\\n- 平衡高精度细节雕刻与低模优化策略，通过拓扑重绘与法线烘焙实现视觉细节与性能效率统一。\\n- 完成材质赋予、灯光布置及最终渲染输出，构建物理正确的光照环境完成从模型到图像的转化。\", \"generated_at\": \"2026-03-10T06:06:00.508781\"}', '9da12907-ffda-40fb-9be6-d245c93b1363/pages/a6ae437d-8a96-4ed7-ae3e-5d98d66e1277_v2.png', 'COMPLETED', '2026-03-10 06:04:52', '2026-03-10 06:19:23', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a6e84674-315c-44b5-b651-31003e31fd18', '4e889981-954e-4263-b490-230183b1a644', 6, NULL, '{\"page_id\": \"p07\", \"title\": \"对比分析：传统经验调试 vs 理论量化调试\", \"layout_id\": \"vocational_compare_panel\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p05\"], \"must_cover\": [\"传统试错法弊端：效率低、隐患大\", \"理论计算优势：精准预测、一次成功\", \"对比分析：传统经验调试 vs 理论量化调试的核心概念与背景\", \"对比分析：传统经验调试 vs 理论量化调试的关键方法与执行要点\", \"对比分析：传统经验调试 vs 理论量化调试的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"对比分析：传统经验调试 vs 理论量化调试的核心概念与背景\", \"对比分析：传统经验调试 vs 理论量化调试的关键方法与执行要点\", \"对比分析：传统经验调试 vs 理论量化调试的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_compare\", \"layout_variant\": \"b\", \"logical_page_id\": \"p07\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:45:02.424703\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:44:26', '2026-03-19 01:37:30', 'vocational_compare_panel', '{\"title\": \"对比分析：传统经验调试 vs 理论量化调试\", \"itemA\": {\"title\": \"传统经验调试（试错法）\", \"points\": [\"依赖个人手感与过往案例，缺乏数据支撑导致效率低下，难以应对新型设备或复杂工况。\", \"反复调整参数引发机械冲击，存在设备损坏与安全隐患，增加维护成本和设备寿命损耗。\", \"故障复现困难，无法精准预测加减速过程中的抖动现象，导致调试周期长且结果不稳定。\"]}, \"itemB\": {\"title\": \"理论量化调试（F=ma 驱动）\", \"points\": [\"基于牛顿第二定律精准计算负载惯量与所需推力，一次成功，大幅缩短调试停机时间。\", \"通过公式推导设定加速度阈值，消除启停阶段的机械震荡，确保设备运行平稳可靠。\", \"建立标准化调试流程，确保设备运行平稳度波动小于 0.5s，提升产品质量与生产一致性。\"]}, \"layout_variant\": \"b\", \"variant\": \"b\", \"layout_archetype\": \"feature_compare\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a6f032ac-ee3e-4815-a48e-8a116e844283', '6c250523-422a-46f3-a1f1-42e82424897c', 19, NULL, '{\"page_id\": \"p20\", \"title\": \"学习资源与工具推荐清单\", \"layout_id\": \"key_concepts\", \"has_image\": true, \"keywords\": [\"学习资源与工具推荐清单\", \"场景示意\", \"视觉辅助\"], \"depends_on\": [\"p16\"], \"must_cover\": [\"官方文档\", \"开源教程\", \"素材库\", \"社区论坛\", \"硬件配置建议\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"学习资源与工具推荐清单的核心概念与背景\", \"学习资源与工具推荐清单的关键方法与执行要点\", \"学习资源与工具推荐清单的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p20\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287233\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'key_concepts', '{\"title\": \"学习资源与工具推荐清单\", \"subtitle\": \"官方文档、开源生态与硬件配置指南。\", \"bullets\": [{\"icon\": \"fa-book\", \"text\": \"官方文档中心。\", \"description\": \"覆盖主流引擎（Unity/Unreal）及建模软件（Blender/Maya）的API手册与最佳实践指南，确保技术细节准确无误。\"}, {\"icon\": \"fa-code-branch\", \"text\": \"开源教程库。\", \"description\": \"GitHub与GitLab上的高质量项目仓库，包含从UV展开到置换烘焙的完整脚本与案例源码，支持二次开发。\"}, {\"icon\": \"fa-image\", \"text\": \"专业素材库。\", \"description\": \"提供高精度扫描模型、PBR材质贴图等资产，适用于快速搭建测试场景，减少重复劳动时间。\"}, {\"icon\": \"fa-users\", \"text\": \"开发者社区论坛。\", \"description\": \"Stack Overflow、ArtStation及Discord群组，汇聚全球专家经验，可快速获取疑难问题的解决方案与调试技巧。\"}, {\"icon\": \"fa-microchip\", \"text\": \"硬件配置建议。\", \"description\": \"推荐搭载NVIDIA RTX 40系显卡与32GB以上内存的工作站，以支持实时光线追踪与大规模网格雕刻任务。\"}], \"keyTakeaway\": \"构建‘文档 + 开源 + 社区 + 硬件’四位一体的学习体系，可显著提升技术落地效率与问题解决能力。\", \"image\": {\"src\": \"\", \"alt\": \"学习资源生态示意图：展示文档、代码、素材、社区与硬件的连接关系\", \"position\": \"right\", \"width\": \"35%\"}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
