INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a7a6e0a7-fdba-42a2-9618-41a7a3209cf0', '130ea17c-c678-4285-8c4c-06b099d8fa71', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"复习：牛顿第一定律的局限\", \"layout_id\": \"edu_timeline_steps\", \"has_image\": true, \"keywords\": [\"天平平衡示意图\", \"光滑平面滑块\", \"物理实验台\", \"高对比度黑白线条\", \"科学插画风格\"], \"depends_on\": [\"p03\"], \"must_cover\": [\"惯性概念回顾\", \"力与运动关系的疑问\", \"复习：牛顿第一定律的局限的核心概念与背景\", \"复习：牛顿第一定律的局限的关键方法与执行要点\", \"复习：牛顿第一定律的局限的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [\"pr_p03_1\"], \"points\": [\"复习：牛顿第一定律的局限的核心概念与背景\", \"复习：牛顿第一定律的局限的关键方法与执行要点\", \"复习：牛顿第一定律的局限的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p03_1\"], \"layout_archetype\": \"timeline\", \"layout_variant\": \"a\", \"logical_page_id\": \"p05\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p03_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:15:52.390698\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 02:14:46', '2026-03-17 02:15:52', 'edu_timeline_steps', '{\"title\": \"复习：牛顿第一定律的局限与突破\", \"subtitle\": \"从理想状态走向现实受力分析。\", \"steps\": [{\"title\": \"回顾惯性理想态\", \"description\": \"重温不受外力时物体保持静止或匀速直线运动的规律，明确其作为理论基石的地位。\", \"highlights\": [\"理想光滑平面假设\", \"忽略摩擦阻力影响\"]}, {\"title\": \"提出现实疑问\", \"description\": \"引入实际场景中受力存在的必然性，质疑仅靠惯性定律无法解释加速运动的原因。\", \"highlights\": [\"力与运动状态的关联\", \"非平衡态下的变化\"]}, {\"title\": \"开启对比研究\", \"description\": \"确立本节目标，通过对比不同受力情况，引出加速度定义与受力分析的基础框架。\", \"highlights\": [\"加速度概念引入\", \"受力分析方法铺垫\"]}], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"timeline\"}');
