INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a9288a6c-16ed-458c-87a5-214391c93f82', '2f844b20-de75-4ac5-98d1-2f44296e9e2b', 8, NULL, '{\"page_id\": \"p09\", \"title\": \"典型例题：水平面牵引问题\", \"layout_id\": \"edu_qa_case\", \"has_image\": true, \"keywords\": [\"物理示意图\", \"受力分析图\", \"解题步骤板\", \"学生提问气泡\", \"黑板粉笔质感\"], \"depends_on\": [\"p08\"], \"must_cover\": [\"题目条件\", \"受力分析过程\", \"列方程求解\", \"典型例题：水平面牵引问题的核心概念与背景\", \"典型例题：水平面牵引问题的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p08_1\"], \"points\": [\"典型例题：水平面牵引问题的核心概念与背景\", \"典型例题：水平面牵引问题的关键方法与执行要点\", \"典型例题：水平面牵引问题的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p08_1\"], \"layout_archetype\": \"qa_session\", \"layout_variant\": \"c\", \"logical_page_id\": \"p09\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p08_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:09:35.126019\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 02:08:44', '2026-03-17 02:09:35', 'edu_qa_case', '{\"title\": \"典型例题：水平面牵引问题\", \"subtitle\": \"从受力分析到定量求解。\", \"question\": \"质量为m的物体在水平拉力F作用下沿粗糙水平面运动，动摩擦因数为μ，求物体的加速度大小及方向。\", \"answer\": \"加速度大小为 a = (F - μmg) / m，方向与拉力F方向一致。\", \"analysis\": [{\"title\": \"受力图绘制\", \"content\": \"物体受重力G、支持力N、拉力F、滑动摩擦力f四个力作用；竖直方向二力平衡，水平方向合力提供加速度。\"}, {\"title\": \"正交分解与列式\", \"content\": \"建立水平x轴与竖直y轴坐标系；y轴：N=mg；x轴：F-f=ma，且f=μN；联立解得最终表达式。\"}], \"conclusion\": \"核心提示：摩擦力方向始终与相对运动趋势相反，且大小由正压力与动摩擦因数共同决定。\", \"background_image\": \"\", \"variant\": \"c\", \"layout_variant\": \"c\", \"layout_archetype\": \"qa_session\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a940a079-09a7-4856-a4e3-e4d51405e71f', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 11, NULL, '{\"page_id\": \"p08\", \"title\": \"第二章：主流软件与工具\", \"layout_id\": \"edu_core_hub\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p07\"], \"must_cover\": [\"工具选型提示\", \"第二章：主流软件与工具的核心概念与背景\", \"第二章：主流软件与工具的关键方法与执行要点\", \"第二章：主流软件与工具的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第二章：主流软件与工具的核心概念与背景\", \"第二章：主流软件与工具的关键方法与执行要点\", \"第二章：主流软件与工具的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p12\", \"layout_variant\": \"a\", \"layout_archetype\": \"core_model\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T13:04:03.227803\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'edu_core_hub', '{\"title\": \"第二章：主流软件与工具\", \"content\": [\"软件选型决定数据安全性，掌握拓扑、UV 与材质底层原理，避免碎片化学习，确保模型数据在不同软件工作流中安全可控。\", \"主流工具覆盖建模、渲染全链路。注意场景适配差异，防止脱离工程实战需求，确保教学规范符合工程实战需求。\"], \"highlight\": \"确保模型数据在不同工作流中安全可控且高效流转。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"core_model\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a9547703-9ff6-4e5e-9828-da3896b44614', '2f844b20-de75-4ac5-98d1-2f44296e9e2b', 18, NULL, '{\"page_id\": \"p19\", \"title\": \"结语：探索无止境\", \"layout_id\": \"edu_summary\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p18\"], \"must_cover\": [\"核心知识点回顾\", \"未来学习展望\", \"课程寄语\", \"结语：探索无止境的核心概念与背景\", \"结语：探索无止境的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p01_1\", \"pr_p01_2\", \"pr_p05_1\", \"pr_p06_1\", \"pr_p08_1\", \"pr_p10_1\", \"pr_p12_1\"], \"points\": [\"结语：探索无止境的核心概念与背景\", \"结语：探索无止境的关键方法与执行要点\", \"结语：探索无止境的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_1\", \"pr_p01_2\", \"pr_p05_1\", \"pr_p06_1\", \"pr_p08_1\", \"pr_p10_1\", \"pr_p12_1\"], \"layout_archetype\": \"summary_reflection\", \"layout_variant\": \"b\", \"logical_page_id\": \"p19\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p01_1\", \"pr_p01_2\", \"pr_p05_1\", \"pr_p06_1\", \"pr_p08_1\", \"pr_p10_1\", \"pr_p12_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:09:35.126352\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 02:08:47', '2026-03-17 02:09:35', 'edu_summary', '{\"title\": \"结语：探索无止境\", \"columns\": [{\"title\": \"核心知识闭环\", \"points\": [\"完成从定性观察到定量计算的完整推导，掌握实验探究逻辑与数学建模步骤。\", \"厘清单位制定义使k=1的推导过程，确立标准公式的最终形态与物理意义。\"]}, {\"title\": \"关键方法复盘\", \"points\": [\"深化矢量性与瞬时性理解，确保方向一致性与同时性判断零失误。\", \"通过典型例题拆解，规范受力图绘制、正交分解及计算结果呈现流程。\"]}, {\"title\": \"易错与实战\", \"points\": [\"规避单位换算错误与合力漏算陷阱，结合生活实例解析常见误区。\", \"应用刹车距离与安全带作用原理，深入理解汽车运动控制中的惯性危害。\"]}], \"closing\": \"从公式到智慧，以F=ma为基石，在无限探索中定义速度与激情。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"summary_reflection\"}');
