INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('aa45fb54-3e72-4f7b-bd08-a2af6267a847', '9b5d83ef-2600-4c3b-b852-00607680277d', 5, 'Claude篇', '{\"page_id\": \"p05\", \"title\": \"关键突破：Anthropic的Claude与安全优先\", \"part\": \"Claude篇\", \"points\": [\"由前OpenAI核心成员创立，将‘安全对齐’作为技术基因，从源头规避有害输出\", \"Claude 2/3系列突破上下文限制，支持百万级Token窗口，完美处理长篇文档与复杂逻辑\", \"引入可解释性机制与人类反馈强化学习（RLHF），在医疗、法律等高风险领域建立高信任壁垒\", \"采用宪法AI（Constitutional AI）理念，使模型在缺乏人工标注时也能自我约束并符合伦理规范\"]}', '{\"text\": \"页面标题：关键突破：Anthropic的Claude与安全优先\\n\\n页面文字：\\n- Anthropic由前OpenAI核心成员创立，将安全对齐作为基因从源头规避有害输出风险。\\n- Claude系列突破上下文限制，支持百万级Token窗口完美处理长篇文档与复杂逻辑。\\n- 引入可解释机制与人类反馈强化学习，在医疗法律等高风险领域建立了高信任壁垒。\\n- 采用宪法AI理念使模型在无标注时也能自我约束，确保输出始终符合伦理规范。\", \"generated_at\": \"2026-03-09T08:14:15.317255\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/aa45fb54-3e72-4f7b-bd08-a2af6267a847_v2.png', 'COMPLETED', '2026-03-09 08:13:45', '2026-03-09 09:20:42', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('aac873a0-c779-4aae-a576-af663afd0835', '60390839-f925-4662-a2dc-c92d64253b33', 16, NULL, '{\"page_id\": \"p17\", \"title\": \"本章核心知识图谱总结\", \"layout_id\": \"key_takeaways\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p14\"], \"must_cover\": [\"拓扑规范\", \"流程闭环\", \"工具选择\", \"错误规避\", \"本章核心知识图谱总结的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"本章核心知识图谱总结的核心概念与背景\", \"本章核心知识图谱总结的关键方法与执行要点\", \"本章核心知识图谱总结的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:29:51', '2026-03-10 05:29:51', 'key_takeaways', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('aafc4b3e-df2d-4e5e-a8b6-d45559aa8051', '2786117f-f122-459a-8310-c05a2077848b', 17, NULL, '{\"page_id\": \"p18\", \"title\": \"思考题与作业布置\", \"layout_id\": \"edu_qa_case\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p16\"], \"must_cover\": [\"设计一个特定场景的夹具方案\", \"撰写一份简易的SOP检查表\", \"思考题与作业布置的核心概念与背景\", \"思考题与作业布置的关键方法与执行要点\", \"思考题与作业布置的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"思考题与作业布置的核心概念与背景\", \"思考题与作业布置的关键方法与执行要点\", \"思考题与作业布置的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"qa_session\", \"layout_variant\": \"c\", \"logical_page_id\": \"p18\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:02:17.155637\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:01:25', '2026-03-19 06:02:17', 'edu_qa_case', '{\"title\": \"实战演练：场景化设计与规范制定\", \"question\": \"针对某高反光曲面零件，设计一套兼具稳定性与防损伤的夹具方案，并撰写一份包含关键风险点的简易更换 SOP 检查表。\", \"answer\": \"采用柔性指尖配合局部真空吸附的复合结构；SOP 需包含气源切断确认、吸盘状态目视检查及异常震动应急预案三项核心内容。\", \"analysis\": [{\"title\": \"结构设计逻辑\", \"content\": \"结合曲面特性选择柔性材料减少应力集中，利用真空补偿机制应对表面微小起伏，确保抓取力矩平衡。\"}, {\"title\": \"SOP 执行要点\", \"content\": \"将断电锁定作为首要步骤，细化气压释放的可视化标识，明确人工辅助时的站位与安全距离，杜绝误操作风险。\"}], \"conclusion\": \"工程设计的核心在于细节的闭环，SOP 的价值在于将经验转化为可执行的标准化动作。\", \"background_image\": \"\", \"variant\": \"c\", \"layout_variant\": \"c\", \"layout_archetype\": \"qa_session\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ab4c37e3-daf7-4afc-b35c-65735a4ba73e', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 10, '总结', '{\"page_id\": \"p10\", \"title\": \"总结回顾：AI发展的核心驱动力\", \"part\": \"总结\", \"points\": [\"算法、算力与数据构成驱动AI演进的三大核心引擎，缺一不可\", \"技术路径已从专用弱AI向具备泛化能力的通用强AI不可逆演进\", \"历史周期表明，每一次\'AI寒冬\'的沉淀都将孕育更强劲的技术反弹\", \"未来突破将依赖于三者协同优化，而非单一维度的线性增长\"]}', '{\"text\": \"页面标题：总结回顾：AI发展的核心驱动力\\n\\n页面文字：\\n- 算法、算力与数据构成驱动AI演进的三大核心引擎，三者缺一不可共同作用。\\n- 技术路径已从专用弱AI向具备泛化能力的通用强AI不可逆演进，重塑行业格局。\\n- 历史周期表明，每一次\'AI寒冬\'的沉淀都将孕育更强劲的技术反弹与创新爆发。\\n- 未来突破将依赖于三者协同优化，而非单一维度的线性增长，需注重系统平衡。\\n回顾历程让我们看清规律，从而更好地把握通往未来的关键方向与战略机遇。\", \"generated_at\": \"2026-03-09T08:54:48.435841\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:33', '2026-03-09 08:54:49', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ab60225e-0100-47e6-8960-2d06862f662d', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 6, '第一部分：课程导览与愿景', '{\"title\": \"从思维重塑到资产交付的进阶阶梯：重点展开\", \"points\": [\"从思维重塑到资产交付的进阶阶梯的核心概念与边界\", \"从思维重塑到资产交付的进阶阶梯的典型案例与结果\", \"从思维重塑到资产交付的进阶阶梯在本主题中的落地建议\"], \"layout_id\": \"edu_qa_case\", \"part\": \"第一部分：课程导览与愿景\", \"logical_page_id\": \"p07\", \"has_image\": false, \"keywords\": [\"从思维重塑到资产交付的进阶阶梯的核心概念与边界\", \"从思维重塑到资产交付的进阶阶梯的典型案例与结果\", \"从思维重塑到资产交付的进阶阶梯在本主题中的落地建议\"], \"depends_on\": [\"p06\"], \"must_cover\": [\"从思维重塑到资产交付的进阶阶梯的核心概念与边界\", \"从思维重塑到资产交付的进阶阶梯的典型案例与结果\", \"从思维重塑到资产交付的进阶阶梯在本主题中的落地建议\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"d\", \"layout_archetype\": \"qa_session\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.418758\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_qa_case', '{\"title\": \"从思维重塑到资产交付的进阶阶梯：核心问答\", \"subtitle\": \"六步进阶体系中的关键转化节点。\", \"question\": \"如何界定从思维重塑到资产交付的边界，并确保典型案例可复用？\", \"answer\": \"核心边界在于‘认知内化’完成至‘标准化产出’生成的临界点；通过建立职业精神与技能融合的双向赋能机制，将抽象思维转化为可量化的商业资产。\", \"analysis\": [{\"title\": \"核心概念与边界界定\", \"content\": \"思维重塑是底层逻辑重构，资产交付是上层价值显性化；边界在于是否形成标准化的交付物（如方案、代码、设计稿），基线达标率60%至当前85%的跃升即源于此边界的清晰切割。\"}, {\"title\": \"典型案例与结果验证\", \"content\": \"某学员在强化职业精神维度后，从理论认知直接跨越至商业交付全链路闭环，交付质量显著提升，实现了技术与素养的双向赋能，数据看板显示效率提升40%。\"}], \"conclusion\": \"清晰的边界界定是驱动从概念到商业落地高效转化的核心引擎。\", \"variant\": \"d\", \"layout_variant\": \"d\", \"layout_archetype\": \"qa_session\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ab71dc5a-cf4d-4fa6-9e81-752973c17373', '1d063203-8ece-436a-ad39-9501e3c7e06b', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"章节一：基础几何构建原理\", \"layout_id\": \"sop_vertical_steps\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p04\"], \"must_cover\": [\"章节导语\", \"几何体生成逻辑\", \"章节一：基础几何构建原理的核心概念与背景\", \"章节一：基础几何构建原理的关键方法与执行要点\", \"章节一：基础几何构建原理的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"章节一：基础几何构建原理的核心概念与背景\", \"章节一：基础几何构建原理的关键方法与执行要点\", \"章节一：基础几何构建原理的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p05\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-20T01:09:55.819699\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-20 01:09:16', '2026-03-20 01:09:56', 'sop_vertical_steps', '{\"title\": \"章节一：基础几何构建原理\", \"events\": [{\"title\": \"参数化生成逻辑\", \"description\": \"基于数学方程驱动基本体素（立方体、球体、圆柱）的初始形态构建，确立尺寸精度基准。\", \"is_highlighted\": false}, {\"title\": \"拓扑结构初始化\", \"description\": \"分析网格面数分布规律，确保后续变形操作时布线均匀，避免模型扭曲或破面风险。\", \"is_highlighted\": true}, {\"title\": \"空间约束应用\", \"description\": \"在构建过程中实时对齐世界坐标系，利用辅助线锁定关键节点位置，保证装配接口匹配度。\", \"is_highlighted\": false}], \"accent_color\": \"#27ae60\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('abba80e1-f8f8-45d9-8a75-bb90034878e9', 'f8ce8774-c982-4cd5-a379-23d4cf53bef2', 15, NULL, '{\"page_id\": \"p16\", \"title\": \"课后作业与资源推荐\", \"layout_id\": \"vocational_homework\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p13\"], \"must_cover\": [\"撰写完整的实验排故报告\", \"观看拓展视频链接\", \"预习下一节动量守恒内容\", \"课后作业与资源推荐的核心概念与背景\", \"课后作业与资源推荐的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"课后作业与资源推荐的核心概念与背景\", \"课后作业与资源推荐的关键方法与执行要点\", \"课后作业与资源推荐的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T06:43:32.018327\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 06:42:48', '2026-03-17 14:44:01', 'vocational_homework', '{\"title\": \"课后作业与资源推荐\", \"subtitle\": \"深化排故技能，构建完整知识闭环。\", \"bullets\": [{\"icon\": \"fa-file-text-o\", \"text\": \"撰写实验排故报告。\", \"description\": \"基于前序故障现象，运用动态补偿与空载预调法，系统分析滑轮摩擦与细线质量误差，输出包含数据修正过程的完整报告。\"}, {\"icon\": \"fa-play-circle-o\", \"text\": \"观看拓展视频链接。\", \"description\": \"深入理解激光干涉仪升级方案及高频力传感器在工业现场的应用场景，补充光电门局限性认知。\"}, {\"icon\": \"fa-book\", \"text\": \"预习动量守恒内容。\", \"description\": \"回顾 F=ma 核心纽带作用，提前思考碰撞实验中力、质量、速度变量的关联，为下一节动量守恒定律学习奠定基础。\"}, {\"icon\": \"fa-cogs\", \"text\": \"核心概念复盘。\", \"description\": \"巩固‘动态补偿’与‘空载预调’两大关键方法，明确其在消除初始偏差与提升数据采集分辨率中的工程价值。\"}, {\"icon\": \"fa-check-circle\", \"text\": \"执行要点确认。\", \"description\": \"确保所有操作步骤符合安全规范，设备调试遵循标准流程，培养严谨的职业素养与工匠精神。\"}], \"keyTakeaway\": \"通过撰写规范报告与预习新知，将故障排查经验转化为系统的工程能力，实现从理论到实践的完整闭环。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('abd58aba-9143-4764-bfd1-fec6fe2e43a3', '9da12907-ffda-40fb-9be6-d245c93b1363', 1, '课程导入', '{\"title\": \"3D建模基础教学课程封面：案例复盘\", \"points\": [\"深度剖析案例核心矛盾：从现实需求到数字模型转化的关键痛点\", \"拆解执行决策逻辑：阐述拓扑选择、布线策略与工具链匹配依据\", \"展示最终交付成果：对比原始草图与高精度模型的视觉差异\", \"提炼可复用经验：总结高效工作流与常见工程陷阱的规避方案\"], \"part\": \"课程导入\"}', '{\"text\": \"页面标题：3D建模基础教学课程封面：案例复盘\\n\\n页面文字：\\n- 剖析现实需求转化为数字模型时的核心矛盾与关键痛点问题背景。\\n- 拆解拓扑选择、布线策略及工具链匹配的执行决策逻辑与方法动作。\\n- 展示原始草图与高精度模型的视觉差异，提炼高效工作流经验启示。\", \"generated_at\": \"2026-03-10T06:06:00.213490\"}', '9da12907-ffda-40fb-9be6-d245c93b1363/pages/abd58aba-9143-4764-bfd1-fec6fe2e43a3_v1.png', 'COMPLETED', '2026-03-10 06:04:46', '2026-03-10 06:08:09', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ac3c95fd-f982-4148-b9dd-55fae3946515', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 2, '第一部分：课程导览与愿景', '{\"title\": \"思政引领：3D建模中的职业精神与社会责任\", \"points\": [\"工匠精神：在毫厘之间追求极致，弘扬精益求精的行业风尚\", \"版权意识：尊重原创设计，严守知识产权法律底线\", \"文化自信：将中国传统美学元素融入现代3D设计表达\", \"绿色理念：通过优化拓扑与渲染降低能耗，践行可持续发展观\"], \"layout_id\": \"edu_data_board\", \"part\": \"第一部分：课程导览与愿景\", \"logical_page_id\": \"p03\", \"has_image\": false, \"keywords\": [\"工匠精神：在毫厘之间追求极致，弘扬精益求精的行业风尚\", \"版权意识：尊重原创设计，严守知识产权法律底线\", \"文化自信：将中国传统美学元素融入现代3D设计表达\"], \"depends_on\": [\"p02\"], \"must_cover\": [\"工匠精神：在毫厘之间追求极致，弘扬精益求精的行业风尚\", \"版权意识：尊重原创设计，严守知识产权法律底线\", \"文化自信：将中国传统美学元素融入现代3D设计表达\", \"绿色理念：通过优化拓扑与渲染降低能耗，践行可持续发展观\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"b\", \"layout_archetype\": \"data_dashboard\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.418581\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_data_board', '{\"title\": \"思政引领：3D建模中的职业精神与社会责任\", \"subtitle\": \"核心素养四维矩阵。\", \"metrics\": [{\"value\": \"100%\", \"label\": \"原创版权合规率\", \"note\": \"严守知识产权法律底线。\"}, {\"value\": \"+30%\", \"label\": \"渲染能耗降低幅度\", \"note\": \"绿色理念践行成效。\"}], \"bars\": [{\"label\": \"工匠精神指数\", \"baseline\": 60, \"current\": 95}, {\"label\": \"文化自信融合度\", \"baseline\": 50, \"current\": 88}], \"bullets\": [{\"text\": \"极致匠心：毫厘之间的品质追求。\", \"description\": \"在建模细节中弘扬精益求精的行业风尚，拒绝粗制滥造。\"}, {\"text\": \"版权敬畏：尊重原创的法治意识。\", \"description\": \"将尊重原创设计内化为职业习惯，严守知识产权法律红线。\"}, {\"text\": \"美学自信：传统元素的现代转译。\", \"description\": \"深入挖掘中国传统美学元素，赋能现代3D设计的文化表达。\"}, {\"text\": \"绿色可持续：低碳高效的渲染实践。\", \"description\": \"通过优化拓扑结构与渲染方案降低算力能耗，践行绿色发展观。\"}], \"insight\": \"技术是手段，精神是灵魂；将职业道德融入代码与多边形，塑造有温度的数字工匠。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"data_dashboard\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ac50f4ad-cc45-4f70-9d0b-17e641acb375', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"第二章：高精度雕刻与拓扑重绘\", \"layout_id\": \"feedback_poll\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p08\"], \"must_cover\": [\"章节引入\", \"ZBrush与Blender工作流衔接\", \"第二章：高精度雕刻与拓扑重绘的核心概念与背景\", \"第二章：高精度雕刻与拓扑重绘的关键方法与执行要点\", \"第二章：高精度雕刻与拓扑重绘的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第二章：高精度雕刻与拓扑重绘的核心概念与背景\", \"第二章：高精度雕刻与拓扑重绘的关键方法与执行要点\", \"第二章：高精度雕刻与拓扑重绘的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928507\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'feedback_poll', '{\"title\": \"第二章：高精度雕刻与拓扑重绘\", \"content\": [\"承接前序章节关于布线对动画变形决定性影响的结论，本章将深入工业级工作流核心：利用ZBrush进行高模细节雕刻，并通过拓扑重绘将细节映射至低模骨架。\", \"重点阐述ZBrush与Blender的无缝衔接机制，解析如何构建‘隐形骨架’以支撑动态表演，确保从静态几何到动态角色的平滑过渡。\"], \"highlight\": \"优秀的拓扑不仅是静态几何的堆砌，更是为动态表演预留的‘隐形骨架’。\", \"image\": {\"src\": \"\", \"alt\": \"极简网格点阵背景，职教绿线条勾勒ZBrush与Blender软件图标轮廓，无文字数字\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
