INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ad0e7b46-c117-4642-919c-869cfe5a81af', 'faba4721-d6bc-47a9-847e-395b2a603584', 12, NULL, '{\"page_id\": \"p13\", \"title\": \"典型应用场景：自动驾驶边缘节点\", \"layout_id\": \"title_bullets\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p12\"], \"must_cover\": [\"场景挑战\", \"OpenClaw 解决方案\", \"落地效果\", \"典型应用场景：自动驾驶边缘节点的核心概念与背景\", \"典型应用场景：自动驾驶边缘节点的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"典型应用场景：自动驾驶边缘节点的核心概念与背景\", \"典型应用场景：自动驾驶边缘节点的关键方法与执行要点\", \"典型应用场景：自动驾驶边缘节点的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p13\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:24:32.582415\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:23:02', '2026-03-10 14:55:52', 'title_bullets', '{\"title\": \"典型应用场景：自动驾驶边缘节点\", \"subtitle\": \"低延时高可靠的城市级感知网络。\", \"bullets\": [{\"icon\": \"fa-car-crash\", \"text\": \"复杂场景挑战。\", \"description\": \"自动驾驶面临极端天气、信号遮挡及高并发数据处理难题，传统中心化架构无法满足毫秒级决策需求，存在严重安全隐患。\"}, {\"icon\": \"fa-microchip\", \"text\": \"OpenClaw 解决方案。\", \"description\": \"部署边缘计算节点集群，利用异构资源池化技术将感知、决策与控制算力下沉至路侧单元，实现本地实时推理与云端协同训练。\"}, {\"icon\": \"fa-tachometer-alt\", \"text\": \"极致响应速度。\", \"description\": \"通过动态调度引擎优化任务路由，将端到端感知延迟压缩至15ms以内，确保车辆在高速行驶中的绝对安全响应。\"}, {\"icon\": \"fa-sync\", \"text\": \"断网续传机制。\", \"description\": \"内置离线缓存与断点续传协议，在网络波动或中断情况下，边缘节点仍能独立运行并同步关键数据至云端。\"}, {\"icon\": \"fa-chart-line\", \"text\": \"规模化落地效果。\", \"description\": \"已在多个智慧城市示范区完成部署，支撑日均千万级帧图像处理，显著降低交通拥堵与事故率，验证了架构的鲁棒性。\"}], \"keyTakeaway\": \"OpenClaw赋能自动驾驶边缘节点，在极端环境下实现确定性低延时与高可靠性，重塑未来出行安全标准。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
