INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ae46d268-81ab-4161-917e-905311ea6965', '2f844b20-de75-4ac5-98d1-2f44296e9e2b', 13, NULL, '{\"page_id\": \"p14\", \"title\": \"拓展思考：航天发射与超重失重\", \"layout_id\": \"edu_core_hub\", \"has_image\": true, \"keywords\": [\"火箭升空剪影\", \"星空背景\", \"宇航员漂浮\", \"无文字视觉冲击\", \"宏大叙事感\"], \"depends_on\": [\"p13\"], \"must_cover\": [\"推力大于重力时的加速\", \"超重与失重的临界点\", \"拓展思考：航天发射与超重失重的核心概念与背景\", \"拓展思考：航天发射与超重失重的关键方法与执行要点\", \"拓展思考：航天发射与超重失重的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"拓展思考：航天发射与超重失重的核心概念与背景\", \"拓展思考：航天发射与超重失重的关键方法与执行要点\", \"拓展思考：航天发射与超重失重的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"core_model\", \"layout_variant\": \"a\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:09:35.126165\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 02:08:46', '2026-03-17 02:09:35', 'edu_core_hub', '{\"title\": \"航天发射：超重与失重的临界跨越\", \"subtitle\": \"推力大于重力时的加速奥秘。\", \"center_label\": \"加速度方向决定视重\", \"nodes\": [{\"title\": \"升空阶段超重\"}, {\"title\": \"入轨后完全失重\"}, {\"title\": \"返回舱减速超重\"}, {\"title\": \"航天员受力分析\"}], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"core_model\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ae85204d-1ad9-4246-a07c-1e83b6bebe89', '1d063203-8ece-436a-ad39-9501e3c7e06b', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"细节规格：高精度参数标准\", \"layout_id\": \"detail_specs\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p07\"], \"must_cover\": [\"UV展开比例\", \"法线贴图分辨率\", \"实体尺寸公差\", \"材质物理属性\", \"细节规格：高精度参数标准的核心概念与背景\"], \"promises_open\": [{\"promise_id\": \"pr_p08_1\", \"text\": \"常见建模错误案例及修复方案\", \"must_cover\": [\"破面问题\", \"法线错误\", \"比例失调\"], \"target_page_ids\": [\"p11\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"细节规格：高精度参数标准的核心概念与背景\", \"细节规格：高精度参数标准的关键方法与执行要点\", \"细节规格：高精度参数标准的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-20T01:09:55.819798\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-20 01:09:17', '2026-03-20 01:09:56', 'detail_specs', '{\"title\": \"细节规格：高精度参数标准\", \"content\": [\"UV展开比例需严格遵循1:1或4:1网格对齐，确保贴图无拉伸变形，支撑硬表面边缘锐度。\", \"法线贴图分辨率统一锁定为2048x2048或4096x4096，以承载布尔运算后的微小倒角细节。\", \"实体尺寸公差控制在±0.05mm以内，材质物理属性必须匹配真实世界密度与粗糙度参数。\", \"高精度参数标准旨在消除模型在工业级渲染中的破面与光影错误，确保交付物零瑕疵。\"], \"highlight\": \"UV展开与法线精度决定最终视觉上限。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('af36940e-af8c-4f6e-ba55-e53d2dafbcf8', '8a37f529-e51f-428c-8466-cdc137b73187', 6, NULL, '{\"title\": \"布线策略实战：硬表面 vs 有机体：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"academic_narrative\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p07\", \"depends_on\": [\"p06\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p07\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.107540\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'academic_narrative', '{\"title\": \"布线策略实战：硬表面 vs 有机体\", \"narrative\": [\"在角色装甲与生物制作中，核心矛盾在于刚性结构维持与自然形变需求的冲突。硬表面建模需遵循严格的四边形流形逻辑，通过密集环状支撑确保机械关节的锐利边缘与刚性，避免拉伸变形；而有机体布线则强调沿肌肉走向的流线型分布，利用极点控制形变幅度，实现皮肤褶皱的自然过渡。若将硬表面的刚性拓扑强行用于生物关节，会导致动画撕裂；反之，有机体的稀疏布线用于机械外骨骼，则无法承载高应力下的渲染细节。\", \"执行关键在于决策依据的精准匹配。针对机械部件，采用分层布线策略，在受力点增加支撑环密度，确保UV展开时的线性拉伸最小化；针对生物组织，则需在关节处预留足够的折叠空间（crease space），并平滑处理布线密度梯度。案例显示，混用策略常导致法线贴图错位或蒙皮权重异常，因此必须严格区分物理属性，建立差异化的拓扑规范库。\"], \"margin_notes\": [{\"title\": \"核心概念：拓扑连续性\", \"content\": \"指多边形网格在几何变换中保持邻接关系不变的特性，是防止模型撕裂的物理基础。\"}, {\"title\": \"风险提示：极点滥用\", \"content\": \"硬表面严禁使用五极点以上节点，否则在细分曲面下会产生不可控的凹陷或凸起。\"}], \"pull_quote\": \"布线不仅是几何构建，更是物理属性的数字化映射；错误的拓扑即是对物理规律的违背。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('af4d8478-a35d-4d61-ac80-706bc781f57d', '8a37f529-e51f-428c-8466-cdc137b73187', 16, NULL, '{\"page_id\": \"p17\", \"title\": \"节点连接逻辑与噪声函数应用\", \"layout_id\": \"academic_narrative\", \"has_image\": true, \"keywords\": [\"节点流程图\", \"数学噪声波形\", \"混合模式图标\", \"技术图解风格\"], \"depends_on\": [\"p13\"], \"must_cover\": [\"步骤1：基础噪声生成\", \"步骤2：频率/振幅调节\", \"步骤3：遮罩混合逻辑\", \"步骤4：最终输出\", \"节点连接逻辑与噪声函数应用的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"节点连接逻辑与噪声函数应用的核心概念与背景\", \"节点连接逻辑与噪声函数应用的关键方法与执行要点\", \"节点连接逻辑与噪声函数应用的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p17\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.108078\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'academic_narrative', '{\"title\": \"节点连接逻辑与噪声函数应用\", \"narrative\": [\"节点连接逻辑是程序化纹理构建的骨架，其本质是将数学函数可视化为数据流。第一步基础噪声生成通常始于Perlin或Simplex噪声节点，它们提供了随机但平滑的基底；第二步频率与振幅调节通过乘法或除法节点实现，改变噪声的‘颗粒大小’与‘起伏强度’，从而模拟不同尺度的表面特征；第三步遮罩混合逻辑利用黑白蒙版节点，精准控制两种不同噪声或材质的过渡区域，解决金属球体高光过曝与陶瓷杯面反射均匀的问题；第四步最终输出将处理后的数值映射至PBR工作流的\", \"噪声函数的应用不仅仅是生成随机图案，更是模拟自然界中无序中的有序规律。在处理高反光金属时，需利用高频噪声模拟微观划痕，通过低通滤波平滑整体反射，避免高光破碎；而在处理磨砂陶瓷时，则需结合分形噪声（Fractal Noise）叠加多层不同频率的扰动，以还原微表面粗糙带来的柔和过渡感。关键在于理解每个节点的输入输出维度，确保向量运算的一致性，防止因数据类型不匹配导致的渲染错误。\"], \"margin_notes\": [{\"title\": \"核心概念：分形维数\", \"content\": \"指物体占据空间的复杂程度，在节点树中体现为噪声层级的叠加次数，直接决定表面的精细度与自相似性。\"}, {\"title\": \"技术提示：遮罩混合\", \"content\": \"使用Mix节点时，Alpha值应控制在0.1-0.9之间以避免硬边，配合Gradient节点可实现自然的物理渐变效果。\"}], \"pull_quote\": \"节点树不仅是工具的连接，更是物理规律的可视化表达；每一个参数的微调都是对现实世界光影交互的重新定义。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
