INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('b3a7cadf-c58e-485a-92e8-7868e327cdd5', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef', 7, '第二部分：核心流程', '{\"page_id\": \"p06\", \"title\": \"关键步骤详解：拓扑布线规范\", \"part\": \"第二部分：核心流程\", \"points\": [\"四边面结构确保模型在弯曲与拉伸时保持形态稳定，避免三角面导致的撕裂变形\", \"边缘循环线需严格贴合肌肉纹理走向，以支持角色动画中的自然关节运动\", \"严格控制极点数量与分布，防止高模细分后出现不必要的几何扭曲或凹陷\", \"优化布线密度策略，在动态区域加密、静态区域稀疏以提升渲染效率\"]}', '{\"text\": \"页面标题：关键步骤详解：拓扑布线规范\\n\\n页面文字：\\n- 采用四边面结构可确保模型在弯曲与拉伸时保持形态稳定，彻底避免三角面引发的撕裂变形风险。\\n- 边缘循环线需严格贴合肌肉纹理走向，以此支持角色动画中关节运动时的自然流畅过渡。\\n- 严格控制极点数量与空间分布，防止高模细分后出现不必要的几何扭曲或局部凹陷缺陷。\\n- 实施优化布线密度策略，在动态区域加密、静态区域稀疏，显著提升整体渲染计算效率。\", \"generated_at\": \"2026-03-10T05:38:52.997110\"}', NULL, 'FAILED', '2026-03-10 05:38:32', '2026-03-10 05:38:58', NULL, NULL);
