INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('b7b6cf9c-8159-4328-8b58-ff5408cc45fe', '1d063203-8ece-436a-ad39-9501e3c7e06b', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"设备认知：核心建模工作流\", \"layout_id\": \"equipment_orientation\", \"has_image\": true, \"keywords\": [\"三维软件界面\", \"功能模块示意图\", \"工程蓝配色\", \"极简线条\", \"无文字流程图\"], \"depends_on\": [\"p03\"], \"must_cover\": [\"视图控制区定义\", \"修改器堆栈逻辑\", \"坐标系统解析\", \"快捷键映射表\", \"设备认知：核心建模工作流的核心概念与背景\"], \"promises_open\": [{\"promise_id\": \"pr_p04_1\", \"text\": \"后续将详解多边形建模的核心技法\", \"must_cover\": [\"硬表面建模\", \"有机体拓扑\", \"布线优化\"], \"target_page_ids\": [\"p06\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"设备认知：核心建模工作流的核心概念与背景\", \"设备认知：核心建模工作流的关键方法与执行要点\", \"设备认知：核心建模工作流的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-20T01:09:55.819659\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-20 01:09:16', '2026-03-20 01:09:56', 'equipment_orientation', '{\"title\": \"设备认知：核心建模工作流\", \"left\": {\"header\": \"核心功能模块解析\", \"content\": [\"设备认知：核心建模工作流在核心功能模块解析下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-eye\", \"text\": \"视图控制区：定义四屏交互逻辑与实时缩放平移。\", \"description\": \"解释视图控制区：定义四屏交互逻辑与实时缩放平移在核心功能模块解析维度下的意义。\"}, {\"icon\": \"fa-cubes\", \"text\": \"修改器堆栈：构建非破坏性编辑的层级依赖逻辑。\", \"description\": \"解释修改器堆栈：构建非破坏性编辑的层级依赖逻辑在核心功能模块解析维度下的意义。\"}, {\"icon\": \"fa-arrows-alt\", \"text\": \"坐标系统：解析局部、全局与父级坐标变换体系。\", \"description\": \"解释坐标系统：解析局部、全局与父级坐标变换体系在核心功能模块解析维度下的意义。\"}, {\"icon\": \"fa-keyboard-o\", \"text\": \"快捷键映射：建立高效操作的人机交互基准表。\", \"description\": \"解释快捷键映射：建立高效操作的人机交互基准表在核心功能模块解析维度下的意义。\"}]}, \"right\": {\"header\": \"三维软件界面架构示意\", \"content\": [\"工程蓝配色极简线条风格，展示无文字流程图式界面布局，突出功能区划分与数据流向。\", \"结论：设备认知：核心建模工作流需要结合目标场景做取舍。\"], \"bullets\": []}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('b895af24-52fa-475d-b650-b4a7b05a07b6', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef', 13, '总结与答疑', '{\"page_id\": \"p12\", \"title\": \"课后思考与延伸学习资源\", \"part\": \"总结与答疑\", \"points\": [\"推荐练习项目：复刻经典游戏道具，强化拓扑与材质实战能力\", \"行业前沿技术趋势展望：AI辅助建模与实时渲染引擎新动态\", \"配套教材与开源素材库指引：精选权威书籍及免费模型资源站\", \"建立个人作品集策略：如何整理并展示高质量3D建模案例\"]}', '{\"text\": \"页面标题：课后思考与延伸学习资源\\n\\n页面文字：\\n- 推荐练习项目复刻经典游戏道具，通过强化拓扑与材质实战能力巩固所学。\\n- 关注AI辅助建模与实时渲染引擎新动态，把握行业前沿技术发展趋势。\\n- 指引配套教材与开源素材库，精选权威书籍及免费模型资源站供深入学习。\\n- 建立个人作品集策略，学习如何整理并展示高质量3D建模案例以对接就业。\", \"generated_at\": \"2026-03-10T05:38:51.716822\"}', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef/pages/b895af24-52fa-475d-b650-b4a7b05a07b6_v1.png', 'COMPLETED', '2026-03-10 05:38:44', '2026-03-10 06:04:32', NULL, NULL);
