INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('b9f4561e-3fb8-4da0-b063-8410e200a685', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 2, '导览', '{\"title\": \"目录与学习路线图：案例复盘\", \"points\": [\"问题与场景：解析低模布线混乱导致的动画拉伸痛点\", \"方案与执行：演示四边面重构与循环边优化的关键步骤\", \"结果与启示：对比优化前后渲染效率提升数据\", \"风险提示：警惕过度细分造成的面数冗余与性能瓶颈\"], \"part\": \"导览\"}', '{\"text\": \"目录与学习路线图：案例复盘\\n\\n页面文字：\\n- 问题背景：低模布线混乱导致动画拉伸严重，影响角色动作自然度。\\n- 方法动作：执行四边面重构并优化循环边，重塑模型基础拓扑结构。\\n- 结果启示：优化后渲染效率显著提升，为后续动画制作扫清障碍。\\n- 风险提示：需警惕过度细分造成的面数冗余与实时性能瓶颈问题。\", \"generated_at\": \"2026-03-09T03:39:36.940053\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/b9f4561e-3fb8-4da0-b063-8410e200a685_v1.png', 'COMPLETED', '2026-03-09 03:39:10', '2026-03-09 03:40:26', NULL, NULL);
