INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('bb40a709-516b-42a7-941b-e4516fc219dd', '6eea18f8-c641-48a1-ba84-4c49ed3830d6', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"旧版局限：算力孤岛与生态割裂\", \"layout_id\": \"edu_data_board\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p03\"], \"must_cover\": [\"算力隔离问题\", \"生态碎片化现状\", \"旧版局限：算力孤岛与生态割裂的核心概念与背景\", \"旧版局限：算力孤岛与生态割裂的关键方法与执行要点\", \"旧版局限：算力孤岛与生态割裂的应用场景与注意事项\"], \"promises_open\": [{\"promise_id\": \"pr_p07_1\", \"text\": \"针对算力孤岛的具体解决方案与实施路径\", \"must_cover\": [\"分布式调度策略\", \"硬件抽象层优化\"], \"target_page_ids\": [\"p19\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"旧版局限：算力孤岛与生态割裂的核心概念与背景\", \"旧版局限：算力孤岛与生态割裂的关键方法与执行要点\", \"旧版局限：算力孤岛与生态割裂的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_dashboard\", \"layout_variant\": \"a\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:27:09.079401\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:25:44', '2026-03-10 06:27:09', 'edu_data_board', '{\"title\": \"旧版局限：算力孤岛与生态割裂\", \"subtitle\": \"资源利用率低，协同效率不足。\", \"metrics\": [{\"value\": \"-65%\", \"label\": \"跨域算力共享率\", \"note\": \"较理想状态严重缺失。\"}, {\"value\": \"+120%\", \"label\": \"重复建设成本\", \"note\": \"因生态碎片化导致。\"}], \"bars\": [{\"label\": \"异构设备兼容度\", \"baseline\": 30, \"current\": 85}, {\"label\": \"数据流转效率\", \"baseline\": 40, \"current\": 90}], \"bullets\": [{\"text\": \"算力资源物理隔离。\", \"description\": \"各业务线独立部署，形成无法互通的算力孤岛，导致资源闲置与瓶颈并存。\"}, {\"text\": \"生态标准严重碎片化。\", \"description\": \"缺乏统一接口规范，新旧系统耦合度高，新模块接入成本高昂且周期漫长。\"}, {\"text\": \"协同机制完全缺失。\", \"description\": \"数据流转依赖人工搬运，缺乏自动化调度能力，难以支撑大规模并发场景。\"}], \"insight\": \"必须打破物理边界与逻辑壁垒，构建统一调度底座以激活存量资产。\", \"background_image\": \"https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=1920&auto=format&fit=crop\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_dashboard\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('bbfdac22-92e6-445c-89bb-bb515fe97f34', '60390839-f925-4662-a2dc-c92d64253b33', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"核心概念：拓扑结构与布线\", \"layout_id\": \"theory_explanation\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p04\"], \"must_cover\": [\"网格拓扑定义\", \"流线与变形关系\", \"欧拉公式在建模中的应用\", \"核心概念：拓扑结构与布线的核心概念与背景\", \"核心概念：拓扑结构与布线的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p02_1\"], \"points\": [\"核心概念：拓扑结构与布线的核心概念与背景\", \"核心概念：拓扑结构与布线的关键方法与执行要点\", \"核心概念：拓扑结构与布线的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p02_1\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:29:50', '2026-03-10 05:29:50', 'theory_explanation', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('bc0ea9f2-0e0c-47a6-b9e9-0fa28a883307', '1f37a671-a607-4c8a-8f40-01a92198cd70', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"参数化设计 vs 手动建模\", \"layout_id\": \"comparison_table\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"效率对比\", \"灵活性对比\", \"适用行业对比\", \"学习曲线对比\", \"参数化设计 vs 手动建模的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"参数化设计 vs 手动建模的核心概念与背景\", \"参数化设计 vs 手动建模的关键方法与执行要点\", \"参数化设计 vs 手动建模的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:30:53', '2026-03-10 05:30:53', 'comparison_table', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('bc1e6cd0-04d8-4c13-96a5-7cbf885c54bd', '9b5d83ef-2600-4c3b-b852-00607680277d', 8, '应用价值', '{\"page_id\": \"p09\", \"title\": \"行业影响：重塑内容生产与工作流\", \"part\": \"应用价值\", \"points\": [\"自动生成文案、代码与视觉素材大幅提效，释放创意生产力\", \"个性化教育辅导与智能客服成为企业新标配，降低运营成本\", \"企业级应用正从概念实验走向规模化落地，重构核心业务流程\", \"人机协作模式发生根本性转变，AI 从辅助工具升级为决策伙伴\"]}', '{\"text\": \"页面标题：行业影响：重塑内容生产与工作流\\n\\n页面文字：\\n- 自动生成文案、代码与视觉素材大幅提效，全面释放了人类的创意生产力。\\n- 个性化教育辅导与智能客服成为企业新标配，有效降低了整体运营成本。\\n- 企业级应用正从概念实验走向规模化落地，正在重构核心业务流程与架构。\\n- 人机协作模式发生根本性转变，AI已从辅助工具升级为关键的决策合作伙伴。\", \"generated_at\": \"2026-03-09T08:14:14.916920\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/bc1e6cd0-04d8-4c13-96a5-7cbf885c54bd_v2.png', 'FAILED', '2026-03-09 08:13:51', '2026-03-09 09:20:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('bc381352-713b-421a-b5d7-92cc71618af7', '7a4f3408-ca73-4a61-998e-174a92497610', 8, NULL, '{\"page_id\": \"p09\", \"title\": \"案例研讨：精密仪器外壳建模复盘\", \"layout_id\": \"case_discussion\", \"has_image\": true, \"keywords\": [\"高清产品渲染图\", \"爆炸视图分解\", \"工业蓝调背景\", \"问题聚焦气泡\", \"小组讨论引导区\"], \"depends_on\": [\"p07\"], \"must_cover\": [\"设计意图分析\", \"拓扑重构过程\", \"常见问题诊断\", \"优化方案对比\", \"案例研讨：精密仪器外壳建模复盘的核心概念与背景\"], \"promises_open\": [{\"promise_id\": \"pr_p09_1_6aa9e5d0\", \"text\": \"案例研讨：精密仪器外壳建模复盘的复盘与结果启示\", \"must_cover\": [\"案例复盘\", \"结果启示\"], \"target_page_ids\": [\"p17\"], \"is_hard\": true}], \"promises_close\": [\"pr_p01_2\"], \"points\": [\"案例研讨：精密仪器外壳建模复盘的核心概念与背景\", \"案例研讨：精密仪器外壳建模复盘的关键方法与执行要点\", \"案例研讨：精密仪器外壳建模复盘的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_2\"], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p09\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p01_2\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.266748\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:01', 'case_discussion', '{\"title\": \"案例研讨：精密仪器外壳建模复盘\", \"content\": [\"项目背景聚焦于一款高精密医疗仪器外壳，初始模型存在布线冗余导致细分后表面扭曲，且倒角处出现黑斑瑕疵。\", \"团队通过重构核心拓扑结构，优化支撑边分布并统一四边形面片，成功解决了形变问题并实现了工业级光滑渲染。\", \"此案例启示我们：优秀的硬表面建模不仅依赖工具，更在于对拓扑逻辑的深刻理解与严谨执行。\"], \"highlight\": \"拓扑重构是解决复杂曲面问题的关键钥匙。\", \"image\": {\"src\": \"\", \"alt\": \"高清产品渲染图展示精密仪器外壳，配合爆炸视图分解结构与工业蓝调背景，无文字无Logo\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('bde26672-d861-4d78-8010-c9df62c0aa42', '8a37f529-e51f-428c-8466-cdc137b73187', 22, NULL, '{\"page_id\": \"p23\", \"title\": \"课程总结与致谢\", \"layout_id\": \"ending_academic\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p19\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"summary_reflection\", \"layout_variant\": \"a\", \"logical_page_id\": \"p23\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.108316\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'ending_academic', '{\"title\": \"课程总结与致谢\", \"summary_points\": [\"掌握节点树架构与数据流逻辑：实现从坐标/噪声输入到PBR参数输出的像素级转化。\", \"理解实时渲染优化核心：在视觉保真度与计算资源间寻找平衡，运用LOD技术降低GPU负载。\", \"规避工程常见误区：警惕过度细分网格导致的顶点处理饱和及UV展开不当引发的材质模糊。\", \"建立进阶学习路径：整合专业书籍、开源工具与社区资源，形成完整的技能树成长闭环。\"], \"homework\": [\"基于Blender或Houdini，设计一个包含LOD切换机制的程序化纹理生成工作流，并输出对比视频。\", \"撰写一份关于非平面UV展开中纹理拉伸问题的分析报告，提出至少两种优化方案。\"], \"next_chapter\": \"下节预告：第六章将深入探讨全局光照（Global Illumination）算法及其在实时场景中的近似解法。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"summary_reflection\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('be39a37a-ee5f-4ada-9c73-f3eebba25727', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 15, NULL, '{\"page_id\": \"p10\", \"title\": \"不同领域软件横向测评\", \"layout_id\": \"edu_tri_compare\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"影视级需求\", \"游戏级需求\", \"建筑表现需求\", \"不同领域软件横向测评的核心概念与背景\", \"不同领域软件横向测评的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_job_1\", \"text\": \"就业市场具体数据分析\", \"must_cover\": [\"薪资水平\", \"人才缺口\"], \"target_page_ids\": [\"p26\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"不同领域软件横向测评的核心概念与背景\", \"不同领域软件横向测评的关键方法与执行要点\", \"不同领域软件横向测评的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p16\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_compare\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T13:04:03.227904\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'edu_tri_compare', '{\"title\": \"不同领域软件横向测评\", \"left\": {\"header\": \"测评核心概念\", \"content\": [\"不同领域软件横向测评在测评核心概念下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-book-reader\", \"text\": \"确立行业评估基线，明确工具能力边界。\", \"description\": \"解释确立行业评估基线，明确工具能力边界在测评核心概念维度下的意义。\"}, {\"icon\": \"fa-radar\", \"text\": \"量化性能资源消耗，识别技术债务风险。\", \"description\": \"解释量化性能资源消耗，识别技术债务风险在测评核心概念维度下的意义。\"}, {\"icon\": \"fa-project-diagram\", \"text\": \"分析跨平台 SOP 规范，确保流转安全。\", \"description\": \"解释分析跨平台 SOP 规范，确保流转安全在测评核心概念维度下的意义。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"综合评估预算目标，避免资源浪费。\", \"description\": \"解释综合评估预算目标，避免资源浪费在测评核心概念维度下的意义。\"}]}, \"right\": {\"header\": \"领域需求与执行\", \"content\": [\"不同领域软件横向测评在领域需求与执行下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-film\", \"text\": \"影视渲染精度优先，考察显存与通道支持。\", \"description\": \"解释影视渲染精度优先，考察显存与通道支持在领域需求与执行维度下的意义。\"}, {\"icon\": \"fa-gamepad\", \"text\": \"游戏实时交互优化，关注引擎导出格式。\", \"description\": \"解释游戏实时交互优化，关注引擎导出格式在领域需求与执行维度下的意义。\"}, {\"icon\": \"fa-drafting-compass\", \"text\": \"建筑光影真实感，侧重材质贴图解析力。\", \"description\": \"解释建筑光影真实感，侧重材质贴图解析力在领域需求与执行维度下的意义。\"}, {\"icon\": \"fa-wrench\", \"text\": \"建立参数基线测试，监控资产损耗情况。\", \"description\": \"解释建立参数基线测试，监控资产损耗情况在领域需求与执行维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_compare\"}');
