INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c1989cbd-2320-43dc-bc4f-05cc2b2d46de', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 9, '视觉表现', '{\"page_id\": \"p08\", \"title\": \"灯光布置与渲染引擎初探\", \"part\": \"视觉表现\", \"points\": [\"三点布光法（主光、补光、轮廓光）构建基础立体感与层次\", \"区域光精准照明结合HDRI环境光模拟真实物理光照反射\", \"Cycles路径追踪追求极致画质，Eevee实时引擎兼顾效率预览\", \"利用渲染器特性优化噪点控制与采样设置提升出图速度\"]}', '{\"text\": \"页面标题：灯光布置与渲染引擎初探\\n\\n页面文字：\\n- 采用三点布光法构建主光、补光与轮廓光，奠定场景基础立体感与丰富层次。\\n- 结合区域光精准照明与HDRI环境光，模拟真实物理光照反射以增强沉浸体验。\\n- 依据需求在Cycles路径追踪的极致画质与Eevee实时引擎的高效预览间灵活切换。\\n- 利用渲染器特性优化噪点控制策略与采样设置，显著提升最终出图速度与质量。\", \"generated_at\": \"2026-03-09T03:39:38.191747\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/c1989cbd-2320-43dc-bc4f-05cc2b2d46de_v1.png', 'COMPLETED', '2026-03-09 03:39:20', '2026-03-09 03:47:18', NULL, NULL);
