INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c3c7090b-e68e-4df3-8c39-76e010f25fe8', '8fb9adbb-55b5-496b-9569-be1757626e7c', 11, NULL, '{\"title\": \"进阶案例：斜面与摩擦力：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"vocational_theory\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p12\", \"depends_on\": [\"p11\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p12\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T04:44:29.430666\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 04:43:52', '2026-03-17 04:44:29', 'vocational_theory', '{\"title\": \"进阶案例：斜面与摩擦力：案例复盘\", \"left\": {\"header\": \"问题与场景\", \"content\": [\"进阶案例：斜面与摩擦力：案例复盘在问题与场景下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-exclamation-circle\", \"text\": \"核心矛盾：如何精准计算物体在斜面上的下滑临界状态。\", \"description\": \"解释核心矛盾：如何精准计算物体在斜面上的下滑临界状态在问题与场景维度下的意义。\"}, {\"icon\": \"fa-industry\", \"text\": \"职业场景：物流坡道设计或矿山传送带倾角参数确定。\", \"description\": \"解释职业场景：物流坡道设计或矿山传送带倾角参数确定在问题与场景维度下的意义。\"}, {\"icon\": \"fa-search\", \"text\": \"关键难点：重力方向与坐标系不重合，需正交分解。\", \"description\": \"解释关键难点：重力方向与坐标系不重合，需正交分解在问题与场景维度下的意义。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"受力特征：支持力垂直斜面，摩擦力沿斜面反向。\", \"description\": \"解释受力特征：支持力垂直斜面，摩擦力沿斜面反向在问题与场景维度下的意义。\"}]}, \"right\": {\"header\": \"方案与结果\", \"content\": [\"进阶案例：斜面与摩擦力：案例复盘在方案与结果下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-cogs\", \"text\": \"执行动作：建立沿斜面为x轴、垂直斜面为y轴的坐标系。\", \"description\": \"解释执行动作：建立沿斜面为x轴、垂直斜面为y轴的坐标系在方案与结果维度下的意义。\"}, {\"icon\": \"fa-calculator\", \"text\": \"决策依据：G1=mgsinθ驱动下滑，G2=mgcosθ决定支持力。\", \"description\": \"解释决策依据：G1=mgsinθ驱动下滑，G2=mgcosθ决定支持力在方案与结果维度下的意义。\"}, {\"icon\": \"fa-check-circle\", \"text\": \"可复用经验：斜面问题必须优先进行力的正交分解。\", \"description\": \"解释可复用经验：斜面问题必须优先进行力的正交分解在方案与结果维度下的意义。\"}, {\"icon\": \"fa-triangle-exclamation\", \"text\": \"风险提示：忽略摩擦系数变化会导致安全设计失效。\", \"description\": \"解释风险提示：忽略摩擦系数变化会导致安全设计失效在方案与结果维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c4487cbd-0fa8-440a-903a-3cee8fb67ca3', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 3, '第一部分：课程导览与愿景', '{\"title\": \"课程核心目标：重点展开\", \"points\": [\"课程核心目标的核心概念与边界\", \"课程核心目标的典型案例与结果\", \"课程核心目标在本主题中的落地建议\"], \"layout_id\": \"edu_data_board\", \"part\": \"第一部分：课程导览与愿景\", \"logical_page_id\": \"p04\", \"has_image\": false, \"keywords\": [\"课程核心目标的核心概念与边界\", \"课程核心目标的典型案例与结果\", \"课程核心目标在本主题中的落地建议\"], \"depends_on\": [\"p03\"], \"must_cover\": [\"课程核心目标的核心概念与边界\", \"课程核心目标的典型案例与结果\", \"课程核心目标在本主题中的落地建议\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"a\", \"layout_archetype\": \"data_dashboard\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.418629\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_data_board', '{\"title\": \"课程核心目标：从概念到商业落地\", \"subtitle\": \"基线达标率60% → 当前交付率85%。\", \"metrics\": [{\"value\": \"+45%\", \"label\": \"商业项目交付能力提升\", \"note\": \"对比行业平均水平。\"}, {\"value\": \"100%\", \"label\": \"职业素养融合度\", \"note\": \"思政与技能双重达标。\"}], \"bars\": [{\"label\": \"传统教学交付质量\", \"baseline\": 60, \"current\": 85}], \"bullets\": [{\"text\": \"核心概念与边界界定。\", \"description\": \"明确3D建模不仅是技术操作，更是构建系统化工作流思维与践行工匠精神的过程，划定技术为手段、精神为灵魂的认知边界。\"}, {\"text\": \"典型案例与结果验证。\", \"description\": \"通过资深导师团队指导的实战案例，学员作品从单纯模型制作升级为具备完整商业逻辑的数字资产，显著提升客户满意度与交付效率。\"}, {\"text\": \"主题落地实施建议。\", \"description\": \"将职业道德融入代码与多边形构建中，在每一个建模节点植入责任意识，塑造有温度的数字工匠，实现从理论认知到商业交付的闭环。\"}], \"insight\": \"数据表明，强化核心目标中的职业精神维度，直接驱动了商业交付质量的显著跃升，实现了技术与素养的双向赋能。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_dashboard\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c45b6d5c-e165-4e65-9acb-e9c1fad5e68e', '9da12907-ffda-40fb-9be6-d245c93b1363', 8, '案例分析', '{\"page_id\": \"p07\", \"title\": \"案例拆解：机械零件建模实战\", \"part\": \"案例分析\", \"points\": [\"提取关键参数构建特征树，实现尺寸驱动下的快速迭代修改\", \"运用布尔运算与曲面缝合技术处理复杂过渡，严格控制装配公差\", \"优化CAD数据拓扑结构，确保模型满足3D打印的壁厚与支撑要求\", \"通过仿真模拟验证零件受力情况，修正潜在的结构薄弱点\"]}', '{\"text\": \"页面标题：案例拆解：机械零件建模实战\\n\\n页面文字：\\n- 针对传统设计迭代慢的问题，通过提取关键参数构建特征树，实现尺寸驱动下的快速修改。\\n- 运用布尔运算与曲面缝合技术处理复杂过渡区域，严格控制装配公差以确保零件配合精度。\\n- 优化CAD数据拓扑结构，确保最终模型完全满足3D打印工艺对壁厚与支撑结构的严苛要求。\\n- 结合仿真模拟验证零件受力情况，及时修正潜在的结构薄弱点，形成闭环的设计优化流程。\", \"generated_at\": \"2026-03-10T06:06:00.842853\"}', NULL, 'FAILED', '2026-03-10 06:04:56', '2026-03-10 06:08:28', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c476a832-b469-48da-853b-ddb89582eafd', '1d063203-8ece-436a-ad39-9501e3c7e06b', 6, NULL, '{\"page_id\": \"p07\", \"title\": \"有机体建模：拓扑布线规范\", \"layout_id\": \"technical_tip\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p06\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"quote\", \"layout_variant\": \"a\", \"logical_page_id\": \"p07\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-20T01:09:55.819766\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-20 01:09:16', '2026-03-20 01:09:56', 'technical_tip', '{\"quote\": \"拓扑即骨架，布线定生死。规范的非流式结构是硬表面渲染的基石。\", \"author\": \"工程建模铁律\", \"source\": \"硬表面建模核心规范\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"quote\"}');
