INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c4fe08cf-0752-456d-80c2-c22f2262c3e7', 'f8ce8774-c982-4cd5-a379-23d4cf53bef2', 12, NULL, '{\"page_id\": \"p13\", \"title\": \"进阶故障排查：系统误差来源\", \"layout_id\": \"vocational_case_study\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p10\"], \"must_cover\": [\"滑轮摩擦导致的拉力偏差\", \"细线质量不可忽略时的修正\", \"减小系统误差的工程技巧\", \"进阶故障排查：系统误差来源的核心概念与背景\", \"进阶故障排查：系统误差来源的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"进阶故障排查：系统误差来源的核心概念与背景\", \"进阶故障排查：系统误差来源的关键方法与执行要点\", \"进阶故障排查：系统误差来源的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"b\", \"logical_page_id\": \"p13\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T06:43:32.018222\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 06:42:47', '2026-03-17 14:44:01', 'vocational_case_study', '{\"title\": \"进阶故障排查：系统误差来源\", \"content\": [\"滑轮摩擦与细线质量是常被忽略的系统误差源，需通过更换高精度轴承滑轮及选用轻质高强碳纤维线进行修正。\", \"工程实践中采用‘空载预调法’消除初始偏差，并引入动态补偿算法实时修正拉力读数，显著提升实验精度。\"], \"highlight\": \"核心技巧：动态补偿与空载预调。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c52907f8-8567-497b-952f-95386dd3df9b', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"协作任务：优化复杂硬表面模型的布线\", \"layout_id\": \"group_collab\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p06\"], \"must_cover\": [\"任务分工说明\", \"优化标准清单\", \"交付格式要求\", \"协作任务：优化复杂硬表面模型的布线的核心概念与背景\", \"协作任务：优化复杂硬表面模型的布线的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_case_01\"], \"points\": [\"协作任务：优化复杂硬表面模型的布线的核心概念与背景\", \"协作任务：优化复杂硬表面模型的布线的关键方法与执行要点\", \"协作任务：优化复杂硬表面模型的布线的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_case_01\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_case_01\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928425\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'group_collab', '{\"title\": \"协作任务：优化复杂硬表面模型的布线\", \"subtitle\": \"从理论到实战：团队协同解决拓扑难题。\", \"bullets\": [{\"icon\": \"fa-users\", \"text\": \"任务分工说明。\", \"description\": \"每组需指定拓扑师、动画测试员与质检员，明确各自在建模、变形验证及标准核对中的职责。\"}, {\"icon\": \"fa-list-check\", \"text\": \"优化标准清单。\", \"description\": \"严格检查所有转角处是否存在N-gon，确认支撑环密度是否满足细分曲面要求，保证流动方向符合力学逻辑。\"}, {\"icon\": \"fa-file-export\", \"text\": \"交付格式要求。\", \"description\": \"提交包含原始工程文件、高模细节层及低模拓扑图的压缩包，附带变形测试视频片段以证明布线有效性。\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"常见误区警示。\", \"description\": \"严禁为了美观强行合并面片导致极点堆积，避免在非受力区域随意使用三角面破坏布线流向。\"}], \"keyTakeaway\": \"团队协作的核心在于统一拓扑标准，确保每个模型都能经受住动态变形的严苛考验。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c5442699-fd98-4f6c-8b58-bf1f8c4c128a', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 20, NULL, '{\"page_id\": \"p21\", \"title\": \"致谢\", \"layout_id\": \"ending_field\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p19\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"summary_reflection\", \"layout_variant\": \"b\", \"logical_page_id\": \"p21\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832698\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-09 07:07:33', 'ending_field', '{\"title\": \"致谢\", \"subtitle\": \"感谢每一位探索者。\", \"contact\": \"联系方式：educator@algo-mastery.edu\", \"reflection_blocks\": [{\"title\": \"反思维度：核心脉络\", \"items\": [\"从问题识别到工业级落地的完整闭环\", \"场景选择、边界处理与稳定性优化的串联思考\"]}, {\"title\": \"反思维度：技能沉淀\", \"items\": [\"掌握不稳定快排与稳定归并的实战差异\", \"建立对数据流动本质与物理类比的直观认知\"]}], \"closing\": \"算法之美，不仅在于解决当下，更在于构建未来的逻辑基石。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"summary_reflection\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c5564341-0f88-4cb9-ac95-a7637ed84896', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d', 14, '收尾', '{\"page_id\": \"p12\", \"title\": \"未来展望与答疑环节\", \"part\": \"收尾\", \"points\": [\"多模态融合：文本、图像与语音的协同理解迈向具身智能\", \"垂直落地：NLP在医疗、法律及金融领域的深度定制化应用\", \"互动答疑：针对课程难点进行集中解答与思路梳理\", \"资源推荐：精选开源数据集、经典论文与进阶学习路径\"]}', '{\"text\": \"页面标题：未来展望与答疑环节\\n\\n页面文字：\\n- 多模态融合文本、图像与语音的协同理解迈向具身智能新阶段。\\n- 垂直落地NLP在医疗、法律及金融领域的深度定制化应用持续深化。\\n- 互动答疑针对课程难点进行集中解答与思路梳理，消除学习盲区。\\n- 资源推荐精选开源数据集、经典论文与进阶学习路径助力持续成长。\\n- 感谢各位聆听，期待大家在自然语言处理领域取得更多创新突破。\", \"generated_at\": \"2026-03-16T05:37:22.715811\"}', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d/pages/c5564341-0f88-4cb9-ac95-a7637ed84896_v1.png', 'FAILED', '2026-03-16 05:37:16', '2026-03-16 06:33:52', NULL, NULL);
