INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c6ef2e28-9c5e-4fb5-94e2-78888850d647', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 14, NULL, '{\"page_id\": \"p15\", \"title\": \"第三章：灯光氛围与渲染输出\", \"layout_id\": \"warmup_inquiry\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p13\"], \"must_cover\": [\"章节引入\", \"三点布光进阶\", \"第三章：灯光氛围与渲染输出的核心概念与背景\", \"第三章：灯光氛围与渲染输出的关键方法与执行要点\", \"第三章：灯光氛围与渲染输出的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第三章：灯光氛围与渲染输出的核心概念与背景\", \"第三章：灯光氛围与渲染输出的关键方法与执行要点\", \"第三章：灯光氛围与渲染输出的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p15\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928703\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'warmup_inquiry', '{\"question\": \"在紧急交付的高精度游戏角色项目中，若发现渲染后的角色面部在特定角度出现不自然的暗斑，且已确认材质节点无误，作为主美你会如何从灯光布置的角度排查问题？请结合三点布光原则思考可能的原因。\", \"thinkTime\": 30, \"hints\": [\"检查主光（Key Light）角度是否造成不必要的遮挡或过曝\", \"评估补光（Fill Light）强度是否不足以消除阴影死区\", \"分析轮廓光（Rim Light）是否干扰了面部材质的正常反射\"], \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c71a4067-fb34-4fdf-bd6d-d7b567af4ef9', '8fb9adbb-55b5-496b-9569-be1757626e7c', 15, NULL, '{\"page_id\": \"p16\", \"title\": \"工程案例：电梯运行中的超重失重\", \"layout_id\": \"vocational_case_study\", \"has_image\": true, \"keywords\": [\"电梯轿厢内部视角\", \"缆绳张力示意图\", \"楼层显示屏\", \"机械结构细节\"], \"depends_on\": [\"p14\"], \"must_cover\": [\"加速上升超重\", \"加速下降失重\", \"视重与实重的区别\", \"工程案例：电梯运行中的超重失重的核心概念与背景\", \"工程案例：电梯运行中的超重失重的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"工程案例：电梯运行中的超重失重的核心概念与背景\", \"工程案例：电梯运行中的超重失重的关键方法与执行要点\", \"工程案例：电梯运行中的超重失重的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"b\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T04:44:29.430821\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 04:43:52', '2026-03-17 04:44:29', 'vocational_case_study', '{\"title\": \"工程案例：电梯运行中的超重失重\", \"content\": [\"电梯加速上升或减速下降时，加速度方向向上，支持力大于重力，人处于超重状态；反之，加速下降或减速上升时，加速度向下，支持力小于重力，人处于失重状态。\", \"视重即支持力大小，实重为物体实际重力（mg）。工程师需依据牛顿第二定律设计缆绳张力与制动系统，确保在极端工况下结构强度满足安全系数要求。\"], \"highlight\": \"关键结论：超重与失重取决于加速度方向，而非速度方向。\", \"image\": {\"src\": \"\", \"alt\": \"电梯轿厢内部视角，显示楼层显示屏变化，侧面叠加缆绳张力矢量图与机械结构细节剖面\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"concept_explain\"}');
