INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c99f994b-1700-4f5e-8c61-f6bbe90a9c32', 'e7189705-04c2-4928-8d6c-da2bacf02e42', 4, NULL, '{\"title\": \"任务工单：传送带加速故障排查：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"vocational_case_study\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p05\", \"depends_on\": [\"p04\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"b\", \"logical_page_id\": \"p05\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T01:36:50.689127\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 01:36:08', '2026-03-19 01:36:51', 'vocational_case_study', '{\"title\": \"任务工单：传送带加速故障排查：案例复盘\", \"background\": \"某物流分拣中心因重载包裹积压，触发传送带加速异常报警，需紧急恢复运行效率。\", \"solutions\": [\"依据牛顿第二定律重新测算负载总质量，剔除冗余安全系数导致的动力过剩设定。\", \"调整变频器加速度斜坡时间，匹配实际摩擦系数，消除启动瞬间的扭矩冲击。\"], \"layout_variant\": \"b\", \"variant\": \"b\", \"layout_archetype\": \"concept_explain\"}');
