INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('cb30b465-804c-447e-a29c-9c2f62004cac', '8fb9adbb-55b5-496b-9569-be1757626e7c', 16, NULL, '{\"page_id\": \"p17\", \"title\": \"课堂总结：知识思维导图\", \"layout_id\": \"vocational_summary\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p15\"], \"must_cover\": [\"核心公式回顾\", \"矢量性强调\", \"解题流程复盘\", \"易错点清单\", \"课堂总结：知识思维导图的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p04_1\", \"pr_p07_1\", \"pr_p10_1\"], \"points\": [\"课堂总结：知识思维导图的核心概念与背景\", \"课堂总结：知识思维导图的关键方法与执行要点\", \"课堂总结：知识思维导图的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p04_1\", \"pr_p07_1\", \"pr_p10_1\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p17\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p04_1\", \"pr_p07_1\", \"pr_p10_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T04:44:29.430868\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 04:43:53', '2026-03-17 04:44:29', 'vocational_summary', '{\"title\": \"课堂总结：知识思维导图\", \"subtitle\": \"牛顿第二定律核心体系回顾。\", \"bullets\": [{\"icon\": \"fa-calculator\", \"text\": \"核心公式确立。\", \"description\": \"基于控制变量法实验，推导得出 F=kma，在国际单位制下 k=1，最终确立 F=ma。\"}, {\"icon\": \"fa-vector-square\", \"text\": \"矢量性强调。\", \"description\": \"合外力方向始终与加速度方向一致，与速度方向无必然联系，需注意方向分解与合成。\"}, {\"icon\": \"fa-list-ol\", \"text\": \"解题流程复盘。\", \"description\": \"标准步骤：明确研究对象 -> 受力分析 -> 建立坐标系 -> 列方程求解 -> 检验结果合理性。\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"易错点清单。\", \"description\": \"误区一：误认为力是维持运动的原因；误区二：混淆速度与加速度概念；误区三：忽略摩擦力干扰。\"}, {\"icon\": \"fa-cogs\", \"text\": \"复杂受力分析。\", \"description\": \"处理含摩擦力的斜面或连接体问题时，需先计算摩擦力 f=μN，再求合力进行动力学分析。\"}], \"keyTakeaway\": \"掌握 F=ma 的矢量本质与解题规范，能灵活应用于汽车安全、电梯工程等真实职业场景。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
