INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('cc40a7f7-6e33-4daf-af43-9a3e77ef4d98', '130ea17c-c678-4285-8c4c-06b099d8fa71', 11, NULL, '{\"page_id\": \"p12\", \"title\": \"第三章：从课堂到世界\", \"layout_id\": \"edu_qa_case\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p10\"], \"must_cover\": [\"知识迁移\", \"实际应用价值\", \"第三章：从课堂到世界的核心概念与背景\", \"第三章：从课堂到世界的关键方法与执行要点\", \"第三章：从课堂到世界的应用场景与注意事项\"], \"promises_open\": [{\"promise_id\": \"pr_p11_1\", \"text\": \"最后将总结全课重点并解答核心疑问\", \"must_cover\": [\"知识复盘\", \"思维升华\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"promises_close\": [\"pr_p07_1\"], \"points\": [\"第三章：从课堂到世界的核心概念与背景\", \"第三章：从课堂到世界的关键方法与执行要点\", \"第三章：从课堂到世界的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p07_1\"], \"layout_archetype\": \"qa_session\", \"layout_variant\": \"b\", \"logical_page_id\": \"p12\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p07_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:15:52.390982\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 02:14:48', '2026-03-17 02:15:52', 'edu_qa_case', '{\"title\": \"第三章：从课堂到世界\", \"question\": \"如何将抽象的牛顿定律转化为解决现实工程问题的具体方案？\", \"answer\": \"通过知识迁移将实验室模型映射至复杂场景，利用 F=ma 进行动力学仿真与安全阈值设计。\", \"analysis\": [{\"title\": \"生活实例：汽车安全系统\", \"content\": \"基于瞬时性与矢量性原理，设计安全气囊触发机制，在碰撞瞬间精确计算减速度与冲击载荷。\"}, {\"title\": \"工程应用：航天轨道修正\", \"content\": \"利用多矢量力叠加计算变轨推力，确保卫星在复杂引力场中保持预定轨迹，体现理论指导实践的价值。\"}, {\"title\": \"常见易错点\", \"content\": \"围绕常见易错点说明审题依据、关键步骤与结果检验方式。\"}], \"conclusion\": \"物理定律不仅是公式，更是连接微观运动与宏观工程的通用语言。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"qa_session\"}');
