INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('cca2f532-45ae-4ed9-9012-be56ab10430a', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 5, '第一部分：课程导览与愿景', '{\"title\": \"大核心模块逻辑架构概览：重点展开\", \"points\": [\"大核心模块逻辑架构概览的核心概念与边界\", \"大核心模块逻辑架构概览的典型案例与结果\", \"大核心模块逻辑架构概览在本主题中的落地建议\"], \"layout_id\": \"edu_timeline_steps\", \"part\": \"第一部分：课程导览与愿景\", \"logical_page_id\": \"p06\", \"has_image\": false, \"keywords\": [\"大核心模块逻辑架构概览的核心概念与边界\", \"大核心模块逻辑架构概览的典型案例与结果\", \"大核心模块逻辑架构概览在本主题中的落地建议\"], \"depends_on\": [\"p05\"], \"must_cover\": [\"大核心模块逻辑架构概览的核心概念与边界\", \"大核心模块逻辑架构概览的典型案例与结果\", \"大核心模块逻辑架构概览在本主题中的落地建议\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"a\", \"layout_archetype\": \"timeline\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.418717\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_timeline_steps', '{\"title\": \"大核心模块逻辑架构概览：六步进阶体系\", \"subtitle\": \"从理论认知到商业交付的全链路闭环。\", \"steps\": [{\"title\": \"模块一：思维重构与基础规范\", \"description\": \"建立系统化工作流思维，确立行业标准与职业底线，完成从感性认知到理性规范的思维转型。\", \"highlights\": [\"构建工作流框架\", \"确立职业标准\"]}, {\"title\": \"模块二：核心技术栈深度攻坚\", \"description\": \"针对主流软件进行模块化拆解，掌握高难度建模、拓扑优化及材质表现技巧，夯实技术底座。\", \"highlights\": [\"攻克技术难点\", \"精通软件特性\"]}, {\"title\": \"模块三：艺术审美与风格塑造\", \"description\": \"融合色彩理论与构图美学，培养独特的艺术风格，确保作品在商业应用中具有视觉冲击力与辨识度。\", \"highlights\": [\"提升审美层级\", \"塑造个人风格\"]}, {\"title\": \"模块四：工程落地与流程协同\", \"description\": \"模拟真实商业环境，学习多部门协作流程，掌握文件管理与版本控制，确保项目高效推进。\", \"highlights\": [\"模拟真实协作\", \"优化生产流程\"]}, {\"title\": \"模块五：商业交付与价值转化\", \"description\": \"聚焦客户需求分析，提供定制化解决方案，完成从模型制作到最终商业成果的价值闭环。\", \"highlights\": [\"对接客户需求\", \"实现价值交付\"]}, {\"title\": \"模块六：持续迭代与职业升华\", \"description\": \"基于反馈机制进行技术迭代，践行工匠精神，将职业道德内化为职业习惯，开启终身成长之路。\", \"highlights\": [\"持续技术迭代\", \"内化职业精神\"]}], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"timeline\"}');
