INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('cff90d7f-2c59-4f67-8071-6bb214d015f0', 'e43174bb-6386-4c02-9c5d-efa37adcd2cc', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"建模流派对比：NURBS vs Polygon\", \"layout_id\": \"comparison_table\", \"has_image\": false, \"keywords\": [\"mathematical formulas\", \"wireframe mesh\", \"clean lines\", \"grid structure\"], \"depends_on\": [\"p04\"], \"must_cover\": [\"NURBS的参数化特性\", \"Polygon的离散化优势\", \"应用场景差异\", \"建模流派对比：NURBS vs Polygon的核心概念与背景\", \"建模流派对比：NURBS vs Polygon的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p02_1\"], \"points\": [\"建模流派对比：NURBS vs Polygon的核心概念与背景\", \"建模流派对比：NURBS vs Polygon的关键方法与执行要点\", \"建模流派对比：NURBS vs Polygon的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p02_1\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:18:54', '2026-03-10 05:18:54', 'comparison_table', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('d01b2374-cf58-49e8-9557-859e74d2d81c', '8a37f529-e51f-428c-8466-cdc137b73187', 18, NULL, '{\"page_id\": \"p19\", \"title\": \"第五章：实时渲染引擎优化\", \"layout_id\": \"academic_narrative\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p15\"], \"must_cover\": [\"章节引入\", \"LOD与烘焙策略\", \"第五章：实时渲染引擎优化的核心概念与背景\", \"第五章：实时渲染引擎优化的关键方法与执行要点\", \"第五章：实时渲染引擎优化的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第五章：实时渲染引擎优化的核心概念与背景\", \"第五章：实时渲染引擎优化的关键方法与执行要点\", \"第五章：实时渲染引擎优化的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p19\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.108163\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'academic_narrative', '{\"title\": \"第五章：实时渲染引擎优化\", \"narrative\": [\"实时渲染引擎优化的核心在于平衡视觉 fidelity 与计算资源消耗。在程序化纹理构建（如前章所述）的基础上，本章聚焦于如何将静态资产转化为动态场景中的高效表达。LOD（多细节层次）技术通过根据摄像机距离动态切换模型精度，显著降低 GPU 负载；而烘焙策略则预先计算光照信息至贴图，将复杂的实时光线追踪转化为简单的纹理采样，从而在移动端或 VR 设备中维持高帧率。\", \"执行要点涵盖材质实例化与遮挡剔除。通过共享材质属性减少状态切换开销，利用视锥体剔除和遮挡剔除算法避免渲染不可见几何体。此外，结合程序化噪声生成的动态纹理，可在不增加显存占用的前提下模拟复杂表面变化，这是实现大规模开放世界场景流畅运行的关键。\"], \"margin_notes\": [{\"title\": \"核心概念：LOD (Level of Detail)\", \"content\": \"一种根据物体与摄像机距离动态调整模型面数或纹理分辨率的技术，是实时渲染性能优化的基石。\"}, {\"title\": \"旁注：烘焙策略\", \"content\": \"将复杂的光照计算结果‘固化’到贴图中，牺牲部分灵活性换取极致的实时渲染速度。\"}], \"pull_quote\": \"优化的本质并非单纯削减画质，而是在人眼感知阈值内，以最小的计算代价实现最大的视觉真实感。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
