INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('d7c53ac2-cd8d-4b68-a252-fb4cefea74d6', '8ccaacf6-cf8f-4cd6-8ca8-7d5f28350c89', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"八、安全规范：调试过程中的风险管控\", \"layout_id\": \"vocational_case_study\", \"has_image\": true, \"keywords\": [\"安全操作规程\", \"防护装备\", \"紧急停止按钮\", \"警示标志\", \"规范作业场景\"], \"depends_on\": [\"p09\"], \"must_cover\": [\"断电挂牌制度\", \"人员站位要求\", \"异常处理预案\", \"八、安全规范：调试过程中的风险管控的核心概念与背景\", \"八、安全规范：调试过程中的风险管控的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"八、安全规范：调试过程中的风险管控的核心概念与背景\", \"八、安全规范：调试过程中的风险管控的关键方法与执行要点\", \"八、安全规范：调试过程中的风险管控的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:41:09.848058\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:40:28', '2026-03-17 07:41:10', 'vocational_case_study', '{\"title\": \"八、安全规范：调试过程中的风险管控\", \"content\": [\"严格执行断电挂牌制度（LOTO），在变频器及电机动力端悬挂警示牌，确认无残余电压后方可接触内部线路。\", \"调试期间人员需保持安全站位，严禁身体部位进入运动部件危险区，并明确紧急停止按钮位置以应对突发异常。\"], \"highlight\": \"安全是调试的前提，任何参数优化不得以牺牲人员与设备安全为代价。\", \"image\": {\"src\": \"\", \"alt\": \"一名佩戴安全帽和绝缘手套的技术人员正在对电气柜进行操作，旁边清晰可见红色的急停按钮和挂有‘禁止合闸’牌子的断路器\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('d7e913c5-b3d4-4332-91e9-71367e30ca62', '4e889981-954e-4263-b490-230183b1a644', 11, NULL, '{\"page_id\": \"p12\", \"title\": \"随堂测试：参数计算与故障判断\", \"layout_id\": \"vocational_quiz\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p03\", \"p05\", \"p07\"], \"must_cover\": [\"题目1：已知质量与加速度求推力\", \"题目2：识别导致抖动的错误参数\", \"参考答案解析区\", \"随堂测试：参数计算与故障判断的核心概念与背景\", \"随堂测试：参数计算与故障判断的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"随堂测试：参数计算与故障判断的核心概念与背景\", \"随堂测试：参数计算与故障判断的关键方法与执行要点\", \"随堂测试：参数计算与故障判断的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p12\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:45:02.424912\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:44:27', '2026-03-19 01:37:30', 'vocational_quiz', '{\"title\": \"随堂测试：参数计算与故障判断\", \"question\": \"【计算】已知负载质量m=5kg，目标加速度a=2m/s²，求所需推力F？ 【判断】若电机波形出现高频震荡，最可能的错误参数是？（A. 增益过高 B. 速度过低）\", \"answer\": \"1. F=ma=5×2=10N；2. 选A。增益过高会引发系统共振，导致波形震荡与定位不准，需降低比例系数。\", \"note\": \"请结合前序理论课与实操数据独立完成，答案需精确到小数点后一位，注意单位换算。\", \"layout_variant\": \"a\", \"variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('d8cb99f8-0530-468d-b08c-743138936704', '9b5d83ef-2600-4c3b-b852-00607680277d', 6, 'Gemini篇', '{\"page_id\": \"p06\", \"title\": \"生态优势：Google Gemini的多模态原生设计\", \"part\": \"Gemini篇\", \"points\": [\"原生多模态架构从训练阶段即融合文本、图像、音频与视频，实现跨模态深度理解而非简单拼接\", \"依托Google全球海量数据资源，构建起端侧设备与云端算力无缝协同的完整生态系统\", \"推出Ultra、Pro、Nano三级模型矩阵，精准匹配高算力推理、通用办公及移动端实时交互场景\", \"通过Android系统与Workspace套件深度集成，将AI能力无缝嵌入用户日常数字工作流\"]}', '{\"text\": \"页面标题：生态优势：Google Gemini的多模态原生设计\\n\\n页面文字：\\n- 原生多模态架构从训练阶段即融合文本、图像、音频与视频，实现跨模态深度理解而非简单拼接。\\n- 依托Google全球海量数据资源，构建起端侧设备与云端算力无缝协同的完整生态系统。\\n- 推出Ultra、Pro、Nano三级模型矩阵，精准匹配高算力推理、通用办公及移动端实时交互场景。\\n- 通过Android系统与Workspace套件深度集成，将AI能力无缝嵌入用户日常数字工作流。\", \"generated_at\": \"2026-03-09T08:14:14.916891\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/d8cb99f8-0530-468d-b08c-743138936704_v1.png', 'FAILED', '2026-03-09 08:13:48', '2026-03-09 09:20:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('d91d09f7-ca30-4832-8ce6-e641e8a19307', '14c0f24c-10e7-4309-a927-d9db1066897c', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"硬表面建模：布尔运算与倒角\", \"layout_id\": \"infographic_flow\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p08\"], \"must_cover\": [\"布尔切割流程\", \"倒角厚度控制\", \"非破坏性编辑\", \"硬表面建模：布尔运算与倒角的核心概念与背景\", \"硬表面建模：布尔运算与倒角的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"硬表面建模：布尔运算与倒角的核心概念与背景\", \"硬表面建模：布尔运算与倒角的关键方法与执行要点\", \"硬表面建模：布尔运算与倒角的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.773922\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'infographic_flow', '{\"title\": \"硬表面建模：布尔运算与倒角\", \"subtitle\": \"从非破坏性编辑到完美拓扑的构建逻辑。\", \"bullets\": [{\"icon\": \"fa-cube\", \"text\": \"布尔切割流程标准化。\", \"description\": \"建立‘先粗切后精修’的非破坏性工作流，利用修改器堆栈保留原始几何体，避免直接合并导致的网格错误。\"}, {\"icon\": \"fa-arrows-alt-h\", \"text\": \"倒角厚度智能控制。\", \"description\": \"根据模型最终渲染比例设定倒角宽度，过薄会导致光照伪影，过厚则破坏硬表面锐利感，需保持参数化关联。\"}, {\"icon\": \"fa-layer-group\", \"text\": \"非破坏性编辑策略。\", \"description\": \"全程使用修改器（Modifier）而非应用操作，确保在遇到拓扑问题时可随时回溯至布尔运算前的状态进行修复。\"}], \"keyTakeaway\": \"掌握非破坏性布尔与倒角是解决硬表面拓扑撕裂、保障流体动力学计算路径完整性的核心前提。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
