INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('db0ac9b0-13bc-4482-a2dd-3a9321a26282', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 17, '第二部分：思维重塑与底层逻辑', '{\"title\": \"空间坐标轴概念在建模中的核心地位：重点展开\", \"points\": [\"空间坐标轴概念在建模中的核心地位的核心概念与边界\", \"空间坐标轴概念在建模中的核心地位的典型案例与结果\", \"空间坐标轴概念在建模中的核心地位在本主题中的落地建议\"], \"layout_id\": \"edu_core_hub\", \"part\": \"第二部分：思维重塑与底层逻辑\", \"logical_page_id\": \"p18\", \"has_image\": false, \"keywords\": [\"空间坐标轴概念在建模中的核心地位的核心概念与边界\", \"空间坐标轴概念在建模中的核心地位的典型案例与结果\", \"空间坐标轴概念在建模中的核心地位在本主题中的落地建议\"], \"depends_on\": [\"p17\"], \"must_cover\": [\"空间坐标轴概念在建模中的核心地位的核心概念与边界\", \"空间坐标轴概念在建模中的核心地位的典型案例与结果\", \"空间坐标轴概念在建模中的核心地位在本主题中的落地建议\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"a\", \"layout_archetype\": \"core_model\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.419210\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_core_hub', '{\"title\": \"空间坐标轴：建模操作的绝对基准\", \"subtitle\": \"构建虚拟世界的几何秩序与定位法则。\", \"center_label\": \"XYZ坐标系\", \"nodes\": [{\"title\": \"原点定位逻辑\"}, {\"title\": \"轴向约束机制\"}, {\"title\": \"相对空间变换\"}, {\"title\": \"行业应用规范\"}], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"core_model\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('db1b20d9-63a5-4822-bc7f-7adf5fbb2f11', '8a37f529-e51f-428c-8466-cdc137b73187', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"第二章：UV展开与空间利用率\", \"layout_id\": \"comparison_table\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p06\"], \"must_cover\": [\"章节引入\", \"UV空间管理重要性\", \"第二章：UV展开与空间利用率的核心概念与背景\", \"第二章：UV展开与空间利用率的关键方法与执行要点\", \"第二章：UV展开与空间利用率的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第二章：UV展开与空间利用率的核心概念与背景\", \"第二章：UV展开与空间利用率的关键方法与执行要点\", \"第二章：UV展开与空间利用率的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.107583\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'comparison_table', '{\"title\": \"UV展开与空间利用率对比分析\", \"subtitle\": \"第二章核心：从拓扑到纹理映射的效能转化。\", \"items\": [{\"name\": \"空间利用率\", \"description\": \"有效纹理像素占比。\", \"features\": [\"硬表面：追求100%填充，允许微小缝隙以最大化分辨率\", \"有机体：保留5%-10%冗余区，防止接缝处拉伸模糊\"]}, {\"name\": \"切缝策略\", \"description\": \"隐藏接缝位置的选择。\", \"features\": [\"硬表面：沿结构线或隐蔽边缘切割，保持视觉连贯性\", \"有机体：沿肌肉分界线或阴影区域分布，减少视觉干扰\"]}, {\"name\": \"畸变控制\", \"description\": \"UV坐标与3D模型的形变程度。\", \"features\": [\"硬表面：优先保证直线度，允许轻微面积压缩\", \"有机体：优先保证曲率一致性，严格控制非线性拉伸\"]}], \"conclusion\": \"UV管理需根据模型物理属性动态调整策略：硬表面重精度与填充，有机体重自然形变与容错，二者不可混淆。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('db609e6f-f4b0-4a48-a4e7-c1f2cdce7add', '8ccaacf6-cf8f-4cd6-8ca8-7d5f28350c89', 8, NULL, '{\"page_id\": \"p09\", \"title\": \"七、对比分析：传统调试 vs 定律指导调试\", \"layout_id\": \"vocational_lead_in\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p08\"], \"must_cover\": [\"经验法的局限性\", \"理论法的优势\", \"效率与安全性对比\", \"七、对比分析：传统调试 vs 定律指导调试的核心概念与背景\", \"七、对比分析：传统调试 vs 定律指导调试的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"七、对比分析：传统调试 vs 定律指导调试的核心概念与背景\", \"七、对比分析：传统调试 vs 定律指导调试的关键方法与执行要点\", \"七、对比分析：传统调试 vs 定律指导调试的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"b\", \"logical_page_id\": \"p09\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:41:09.847988\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:40:28', '2026-03-17 07:41:10', 'vocational_lead_in', '{\"title\": \"七、对比分析：传统调试 vs 定律指导调试\", \"content\": [\"传统经验法依赖技师个人直觉，缺乏统一标准，导致调试效率低且易因误判引发设备过载或停机风险。\", \"定律指导法基于物理公式与负载特性进行量化计算，能精准设定加减速时间与力矩阈值，显著提升系统响应速度与运行稳定性。\"], \"highlight\": \"从“凭感觉”转向“算得准”，实现调试过程的标准化与安全化。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"concept_explain\"}');
