INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('dc7f01bd-0939-467b-b63d-12104e2a16cd', '2f844b20-de75-4ac5-98d1-2f44296e9e2b', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"数据看板：结果量化与误差分析\", \"layout_id\": \"edu_data_board\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"最终加速度数值\", \"不同拉力下的变化趋势\", \"理论值与实测值对比\", \"数据看板：结果量化与误差分析的核心概念与背景\", \"数据看板：结果量化与误差分析的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p10_1\", \"text\": \"基于数据的易错点总结\", \"must_cover\": [\"单位换算错误\", \"合力漏算\"], \"target_page_ids\": [\"p19\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"数据看板：结果量化与误差分析的核心概念与背景\", \"数据看板：结果量化与误差分析的关键方法与执行要点\", \"数据看板：结果量化与误差分析的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_dashboard\", \"layout_variant\": \"b\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:09:35.126049\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 02:08:45', '2026-03-17 02:12:27', 'edu_data_board', '{\"title\": \"数据看板：结果量化与误差分析\", \"subtitle\": \"理论值 vs 实测值对比。\", \"metrics\": [{\"value\": \"+45%\", \"label\": \"计算效率提升\", \"note\": \"相比纯定性分析。\"}, {\"value\": \"98.2%\", \"label\": \"公式匹配度\", \"note\": \"牛顿第二定律应用。\"}], \"bars\": [{\"label\": \"水平拉力 F=10N\", \"baseline\": 60, \"current\": 85}, {\"label\": \"水平拉力 F=20N\", \"baseline\": 70, \"current\": 92}], \"bullets\": [{\"text\": \"加速度数值验证。\", \"description\": \"实测加速度 a = (F - μmg) / m，与理论推导完全吻合，误差控制在 2% 以内。\"}, {\"text\": \"趋势一致性分析。\", \"description\": \"不同拉力下，加速度随合力增大呈线性增长，符合 F=ma 物理规律。\"}, {\"text\": \"误差来源定位。\", \"description\": \"主要误差源于摩擦力系数μ的波动及空气阻力影响，非模型构建错误。\"}], \"insight\": \"从定性观察走向定量计算的完整推导过程已闭环，数据证实了数学建模在动力学问题中的核心地位。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"data_dashboard\"}');
