INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('dd7a9122-e397-4f4b-a757-c9045f1a1cb5', 'faba4721-d6bc-47a9-847e-395b2a603584', 13, NULL, '{\"title\": \"典型应用场景：自动驾驶边缘节点：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"system_comparison\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p14\", \"depends_on\": [\"p13\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:24:32.582445\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:23:02', '2026-03-10 06:24:33', 'system_comparison', '{\"title\": \"典型应用场景：自动驾驶边缘节点：案例复盘\", \"left\": {\"header\": \"核心矛盾与场景挑战\", \"content\": [\"典型应用场景：自动驾驶边缘节点：案例复盘在核心矛盾与场景挑战下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-triangle-exclamation\", \"text\": \"极端天气与信号遮挡导致感知数据缺失，传统架构决策延迟超50ms。\", \"description\": \"解释极端天气与信号遮挡导致感知数据缺失，传统架构决策延迟超50ms在核心矛盾与场景挑战维度下的意义。\"}, {\"icon\": \"fa-server\", \"text\": \"高并发数据处理需求激增，中心化云端算力无法支撑毫秒级实时响应。\", \"description\": \"解释高并发数据处理需求激增，中心化云端算力无法支撑毫秒级实时响应在核心矛盾与场景挑战维度下的意义。\"}, {\"icon\": \"fa-shield-halved\", \"text\": \"传输链路长且不可控，存在严重的数据泄露与指令篡改安全隐患。\", \"description\": \"解释传输链路长且不可控，存在严重的数据泄露与指令篡改安全隐患在核心矛盾与场景挑战维度下的意义。\"}, {\"icon\": \"fa-bolt\", \"text\": \"动态环境下的算力资源碎片化，难以满足突发工况的弹性调度需求。\", \"description\": \"解释动态环境下的算力资源碎片化，难以满足突发工况的弹性调度需求在核心矛盾与场景挑战维度下的意义。\"}]}, \"right\": {\"header\": \"OpenClaw方案执行与成效\", \"content\": [\"典型应用场景：自动驾驶边缘节点：案例复盘在OpenClaw方案执行与成效下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-microchip\", \"text\": \"部署边缘计算节点，实现本地毫秒级推理，端到端延迟降低至8ms。\", \"description\": \"解释部署边缘计算节点，实现本地毫秒级推理，端到端延迟降低至8ms在OpenClaw方案执行与成效维度下的意义。\"}, {\"icon\": \"fa-network-wired\", \"text\": \"构建分布式协同网络，利用零信任架构保障跨节点通信绝对安全。\", \"description\": \"解释构建分布式协同网络，利用零信任架构保障跨节点通信绝对安全在OpenClaw方案执行与成效维度下的意义。\"}, {\"icon\": \"fa-chart-line\", \"text\": \"引入智能增量构建引擎，复杂场景模型迭代周期从小时级缩短至分钟。\", \"description\": \"解释引入智能增量构建引擎，复杂场景模型迭代周期从小时级缩短至分钟在OpenClaw方案执行与成效维度下的意义。\"}, {\"icon\": \"fa-check-circle\", \"text\": \"建立全链路资源画像机制，故障定位时间减少90%，系统可用性达99.9%。\", \"description\": \"解释建立全链路资源画像机制，故障定位时间减少90%，系统可用性达99.9%在OpenClaw方案执行与成效维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
