INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e179c0e0-cb9a-4cfa-be19-f4918bc36f15', 'faba4721-d6bc-47a9-847e-395b2a603584', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"第三章：生态扩张与性能极限 (2023-Present)\", \"layout_id\": \"title_content\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p07\"], \"must_cover\": [\"大规模集群部署\", \"AI 模型推理加速\", \"行业标杆案例\", \"第三章：生态扩张与性能极限 (2023-Present)的核心概念与背景\", \"第三章：生态扩张与性能极限 (2023-Present)的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p08_1\", \"text\": \"通过真实数据看板展示系统峰值性能指标\", \"must_cover\": [\"吞吐量\", \"延迟\", \"能耗比\"], \"target_page_ids\": [\"p09\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"第三章：生态扩张与性能极限 (2023-Present)的核心概念与背景\", \"第三章：生态扩张与性能极限 (2023-Present)的关键方法与执行要点\", \"第三章：生态扩张与性能极限 (2023-Present)的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:24:32.582293\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:23:01', '2026-03-10 06:24:33', 'title_content', '{\"title\": \"第三章：生态扩张与性能极限 (2023-Present)\", \"content\": [\"基于前序协议层革新与动态调度引擎的基石，系统正式迈入大规模集群部署阶段，构建起支撑万卡级 AI 训练与推理的分布式算力底座。\", \"核心突破在于引入异构资源池化技术，通过智能感知负载自动路由最优节点，实现从单点高并发到全域负载均衡的质的飞跃，彻底消除传统架构的通信瓶颈。\", \"行业标杆案例显示，新架构在金融风控与实时推荐场景中，成功将千级并发下的任务分发延迟压缩至毫秒级，确立了行业新的性能基准线。\"], \"highlight\": \"从单体架构向全域弹性云原生集群的跨越，定义AI时代算力分配新标准。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e24e34ef-3e79-48d4-83ef-370981c8d08a', '8ccaacf6-cf8f-4cd6-8ca8-7d5f28350c89', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"六、关键步骤详解：加减速时间计算\", \"layout_id\": \"vocational_step_by_step\", \"has_image\": true, \"keywords\": [\"示波器波形图\", \"速度曲线对比\", \"平滑启动示意\", \"数据图表\", \"技术界面截图\"], \"depends_on\": [\"p07\"], \"must_cover\": [\"T=V/a公式应用\", \"不同负载下的时间调整\", \"避免机械冲击的阈值\", \"六、关键步骤详解：加减速时间计算的核心概念与背景\", \"六、关键步骤详解：加减速时间计算的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"六、关键步骤详解：加减速时间计算的核心概念与背景\", \"六、关键步骤详解：加减速时间计算的关键方法与执行要点\", \"六、关键步骤详解：加减速时间计算的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"process_steps\", \"layout_variant\": \"a\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T07:41:09.847907\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 07:40:28', '2026-03-17 07:41:10', 'vocational_step_by_step', '{\"title\": \"六、关键步骤详解：加减速时间计算\", \"subtitle\": \"基于T=V/a公式的精准控制策略。\", \"steps\": [{\"number\": 1, \"label\": \"公式应用推导\", \"description\": \"利用T=V/a计算基础时间，结合电机额定转速确定基准。\", \"icon\": \"fa-calculator\"}, {\"number\": 2, \"label\": \"负载动态修正\", \"description\": \"重载工况延长加速时间，轻载适当缩短以提升响应速度。\", \"icon\": \"fa-balance-scale\"}, {\"number\": 3, \"label\": \"冲击阈值设定\", \"description\": \"监控电流尖峰，确保加减速过程不触发过流保护阈值。\", \"icon\": \"fa-exclamation-triangle\"}, {\"number\": 4, \"label\": \"波形平滑优化\", \"description\": \"通过S型曲线调整，消除机械传动系统的刚性冲击。\", \"icon\": \"fa-wave-square\"}], \"image\": {\"src\": \"\", \"alt\": \"不同负载下的速度曲线对比与示波器波形\", \"width\": \"50%\"}, \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"process_steps\"}');
