INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e3649e99-dfc4-4594-b132-c5c747839397', 'c3f4f20a-0839-4fb0-9375-125c6af13f37', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"执行器分类一：夹持式（机械手爪）\", \"layout_id\": \"sk_record\", \"has_image\": true, \"keywords\": [\"平行卡爪\", \"电动夹爪内部结构\", \"金属工件抓取\", \"机械传动特写\", \"清晰剖面图\"], \"depends_on\": [\"p04\"], \"must_cover\": [\"二指/三指结构差异\", \"气动/电动驱动原理\", \"高刚性夹持力特性\", \"执行器分类一：夹持式（机械手爪）的核心概念与背景\", \"执行器分类一：夹持式（机械手爪）的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p01_2\", \"pr_p03_1\"], \"points\": [\"执行器分类一：夹持式（机械手爪）的核心概念与背景\", \"执行器分类一：夹持式（机械手爪）的关键方法与执行要点\", \"执行器分类一：夹持式（机械手爪）的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_2\", \"pr_p03_1\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p05\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p01_2\", \"pr_p03_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:04:18.360804\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:03:27', '2026-03-19 06:04:18', 'sk_record', '{\"title\": \"执行器分类一：夹持式（机械手爪）\", \"rows\": [{\"label\": \"结构形态\", \"value\": \"二指/三指平行卡爪\", \"extra\": \"二指适用于规则矩形件，三指提供更高稳定性与中心定位能力。\"}, {\"label\": \"驱动原理\", \"value\": \"气动活塞/电动伺服\", \"extra\": \"气动响应快成本低，电动可精准控制夹持力与开合速度。\"}, {\"label\": \"力学特性\", \"value\": \"高刚性大夹持力\", \"extra\": \"通过齿轮齿条或连杆机构放大驱动力，适合金属等重型工件抓取。\"}, {\"label\": \"接触方式\", \"value\": \"硬性点/面接触\", \"extra\": \"直接接触工件表面，需配合软胶垫以防划伤精密表面。\"}, {\"label\": \"典型场景\", \"value\": \"汽车零部件搬运\", \"extra\": \"发动机缸体、变速箱壳体等重且形状规则的金属件装配与码垛。\"}], \"summary\": \"夹持式执行器凭借高刚性与大夹持力，成为汽车产线处理金属工件的首选。其核心在于通过机械传动实现精确的刚性抓取，但需注意对工件表面的保护与适配性设计。\", \"bullets\": [{\"icon\": \"fa-check\", \"text\": \"执行器分类一：夹持式（机械手爪）的关键概念。\", \"description\": \"说明执行器分类一：夹持式（机械手爪）的关键概念在当前主题中的价值与应用方式。\"}, {\"icon\": \"fa-check\", \"text\": \"执行器分类一：夹持式（机械手爪）的实践方法。\", \"description\": \"说明执行器分类一：夹持式（机械手爪）的实践方法在当前主题中的价值与应用方式。\"}, {\"icon\": \"fa-check\", \"text\": \"执行器分类一：夹持式（机械手爪）的风险与边界。\", \"description\": \"说明执行器分类一：夹持式（机械手爪）的风险与边界在当前主题中的价值与应用方式。\"}], \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
