INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e458cbdb-2e1d-44db-ba29-a56870ededa1', '6eea18f8-c641-48a1-ba84-4c49ed3830d6', 11, NULL, '{\"page_id\": \"p12\", \"title\": \"未来图景：从专用工具到通用智能底座\", \"layout_id\": \"edu_logic_flow\", \"has_image\": true, \"keywords\": [\"三阶段流程图\", \"未来城市剪影\", \"智能网络连接\", \"青色光流\", \"深色空间感\"], \"depends_on\": [\"p11\"], \"must_cover\": [\"短期演进路线\", \"中期生态扩张\", \"长期通用化愿景\", \"未来图景：从专用工具到通用智能底座的核心概念与背景\", \"未来图景：从专用工具到通用智能底座的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p12_1\"], \"points\": [\"未来图景：从专用工具到通用智能底座的核心概念与背景\", \"未来图景：从专用工具到通用智能底座的关键方法与执行要点\", \"未来图景：从专用工具到通用智能底座的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p12_1\"], \"layout_archetype\": \"process_flow\", \"layout_variant\": \"a\", \"logical_page_id\": \"p12\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p12_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:27:09.079709\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:25:46', '2026-03-10 06:27:09', 'edu_logic_flow', '{\"title\": \"未来图景：从专用工具到通用智能底座\", \"stages\": [{\"title\": \"短期演进路线\", \"description\": \"聚焦单点性能极致优化，完善垂直行业解决方案，快速验证技术重构带来的效率红利与成本优势。\"}, {\"title\": \"中期生态扩张\", \"description\": \"推动跨域互联互通，构建开放兼容的开发者生态，实现从单一产品向平台化、标准化基础设施的跃迁。\"}, {\"title\": \"长期通用化愿景\", \"description\": \"打造具备自进化能力的通用智能底座，深度融合AI大模型，赋能万物互联时代的城市级智能决策中枢。\"}], \"background_image\": \"https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=1920&auto=format&fit=crop\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"process_flow\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e4a7f301-613d-46a0-a6b4-d939f73eabbd', '6c250523-422a-46f3-a1f1-42e82424897c', 20, NULL, '{\"page_id\": \"p21\", \"title\": \"课程总结与知识图谱回顾\", \"layout_id\": \"key_takeaways\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p17\"], \"must_cover\": [\"核心概念串联\", \"技能树梳理\", \"常见误区提醒\", \"下一步行动指南\", \"课程总结与知识图谱回顾的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p16_1_630fbd9d\", \"pr_p02_1\", \"pr_p02_2\"], \"points\": [\"课程总结与知识图谱回顾的核心概念与背景\", \"课程总结与知识图谱回顾的关键方法与执行要点\", \"课程总结与知识图谱回顾的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p16_1_630fbd9d\", \"pr_p02_1\", \"pr_p02_2\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p21\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p16_1_630fbd9d\", \"pr_p02_1\", \"pr_p02_2\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287290\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 14:27:25', 'key_takeaways', '{\"title\": \"课程总结与知识图谱回顾\", \"subtitle\": \"核心概念串联与技能树全景梳理。\", \"bullets\": [{\"icon\": \"fa-link\", \"text\": \"核心概念串联。\", \"description\": \"从拓扑结构定义出发，经UV展开映射、动态雕刻细化，最终通过置换烘焙实现低模高显，形成完整工作流闭环。\"}, {\"icon\": \"fa-sitemap\", \"text\": \"技能树梳理。\", \"description\": \"掌握布线规则与法线控制是基础；UV岛布局与接缝优化是关键；雕刻笔刷与平滑组应用是进阶；烘焙参数调优是实战核心。\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"常见误区提醒。\", \"description\": \"避免过度依赖自动工具而忽视手动调整；忽略法线方向导致光照错误；未检查自相交引发渲染崩溃。\"}, {\"icon\": \"fa-arrow-right\", \"text\": \"下一步行动指南。\", \"description\": \"立即实践低模高模置换烘焙全流程，复现课程案例；参与社区挑战赛；阅读进阶论文深化理论理解。\"}, {\"icon\": \"fa-check-circle\", \"text\": \"承诺事项闭环。\", \"description\": \"已涵盖案例复盘（pr_p16_1_630fbd9d）、拓扑原则拆解（pr_p02_1）及完整工作流展示（pr_p02_2），确保知识体系无遗漏。\"}], \"keyTakeaway\": \"本课程构建了从理论基础到工程实践的完整知识图谱，强调规范操作与问题预判，助力学员高效产出影视级实时渲染资产。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e50719e2-60bb-49c1-b454-d2b2610f6b7a', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef', 9, '第三部分：案例实战', '{\"page_id\": \"p08\", \"title\": \"案例拆解二：有机生物角色建模\", \"part\": \"第三部分：案例实战\", \"points\": [\"基于解剖学简化肌肉群，构建符合生物力学的底层拓扑结构\", \"针对关节弯曲区（如肘部、膝盖）加密布线以支持平滑变形\", \"利用ZBrush动态网格雕刻细节，通过法线贴图映射至低模表面\", \"权重绘制技巧确保肢体运动时皮肤拉伸自然无扭曲\"]}', '{\"text\": \"页面标题：案例拆解二：有机生物角色建模\\n\\n页面文字：\\n- 针对游戏角色关节弯曲区易变形的痛点，基于解剖学简化肌肉群构建符合生物力学的底层拓扑结构。\\n- 在肘部与膝盖等高应力区域实施加密布线策略，确保模型在复杂运动下支持平滑自然的形变效果。\\n- 利用ZBrush动态网格雕刻细节后映射至低模表面，配合权重绘制技巧彻底消除肢体拉伸时的皮肤扭曲现象。\", \"generated_at\": \"2026-03-10T05:38:52.925718\"}', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef/pages/e50719e2-60bb-49c1-b454-d2b2610f6b7a_v1.png', 'COMPLETED', '2026-03-10 05:38:37', '2026-03-10 06:08:00', NULL, NULL);
