INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e5abd904-7f7e-4776-b1a8-bf2656403b2e', '2786117f-f122-459a-8310-c05a2077848b', 11, NULL, '{\"page_id\": \"p12\", \"title\": \"进阶知识：复合式与智能末端\", \"layout_id\": \"edu_data_board\", \"has_image\": true, \"keywords\": [\"多功能复合夹爪\", \"力觉传感器集成\", \"柔性手指设计\", \"未来智能制造\", \"复杂曲面抓取\"], \"depends_on\": [\"p10\"], \"must_cover\": [\"复合式执行器定义\", \"力控与视觉反馈的应用\", \"行业趋势展望\", \"进阶知识：复合式与智能末端的核心概念与背景\", \"进阶知识：复合式与智能末端的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"进阶知识：复合式与智能末端的核心概念与背景\", \"进阶知识：复合式与智能末端的关键方法与执行要点\", \"进阶知识：复合式与智能末端的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_dashboard\", \"layout_variant\": \"a\", \"logical_page_id\": \"p12\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:02:17.155469\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:01:23', '2026-03-19 06:02:17', 'edu_data_board', '{\"title\": \"进阶知识：复合式与智能末端\", \"subtitle\": \"定义未来柔性制造的执行边界。\", \"metrics\": [{\"value\": \"+60%\", \"label\": \"复杂曲面抓取成功率\", \"note\": \"传统刚性夹爪对比。\"}, {\"value\": \"30ms\", \"label\": \"力觉反馈响应延迟\", \"note\": \"实现精密自适应控制。\"}], \"bars\": [{\"label\": \"单一功能适用场景占比\", \"baseline\": 80, \"current\": 45}, {\"label\": \"多模态复合执行器渗透率\", \"baseline\": 20, \"current\": 75}], \"bullets\": [{\"text\": \"复合式结构设计。\", \"description\": \"集成真空吸附与机械夹持双重机制，通过柔性手指设计实现对易碎品、不规则曲面的无损抓取。\"}, {\"text\": \"智能感知与反馈。\", \"description\": \"内置高精度力觉传感器与视觉系统，实时调整抓取力度与姿态，适应动态变化的生产环境。\"}], \"insight\": \"从单一功能向复合智能演进是行业必然趋势，通过力控与视觉融合，解决传统末端无法处理的复杂工况难题。\", \"background_image\": \"https://images.unsplash.com/photo-1581092160562-40aa08e78837?q=80&w=2070&auto=format&fit=crop\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_dashboard\"}');
