INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e5d49caa-3795-42ec-a53f-09dc39dfb872', 'c3f4f20a-0839-4fb0-9375-125c6af13f37', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"工业案例复盘：焊接与搬运\", \"layout_id\": \"sk_materials\", \"has_image\": true, \"keywords\": [\"焊接机器人末端\", \"搬运码垛场景\", \"混合生产线\", \"多工位协同\", \"高清实拍\"], \"depends_on\": [\"p07\"], \"must_cover\": [\"焊接场景为何首选夹持\", \"板材搬运为何首选吸附\", \"复合工况下的组合方案\", \"工业案例复盘：焊接与搬运的核心概念与背景\", \"工业案例复盘：焊接与搬运的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p08_1_3b3af7f7\", \"text\": \"工业案例复盘：焊接与搬运的复盘与结果启示\", \"must_cover\": [\"案例复盘\", \"结果启示\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"promises_close\": [\"pr_p03_1\"], \"points\": [\"工业案例复盘：焊接与搬运的核心概念与背景\", \"工业案例复盘：焊接与搬运的关键方法与执行要点\", \"工业案例复盘：焊接与搬运的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p03_1\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p03_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:04:18.360915\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:03:28', '2026-03-19 06:04:18', 'sk_materials', '{\"title\": \"工业案例复盘：焊接与搬运\", \"rows\": [{\"label\": \"焊接机器人末端\", \"value\": \"采用双指气动夹爪，提供稳定夹持力以固定焊件，防止高温变形导致的位置偏移。\", \"extra\": \"背景：焊缝精度要求高；方法：刚性夹持；结果：良品率提升15%\"}, {\"label\": \"板材自动搬运\", \"value\": \"部署多吸盘阵列，利用柔性形变贴合钢板曲面，实现无划伤快速吸取与码垛。\", \"extra\": \"背景：表面易划伤；方法：真空阵列；结果：效率提升30%且零损伤\"}, {\"label\": \"混合生产线协同\", \"value\": \"主臂配置快换接口，根据工位需求在夹爪与吸盘间切换，适应多品种混流生产。\", \"extra\": \"背景：产品换型频繁；方法：SOP快换；结果：换线时间缩短至2分钟\"}, {\"label\": \"多工位同步作业\", \"value\": \"左侧工位夹持重型铸件进行去毛刺，右侧工位吸附薄板进行喷涂，互不干扰。\", \"extra\": \"背景：空间受限；方法：分区控制；结果：产能最大化\"}, {\"label\": \"复合工况挑战\", \"value\": \"面对不规则异形件，单一执行器失效，需设计‘夹持+吸附’复合末端方案。\", \"extra\": \"背景：形状复杂；方法：组合设计；结果：覆盖95%以上工件类型\"}], \"summary\": \"核心启示：焊接场景依赖夹持的稳定性，搬运场景依赖吸附的适应性，智能产线需具备灵活切换能力。\", \"bullets\": [{\"icon\": \"fa-check\", \"text\": \"工业案例复盘：焊接与搬运的关键概念。\", \"description\": \"说明工业案例复盘：焊接与搬运的关键概念在当前主题中的价值与应用方式。\"}, {\"icon\": \"fa-check\", \"text\": \"工业案例复盘：焊接与搬运的实践方法。\", \"description\": \"说明工业案例复盘：焊接与搬运的实践方法在当前主题中的价值与应用方式。\"}, {\"icon\": \"fa-check\", \"text\": \"工业案例复盘：焊接与搬运的风险与边界。\", \"description\": \"说明工业案例复盘：焊接与搬运的风险与边界在当前主题中的价值与应用方式。\"}], \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
