INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e75ba9e4-54fd-4dc1-bd05-decb16db9cb8', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef', 11, '第四部分：问题复盘', '{\"page_id\": \"p10\", \"title\": \"常见错误诊断与避坑指南\", \"part\": \"第四部分：问题复盘\", \"points\": [\"模型破面与法线反转的快速修复：利用重计算法线与布尔运算检查器即时修正几何缺陷\", \"贴图拉伸与分辨率不足的解决方案：优化UV布局疏密比并应用高分辨率纹理烘焙技术\", \"文件过大导致软件崩溃的优化手段：实施网格减面、清理未用数据及分块保存工程策略\"]}', '{\"text\": \"页面标题：常见错误诊断与避坑指南\\n\\n页面文字：\\n- 针对模型破面与法线反转导致的渲染黑斑问题，利用重计算法线与布尔运算检查器即时修正几何缺陷。\\n- 解决贴图拉伸与分辨率不足的视觉瑕疵，通过优化UV布局疏密比并应用高分辨率纹理烘焙技术恢复质感。\\n- 应对文件过大导致软件崩溃的崩溃风险，实施网格减面、清理未用数据及分块保存工程策略保障工作流稳定。\", \"generated_at\": \"2026-03-10T05:38:52.925729\"}', NULL, 'FAILED', '2026-03-10 05:38:40', '2026-03-10 05:38:58', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e7eedaf5-4c88-4d51-8702-fd434ebbdb27', 'e43174bb-6386-4c02-9c5d-efa37adcd2cc', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"欧拉公式与拓扑约束\", \"layout_id\": \"theory_explanation\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p06\"], \"must_cover\": [\"V-E+F=2 推导\", \"闭合曲面的拓扑要求\", \"非流形几何的禁忌\", \"欧拉公式与拓扑约束的核心概念与背景\", \"欧拉公式与拓扑约束的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p07_1\", \"text\": \"讲解如何通过布线优化提升模型性能\", \"must_cover\": [\"循环边分布\", \"三角面风险\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"欧拉公式与拓扑约束的核心概念与背景\", \"欧拉公式与拓扑约束的关键方法与执行要点\", \"欧拉公式与拓扑约束的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:18:54', '2026-03-10 05:18:54', 'theory_explanation', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e83d2a3e-b06a-48c6-8b4e-5cbadfd69434', 'e7189705-04c2-4928-8d6c-da2bacf02e42', 11, NULL, '{\"page_id\": \"p12\", \"title\": \"易错点警示：超重与失重\", \"layout_id\": \"vocational_compare_panel\", \"has_image\": true, \"keywords\": [\"电梯上升下降对比\", \"弹簧秤读数变化\", \"红色警示边框\", \"错误 vs 正确 对照\", \"动态模拟图\"], \"depends_on\": [\"p10\"], \"must_cover\": [\"视重与实际重力的区别\", \"加速度方向判断\", \"常见思维误区纠正\", \"易错点警示：超重与失重的核心概念与背景\", \"易错点警示：超重与失重的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"易错点警示：超重与失重的核心概念与背景\", \"易错点警示：超重与失重的关键方法与执行要点\", \"易错点警示：超重与失重的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_compare\", \"layout_variant\": \"a\", \"logical_page_id\": \"p12\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T01:36:50.689368\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 01:36:10', '2026-03-19 01:36:51', 'vocational_compare_panel', '{\"title\": \"易错点警示：超重与失重\", \"itemA\": {\"title\": \"错误认知（视重即实重）\", \"points\": [\"误认为电梯加速上升时体重增加是因为重力变大\", \"混淆‘视重’（弹簧秤读数）与‘实际重力’（mg）\", \"仅凭运动方向判断超重/失重，忽略加速度方向\"]}, \"itemB\": {\"title\": \"正确判定（依据加速度方向）\", \"points\": [\"超重：加速度a向上（加速上升或减速下降），此时 F_N = mg + ma > mg\", \"失重：加速度a向下（加速下降或减速上升），此时 F_N = mg - ma < mg\", \"完全失重：a=g（自由落体），视重为零，但实际重力mg不变\"]}, \"layout_variant\": \"a\", \"variant\": \"a\", \"layout_archetype\": \"feature_compare\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e87199b0-f065-4546-88df-723e14ac7f09', '9da12907-ffda-40fb-9be6-d245c93b1363', 6, '技术深化', '{\"page_id\": \"p05\", \"title\": \"关键技术：多边形建模详解\", \"part\": \"技术深化\", \"points\": [\"掌握挤出、倒角与切角工具的层级组合，快速构建复杂机械与建筑基础形态\", \"解析环形与支撑线布线逻辑，确保模型在蒙皮绑定与动画变形时保持结构稳定\", \"规避布尔运算产生的非流形几何体，执行网格清理以优化拓扑流向\", \"建立从低模拓扑到高模细节的标准化工作流，平衡面数效率与视觉精度\"]}', '{\"text\": \"页面标题：关键技术：多边形建模详解\\n\\n页面文字：\\n- 熟练掌握挤出、倒角与切角工具的层级组合，能够高效构建复杂的机械结构与建筑基础形态。\\n- 深入解析环形布线与支撑线逻辑，确保模型在蒙皮绑定及动画变形过程中始终保持结构稳定。\\n- 主动规避布尔运算产生的非流形几何体，严格执行网格清理以优化整体拓扑流向与数据质量。\\n- 建立从低模拓扑到高模细节的标准化工作流，在面数效率与视觉精度之间取得最佳平衡。\", \"generated_at\": \"2026-03-10T06:06:00.842848\"}', NULL, 'FAILED', '2026-03-10 06:04:53', '2026-03-10 06:08:22', NULL, NULL);
