INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e989647f-4e76-461f-a148-a4497646b1c1', 'd9b1c7c5-f842-4806-a0dc-c6341952c1c1', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"AI发展的关键量化里程碑\", \"layout_id\": \"edu_data_board\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"算力增长摩尔定律\", \"参数量指数级上升\", \"训练成本变化\", \"性能突破阈值\", \"AI发展的关键量化里程碑的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p09_1\"], \"points\": [\"AI发展的关键量化里程碑的核心概念与背景\", \"AI发展的关键量化里程碑的关键方法与执行要点\", \"AI发展的关键量化里程碑的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p09_1\"], \"layout_archetype\": \"data_dashboard\", \"layout_variant\": \"b\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 09:25:55', '2026-03-10 09:25:55', 'edu_data_board', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ea1a8fc6-3347-4c83-bc99-3d203ef85c7c', '9da12907-ffda-40fb-9be6-d245c93b1363', 10, '问题排查', '{\"page_id\": \"p09\", \"title\": \"常见问题诊断与优化方案\", \"part\": \"问题排查\", \"points\": [\"识别并修复非流形几何体以消除渲染破洞与光照错误\", \"应用减面算法与 LOD 技术平衡模型精度与实时性能\", \"统一法线方向修正黑面阴影并恢复正确的光影交互\", \"建立网格自检清单预防拓扑断裂与重叠顶点问题\"]}', '{\"text\": \"页面标题：常见问题诊断与优化方案\\n\\n页面文字：\\n- 识别并修复非流形几何体以消除渲染破洞与光照错误，保障模型完整性。\\n- 应用减面算法与LOD技术平衡模型精度与实时性能，提升运行效率。\\n- 统一法线方向修正黑面阴影并恢复正确的光影交互，避免视觉瑕疵。\\n- 建立网格自检清单预防拓扑断裂与重叠顶点问题，从源头降低出错率。\", \"generated_at\": \"2026-03-10T06:06:00.404485\"}', NULL, 'FAILED', '2026-03-10 06:04:58', '2026-03-10 06:08:34', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ea355567-a451-4ada-82ef-d1c6db3b891c', '7a4f3408-ca73-4a61-998e-174a92497610', 12, NULL, '{\"page_id\": \"p13\", \"title\": \"互动测验：材质属性匹配挑战\", \"layout_id\": \"quiz_interaction\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p11\"], \"must_cover\": [\"金属度/粗糙度测试\", \"法线贴图识别\", \"环境光遮蔽效果\", \"互动测验：材质属性匹配挑战的核心概念与背景\", \"互动测验：材质属性匹配挑战的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"互动测验：材质属性匹配挑战的核心概念与背景\", \"互动测验：材质属性匹配挑战的关键方法与执行要点\", \"互动测验：材质属性匹配挑战的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p13\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.267086\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:25', 'quiz_interaction', '{\"title\": \"互动测验：材质属性匹配挑战\", \"subtitle\": \"基于UV展开与纹理映射的实战检验。\", \"bullets\": [{\"icon\": \"fa-microchip\", \"text\": \"金属度与粗糙度辨析。\", \"description\": \"在复杂光照环境下，快速识别高反光表面的微细划痕与氧化层差异，判断PBR参数中的Metallic值是否准确。\"}, {\"icon\": \"fa-cubes\", \"text\": \"法线贴图深度感知。\", \"description\": \"通过观察表面凹凸阴影的变化趋势，反推法线贴图的强度设置，判断细节雕刻的合理性。\"}, {\"icon\": \"fa-eye\", \"text\": \"环境光遮蔽效果验证。\", \"description\": \"检查模型缝隙、角落处的接触阴影是否自然过渡，评估AO贴图对空间深度的贡献度。\"}, {\"icon\": \"fa-check-circle\", \"text\": \"材质属性匹配逻辑。\", \"description\": \"综合金属度、粗糙度、法线与AO四项指标，构建完整的材质视觉特征库，实现快速分类匹配。\"}], \"keyTakeaway\": \"掌握多参数协同分析方法，是提升材质还原度与制作效率的关键核心。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
