INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('eb0fa5ec-ddc0-4efe-bcdc-2f51938ec9da', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 1, '导览', '{\"page_id\": \"p02\", \"title\": \"目录与学习路线图\", \"part\": \"导览\", \"points\": [\"主流建模软件对比：Blender、Maya与C4D的选型策略\", \"三维基石解析：从多边形拓扑到UV展开的核心逻辑\", \"实战路径指引：硬表面与有机生物案例全流程拆解\", \"进阶方向规划：渲染工作流与行业资源生态概览\"]}', '{\"text\": \"目录与学习路线图\\n\\n页面文字：\\n- 主流建模软件对比：Blender、Maya与C4D的选型策略。\\n- 三维基石解析：从多边形拓扑到UV展开的核心逻辑。\\n- 实战路径指引：硬表面与有机生物案例全流程拆解。\\n- 进阶方向规划：渲染工作流与行业资源生态概览。\", \"generated_at\": \"2026-03-09T03:39:36.940051\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/eb0fa5ec-ddc0-4efe-bcdc-2f51938ec9da_v1.png', 'COMPLETED', '2026-03-09 03:39:09', '2026-03-09 03:40:07', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('eb34e93e-9768-467b-b5ce-00e249c32f8d', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 13, NULL, '{\"title\": \"实战演练：不同场景下的选择：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"case_before_after\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p14\", \"depends_on\": [\"p13\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832334\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'case_before_after', '{\"title\": \"案例复盘：从混乱到有序的进阶之路\", \"left\": {\"header\": \"问题与场景：核心矛盾\", \"content\": [\"实战演练：不同场景下的选择：案例复盘在问题与场景：核心矛盾下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-exclamation-triangle\", \"text\": \"无序数据流导致系统响应迟滞，用户体验严重受损。\", \"description\": \"解释无序数据流导致系统响应迟滞，用户体验严重受损。在问题与场景：核心矛盾维度下的意义。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"传统全量遍历无法识别已排序区间，造成大量无效计算。\", \"description\": \"解释传统全量遍历无法识别已排序区间，造成大量无效计算。在问题与场景：核心矛盾维度下的意义。\"}, {\"icon\": \"fa-database\", \"text\": \"关键业务数据存在重复值，需严格保持原有相对顺序。\", \"description\": \"解释关键业务数据存在重复值，需严格保持原有相对顺序。在问题与场景：核心矛盾维度下的意义。\"}, {\"icon\": \"fa-clock\", \"text\": \"实时性要求极高，O(n²) 的原始算法无法满足时效标准。\", \"description\": \"解释实时性要求极高，O(n²) 的原始算法无法满足时效标准。在问题与场景：核心矛盾维度下的意义。\"}]}, \"right\": {\"header\": \"方案与结果：决策与启示\", \"content\": [\"实战演练：不同场景下的选择：案例复盘在方案与结果：决策与启示下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-check-circle\", \"text\": \"引入标志位 flag 监测交换状态，无变动即立即终止循环。\", \"description\": \"解释引入标志位 flag 监测交换状态，无变动即立即终止循环。在方案与结果：决策与启示维度下的意义。\"}, {\"icon\": \"fa-chart-line\", \"text\": \"实测平均耗时降低 65%，在部分有序数据下接近 O(n)。\", \"description\": \"解释实测平均耗时降低 65%，在部分有序数据下接近 O(n)。在方案与结果：决策与启示维度下的意义。\"}, {\"icon\": \"fa-shield-alt\", \"text\": \"成功保留重复元素的原始顺序，满足金融级稳定性需求。\", \"description\": \"解释成功保留重复元素的原始顺序，满足金融级稳定性需求。在方案与结果：决策与启示维度下的意义。\"}, {\"icon\": \"fa-lightbulb\", \"text\": \"经验表明：针对特定数据特征定制终止条件是关键优化点。\", \"description\": \"解释经验表明：针对特定数据特征定制终止条件是关键优化点。在方案与结果：决策与启示维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
