INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ec26c37c-bf48-4f6c-b4ec-298ebeca3ff8', '7a4f3408-ca73-4a61-998e-174a92497610', 17, NULL, '{\"page_id\": \"p18\", \"title\": \"课后拓展：资源推荐与学习路径\", \"layout_id\": \"group_collab\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p16\"], \"must_cover\": [\"官方文档链接\", \"优质教程网站\", \"插件推荐列表\", \"社区交流渠道\", \"课后拓展：资源推荐与学习路径的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"课后拓展：资源推荐与学习路径的核心概念与背景\", \"课后拓展：资源推荐与学习路径的关键方法与执行要点\", \"课后拓展：资源推荐与学习路径的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p18\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.267592\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:01', 'group_collab', '{\"title\": \"课后拓展：资源推荐与学习路径\", \"subtitle\": \"构建持续成长的数字资产生产体系。\", \"bullets\": [{\"icon\": \"fa-book\", \"text\": \"官方文档与核心教程。\", \"description\": \"提供主流建模软件的官方文档链接及高质量基础教程网站，确保技术原理理解准确。\"}, {\"icon\": \"fa-plug\", \"text\": \"高效插件推荐列表。\", \"description\": \"精选用于自动布线、硬表面倒角及UV优化的专业插件，提升复杂模型制作效率。\"}, {\"icon\": \"fa-users\", \"text\": \"社区交流渠道。\", \"description\": \"接入资深艺术家论坛与技术社群，获取关于布线原则与有机体塑造的最新实战经验。\"}, {\"icon\": \"fa-route\", \"text\": \"进阶学习路径图。\", \"description\": \"规划从基础拓扑到材质映射的完整学习路线，明确下一步攻克硬表面处理的方向。\"}, {\"icon\": \"fa-leaf\", \"text\": \"开源资源库访问。\", \"description\": \"开放包含高质量拓扑参考模型与PBR材质贴图的云端资源库，供日常练习使用。\"}], \"keyTakeaway\": \"利用优质资源填补技能短板，将工匠精神转化为可量化的生产力。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
