INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('eced4c72-7ff2-45b6-a7ec-e208d14a8e4a', '7a81bcb8-4fb4-428e-a65d-75a571002d70', 1, NULL, '{\"title\": \"核心内容\", \"points\": [\"技术原理\"]}', '{\"text\": \"页面标题：核心内容\\n页面文字：\\n- 新核心内容描述\", \"generated_at\": \"2026-03-19T16:58:00.042556\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-19 08:58:00', '2026-03-19 16:58:00', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ed0088d9-1499-4883-bea5-3fdd6b29825b', '9da12907-ffda-40fb-9be6-d245c93b1363', 15, '技术深化', '{\"title\": \"解析多边形建模、曲面建模等核心流派：重点展开\", \"points\": [\"明确多边形建模基于网格拓扑，适用于游戏角色与影视动画的实时渲染场景\", \"阐述NURBS曲面建模依赖数学曲线，是工业设计与精密机械制造的标准化方案\", \"对比两者在布尔运算、布线逻辑及修改器堆栈上的本质差异与适用边界\", \"通过汽车车身（曲面）与低模角色（多边形）案例，展示不同流派的最终成果特征\", \"提供混合工作流建议：利用高模雕刻细节配合低模拓扑，实现效率与质量的平衡\"], \"part\": \"技术深化\"}', '{\"text\": \"页面标题：解析多边形建模、曲面建模等核心流派：重点展开\\n\\n页面文字：\\n- 多边形建模基于网格拓扑，专为游戏角色与影视动画的实时渲染场景设计。\\n- NURBS曲面建模依赖精确数学曲线，是工业设计与精密机械制造的标准化方案。\\n- 两者在布尔运算、布线逻辑及修改器堆栈上存在本质差异，需严格界定适用边界。\\n- 汽车车身展示曲面平滑特征，低模角色体现多边形结构，直观呈现流派成果区别。\\n- 建议采用混合工作流，利用高模雕刻细节配合低模拓扑，实现效率与质量的平衡。\", \"generated_at\": \"2026-03-10T06:06:01.771745\"}', '9da12907-ffda-40fb-9be6-d245c93b1363/pages/ed0088d9-1499-4883-bea5-3fdd6b29825b_v1.png', 'COMPLETED', '2026-03-10 06:05:06', '2026-03-10 06:13:25', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ed04c6be-d805-4cc6-b140-c4f11a329a16', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 11, '展望', '{\"page_id\": \"p11\", \"title\": \"展望未来：AGI之路与人机共生\", \"part\": \"展望\", \"points\": [\"多模态融合与神经符号系统将成为通向通用人工智能（AGI）的关键路径\", \"人机协作模式将取代单纯替代，人类负责决策与创意，AI 专注执行与优化\", \"建立全球统一的伦理规范与监管框架，确保 AI 发展可信、可控且可持续\"]}', '{\"text\": \"页面标题：展望未来：AGI之路与人机共生\\n\\n页面文字：\\n- 多模态融合与神经符号系统将成为通向通用人工智能（AGI）的关键路径，打破感知壁垒。\\n- 人机协作模式将取代单纯替代，人类负责决策与创意，AI专注执行与优化实现共赢。\\n- 建立全球统一的伦理规范与监管框架，确保 AI 发展可信、可控且可持续地造福人类。\\n站在新的起点，我们应携手共进，以智慧驾驭技术，开启人机共生的美好新篇章。\", \"generated_at\": \"2026-03-09T08:54:48.435842\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:35', '2026-03-09 08:54:49', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ed0a3998-c38b-45ef-9a41-b91fa515f996', 'c3f4f20a-0839-4fb0-9375-125c6af13f37', 13, NULL, '{\"page_id\": \"p14\", \"title\": \"互动环节：最佳方案展示\", \"layout_id\": \"sk_task\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p13\"], \"must_cover\": [\"各小组方案汇报\", \"教师点评修正\", \"最优解总结\", \"互动环节：最佳方案展示的核心概念与背景\", \"互动环节：最佳方案展示的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"互动环节：最佳方案展示的核心概念与背景\", \"互动环节：最佳方案展示的关键方法与执行要点\", \"互动环节：最佳方案展示的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"b\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T06:04:18.361100\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 06:03:29', '2026-03-19 06:04:18', 'sk_task', '{\"title\": \"互动环节：最佳方案展示\", \"prompt\": \"各小组依据决策结果进行方案汇报，教师引导点评修正，共同提炼最优解。\", \"roles\": [\"汇报组长\", \"评审教师\", \"观察组员\"], \"questions\": [\"你的选型如何平衡了安全与效率？\", \"针对零件A/B/C的特殊性，采取了哪些关键防护措施？\"], \"notes\": [\"每组汇报限时3分钟，需包含选型理由与预期结果。\", \"教师点评聚焦逻辑漏洞与改进空间，不直接给答案。\"], \"content\": [\"互动环节：最佳方案展示在真实场景中的应用价值与落地建议。\", \"互动环节：最佳方案展示在真实场景中的应用价值与落地建议。\"], \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"concept_explain\"}');
