INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('eda07287-be0c-4568-ba74-3792caa842af', 'e7189705-04c2-4928-8d6c-da2bacf02e42', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"公式的物理意义与矢量性\", \"layout_id\": \"vocational_theory\", \"has_image\": true, \"keywords\": [\"力的矢量分解示意图\", \"加速度方向箭头\", \"受力分析图\", \"三维坐标系\", \"工业风线条图解\"], \"depends_on\": [\"p08\"], \"must_cover\": [\"F、m、a的方向一致性\", \"瞬时对应关系\", \"独立性原理\", \"公式的物理意义与矢量性的核心概念与背景\", \"公式的物理意义与矢量性的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p09_1\", \"text\": \"解决复杂受力问题的标准步骤\", \"must_cover\": [\"受力分析\", \"正交分解\", \"列方程求解\"], \"target_page_ids\": [\"p11\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"公式的物理意义与矢量性的核心概念与背景\", \"公式的物理意义与矢量性的关键方法与执行要点\", \"公式的物理意义与矢量性的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T01:36:50.689309\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 01:36:09', '2026-03-19 01:36:51', 'vocational_theory', '{\"title\": \"公式的物理意义与矢量性\", \"description\": \"牛顿第二定律不仅是数量关系，更是矢量方程。F、m、a三者存在严格的瞬时对应与方向一致性，这是解决复杂动力学问题的基石。\", \"bullets\": [\"方向一致性：加速度a的方向始终与合外力F的方向严格一致，与速度方向无关\", \"瞬时对应性：力变化瞬间，加速度立即随之改变，无时间延迟\", \"独立性原理：物体在某一方向的受力只决定该方向的加速度，与其他方向运动互不干扰\"], \"practiceLabel\": \"工业现场应用：传送带纠偏系统\", \"layout_variant\": \"a\", \"variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('eda1aca6-3ce5-48dc-ba47-f561d11a1227', '8fb9adbb-55b5-496b-9569-be1757626e7c', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"情景导入：汽车加速与刹车\", \"layout_id\": \"vocational_lead_in\", \"has_image\": true, \"keywords\": [\"汽车加速动态图\", \"刹车痕迹特写\", \"工业实景\", \"实训蓝橙配色\"], \"depends_on\": [\"p03\"], \"must_cover\": [\"力的大小影响加速度\", \"质量对运动状态改变的影响\", \"情景导入：汽车加速与刹车的核心概念与背景\", \"情景导入：汽车加速与刹车的关键方法与执行要点\", \"情景导入：汽车加速与刹车的应用场景与注意事项\"], \"promises_open\": [{\"promise_id\": \"pr_p04_1\", \"text\": \"力、质量与加速度的具体数学关系\", \"must_cover\": [\"控制变量法实验结论\", \"比例关系推导\"], \"target_page_ids\": [\"p17\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"情景导入：汽车加速与刹车的核心概念与背景\", \"情景导入：汽车加速与刹车的关键方法与执行要点\", \"情景导入：汽车加速与刹车的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"b\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T04:44:29.430258\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 04:43:50', '2026-03-17 04:44:29', 'vocational_lead_in', '{\"title\": \"情景导入：汽车加速与刹车\", \"content\": [\"工业实训中，汽车加速过程直观展示了力的大小如何决定加速度，而刹车痕迹则揭示了质量对运动状态改变的制约作用。\", \"通过观察真实车辆的动态变化，学生需理解F=ma在工程实践中的核心意义，掌握从现象到本质的分析逻辑。\"], \"highlight\": \"力是改变物体运动状态的原因。\", \"image\": {\"src\": \"\", \"alt\": \"汽车加速动态图与刹车痕迹特写，背景为工业实景，采用蓝橙配色方案\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ef060139-8ea0-4d8c-9859-5567f089f40a', 'e7189705-04c2-4928-8d6c-da2bacf02e42', 6, NULL, '{\"page_id\": \"p07\", \"title\": \"控制变量法实验设计\", \"layout_id\": \"vocational_step_by_step\", \"has_image\": true, \"keywords\": [\"气垫导轨实验装置\", \"光电门传感器\", \"砝码组\", \"数据记录表\", \"实验室操作台\"], \"depends_on\": [\"p05\"], \"must_cover\": [\"保持质量不变，改变力\", \"保持力不变，改变质量\", \"数据采集步骤\", \"控制变量法实验设计的核心概念与背景\", \"控制变量法实验设计的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p04_1\"], \"points\": [\"控制变量法实验设计的核心概念与背景\", \"控制变量法实验设计的关键方法与执行要点\", \"控制变量法实验设计的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p04_1\"], \"layout_archetype\": \"process_steps\", \"layout_variant\": \"a\", \"logical_page_id\": \"p07\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-19T01:36:50.689184\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-19 01:36:09', '2026-03-19 01:36:51', 'vocational_step_by_step', '{\"title\": \"控制变量法实验设计：气垫导轨系统\", \"steps\": [{\"title\": \"STEP 01: 装置搭建与调平\", \"label\": \"STEP 01\", \"desc\": \"组装气垫导轨与光电门传感器，调节底座螺丝使滑块匀速滑行，消除摩擦干扰，确保实验环境纯净。\"}, {\"title\": \"STEP 02: 恒定质量变力测试\", \"label\": \"STEP 02\", \"desc\": \"保持滑块质量不变，通过增减砝码组改变牵引力，记录不同拉力下的加速度数据，验证F-m关系。\"}, {\"title\": \"STEP 03: 恒定力变质量测试\", \"label\": \"STEP 03\", \"desc\": \"保持牵引力不变，在滑块上添加配重块改变总质量，采集多组数据以探究a与m的反比关系。\"}, {\"title\": \"STEP 04: 数据采集与记录\", \"label\": \"STEP 04\", \"desc\": \"利用光电门传感器自动记录时间间隔，填写标准数据记录表，确保原始数据真实、完整、可追溯。\"}], \"layout_variant\": \"a\", \"variant\": \"a\", \"layout_archetype\": \"process_steps\"}');
