INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('f314feb2-cf3f-4fc6-a7da-db517b115eaa', '8fb9adbb-55b5-496b-9569-be1757626e7c', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"核心公式：F=ma的深度解析\", \"layout_id\": \"vocational_theory\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p07\"], \"must_cover\": [\"公式形式 F=ma\", \"矢量性（方向一致）\", \"瞬时性\", \"独立性\", \"核心公式：F=ma的深度解析的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p07_1\"], \"points\": [\"核心公式：F=ma的深度解析的核心概念与背景\", \"核心公式：F=ma的深度解析的关键方法与执行要点\", \"核心公式：F=ma的深度解析的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p07_1\"], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"b\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T04:44:29.430473\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 04:43:51', '2026-03-17 04:44:29', 'vocational_theory', '{\"title\": \"核心公式：F=ma的深度解析\", \"left\": {\"header\": \"公式确立与物理内涵\", \"content\": [\"基于前序实验数据，将比例关系 a ∝ F/m 转化为等式。在国际单位制下，比例系数 k=1，从而确立牛顿第二定律的数学表达形式 F=ma。\"], \"bullets\": [{\"icon\": \"fa-math-operations\", \"text\": \"公式形式：F=ma，其中F为合外力，m为质量，a为加速度。\", \"description\": \"解释公式形式：F=ma，其中F为合外力，m为质量，a为加速度在公式确立与物理内涵维度下的意义。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"矢量性：加速度方向始终与合外力方向保持一致。\", \"description\": \"解释矢量性：加速度方向始终与合外力方向保持一致在公式确立与物理内涵维度下的意义。\"}, {\"icon\": \"fa-stopwatch\", \"text\": \"瞬时性：力变则加速度即时改变，无时间滞后。\", \"description\": \"解释瞬时性：力变则加速度即时改变，无时间滞后在公式确立与物理内涵维度下的意义。\"}, {\"icon\": \"fa-project-diagram\", \"text\": \"独立性：各方向受力独立产生对应方向的加速度。\", \"description\": \"解释独立性：各方向受力独立产生对应方向的加速度在公式确立与物理内涵维度下的意义。\"}]}, \"right\": {\"header\": \"职业场景应用逻辑\", \"content\": [\"在工程实训中，理解该公式是进行设备选型、运动控制及安全防护计算的基础。必须明确力的作用效果直接取决于质量和加速度的乘积。\", \"结论：核心公式：F=ma的深度解析需要结合目标场景做取舍。\"], \"bullets\": [{\"icon\": \"fa-cogs\", \"text\": \"设备选型：根据负载质量计算驱动电机所需的最小推力。\", \"description\": \"解释设备选型：根据负载质量计算驱动电机所需的最小推力在职业场景应用逻辑维度下的意义。\"}, {\"icon\": \"fa-shield-alt\", \"text\": \"安全制动：依据最大允许减速度反推紧急制动距离。\", \"description\": \"解释安全制动：依据最大允许减速度反推紧急制动距离在职业场景应用逻辑维度下的意义。\"}, {\"icon\": \"fa-tachometer-alt\", \"text\": \"过程控制：通过调节输入力精确控制工件的运动状态。\", \"description\": \"解释过程控制：通过调节输入力精确控制工件的运动状态在职业场景应用逻辑维度下的意义。\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"故障诊断：当实际加速度偏离理论值时排查受力异常。\", \"description\": \"解释故障诊断：当实际加速度偏离理论值时排查受力异常在职业场景应用逻辑维度下的意义。\"}]}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"data_metrics\"}');
