INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('f37242e3-fbe9-41c0-8392-50a1f0acd1e7', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 26, '第六部分：答疑总结与未来展望', '{\"title\": \"新手高频痛点速查与解决方案\", \"points\": [\"软件崩溃原因排查与卡顿优化方案\", \"渲染噪点处理技巧与快捷键记忆法\", \"常见问题Q&A：从入门到精通的关键障碍突破\"], \"layout_id\": \"edu_tri_compare\", \"part\": \"第六部分：答疑总结与未来展望\", \"logical_page_id\": \"p27\", \"has_image\": false, \"keywords\": [\"软件崩溃原因排查与卡顿优化方案\", \"渲染噪点处理技巧与快捷键记忆法\", \"常见问题Q&A：从入门到精通的关键障碍突破\"], \"depends_on\": [\"p26\"], \"must_cover\": [\"软件崩溃原因排查与卡顿优化方案\", \"渲染噪点处理技巧与快捷键记忆法\", \"常见问题Q&A：从入门到精通的关键障碍突破\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"b\", \"layout_archetype\": \"feature_compare\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.419606\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_tri_compare', '{\"title\": \"新手高频痛点速查与解决方案\", \"badge\": \"避坑指南\", \"columns\": [{\"title\": \"性能瓶颈排查\", \"points\": [\"崩溃主因：显存溢出或内存泄漏，需检查纹理分辨率是否超过硬件上限\", \"卡顿优化：开启视锥体剔除，简化背景网格，使用LOD多级细节系统\", \"快捷键记忆：Ctrl+Z（撤销）与G/S/R（移动/缩放/旋转）肌肉记忆训练\"]}, {\"title\": \"渲染质量修正\", \"points\": [\"噪点处理：提升采样值（Samples）至300+，启用降噪器（OptiX/Denoise）\", \"光照技巧：避免过曝，使用HDRI环境光配合区域光源柔化阴影\", \"材质调试：检查法线方向，确保PBR金属度与粗糙度数值归一化\"]}, {\"title\": \"关键障碍突破\", \"points\": [\"UV展开错误：保持岛间间距，避免重叠，优先使用自动展开辅助手动调整\", \"绑定失败：检查权重绘制平滑度，修复非流形几何体导致的蒙皮扭曲\", \"学习路径：从单一硬表面组件入手，逐步过渡到完整角色装配流程\"]}], \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_compare\"}');
