INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('f4b8a11f-9e24-4806-a8b6-aa10ea248652', '8a37f529-e51f-428c-8466-cdc137b73187', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"布线策略实战：硬表面 vs 有机体\", \"layout_id\": \"case_study\", \"has_image\": true, \"keywords\": [\"对比图示\", \"左侧机械结构\", \"右侧生物肌肉线条\", \"学术风格线条画\"], \"depends_on\": [\"p05\"], \"must_cover\": [\"硬表面布线特征\", \"有机体布线特征\", \"差异对比分析\", \"布线策略实战：硬表面 vs 有机体的核心概念与背景\", \"布线策略实战：硬表面 vs 有机体的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"布线策略实战：硬表面 vs 有机体的核心概念与背景\", \"布线策略实战：硬表面 vs 有机体的关键方法与执行要点\", \"布线策略实战：硬表面 vs 有机体的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T04:52:14.107502\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 04:50:26', '2026-03-10 04:52:14', 'case_study', '{\"title\": \"典型案例分析：硬表面 vs 有机体\", \"scenario\": \"在角色装甲设计与生物角色制作中，面对截然不同的物理属性与运动需求，需采用差异化的布线策略。\", \"challenge\": \"如何在保证机械结构刚性的同时，实现生物组织的自然形变？若策略混用会导致何种渲染或动画故障？\", \"points\": [{\"title\": \"硬表面特征：规则化与分段\", \"description\": \"采用平行等距的四边形循环，强调直角与锐利边缘；布线服务于结构分割而非形变，注重UV展开的规整性。\"}, {\"title\": \"有机体特征：流线化与动态\", \"description\": \"依据肌肉走向布置环形与放射状布线，允许局部三角形过渡；重点在于关节弯曲时的体积保持与无褶皱变形。\"}, {\"title\": \"布线策略实战：硬表面 vs 有机体的应用场景与注意事项\", \"description\": \"围绕布线策略实战：硬表面 vs 有机体的应用场景与注意事项给出问题、方法与启示。\"}], \"conclusion\": \"案例启示：布线即逻辑。硬表面追求‘静态稳定’，有机体追求‘动态兼容’；混淆两者将导致动画解算失败或光影伪影。\", \"image\": \"https://example.com/hard_surface_vs_organic_compare.png\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('f5107022-d1f6-4230-bd52-3a0b8d551103', '6eea18f8-c641-48a1-ba84-4c49ed3830d6', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"进化引擎：OpenClaw 核心模型解析\", \"layout_id\": \"edu_timeline_steps\", \"has_image\": true, \"keywords\": [\"中心发光节点\", \"四向连接箭头\", \"深色科技网络\", \"青色高亮连线\", \"抽象几何图形\"], \"depends_on\": [\"p05\"], \"must_cover\": [\"中心控制单元\", \"四向功能模块\", \"动态关联机制\", \"进化引擎：OpenClaw 核心模型解析的核心概念与背景\", \"进化引擎：OpenClaw 核心模型解析的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p03_1\"], \"points\": [\"进化引擎：OpenClaw 核心模型解析的核心概念与背景\", \"进化引擎：OpenClaw 核心模型解析的关键方法与执行要点\", \"进化引擎：OpenClaw 核心模型解析的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p03_1\"], \"layout_archetype\": \"timeline\", \"layout_variant\": \"a\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p03_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:27:09.079537\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:25:45', '2026-03-10 07:36:50', 'edu_timeline_steps', '{\"title\": \"进化引擎：OpenClaw 核心模型解析\", \"subtitle\": \"中心控制驱动四向协同。\", \"steps\": [{\"title\": \"中心控制单元\", \"description\": \"作为全链路大脑，负责全局状态感知、策略下发与异常熔断，确保系统高可用运行。\", \"highlights\": [\"全局状态实时感知\", \"智能策略动态下发\"]}, {\"title\": \"感知与决策模块\", \"description\": \"向上对接多源异构数据，向下输出精准指令，实现从数据采集到执行反馈的闭环控制。\", \"highlights\": [\"多源数据融合分析\", \"毫秒级决策响应\"]}, {\"title\": \"执行与协同模块\", \"description\": \"驱动底层硬件动作，协调多方资源并行作业，保障复杂任务的高效分解与同步执行。\", \"highlights\": [\"硬件指令精准映射\", \"多端任务并行调度\"]}, {\"title\": \"反馈与优化模块\", \"description\": \"收集执行结果数据，通过机器学习迭代模型参数，持续提升系统适应性与处理效能。\", \"highlights\": [\"全链路数据回流\", \"模型参数自进化\"]}], \"background_image\": \"https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=1920&auto=format&fit=crop\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"timeline\"}');
