INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('f5e7b272-4c48-4770-a4a8-f23f11512331', '9b5d83ef-2600-4c3b-b852-00607680277d', 0, '引言', '{\"page_id\": \"p01\", \"title\": \"封面：生成式AI的演进与变革\", \"part\": \"引言\", \"points\": [\"梳理从早期概念萌芽到当前技术全面爆发的关键时间轴节点\", \"深度聚焦ChatGPT、Claude、Gemini三大核心模型的技术突破\", \"系统阐述生成式AI的发展脉络、差异化定位及未来演进趋势\"]}', '{\"text\": \"页面标题：封面：生成式AI的演进与变革\\n\\n页面文字：\\n- 梳理从早期概念萌芽到当前技术全面爆发的关键时间轴节点，构建清晰发展脉络。\\n- 深度聚焦ChatGPT、Claude、Gemini三大核心模型的技术突破，解析其差异化定位。\\n- 系统阐述生成式AI的发展脉络、未来演进趋势及行业变革方向。\", \"generated_at\": \"2026-03-09T08:14:14.359464\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/f5e7b272-4c48-4770-a4a8-f23f11512331_v2.png', 'COMPLETED', '2026-03-09 08:13:36', '2026-03-09 09:20:42', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('f63e06fb-2112-40ca-b6be-0e182fc1ee0a', '8fb9adbb-55b5-496b-9569-be1757626e7c', 13, NULL, '{\"page_id\": \"p14\", \"title\": \"随堂测验：概念与计算\", \"layout_id\": \"vocational_quiz\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p12\"], \"must_cover\": [\"判断力与加速度方向关系\", \"简单数值计算\", \"概念辨析\", \"随堂测验：概念与计算的核心概念与背景\", \"随堂测验：概念与计算的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"随堂测验：概念与计算的核心概念与背景\", \"随堂测验：概念与计算的关键方法与执行要点\", \"随堂测验：概念与计算的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T04:44:29.430745\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 04:43:52', '2026-03-17 04:44:29', 'vocational_quiz', '{\"title\": \"随堂测验：概念与计算\", \"subtitle\": \"检验牛顿第二定律应用能力。\", \"bullets\": [{\"icon\": \"fa-arrow-right\", \"text\": \"判断力与加速度方向关系。\", \"description\": \"根据F=ma，合外力方向始终与加速度方向一致，与速度方向无必然联系。\"}, {\"icon\": \"fa-calculator\", \"text\": \"简单数值计算练习。\", \"description\": \"已知m=2kg, F=10N, a=5m/s²，验证方程成立并计算摩擦力。\"}, {\"icon\": \"fa-question-circle\", \"text\": \"概念辨析：超重与失重。\", \"description\": \"加速度向上为超重，向下为失重，视重不等于实际重力。\"}, {\"icon\": \"fa-lightbulb\", \"text\": \"核心要点总结。\", \"description\": \"掌握受力分析步骤，熟练运用正交分解法解决斜面与水平面问题。\"}], \"keyTakeaway\": \"准确受力分析与正确的坐标系建立是解决动力学问题的基石。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
