INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('f8e17d77-d01f-4649-8b95-f32bb904dd95', 'f8ce8774-c982-4cd5-a379-23d4cf53bef2', 2, NULL, '{\"page_id\": \"p03\", \"title\": \"任务情境：自动化产线加速度异常\", \"layout_id\": \"vocational_lead_in\", \"has_image\": true, \"keywords\": [\"自动化流水线\", \"传送带电机\", \"工程师诊断场景\", \"橙色警示标识\", \"工业实景摄影\"], \"depends_on\": [\"p02\"], \"must_cover\": [\"真实职业场景描述\", \"产线加速度失控痛点\", \"引出牛顿第二定律应用\", \"任务情境：自动化产线加速度异常的核心概念与背景\", \"任务情境：自动化产线加速度异常的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p06_1\", \"text\": \"后续将详细拆解如何通过F=ma公式反推故障原因\", \"must_cover\": [\"力与加速度的定量关系\", \"变量控制逻辑\"], \"target_page_ids\": [\"p15\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"任务情境：自动化产线加速度异常的核心概念与背景\", \"任务情境：自动化产线加速度异常的关键方法与执行要点\", \"任务情境：自动化产线加速度异常的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p03\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T06:43:32.017859\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 06:42:45', '2026-03-17 14:44:01', 'vocational_lead_in', '{\"title\": \"任务情境：自动化产线加速度异常\", \"content\": [\"某精密电子组装车间传送带电机在负载突增时出现非预期加速，导致产品错位报废。现场工程师需立即排查是控制系统故障还是机械传动问题。\", \"本任务将利用牛顿第二定律（F=ma）建立动力学模型，通过对比理论加速度与实测数据，精准定位异常根源，掌握工业设备故障诊断的核心方法。\"], \"highlight\": \"痛点：加速度失控引发的质量事故与效率损失。\", \"image\": {\"src\": \"\", \"alt\": \"自动化流水线传送带特写，橙色警示灯闪烁，工程师手持平板电脑正在检测电机运行状态，背景为整洁的工业实训车间\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('f93c9ba1-f485-4556-ac11-5566371e87d9', '8fb9adbb-55b5-496b-9569-be1757626e7c', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"进阶案例：斜面与摩擦力\", \"layout_id\": \"vocational_homework\", \"has_image\": true, \"keywords\": [\"斜面模型图\", \"受力分解示意图\", \"摩擦系数标注\", \"工程力学图\"], \"depends_on\": [\"p10\"], \"must_cover\": [\"重力分解\", \"支持力与摩擦力\", \"沿斜面方向的牛顿第二定律\", \"进阶案例：斜面与摩擦力的核心概念与背景\", \"进阶案例：斜面与摩擦力的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p10_1\"], \"points\": [\"进阶案例：斜面与摩擦力的核心概念与背景\", \"进阶案例：斜面与摩擦力的关键方法与执行要点\", \"进阶案例：斜面与摩擦力的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p10_1\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p10_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T04:44:29.430617\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 04:43:51', '2026-03-17 04:44:29', 'vocational_homework', '{\"title\": \"进阶案例：斜面与摩擦力\", \"subtitle\": \"复杂环境下的重力分解与摩擦计算。\", \"bullets\": [{\"icon\": \"fa-project-diagram\", \"text\": \"重力正交分解。\", \"description\": \"将重力沿斜面方向和垂直斜面方向分解为分力G1和G2。\"}, {\"icon\": \"fa-hand-paper\", \"text\": \"支持力与摩擦力。\", \"description\": \"计算垂直斜面方向的支持力N，进而确定滑动摩擦力f=μN。\"}, {\"icon\": \"fa-rocket\", \"text\": \"沿斜面牛顿第二定律。\", \"description\": \"沿斜面方向列式 ma = Gsinθ - f，求解加速度或位移。\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"关键执行要点。\", \"description\": \"优先处理垂直斜面方向的力平衡，再处理沿斜面方向的加速运动。\"}], \"keyTakeaway\": \"掌握斜面模型核心在于正确分解重力并准确判定摩擦力状态，这是解决复杂工程力学问题的基石。\", \"image\": {\"src\": \"\", \"alt\": \"斜面模型受力分解示意图，标注重力、支持力、摩擦力及角度\", \"position\": \"right\", \"width\": \"35%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('f9b6bc4c-7044-432f-8868-c0aa21e8ed21', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 7, '技能实操', '{\"page_id\": \"p06\", \"title\": \"有机生物建模技巧\", \"part\": \"技能实操\", \"points\": [\"利用数字雕刻工具精准塑造肌肉走向与皮肤褶皱细节\", \"采用对称建模提升效率，结合局部细化策略优化关键区域\", \"融入基础解剖学知识确保角色结构合理且符合生理逻辑\", \"掌握拓扑布线对表情变形与动态流畅度的关键影响\"]}', '{\"text\": \"页面标题：有机生物建模技巧\\n\\n页面文字：\\n- 利用数字雕刻工具精准塑造肌肉走向与皮肤褶皱，赋予角色生动细节。\\n- 采用对称建模提升效率，结合局部细化策略重点优化面部等关键区域。\\n- 融入基础解剖学知识确保角色结构合理，使形态完全符合生理逻辑。\\n- 深刻理解拓扑布线对表情变形的影响，保障角色动态表演的流畅自然。\", \"generated_at\": \"2026-03-09T03:39:37.135422\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/f9b6bc4c-7044-432f-8868-c0aa21e8ed21_v1.png', 'COMPLETED', '2026-03-09 03:39:17', '2026-03-09 03:45:49', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('faa0c7df-1109-4b21-8e33-bf62ca9f1e36', 'ea9f06c0-6a32-4cb7-b83e-2f46a3e6f0ef', 0, '课程导入', '{\"page_id\": \"p01\", \"title\": \"封面：3D建模基础教学课程\", \"part\": \"课程导入\", \"points\": [\"面向高校设计、动画及工程类专业学生，奠定三维数字创作基础\", \"核心目标：系统掌握空间坐标原理、主流建模流派与标准化生产流程\", \"采用案例驱动教学法，从理论概念直达游戏、影视及工业制造实战场景\"]}', '{\"text\": \"页面标题：封面：3D建模基础教学课程\\n\\n页面文字：\\n- 本课程专为高校设计、动画及工程类专业学生打造，旨在奠定坚实的三维数字创作基础。\\n- 核心目标在于系统掌握空间坐标原理、主流建模流派以及标准化的工业生产全流程。\\n- 采用案例驱动教学法，将理论概念直接延伸至游戏开发、影视制作及工业制造等实战场景。\", \"generated_at\": \"2026-03-10T05:38:52.044263\"}', NULL, 'GENERATING', '2026-03-10 05:38:19', '2026-03-10 05:38:57', NULL, NULL);
