INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('fbfcadbf-b428-4405-ad70-400fb52c5516', '60390839-f925-4662-a2dc-c92d64253b33', 6, NULL, '{\"page_id\": \"p07\", \"title\": \"标准建模流程图解\", \"layout_id\": \"diagram_illustration\", \"has_image\": true, \"keywords\": [\"学术流程图\", \"3D网格线框\", \"冷灰色调\", \"极简线条\", \"几何节点\"], \"depends_on\": [\"p05\"], \"must_cover\": [\"构建基础形态\", \"细分曲面\", \"细节雕刻\", \"UV展开\", \"标准建模流程图解的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p02_2\"], \"points\": [\"标准建模流程图解的核心概念与背景\", \"标准建模流程图解的关键方法与执行要点\", \"标准建模流程图解的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p02_2\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:29:50', '2026-03-10 05:29:50', 'diagram_illustration', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('fc1d60dc-4ebb-4b95-97a4-ab04c24bd08e', '9da12907-ffda-40fb-9be6-d245c93b1363', 7, '技术深化', '{\"page_id\": \"p06\", \"title\": \"进阶技巧：NURBS与细分曲面\", \"part\": \"技术深化\", \"points\": [\"解析NURBS数学曲线在工业产品高精度曲面构建中的核心优势\", \"演示细分曲面算法如何将低模网格平滑转化为有机生物形态\", \"对比NURBS与细分曲面在不同行业场景下的适用性与局限性\", \"探讨混合建模策略以实现复杂机械结构与自然形态的完美融合\"]}', '{\"text\": \"页面标题：进阶技巧：NURBS与细分曲面\\n\\n页面文字：\\n- 解析NURBS数学曲线在工业产品高精度曲面构建中的核心优势，确立精密设计的标准范式。\\n- 演示细分曲面算法如何将低模网格平滑转化为有机的生物形态，实现自然流畅的视觉表现。\\n- 对比NURBS与细分曲面在不同行业场景下的适用性与局限性，为项目选型提供科学依据。\\n- 探讨混合建模策略以实现复杂机械结构与自然形态的完美融合，拓展三维创作的技术边界。\", \"generated_at\": \"2026-03-10T06:06:00.842852\"}', NULL, 'FAILED', '2026-03-10 06:04:55', '2026-03-10 06:08:25', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('fc2372b0-b1f3-4337-955c-1a265d06c3c7', '766dd313-1e7e-43f8-b4e9-3ca4b9e71dd6', 2, NULL, '{\"page_id\": \"p03\", \"title\": \"建模核心机制解析\", \"layout_id\": \"edu_core_hub\", \"has_image\": true, \"keywords\": [\"中心圆形节点\", \"四向连接线\", \"青色高亮数据流\", \"深蓝色卡片容器\", \"抽象拓扑结构\"], \"depends_on\": [\"p02\"], \"must_cover\": [\"多边形与 NURBS 区别\", \"顶点面体逻辑\", \"参数化修改器\", \"建模核心机制解析的核心概念与背景\", \"建模核心机制解析的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p03_1\", \"text\": \"不同软件的性能差异对比\", \"must_cover\": [\"行业偏好\", \"学习成本\"], \"target_page_ids\": [\"p20\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"建模核心机制解析的核心概念与背景\", \"建模核心机制解析的关键方法与执行要点\", \"建模核心机制解析的应用场景与注意事项\"], \"required_close_promise_ids\": []}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-06 09:45:17', '2026-03-06 09:45:17', 'edu_core_hub', NULL);
