INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('fca21d84-d873-49ec-8948-8550e4c5355b', 'a2fd39b5-8219-45ef-abe1-9be04d06dd66', 25, '第五部分：动态呈现与资产交付', '{\"title\": \"综合实战模拟：限时设计挑战与评审反馈\", \"points\": [\"需求分析阶段的核心痛点识别\", \"快速原型制作与迭代优化过程复盘\", \"评审反馈收集与经验教训总结\", \"结果启示：可复用的团队协作经验与风险提示\"], \"layout_id\": \"edu_qa_case\", \"part\": \"第五部分：动态呈现与资产交付\", \"logical_page_id\": \"p26\", \"has_image\": false, \"keywords\": [\"需求分析阶段的核心痛点识别\", \"快速原型制作与迭代优化过程复盘\", \"评审反馈收集与经验教训总结\"], \"depends_on\": [\"p25\"], \"must_cover\": [\"需求分析阶段的核心痛点识别\", \"快速原型制作与迭代优化过程复盘\", \"评审反馈收集与经验教训总结\", \"结果启示：可复用的团队协作经验与风险提示\"], \"promises_open\": [{\"promise_id\": \"pr_p26_1_780aeab9\", \"text\": \"综合实战模拟：限时设计挑战与评审反馈的复盘与结果启示\", \"must_cover\": [\"案例复盘\", \"结果启示\"], \"target_page_ids\": [\"p28\"], \"is_hard\": true}], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_variant\": \"b\", \"layout_archetype\": \"qa_session\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-16T01:21:07.419562\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-16 01:19:44', '2026-03-16 01:21:07', 'edu_qa_case', '{\"title\": \"综合实战模拟：限时设计挑战与评审反馈\", \"subtitle\": \"从需求痛点到最终交付的全链路复盘。\", \"question\": \"在48小时极限开发周期内，如何快速识别核心需求痛点并完成高质量原型交付？\", \"answer\": \"采用‘敏捷原型 + 动态评审’双轨制：先构建低保真拓扑验证结构逻辑，再分阶段注入高精度细节，确保关键路径不阻塞。\", \"analysis\": [{\"title\": \"痛点精准定位\", \"content\": \"通过需求拆解矩阵，将模糊的‘科幻感’转化为具体的‘机械咬合度’与‘发光逻辑’指标，避免无效建模。\"}, {\"title\": \"迭代优化闭环\", \"content\": \"每4小时进行一次内部评审，针对布线冗余与面数超标问题即时重构，而非等到最后统一清理。\"}, {\"title\": \"经验沉淀与风控\", \"content\": \"建立常见崩溃场景库，提前预设代理物体；团队协作中明确主责人，防止多头修改导致版本冲突。\"}], \"conclusion\": \"成功的关键不在于速度，而在于对核心约束的早期识别与果断的取舍决策。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"qa_session\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('fca481e0-5cd6-4c0b-a95b-7724edb65fcd', '14c0f24c-10e7-4309-a927-d9db1066897c', 13, NULL, '{\"page_id\": \"p14\", \"title\": \"PBR材质工作流详解\", \"layout_id\": \"case_before_after\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p12\"], \"must_cover\": [\"漫反射/法线/粗糙度\", \"金属度贴图\", \"环境光遮蔽\", \"PBR材质工作流详解的核心概念与背景\", \"PBR材质工作流详解的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"PBR材质工作流详解的核心概念与背景\", \"PBR材质工作流详解的关键方法与执行要点\", \"PBR材质工作流详解的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.774031\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'case_before_after', '{\"title\": \"PBR材质工作流详解\", \"left\": {\"header\": \"基础贴图通道\", \"content\": [\"漫反射贴图定义基础色彩，法线贴图模拟微细几何起伏，粗糙度控制表面光泽分布。\"], \"bullets\": [{\"icon\": \"fa-microscope\", \"text\": \"漫反射/法线/粗糙度精准匹配。\", \"description\": \"解释漫反射/法线/粗糙度精准匹配在基础贴图通道维度下的意义。\"}, {\"icon\": \"fa-cube\", \"text\": \"环境光遮蔽增强角落细节。\", \"description\": \"解释环境光遮蔽增强角落细节在基础贴图通道维度下的意义。\"}]}, \"right\": {\"header\": \"金属度与流程规范\", \"content\": [\"金属度贴图区分非金属与导体反射特性，严格遵循能量守恒原则优化渲染效率。\", \"结论：PBR材质工作流详解需要结合目标场景做取舍。\"], \"bullets\": [{\"icon\": \"fa-bolt\", \"text\": \"金属度贴图逻辑判断。\", \"description\": \"解释金属度贴图逻辑判断在金属度与流程规范维度下的意义。\"}, {\"icon\": \"fa-tasks\", \"text\": \"标准化PBR工作流执行。\", \"description\": \"解释标准化PBR工作流执行在金属度与流程规范维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('fd1de92a-8268-47bb-abb6-0a7007c52aba', 'ab2ec2c8-cb17-41e9-beb4-40c851abbea2', 18, NULL, '{\"page_id\": \"p19\", \"title\": \"课后思考与拓展任务\", \"layout_id\": \"edu_data_board\", \"has_image\": true, \"keywords\": [\"数据图表占位\", \"思考题列表\", \"青色高亮重点\", \"深色底纹\", \"无文字水印\"], \"depends_on\": [\"p16\"], \"must_cover\": [\"课后习题推荐\", \"探究性实验建议\", \"进阶阅读材料\", \"课后思考与拓展任务的核心概念与背景\", \"课后思考与拓展任务的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"课后思考与拓展任务的核心概念与背景\", \"课后思考与拓展任务的关键方法与执行要点\", \"课后思考与拓展任务的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_dashboard\", \"layout_variant\": \"a\", \"logical_page_id\": \"p19\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-17T02:06:57.191080\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-17 01:42:02', '2026-03-17 02:06:57', 'edu_data_board', '{\"title\": \"课后思考与拓展任务\", \"subtitle\": \"深化牛顿第二定律认知边界。\", \"metrics\": [{\"value\": \"+45%\", \"label\": \"探究深度提升\", \"note\": \"较基础习题。\"}, {\"value\": \"3 类\", \"label\": \"拓展维度\", \"note\": \"实验/阅读/思考。\"}], \"bars\": [{\"label\": \"基础计算能力\", \"baseline\": 80, \"current\": 92}, {\"label\": \"复杂系统分析\", \"baseline\": 45, \"current\": 75}], \"bullets\": [{\"text\": \"分层习题推荐。\", \"description\": \"覆盖电梯视重辨析与连接体受力分析，强化整体法与隔离法协同运用。\"}, {\"text\": \"探究性实验建议。\", \"description\": \"设计多变量控制实验，验证非惯性系下加速度与合力的非线性关联特征。\"}, {\"text\": \"进阶阅读材料。\", \"description\": \"引入相对运动视角下的力学变换，拓展从定性感知到定量计算的思维闭环。\"}], \"insight\": \"通过多维拓展任务，将课堂知识图谱延伸至真实复杂场景，实现从解题能力到科学探究素养的跃迁。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_dashboard\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('fd951099-447c-478e-8472-9ee9700bdb56', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d', 7, '应用场景', '{\"page_id\": \"p07\", \"title\": \"核心任务三：机器翻译与摘要生成\", \"part\": \"应用场景\", \"points\": [\"Seq2Seq架构结合注意力机制，解决长序列编码解码中的信息丢失难题\", \"神经机器翻译（NMT）实现端到端训练，显著提升翻译流畅度与上下文一致性\", \"抽取式摘要保留原文关键句，生成式摘要则重构语言以提炼核心语义\", \"两者在新闻快讯、文档综述及跨语言交流场景中各有独特的应用价值\"]}', '{\"text\": \"页面标题：核心任务三：机器翻译与摘要生成\\n\\n页面文字：\\n- 采用Seq2Seq架构结合注意力机制，有效解决长序列编码解码过程中常见的信息丢失难题。\\n- 神经机器翻译通过端到端训练模式，显著提升了跨语言转换时的流畅度与上下文逻辑一致性。\\n- 抽取式摘要保留原文关键句，而生成式摘要则重构语言以提炼核心语义，两者各有独特价值。\\n- 这些技术广泛应用于新闻快讯自动生成、长文档综述整理及跨国跨语言交流等实际业务场景。\", \"generated_at\": \"2026-03-16T05:37:23.049268\"}', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d/pages/fd951099-447c-478e-8472-9ee9700bdb56_v1.png', 'COMPLETED', '2026-03-16 05:37:05', '2026-03-16 06:31:41', NULL, NULL);
