INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('fe7c4ea9-08db-4adb-ba95-9274a02fbfac', 'e43174bb-6386-4c02-9c5d-efa37adcd2cc', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"第一章：三维空间与数字几何\", \"layout_id\": \"academic_practice\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p03\"], \"must_cover\": [\"章节引入\", \"第一章：三维空间与数字几何的核心概念与背景\", \"第一章：三维空间与数字几何的关键方法与执行要点\", \"第一章：三维空间与数字几何的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第一章：三维空间与数字几何的核心概念与背景\", \"第一章：三维空间与数字几何的关键方法与执行要点\", \"第一章：三维空间与数字几何的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-10 05:18:54', '2026-03-10 05:18:54', 'academic_practice', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('fe85b6e8-7d1b-4abc-8fa5-bfa2d7f019f2', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d', 11, '收尾', '{\"page_id\": \"p12\", \"title\": \"未来展望与答疑环节\", \"part\": \"收尾\", \"points\": [\"多模态融合与具身智能：NLP将突破纯文本限制，迈向感知与行动一体化的新阶段\", \"垂直行业落地：医疗、法律等高精度场景将成为大模型商业化深耕的核心战场\", \"互动答疑：开放现场提问，解答课程中的技术难点与学习困惑\", \"资源推荐：分享经典论文列表、开源数据集及进阶学习路径指南\"]}', '{\"text\": \"页面标题：未来展望与答疑环节\\n\\n页面文字：\\n- 多模态融合与具身智能：NLP将突破纯文本限制，迈向感知与行动一体化的新阶段。\\n- 垂直行业落地：医疗、法律等高精度场景将成为大模型商业化深耕的核心战场。\\n- 互动答疑：开放现场提问，解答课程中的技术难点与学习困惑。\\n- 资源推荐：分享经典论文列表、开源数据集及进阶学习路径指南。\\n- 结语：希望同学们能将理论转化为实践，共同推动自然语言处理技术的创新应用。\", \"generated_at\": \"2026-03-16T05:37:22.733011\"}', '9eea7980-f6c7-4f16-8e32-59f2ec058d8d/pages/fe85b6e8-7d1b-4abc-8fa5-bfa2d7f019f2_v1.png', 'FAILED', '2026-03-16 05:37:11', '2026-03-16 06:32:54', NULL, NULL);
