INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ff3a06d2-5b13-428c-bec9-a04c11f2e5aa', '6eea18f8-c641-48a1-ba84-4c49ed3830d6', 16, NULL, '{\"page_id\": \"p17\", \"title\": \"常见问答：关于 OpenClaw 的误解澄清\", \"layout_id\": \"edu_qa_case\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p16\"], \"must_cover\": [\"Q1: 安全性疑问\", \"A1: 沙箱机制详解\", \"Q2: 兼容性问题\", \"A2: 驱动层适配方案\", \"常见问答：关于 OpenClaw 的误解澄清的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"常见问答：关于 OpenClaw 的误解澄清的核心概念与背景\", \"常见问答：关于 OpenClaw 的误解澄清的关键方法与执行要点\", \"常见问答：关于 OpenClaw 的误解澄清的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"qa_session\", \"layout_variant\": \"b\", \"logical_page_id\": \"p17\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-10T06:27:09.079825\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-10 06:25:47', '2026-03-10 06:27:09', 'edu_qa_case', '{\"title\": \"关于 OpenClaw 的误解澄清\", \"subtitle\": \"直面核心疑问，构建安全信任基石。\", \"question\": \"OpenClaw 是否具备足够的安全性与广泛的兼容性？\", \"answer\": \"通过多层沙箱隔离机制确保绝对安全，并采用自适应驱动层实现全平台无缝适配。\", \"analysis\": [{\"title\": \"安全性疑问解析\", \"content\": \"采用内核级沙箱隔离技术，切断恶意代码传播路径，确保运行环境零泄露风险。\"}, {\"title\": \"兼容性问题方案\", \"content\": \"驱动层自动识别硬件特征并动态加载适配模块，解决异构环境下的部署冲突难题。\"}], \"conclusion\": \"安全是底线，兼容是基石，OpenClaw 以技术自信回应所有质疑。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"qa_session\"}');
