INSERT INTO `projects` (`id`, `idea_prompt`, `outline_text`, `description_text`, `extra_requirements`, `creation_type`, `template_image_path`, `status`, `created_at`, `updated_at`, `render_mode`, `template_style`, `export_extractor_method`, `export_inpaint_method`, `scheme_id`, `user_id`) VALUES ('c3f4f20a-0839-4fb0-9375-125c6af13f37', '请为高职《工业机器人技术》课程生成一份 PPT 大纲。\n主题： 工业机器人的末端执行器（夹持器）分类与应用。\n教学对象： 机电一体化专业大二学生。\n要求： > 1. 情境导入： 以汽车自动化生产线上的焊接与抓取任务作为开场情境。\n2. 理实结合： 重点讲解吸附式、夹持式执行器的结构差异，并对应到实际工业案例中。\n3. 职业标准： 加入关于末端工具更换的安全操作规范（SOP）。\n4. 课堂互动： 在结尾设置一个“根据给定零件选配最合适夹具”的案例讨论环节。\n风格： 科技严谨，配合清晰的结构化图表布局。', NULL, NULL, NULL, 'idea', NULL, 'DESCRIPTIONS_GENERATED', '2026-03-19 14:03:07', '2026-03-19 14:25:17', 'html', NULL, 'hybrid', 'hybrid', 'voc_skill', '1');
